insert into hudsonu.event values(10015083,'LGBTQ+ Professional Headschots',cast('2024-03-25 16:00' as date),cast('2024-03-25 17:00' as date),'Alumni Hall Room 111','Group Business',NULL,'LAMBDA','Do you have a fun, fruity head shot for your LinkedIn in yet? How about one for your research presentation poster or conference? Well look no further! In celebration of 2024 Queerfest, come get a professional headshot for FREE! March 25th from 4-6pm. Spots are limited so register here: https://forms.gle/1xsk4LqMDVVLwWZX8.',500);
insert into hudsonu.event values(1025954,'Buddhist Lunch Discussion',cast('2016-09-06 12:15' as date),cast('2016-09-06 12:15' as date),'Chapel basement lounge, University chapel','Spirituality',NULL,'HBC','Hudson Buddhist Community holds lunch discussions every other Tuesday from 12.20pm-1.10pm in the chapel basement lounge. There will be six lunches for the Fall 2017 semester. For the 2016-2017 academic year, we are going to use this text: The Thirty-seven Practices of a Bodhisattva by Ngulchu Thogme Zangpo. This text is centered around practices of a Mahayana Buddhist and teaches some of the most essential principles and ways of practice in Buddhism. For each discussion, we are going to talk about two or three verses of the text. Not only will we study the literal and deeper meaning of the text, we are going to discuss how to incorporate some of the teachings into daily lives. While a member of the group who has studied and prepared for the discussion materials will facilitate each discussion, all are encouraged to voice your own opinions in order to create a engaging and intellectual atmosphere for everyone to learn about Buddhism as well as to reflect on one''s life and beliefs. All members from the Hudson community are welcome, and we aim to make all materials intelligible and accessible to all.',340);
insert into hudsonu.event values(1025955,'Buddhist Lunch Discussion',cast('2016-09-20 12:15' as date),cast('2016-09-20 12:15' as date),'chapel basement lounge, university chapel','Spirituality',NULL,'HBC','Hudson Buddhist Community holds lunch discussions every other Tuesday from 12.20pm-1.10pm in the chapel basement lounge. There will be six lunches for the Fall 2017 semester. For the 2016-2017 academic year, we are going to use this text: The Thirty-seven Practices of a Bodhisattva by Ngulchu Thogme Zangpo. This text is centered around practices of a Mahayana Buddhist and teaches some of the most essential principles and ways of practice in Buddhism. For each discussion, we are going to talk about two or three verses of the text. Not only will we study the literal and deeper meaning of the text, we are going to discuss how to incorporate some of the teachings into daily lives. While a member of the group who has studied and prepared for the discussion materials will facilitate each discussion, all are encouraged to voice your own opinions in order to create a engaging and intellectual atmosphere for everyone to learn about Buddhism as well as to reflect on one''s life and beliefs. All members from the Hudson community are welcome, and we aim to make all materials intelligible and accessible to all.',340);
