insert into hudsonu.event values(1157513,'Hudson Stand Up Presents: City Escape',cast('2017-02-04 21:00' as date),cast('2017-02-04 22:30' as date),'Donovan''s Pub','Arts',NULL,'HSU','Hudson Stand Up will be inviting three New York City Comedians to join them at an epic comedy show. The comedians, Rashad Bashir, Justin Ramos, and Kevin Mason, will be performing at Donovan''s Pub during a one and a half hour showcase. Hudson Stand Up Comedians will be opening for the performers. The performance will be taking place from 9pm-10:30pm on February 4th, 2017.'||chr(10)||'In addition, the comedians will be holding a workshop with Hudson Stand Up members earlier in the evening. This serves the purpose of educating any and all students who wish to come and learn more about the best practices in stand up comedy.'||chr(10)||'The performance in Donovan''s Pub will be open to all Hudson students and staff.',500);
insert into hudsonu.event values(1213352,'Konosioni Induction Ceremony',cast('2017-02-10 15:15' as date),cast('2017-02-10 17:30' as date),'Hudson Chapel','Group Business',NULL,'THS','Induction ceremony for the Konosioni Class of 2017.',750);
insert into hudsonu.event values(1213392,'Shabbat',cast('2017-01-27 12:00' as date),cast('2017-05-12 12:00' as date),'SAP','Spirituality',NULL,'HJU','Shabbat: The Hudson Jewish Union is requesting funding for Shabbat dinners in order to prepare for and celebrate one of the most important days and oldest traditions in Judaism. Shabbat is the most holy Jewish holiday and we invite everyone in the surrounding area including the town of Hamilton.  We are the only Synagogue within 40 miles of Hamilton.  Specifically, all funds will be going to the food costs and dinner associated with the traditional Sabbath meal as well as the traditions we practice such as lighting candles and drinking grape juice (Not wine).',140);
insert into hudsonu.event values(173235,'Classic City Invitational (UGA)',cast('2012-10-19 09:00' as date),cast('2012-10-22 20:00' as date),'Atlanta, Georgia',NULL,NULL,'MT','The Hudson University Mock Trial team was recently invited to participate in an elite tournament at the University of Georgia. Attending this tournament would involve leaving Hudson on October 19th, flying to Atlanta, Georgia for two days of competition, and flying back to Hudson.',300);
insert into hudsonu.event values(173329,'US Universities National Open Debate Tournament',cast('2012-05-10 13:15' as date),cast('2012-07-10 11:15' as date),'Claremont McKenna College, 500 E. 9th Street Claremont, CA 91711 (909) 621-8000',NULL,NULL,'DS','Claremont McKenna College together will Claremont Colleges Debate Union is hosting US universities National Open Debate Tournament. This tournament will be based on British parliamentary format, and is open to all US universities and colleges. The tournament will consist of 8 preliminary rounds on the first two days, followed by three elimination rounds on the third day. Hudson University has been invited, and will be sending 3 debate team and 2 judges to the tournament. Auditions for the tournament are still ongoing.',450);
insert into hudsonu.event values(177823,'International Talk Like a Pirate Day Dinner',cast('2012-09-22 18:00' as date),cast('2012-09-22 18:00' as date),'ALANA Cultural Center',NULL,NULL,'SASS','Pirates and Pasta, come learn about the origins of this holiday and its significance.',290);
insert into hudsonu.event values(178332,'Russian Tea CANCELLED',cast('2012-10-08 16:30' as date),cast('2012-10-08 16:30' as date),'Lawrence 201',NULL,NULL,'REC','Students will discuss Russian culture and contemporary Russian issues, while enjoying tea and traditional Russian sweets. Russian language proficiency is not required.'||chr(10)||' ',420);
insert into hudsonu.event values(178334,'Days of Destruction, Days of Revolt: An evening with Chris Hedges',cast('2012-10-22 19:00' as date),cast('2012-10-22 21:30' as date),'Love Auditorium',NULL,NULL,'DM','Democracy Matters, PCON, Environmental Studies, CORE Scientific Perspectives, the Geography department, and NASC will bring Chris Hedges to campus on October 22nd to deliver a lecture on his latest book entitled Days of Destruction, Days of Revolt. The lecture will begin at 7, followed by a catered reception/book signing at 8:30, and finally a live showing of the Presidential debate at 9.',550);
insert into hudsonu.event values(181445,'Live Showings of the Presidential Debates',cast('2012-10-16 20:30' as date),cast('2012-10-16 22:00' as date),'Love Auditorium, Persson Auditorium',NULL,NULL,'DM','Democracy Matters would like to host live showings of the Presidential debates and have these showings be catered so as to incentivize students to watch the debates and become more politically aware and engaged. We will also be hosting a panel discussion after the last debate and before voting day. Professors from various academic departments will participate in this event. They will each give a 10 minute talk on how the outcome of the election will affect their particular academic expertise.',590);
insert into hudsonu.event values(181446,'Oktoberfest 2012',cast('2012-10-18 19:00' as date),cast('2012-10-18 20:00' as date),'100 Broad Street (Creative Arts House)',NULL,NULL,'GC','An annual celebration of Germany''s most famous cultural festival by German Club, with food made by club members and lots of interesting activities.',null);
insert into hudsonu.event values(182898,'Thomas Dale and Michael Blaustein',cast('2012-11-10 19:00' as date),cast('2012-11-10 20:15' as date),'LOVE',NULL,NULL,'SAA','Thomas Dale and Michael Blaustein from MTVs Punkd and VH1 talking head shows.',560);
insert into hudsonu.event values(185273,'CWIB Family Weekend Reception',cast('2012-10-27 14:00' as date),cast('2012-10-27 14:30' as date),'13 E Kendrick St Hamilton NY 13346',NULL,NULL,'HWIB','Reception for members of Hudson Women in Business and their families. Keynote from Dan Rosensweig, CEO of Chegg Inc., P''15. ',595);
insert into hudsonu.event values(188982,'BSU Release Night',cast('2012-11-30 18:30' as date),cast('2012-11-30 20:30' as date),'Coop Tv Room',NULL,NULL,'BSU','Release Night is an opportunity for students on campus to express themselves and speak on social, political, economic concerns that they have been pondering. It is a welcoming and encouraging space for dialogue to occur on the basis of the type of concerns, questions, and aspirations etc that Hudson students raise to one another. Black Student Union takes great pride in celebrating students voices and through the hosting of Release Nights we provide this platform.',320);
insert into hudsonu.event values(188992,'Black Solidarity Day',cast('2012-11-05 17:00' as date),cast('2012-11-05 19:00' as date),'Alana Multipurpose Room',NULL,NULL,'BSU',' Solidarity Day is a national event in which black men, women, and, students, and faculty around the country come together in unity to discuss the political status and the future of the black community and its effect on the world overall. The theme for the event this year is "Political and Economic Power through Solidarity". This event seeks to raise awareness and education about the presence and impact of people of color on campus and celebrate our identities and community. ',540);
insert into hudsonu.event values(188993,'BSU Family Weekend Banquet',cast('2012-10-27 17:00' as date),cast('2012-10-27 18:00' as date),'The Edge Cafe',NULL,NULL,'BSU','The Annual BSU Family Weekend Banquet is an event where students and their families come together to celebrate their accomplishments and look forward to the future.',null);
insert into hudsonu.event values(188995,'Pre-Law Society Trip to Syracuse Law School',cast('2012-11-02 08:00' as date),cast('2012-11-02 16:00' as date),'Syracuse University Law School',NULL,NULL,'HPLS','The Pre-Law Society will be taking a field trip to the Syracuse University Law School. Students will have the ability to attend a law class, tour the law school, attend a brief QandA with Admissions/Financial Aid, visit a law firm, and tour a courthouse. ',440);
