insert into hudsonu.event values(189010,'Finance Club NYC Immersion Trip',cast('2012-11-08 10:30' as date),cast('2012-11-10 14:30' as date),'New York City',NULL,NULL,'HTC','On this trip, students will have the chance to interact and network with alumni and other professionals in the financial world - in both corporate and social settings. Students will arrive in New York City Thursday Evening, and will rest before visiting alumni and other professionals within several New York Based financial service firms and banks on Friday. Afterwards, students will have the opportunity to meet, socialize, and network with Hudson Alumni working in the financial industry at a dinner. Students will return Saturday Morning. ',200);
insert into hudsonu.event values(189011,'Finance Managing Directors Visit',cast('2012-11-16 15:00' as date),cast('2012-11-16 19:00' as date),'persson 27, hudson inn',NULL,NULL,'HTC',NULL,180);
insert into hudsonu.event values(190523,'Haunted House',cast('2012-10-27 19:00' as date),cast('2012-10-27 20:00' as date),'La Casa',NULL,NULL,'LASO','Get Ready! Halloween it''s almost here and to celebrate it we will be hosting our annual Haunted House on October 27th from 7:00 pm to 9:00 pm. Co-sponsored by KSA, La Casa and Asia House. '||chr(10)||'Don''t miss out on a great event!! '||chr(10)||' ',350);
insert into hudsonu.event values(190653,'Hudson Economist',cast('2012-10-29 14:45' as date),cast('2012-10-29 14:45' as date),'Hamilton New York',NULL,NULL,'HTC','The Hudson Economist is a magazine on campus that seeks to educate the Hudson and Hamilton Community by publishing objective and factually accurate articles exploring different economic, financial, technological, and business issues, developments, and events.',425);
