insert into hudsonu.event values(202261,'CIDD British Debate Tour 2012',cast('2012-11-29 16:30' as date),cast('2012-12-04 17:30' as date),'Hudson University',NULL,NULL,'DS','Ettie Bailey-King and Willard Foxton will be representing the British National Debate Team on tour throughout the United States Sept-Dec 2012. They will be coming to Hudson on 29th of November, and will be here till 4th of December.',null);
insert into hudsonu.event values(203170,'Gingerbread Competition',cast('2012-11-14 18:00' as date),cast('2012-11-14 20:00' as date),'HOP',NULL,NULL,'HFH','Habitat For Humanity is hosting it''s third annual Gingerbread Competition on November 14th from 6-8pm in the HOP. We will provide all the icing, graham crackers, and candy to build your wonderful creations! Hot chocolate and tea will also be provided. Sign up with your friends and work together! There are a variety of different categories to win prizes in, so there will be many winners!Tickets will be available in the coop!!',300);
