insert into hudsonu.event values(214426,'Student Activities Fair',cast('2013-01-23 16:15' as date),cast('2013-01-23 18:30' as date),'The Hall Of Presidents and Clark Room, James C. Hudson Hall',NULL,NULL,'SGA','Want to get more involved? Come to the Activites Fair to find your niche or do something new that you''ve never experienced, but always wanted to. Show up and be social, its a great place to meet people and get involved with some great groups of kids doing great things!',350);
insert into hudsonu.event values(220017,'CAB Take Two: Hello, I Must Be Going',cast('2013-01-25 22:00' as date),cast('2013-01-25 23:00' as date),'Love Auditorium',NULL,NULL,'SAA','CAB take two presents Hello, I must Be Going:'||chr(10)||'Circumstances force a young divorcee to move back in with her parents in suburban Connecticut, where an affair with a younger guy rejuvenates her passion for life.'||chr(10)||'from imdb.com',null);
insert into hudsonu.event values(220060,'Hudson Activities Fair',cast('2013-01-24 16:30' as date),cast('2013-01-24 18:30' as date),'The HOP/Clark Room (in James C. Hudson Hall)',NULL,NULL,'SGA','Any and every activity you could be a part of will be there! Get out there and get involved, the best experiences you will have in college will be in following your passions or trying new things outside the classroom. Meet people, do something special and sign yourself up!',360);
insert into hudsonu.event values(225877,'Poetry Open Mic Night Featuring: Jose Canta',cast('2013-03-29 20:00' as date),cast('2013-03-29 20:30' as date),'Donovan''s Pub',NULL,NULL,'DPS','A poetry open mic night emceed by and featuring Jose Canta, professional poet and Hamilton College graduate.  The show will emphasize the experiences of this first-generation Latino as well as feature the unique creations of our own student body. ',500);
insert into hudsonu.event values(229605,'ATMA Regional Tournament',cast('2013-02-22 14:00' as date),cast('2013-02-24 22:00' as date),'Buffalo, NY',NULL,NULL,'MT','The mock trial team will be participating in the American Mock Trial Association''s Regional Tournament in Buffalo, NY this February. This is the first of a series of three tournaments sponsored by the American Mock Trial Association, culiminating with the National Championships in April. ',310);
insert into hudsonu.event values(232467,'Konosioni New Member Induction Ceremony',cast('2013-03-04 16:30' as date),cast('2013-03-04 18:30' as date),'Hudson University Chapel',NULL,NULL,'THS','This event will be our formal ceremony to welcome the Konosioni class of 2014.',420);
insert into hudsonu.event values(235885,'Campeonato Mundial Universitario de Debate en Espanol',cast('2013-07-22 21:15' as date),cast('2013-07-31 21:15' as date),'Madrid, Spain',NULL,NULL,'LASO',NULL,180);
insert into hudsonu.event values(235941,'N+1 Magazine Discussion',cast('2013-03-20 16:30' as date),cast('2013-03-20 16:30' as date),'105 Lawrence',NULL,NULL,'PORT','N+1 Magazine, a literary magazine, will be doing a college campus tour and is coming to Hudson in March. They will lead a reading and discussion about publishing, how to make money as a writer, and other topics pertaining to the literary world. ',500);
insert into hudsonu.event values(237377,'Ron Paul Lecture: "Liberty Defined: The Future of Freedom"',cast('2013-04-24 16:00' as date),cast('2013-04-24 17:30' as date),'Chapel',NULL,NULL,'CR','Ron Paul will be speaking today in the Hudson Memorial Chapel at 5pm. Doors will open at 4pm so that audience members can get their seats. The event is ticket and you must present your ticket upon entering the venue to be granted admission. 20-30 extra tickets will be available at the door on a first come/ first serve basis for those who were unable to get them during the original ticket sale.'||chr(10)||'Dr. Paul will be speaking for approximately 45 minutes and will then answer any questions presented by the audience. It has been requested that no audio or video recordings be permitted during the lecture. In the event that you do not have a ticket and would still like to see the lecture, a Live Stream will be available in Lawrence 105.This event is sponsored by the College Republicans, the Center for Freedom and Western Civilization, the Institute for Philosophy, Politics, and Economics, The Budget Allocation Committee, Students for a Sensible Drug Policy, and The Hudson Entrepreneurs Club.'||chr(10)||''||chr(10)||'For any additional questions regarding the event, please contact Taylor Hollen (thollen@hudson.edu).',500);
insert into hudsonu.event values(238994,'Rick Kahlbaurgh Lecture',cast('2013-04-11 17:00' as date),cast('2013-04-11 17:15' as date),'Ho 101',NULL,NULL,'HTC','Rick Kahlbaurgh and Ted Rollins, both CEOs of public companies are coming to campus on April 11th to speak on three main topics: IPOs, MandA deals, and the developing the necessary skills to run a company.',null);
insert into hudsonu.event values(244415,'The Naked Truth about Homosexuality in the Caribbean',cast('2013-03-28 11:30' as date),cast('2013-03-28 11:15' as date),'Women Studies Lounge',NULL,NULL,'CSA','With the help of WMST and LGBTQ Initiatives, CSA will be hosting a brown bag about the issue of homosexuality in the Caribbean. There will be a panel of students, some speaking from first-hand experience, about the homosexuality surrounding the communities in the Caribbean and the steps being taken to overcome this issue. Come out for a great discussion and invite your friends! Hosted by CSA',440);
insert into hudsonu.event values(249613,'Gate-Town Connection',cast('2013-04-07 16:00' as date),cast('2013-04-07 18:00' as date),'Whitnall Field',NULL,NULL,'BDS','Please join Hudson faculty and Hamilton residents on Whitnall Field for our third town-gown event, celebrating the strong connection between the Hudson and Hamilton communities. There will be a free BBQ (Frank will be closed), Danger Boy concert, inflatables, and a pie-eating contest!',425);
insert into hudsonu.event values(252280,'CCF Large Group: Modern Day Slavery',cast('2013-04-09 19:00' as date),cast('2013-04-09 19:00' as date),'Chapel Basement',NULL,NULL,'HCF','Discussion on the facts, causes, and ramifications of modern day slavery and human trafficking. 27 Million people are enslaved today, find out more.',null);
insert into hudsonu.event values(252281,'CCF Brown Bag: Shine a Light on Slavery',cast('2013-04-09 12:15' as date),cast('2013-04-09 12:15' as date),'Chapel Basement',NULL,NULL,'HCF','Brown Bag lunch lead by Susan Thomson of the PCON department and senior Jenna Jacoby about modern day slavery and human trafficking. Part of Hudson Christian Fellowship''s Shine a Light on Slavery Week in conjunction with "End It Movement." Catered by Hamilton Whole foods. ',400);
insert into hudsonu.event values(253676,'Spring Party Weekend 2013',cast('2013-04-19 19:30' as date),cast('2013-04-21 15:00' as date),'Various',NULL,NULL,'SAA','For a more in depth description of events please visit our website at www.hudsonspw.com',250);
insert into hudsonu.event values(254605,'Wearable Art Runway Show',cast('2013-04-27 17:00' as date),cast('2013-04-27 20:00' as date),'Parker Commons',NULL,NULL,'SAA',NULL||chr(10)||'Students in groups of 2-4 people--one model included-- have two hours to design and create their own wearable art dresses/clothing out of recycled materials. At 7:30 PM doors will open to audience, and the groups'' designs will be modeled on the runway and the audience will vote for their favorite creation. Food and refreshments will be served as votes are tallied. The winning team gets a prize and bragging rights!'||chr(10)||'',370);
insert into hudsonu.event values(256313,'Mid-Term Study Break',cast('2013-10-20 17:30' as date),cast('2013-10-20 18:00' as date),'Donovan''s Pub',NULL,NULL,'SAA','This is a study break for students in Donovan''s Pub with mozzarella sticks, pizza, and chicken tenders. ',220);
insert into hudsonu.event values(256316,'The Fifth Annual Hudson Classic',cast('2013-11-02 06:00' as date),cast('2013-11-03 22:00' as date),'Hamilton, NY',NULL,NULL,'MT','On November 2-3, 2013, the Hudson Mock Trial Team will be hosting the Fifth Annual Hudson Classic Mock Trial Tournament on campus. During this weekend, other AMTA recognized teams from various universities will attend and compete against the Hudson team and each other in four rounds of "mock trials."Attorneys and judges from the area, as well as a number of Hudson alumni, will also attend to judge the rounds. ',350);
insert into hudsonu.event values(256318,'CIC Fall Break Overnight Trip to NYC',cast('2013-10-13 05:30' as date),cast('2013-10-14 02:30' as date),'New York City',NULL,NULL,'HIC',NULL,180);
insert into hudsonu.event values(256344,'Bienvenidos BBQ',cast('2013-08-29 12:30' as date),cast('2013-08-29 13:30' as date),'La Casa',NULL,NULL,'LASO','The Bienvenidos BBQ is an event for all incoming Latino/Hispanic students to meet other Latino/Hispanic students, and anyone other Hudson students that are interested in coming to the BBQ. This is a networking/social event with catered food and Latino music to demonstrate some of Hudsons diversity. ',190);
insert into hudsonu.event values(270378,'Welcome Back Release Night',cast('2013-09-06 18:30' as date),cast('2013-09-06 19:30' as date),'ALANA Lounge',NULL,NULL,'BSU','Release Night is an opportunity for students on campus to express themselves and speak on social, political, and economic concerns that they have been pondering. It is a welcoming and encouraging space for dialogue to occur on the basis of the type of concerns, questions, and aspirations that Hudson students raise to one another. The Black Student Union takes great pride in celebrating students voices. Through the hosting of Release Nights we provide this platform.'||chr(10)||'Essentially, it is a chance to gain support and recognition through others about the struggles and achievements that Hudson students may be enduring. Students are provided a support structure, which allows them to openly voice their thoughts without fear of being judged. We want to especially hold a Welcome Back Release Night event to attract first-years so they feel comfortable actively interacting with students on their own terms, with regard to what it is they feel they want to share.',375);
insert into hudsonu.event values(281691,'Take Two Saturday Matinee: Silver Linings Playbook',cast('2013-04-27 15:30' as date),cast('2013-04-27 16:45' as date),'Love Auditorium',NULL,NULL,'SAA','CAB Take Two present:'||chr(10)||'Silver Linings Playbook (Fri 7pm, Sat 3:30pm and 10pm) '||chr(10)||'After a stint in a mental institution, former teacher Pat Solitano moves back in with his parents and tries to reconcile with his ex-wife. Things get more challenging when Pat meets Tiffany, a mysterious girl with problems of her own.'||chr(10)||'The Hobbit: An Expected Journey (Fri 10pm, Sat 7pm) '||chr(10)||'A younger and more reluctant Hobbit, Bilbo Baggins, sets out on an "unexpected journey" to the Lonely Mountain with a spirited group of Dwarves to reclaim their stolen mountain home from a dragon named Smaug.'||chr(10)||' ',400);
insert into hudsonu.event values(281747,'Student Involvement Fair',cast('2013-09-03 16:00' as date),cast('2013-09-03 17:00' as date),'Academic Quad (HOP and Huntington if rain)',NULL,NULL,'SGA','If you are interested in joining a student organization at Hudson, come to the student involvement fair! Representatives from each student organization will be available to tell you more about their organizations and recruit new members. ',200);
