insert into hudsonu.event values(287389,'Pre-Law Practice LSAT',cast('2013-09-28 08:00' as date),cast('2013-09-28 11:00' as date),'101 Ho',NULL,NULL,'HPLS','The Pre-Law will be hosting its second annual practice LSAT test, the weekend before the October LSAT test date. Having a practice test helps students simulate the real experience, and allows for a test-day experience ahead of time. This helps to better prepare students for the actual experience of taking an LSAT. The test will be proctored, and will include the most recent LSAT prep tests. ',650);
