insert into hudsonu.event values(319934,'BSU Fall Keynote Speaker Series: "Civil Rights in America. What are you going to do about it?" lecture by Joe Madison',cast('2013-10-28 17:30' as date),cast('2013-10-28 17:30' as date),'Love Auditorium',NULL,NULL,'BSU','The Black Student Union will host Joe Madison as our Fall Keynote Speaker. Joe Madison, also known as "The Black Eagle", is a legendary voice in radio. Madison is a talk radio personality heard on Sirius XM Satellite Radio, Inc. He has been named one of Talker Magazine''s 10 Most important Radio Talk Show Host nine times. That recognition only skims the surface of his extraordinary commitment to social justice locally and internationally. Madison is more than just a radio talk show host. He is a radio activist. Not only does he use his microphone to bring attention to social injustices here and abroad, he also challenges himself and his listeners to do something about it. Joe Madison will speak to Hudson University about the Civil Rights Movement, the 50th Anniversary of the March on Washington, the Trayvon Martin case and white privilege. This event is co-sponsored by The Department of Writing and Rhetoric. Dinner is to follow at 7 in ALANA.',580);
insert into hudsonu.event values(319944,'Students for Environmental Action Film Series',cast('2013-11-06 19:00' as date),cast('2013-11-06 21:00' as date),'Ho 101',NULL,'Sustainability','SEA',NULL,180);
insert into hudsonu.event values(319945,'Black Solidarity Day Dinner',cast('2013-11-04 20:00' as date),cast('2013-11-04 21:30' as date),'ALANA Multipurpose Room',NULL,NULL,'BSU','"Black Solidarity Day is a day to celebrate solidarity between all Black individuals. On the Hudson campus, the BSU uses this as an opportunity to celebrate solidarity between everyone regardless of race, gender, sexuality etc. Black Solidarity Day consists of a speakout, a traditional candle-lit walk from the HRC to ALANA, and a dinner. The speakout will be held on the Chapel Steps from12:15-1:15. President Herbst will be there to say a few words on diversity at Hudson. The traditional candle-lit walk from the HRC to ALANA will start at 7:45 and the dinner will be from 8-9:30 at ALANA. The dinner is used to discuss the theme for the day while providing a safe, welcoming and uniting environment."',480);
