insert into hudsonu.event values(319948,'International Game Night',cast('2013-11-08 19:00' as date),cast('2013-11-08 22:30' as date),'Coop Multimedia room + Fire place',NULL,NULL,'HIC','We are planning to host an International Games Night to share the traditional games of various cultures. This event will be a collaboration of many cultural groups across the campus, including Korean Students Association, German Club, French Club, Chinese Interest Association, Latin American Students Organization, Caribbean Students Association, Hudson Vietnam Society, Japan Club, South Asian Cultural Club, ASU, Russian Club.',290);
