insert into hudsonu.event values(345517,'AMTA Regional Tournament',cast('2014-02-07 15:00' as date),cast('2014-02-09 23:00' as date),'Buffalo State University',NULL,NULL,'MT','The Hudson Mock Trial Team will be competing in the annual AMTA Regional tournament in hopes of gaining a bid to ORCS - the first round of national competition. ',290);
insert into hudsonu.event values(361007,'Princeton Interactive Crisis Simulation 2014',cast('2014-02-20 16:30' as date),cast('2014-02-23 17:30' as date),'Princeton, NJ',NULL,NULL,'MUN','This is a crisis-based Model United Nations conference, meaning that our delegates will be in a much more competitive and immersive environment than at regular conferences. The conference lasts for four days, over the course of which our delegates debate in committee sessions for upwards of 7 hours a day in order to advance the position of their assigned country.',440);
insert into hudsonu.event values(366322,'Northeast Regionals',cast('2014-02-22 08:00' as date),cast('2014-02-23 20:00' as date),'Western Connecticut College',NULL,NULL,'DS','Western Connecticut College will host the Hat City Debate Tournament, which serves as the regional championship. The tournament is a British Parliamentary style tournament featuring five preliminary rounds of competition and is open to both novice and varsity level debaters. It will take place Saturday, February 22 through Sunday, February 23. Hudson will be competing against many of the best teams in the US. ',590);
insert into hudsonu.event values(366329,'Africana Women''s Week',cast('2014-02-25 11:30' as date),cast('2014-03-09 02:00' as date),'WMST',NULL,NULL,'SRT','Sisters of the Round Table (SORT) is requesting funding for our annual Africana Womens Week, a week dedicated to highlighting inspirational women of color and identifying with womens issues. Sisters of the Round Table is a support network for women of color that focuses on increasing awareness and addressing issues facing women and women of color within and beyond the Hudson community. This year, SORT is designating the last week of February, leading into Womens History Month as Africana Womens Week (s). This year we are planning to have our events from February 25 to March 8, 2013 in order to space out our events so more people are likely to attend and to reduce stress from CORE members organizing these events.  Africana Womens Week not only raises awareness about the issues talked about in its forum, but also that March is Womens History Month - meant to celebrate the beauty, intellect and accomplishment of the women who came before us, and a guide to the women after us. The purpose of this week is to hold events pertaining to issues concerning women of color and also to pay homage to prominent female figures of color and female figures in general, that deserve recognition, and often go unnoticed. Each event that SORT sponsors this week will be focused on both building a support network and fostering a greater sense of community. All of our events will address basic human issues such as inequality, identity issues and problems with self-expression, which affect a great number of people in the Hudson community. All events will be open to the Hudson community to attend and we hope they foster better relationships among the members of this community as well as enhance peoples understanding of themselves and the relationships that they share with people. ',320);
insert into hudsonu.event values(366330,'Konosioni Induction',cast('2014-02-14 15:00' as date),cast('2014-02-14 17:00' as date),'Memorial Chapel',NULL,NULL,'THS','New members of Konosioni are traditionally selected in the spring of each academic year. After being selected, new members are inducted into the honor society by current Konosioni members. It is a time to acknowledge their outstanding leadership, and their dedicated service to the community and preservation of tradition.  ',430);
