insert into hudsonu.event values(375550,'Hudson IV Tournament',cast('2014-03-28 12:15' as date),cast('2014-03-30 19:00' as date),'Hudson University',NULL,NULL,'DS','For that past four years the Hudson IV British Parliamentary Debate Tournament has drawn teams from the US, Canada and abroad. Past champions include Sydney University Union, University of Pennsylvania, and University of Otago. At a minimum, come see the Championship Round on 03/30 (tournament schedule below).Selected rounds will be livestreamed and can be viewed live on any internet-connected device.Tournament Schedule:Saturday (March 29)Opening Ceremonies 9:45-11:45 Round 111:45-1:45 Round 22:45-4:45 Round 34:45-6:45 Round 4Sunday (March 30)9:00-11:00 Round 5Break Announcement11:30-1:30 Quarterfinal (Livestreamed)2:30-4:30 Semi-Final (Livestreamed)4:30-6:30 Final (Livestreamed)',580);
insert into hudsonu.event values(375554,'Mediterranean Model United Nations',cast('2014-03-28 15:30' as date),cast('2014-03-30 15:30' as date),'Menton, France',NULL,NULL,'MUN','MEDMUN is a Model United Nations Conference dedicated to the Middle-East and the Mediterranean region. It is hosted by the Sciences Po College, Middle East and Mediterranean campus in Menton, France, and aims to tackle some of the numerous issues facing this region today. It is a chance to understand the complexity of the United Nations mission in the Middle-East and the Mediterranean region.'||chr(10)||'Normally our club attends Worlds MUN hosted by Harvard, but due to an increase of applicants our team was waitlisted and decided it was not worth waiting to see if we got in to plan our trip.',480);
