insert into hudsonu.event values(380815,'Project Unbreakable',cast('2014-04-17 12:30' as date),cast('2014-04-17 12:30' as date),'Lathrop 207',NULL,'Volunteer and Community Service ','TN','"The mission of Project Unbreakable is to increase awareness of the issues surrounding sexual assault and encourage the act of healing through art. Since the project''s conception in October 2011 by then nineteen year old Grace Brown, it has featured over two thousand images of sexual assault survivors holding posters with quotes from their attackers. Project Unbreakable has been featured media outlets such as Glamour, TIME, The Huffington Post, and The Guardian." Project Unbreakable''s website can be found at: http://projectunbreakable.tumblr.com/',null);
insert into hudsonu.event values(398329,'A Lecture by Katie Redford - Director and Co-Founder of EarthRights International',cast('2014-04-17 18:30' as date),cast('2014-04-17 19:30' as date),'Love Auditorium',NULL,NULL,'SEA','Alumna Katie Redford, current Director and Co-Founder of EarthRights International, is returning to campus to talk about her work and the role of corporations in present day society.  Join Students for Environmental Action, the Environmental Studies department, the Geography department, Career Services, and the Hudson University Office of Sustainability for light food and welcoming Ms. Redford back to the Hudson campus.',360);
insert into hudsonu.event values(399662,'Cambridge IV',cast('2014-11-14 16:00' as date),cast('2014-11-16 20:00' as date),'Cambridge, UK',NULL,NULL,'DS','The Cambridge Intervarsity (IV) tournament is one of the largest, most prestigious, and most competitive debating events on the British Parliamentary Debate Circuit. Hosted and run by the Cambridge Union Society, the IV attracts many of the best teams from universities all over the world. The Cambridge Union dates from 1815, and has a long history of hosting World leaders including Presidents, Prime Ministers, entrepreneurs, political activists, Nobel Price lauriates, Celebrities, and Sports Starts. The Unions weekly debates serve to engage and to challenge presumptions and prejudices and play to a packed house. The finals of the Cambridge IV are hosted in the Unions famous debate chamber which was modelled after the UKs House of Commons.'||chr(10)||'The next competition will be held on the 15th-16th November 2014. Over three hundred students will be attending and Hudson will send 3 teams consisting of a total of 6 students. Select rounds will be livestreamed. ',550);
insert into hudsonu.event values(399663,'Oxford IV',cast('2014-11-07 15:00' as date),cast('2014-11-09 20:00' as date),'Oxford, UK',NULL,NULL,'DS','The Oxford Inter-Varsity Debating Competition, hosted by the famous Oxford Union and the birthplace of BP debate, is one of the largest and most prestigious debating competition on the UK University circuit, and indeed globally. This year it will take place on the 8th-9th November 2014. This years Oxford IV will see five preliminary rounds of 7 minute speeches, breaking to Quarter Finals, ESL Semi Finals and novice Grand Final, world class judging led by an awesome CA team, all Grand Finals hosted in the famous Oxford Union Chamber, 140 team cap, introductory debating workshops, a Novice Grand Final and Best Novice Speaker prize. Select rounds will be available for viewing via livestream. ',420);
insert into hudsonu.event values(400323,'Night Market',cast('2014-04-04 22:00' as date),cast('2014-04-05 00:00' as date),'PAC House (110 Broad Street)',NULL,NULL,'KCA','This Friday from 10 P.M. to 1 A.M. there will be the 3rd Annual Night Market. Come enjoy late night food @110 Broad Street catered by different restaurants such as the Barge, Utica Street Cafe, Royal Indian Grill, and Mitsuba Hibachi Steakhouse and Grill, La Cocina and different club organizations (KSA, Brothers, Israeli Club, German Club, French Club, LASO, SACC, Hawaii Club, Israeli Club, CIA, HVS, and the Sustainability Office)',250);
