insert into hudsonu.event values(462686,'Women in Leadership- The Journey of an African Woman in International Development and at Senior Level Cabinet Positions in Post-Conflict Liberia',cast('2014-09-19 17:00' as date),cast('2014-09-19 18:00' as date),'Center for Women''s Studies',NULL,NULL,'AS','This event involves a lecture given by Former Minister Hon. King-Akerele pertaining to her experience as a female Liberian Minister for Foreign Affairs as she expatiates on the role that African women can play and do play. As a world leader, Minister King-Akerele is a strong believer in the potential of Africas emerging youth to become impactful future leaders. Prior to Obamas recent US-Africa summit, she had been advocating for African countries to cultivate their youth through a variety of programs and policies. She will be speaking on Africa''s emerging leadership and on her vast experience as a woman of color in world politics and diplomacy. ',625);
insert into hudsonu.event values(462968,'Brothers and BDS Basketball Tournament',cast('2014-09-13 12:00' as date),cast('2014-09-13 14:00' as date),'Huntington Gymnasium, Broad St Broad St Hudson University, Hamilton, NY 13346',NULL,NULL,'BROS','Brothers and BDS present a 3 vs 3 Basketball Tournament fundraiser for the Publicolor and Innovation: Africa on Septemeber 13 at Noon in Huntington Gym. Invite your friends and Hamilton Locals. Get ready to compete and have fun.Here are links to the organization''s respective websites:http://www.publicolor.orghttp://www.innoafrica.org',550);
insert into hudsonu.event values(470450,'Alumni in China Virtual Panel',cast('2014-09-17 19:15' as date),cast('2014-09-17 19:30' as date),'Persson Auditorium',NULL,NULL,'HWIB','Hudson Asia Business Club is bringing five extraordinary alumni who are currently working at Shanghai, China on a virtual panel at Persson Auditorium at 7:15 pm on Sept. 17. Five alumni are from various industries, such as strategy consulting, legal, financial services, and higher educations. The virtual panel will cover the professional exprience and job opportunities in China. Don''t miss this great event if you are interested in pursing an international career in Asia. Food and drinks will be provided.',450);
insert into hudsonu.event values(471813,'Ebola in Africa: Deadly Threat or Media Hype?',cast('2014-09-18 11:15' as date),cast('2014-09-18 11:15' as date),'Lawrence 105 (Ho LEcture Room)',NULL,NULL,'HGHC','Ebola has been prominently in the news recently, with over 2000 cases this year in western Africa. This outbreak has raised many questions, including: where does Ebola come from; how does it cause disease; and how it is transmitted? Why has the current outbreak has gained such a high level of attention? Is Ebola a threat to a wider region of Africa or even the US? Associate Professor Geoff Holm will answer these questions and more about the biology and epidemiology of Ebola at a Brown Bag Lunch, sponsored by the Hudson Global Health Initiative. Thursday, September 18, at 11:20 in the Ho Lecture Room in Lawrence Hall.'||chr(10)||' ',425);
