insert into hudsonu.event values(507941,'The Hudson Hookup Culture Brown Bag',cast('2014-10-23 11:30' as date),cast('2014-10-23 12:00' as date),'O''Conner Campus Center','Thoughtful Learning',NULL,'BROS','Brothers and SGA presents its semi-annual brown bag on The Hudson Hookup Culture in the Coop TV on Thursday October 23 at 11:30am. We will have free Royal Indian Food.'||chr(10)||'The goal is of the Brown Bag is to foster meaningful and insightful discussions about taboo conversations regarding sex, gender, sexual orientation, sexual desires, urges, and fears in a safe productive manner.'||chr(10)||'We want to equip students with definitions and the language to talk about "hooking up" and to nuance the perception that people do not date at Hudson and why he/she/ze may choose to engage in this culture or not.'||chr(10)||'We hope everyone leaves the meeting learning the complexities and different factors that create and perpetuate the hook up culture.',null);
