insert into hudsonu.event values(606727,'Spring 2015 Leaders'' Training',cast('2015-03-26 16:30' as date),cast('2015-03-26 17:30' as date),'Olin Hall','Thoughtful Learning',NULL,'SGA','The Spring 2015 Leaders Training will be held on Thursday, March 26 from 4:30-6:30 PM in Love Auditorium and the surrounding classrooms. Food and refreshments will be provided in the lobby preceding the keynote address. Following the keynote address the training will consist of three 25-minute seminars in Love Auditorium, and leaders will have the choice to attend one of two seminars for both Sessions I and II. After this, all attendees will reconvene in Love Auditorium for Session III and a brief wrap up.'||chr(10)||'Topics for the evening include:'||chr(10)||''||chr(10)||''||chr(10)||'Primary Funding Sources: BAC Proposals'||chr(10)||''||chr(10)||''||chr(10)||'Professional Networks and Experience Translation'||chr(10)||''||chr(10)||''||chr(10)||'Effective Promotional Strategies'||chr(10)||''||chr(10)||''||chr(10)||'Secondary Funding Sources: Broad Street Association, Dean of the College, and Organizational Development Fund'||chr(10)||''||chr(10)||''||chr(10)||'Facilities and Campus Safety: Event Logistical Considerations'||chr(10)||''||chr(10)||''||chr(10)||'OAT-F: Practice and Process'||chr(10)||''||chr(10)||''||chr(10)||'Diversity and Inclusivity for Organizations'||chr(10)||''||chr(10)||''||chr(10)||'Attendance is mandatory for at least one representative of each student organization from CLSI and ALANA. However, we encourage you to invite additional members of your organization(s) to attend seminars that may be of interest to them. If you have any questions or concerns, feel free to reach out to David Kim, SGA/CLSI Liaison to Student Organizations, at sgaliaison@hudson.edu.',425);
