insert into hudsonu.event values(722316,'Harold and Maude',cast('2015-10-17 17:00' as date),cast('2015-10-17 18:00' as date),'Golden Auditorium, Little Hall','Arts',NULL,'HFS','A strange teenager, who enjoys attending funerals, befriends a seventy-nine year old woman and learns a thing or two about life. Released in 1971, this comedic cult classic will encourage you to live a bit lighter and remind you that it''s alright to make an ass out of yourself. Soundtrack written by Cat Stevens. Running time is 91 minutes.',null);
