insert into hudsonu.event values(821040,'Business Speed Networking',cast('2015-04-09 19:00' as date),cast('2015-04-09 19:00' as date),'Hall of Presidents','Group Business',NULL,'HWIB','To kick of Entrepreneur Weekend, Hudson Women in Business in collaboration with Communications Club, Marketing Club, Finance Club and Consulting Club is hosting a professional and engaging speed networking event on Thursday April 9 from 7-8pm in the Hall of Presidents. Please join us to improve your networking skills, share your professional experiences, speak with Hudson pre-professional club leaders, interact with Hudson students across class years, and learn from an alumni guest speaker! Students will be paired across class years and participate in a fun speed networking, simliar to speed daring! Come for a free Hamilton Eatery dinner! '||chr(10)||' ',400);
insert into hudsonu.event values(8297356,'FUSE AUDITIONS!!!',cast('2022-09-11 12:30' as date),cast('2022-09-11 13:00' as date),'Ryan Studio 209','Arts','Dance','FUSE','Come to Ryan 209 on Sunday, September 11th (12:30-2:00PM) to audition for FUSE, meet and dance with all our members, and learn more about FUSE!!! We are excited to meet you all!',null);
insert into hudsonu.event values(8309853,'The Hudson Resolutions Fall 2022 Auditions',cast('2022-09-08 16:00' as date),cast('2022-09-08 19:00' as date),'Dana Arts Center practice rooms','Arts','Concert/Music','HR','Sign up to audition for Hudson''s oldest gender inclusive a cappella group: The Hudson Resolutions. First-round auditions will take place from Thursday, Sept. 8th - Saturday, Sept. 10th in the Dana Arts Center practice rooms. The Google Form to request an audition is below; once you submit the form, the Reso secretary will reach out to you to confirm your audition time based on your expressed availability. You can also find Reso members tabling at the Coop or Frank Dining Hall and sign up in-person as well. Hope to see you there!'||chr(10)||'Audition Request Form: https://forms.gle/uESbvhMVrLcTuMr97',220);
