insert into hudsonu.event values(9280729,'Sex Museum: The Intersections of Our Bodies',cast('2023-09-20 17:00' as date),cast('2023-09-20 18:00' as date),'O''Connor Campus Center - COOP','Thoughtful Learning',NULL,'ALANA','Another sex museum opens it''s doors!'||chr(10)||'This chapter of the Sex Museum is focused on intersections of our bodies, its cultural and social representations, as well as our perceptions of the body.'||chr(10)||'Come and learn about:'||chr(10)||'- Healthy relationships;'||chr(10)||'- Body and its spectrum;'||chr(10)||'- How to address and prevent domestic / intimate / dating violence;'||chr(10)||'- Multiple forms of intimacy etc.'||chr(10)||' '||chr(10)||'There will be various activities, giveaways, and a lot of fun!',null);
insert into hudsonu.event values(9408266,'Zoom Interview with Mike Levinger from Hubspot',cast('2023-09-20 19:00' as date),cast('2023-09-20 19:00' as date),'Persson 210','Group Business',NULL,'HSMC','We will be having a zoom interview with alumni Mike Levinger from Hubspot. He will discuss his role in business development / sales and marketing.'||chr(10)||' ',500);
insert into hudsonu.event values(945052,'Host Your Own Shabbat',cast('2016-11-04 12:00' as date),cast('2016-11-04 12:00' as date),'SAP','Spirituality',NULL,'HJU','Shabbat: The Hudson Jewish Union is requesting funding for Shabbat dinners hosted individually by Jewish students in order to prepare for and celebrate one of the most important days and oldest traditions in Judaism. Shabbat is the most holy Jewish. Host your own Shabbat draws in other community members to learn about Shabbat in ways that are practices by different people.  For example, some people might do a reform service while other might perform a more conservative service.  This is key to provide a broad perspective regarding Jewish Life. Specifically, all funds will be going to the food costs and dinner associated with the traditional Sabbath meal as well as the traditions we practice such as lighting candles and drinking grape juice (Not wine).',40);
insert into hudsonu.event values(945056,'Shabbat',cast('2016-09-02 12:00' as date),cast('2016-09-02 12:00' as date),'SAP','Spirituality',NULL,'HJU','Shabbat: The Hudson Jewish Union is requesting funding for Shabbat dinners in order to prepare for and celebrate one of the most important days and oldest traditions in Judaism. Shabbat is the most holy Jewish holiday and we invite everyone in the surrounding area including the town of Hamilton.  We are the only Synagogue within 40 miles of Hamilton.  Specifically, all funds will be going to the food costs and dinner associated with the traditional Sabbath meal as well as the traditions we practice such as lighting candles and drinking grape juice (Not wine)',70);
insert into hudsonu.event values(945063,'Community Shabbat',cast('2016-09-09 12:00' as date),cast('2016-09-09 12:00' as date),'SAP','Spirituality',NULL,'HJU','Shabbat: The Hudson Jewish Union is requesting funding for Shabbat dinners in order to prepare for and celebrate one of the most important days and oldest traditions in Judaism. Shabbat is the most holy Jewish holiday and we invite everyone in the surrounding area including the town of Hamilton.  We are the only Synagogue within 40 miles of Hamilton.  Specifically, all funds will be going to the food costs and dinner associated with the traditional Sabbath meal as well as the traditions we practice such as lighting candles and drinking grape juice (Not wine).  Our community shabbats typically bring in double the normal amount of people thus not having the same people every week.  These shabbats include Shabbat 101, Faculty Shabbat, and BBQ Shabbat.  These are also a great way to get the freshman involved in Jewish life as they are within the first few weeks to month of the semester.',345);
insert into hudsonu.event values(9580208,'Zoom Discussion Panel - IBM and Pilothouse',cast('2023-11-30 16:30' as date),cast('2023-11-30 18:00' as date),'020 Lawrence Hall - Humanities Auditorium','Group Business',NULL,'HSMC','Join the Sales and Marketing Club as we welcome Dan Norcia and Annie Eadon. Dan is the director of partnerships at Pilothouse, a high-level digital marketing agency. Annie works with sales enablement strategy and experiences at IBM, a global technology innovator. All are welcome!'||chr(10)||' ',340);
insert into hudsonu.event values(9934602,'Hudson Model UN Weekly Meeting',cast('2024-02-13 18:00' as date),cast('2024-04-23 18:00' as date),'Alumni 110','Cultural',NULL,'MUN','Weekly meeting for Hudsons Model UN team to practice debate skills before competitions',225);
insert into hudsonu.event values(292937,'French Club Coffee Hour',cast('2013-09-25 16:00' as date),cast('2013-09-25 16:00' as date),'French Seminar Room, Lawrence 205',NULL,NULL,'FC','Come practice your French speaking skills with other students and learn about different aspects of French culture while enjoying coffee, tea, and pastries!',null);
insert into hudsonu.event values(292934,'French Club Coffee Hour',cast('2013-11-13 16:00' as date),cast('2013-11-13 17:00' as date),'French Seminar Room, Lawrence 205',NULL,NULL,'FC','Come practice your French speaking skills with other students and learn about different aspects of French culture while enjoying coffee, tea, and pastries!',null);
insert into hudsonu.event values(341922,'Coffee Hours',cast('2014-02-12 16:00' as date),cast('2014-02-12 17:00' as date),'205 Lawrence Hall',NULL,NULL,'FC','French club Coffee Hours are social events at which members of Hudson and Hamilton community can practice their French speaking skills, learn about francophone culture, and enjoy snacks that are representative of the French cuisine.',null);
insert into hudsonu.event values(196131,'Who Cut Off Josephine''s Head: The Politics of Identity and Intangible Cultural Heritage in the Black Atlantic',cast('2012-11-15 19:00' as date),cast('2012-11-15 20:30' as date),'Lawrence Hall, Ho Lecture Room',NULL,NULL,'FC','This event is aimed at introducing aspects of Francophone culture that are often overlooked when studying French, specifically Caribbean history and culture. All students will be invited to hear Professor Curtius speak on the impact of French colonization and culture on Caribbean identity. A symbol of this impact has been the statue of Empress Josephine, wife of Napoleon, which was beheaded in Fort-de-France, Martinique in 1991. She intends to examine the politics of identity and intangible cultural heritage in Martinique, where several Hudson students visited last spring, in hopes to present a different dimension to European and Caribbean identity. Before the lecture, students will have the chance to have personal conversations with Professor Curtius over lunch and promote the use of French conversation outside of the classroom.',null);
insert into hudsonu.event values(292942,'French Club Coffee Hour',cast('2013-12-04 16:00' as date),cast('2013-12-04 17:00' as date),'French Seminar Room, Lawrence 205',NULL,NULL,'FC',NULL,null);
insert into hudsonu.event values(292939,'French Club Coffee Hour',cast('2013-10-23 16:00' as date),cast('2013-10-23 16:00' as date),'French Seminar Room, Lawrence 205',NULL,NULL,'FC',NULL,null);
insert into hudsonu.event values(1033061,'Ghost Hunting with John Zaffis',cast('2016-10-27 20:00' as date),cast('2016-10-27 21:00' as date),'Love Auditorium','Social',NULL,'SAA','Join us for a ~spooky~ night. John Zaffis, the self-described Godfather of the Paranormal, has been featured on the SyFy Channel, the Discovery Channel, Ghost Hunters, Ghost Adventures, and Unsolved Mysteries. His research and personal experiences with the supernatural have convinced him that ghost are, in fact, real. Not convinced? Come see him talk live about his experiences! John Zaffis will have a hour talk about ghost hunting in Love Auditorium followed by a tour and ghost hunt of Hudson''s Campus. Love Auditorium, 10/27, 8pm.'||chr(10)||' '||chr(10)||' ',470);
insert into hudsonu.event values(1033139,'Konosioni Field Day',cast('2016-08-24 15:00' as date),cast('2016-08-24 16:00' as date),'Whitnall Field','Social',NULL,'THS','Show your newfound love for Hudson by competing in one of our longest standing traditions. Residence halls will compete against each other for prizes and glory. Featured event includes tug of war and free food. Be sure to wear the right colors  see the posters around campus or your Community Leader for details. Bring your friends and your game face. Sponsored by Konosioni Senior Honor Society. (Whitnall Field).',450);
insert into hudsonu.event values(1047900,'SORT BACK TO SCHOOL SLEEPOVER',cast('2016-09-30 20:00' as date),cast('2016-09-30 20:00' as date),'wmst','Social',NULL,'SRT','The SORT sleepover is a time to bond and get to know other students on campus. ',120);
insert into hudsonu.event values(1119382,'Harry Potter Week',cast('2016-11-11 20:00' as date),cast('2016-11-17 23:30' as date),'Hudson University','Arts',NULL,'SAA','This event will take place over the course of the week leading up to CAB Take Two''s advanced premier of Fantastic Beasts and Where to Find Them. Several campus groups will be coming together to host the week''s events that include a Yule Ball with ''Gate Night Friday 11/11, Tea Reading with Tea Club Monday 11/14, Wizard Chess with TGA Tuesday 11/15, Trivia Night at Donovan''s Pub Wednesday 11/16, Quidditch tournament with Club Sports Thursday 11/17.',null);
insert into hudsonu.event values(1121876,'ACF Fall Northeast at Columbia',cast('2016-11-04 16:00' as date),cast('2016-11-06 19:00' as date),'Columbia University','Thoughtful Learning',NULL,'HQB','On November 5th, 2016, there will be a collegiate Quiz Bowl Tournament held by the University of Columbia in NYC. This is a really exciting opportunity for the up and coming Hudson Trivia Club. Members who participate in the tournament would leave Hudson on Friday, November 4th (departure time is pending upon members'' schedules) and would return Sunday, November 6th late afternoon. The tournament is to be held at Columbia University in Hamilton Hall on Saturday, November 5th. The check in for the tournament will be from 8:00-8:30 am and the games will begin between 8:45-9:00 am.  Once the tournament is over, there will be ample time to explore New York City. We will stay at a hotel in NYC courtesy of Hudson and will allocate money for food to members for the weekend.   ',220);
insert into hudsonu.event values(1136022,'Newman Lunch',cast('2017-01-30 12:15' as date),cast('2017-01-30 13:15' as date),'Chapel Basement','Spirituality',NULL,'NC','The Newman Community hopes to continue putting on a successful weekly lunch series this spring. The series would feature outside speakers, Hudson faculty, and Hudson students leading discussions about the Catholic faith and the Church. Topics would vary each week, but center on central teachings and practices of the Catholic Church. The lunch would be every Monday from 12:15-1:10 and would be catered by local restaurants. About 75 people a week usually come to these lunches.',null);
