insert into hudsonu.event values(1136034,'Bible Study Lunches',cast('2017-01-25 12:15' as date),cast('2017-01-25 13:15' as date),'Chapel Basement','Spirituality',NULL,'UC','This series of 10 lunch discussions will involve Hudson faculty members and guests coming to talk to students about a particular topic from the Bible, including love/relationships, stress, service discussing what the Bible says about these different topics. Through analysis of Biblical texts, students will discuss how the given topic is portrayed in the Bible and how we can apply lessons from the Biblical text to daily life. These dinner discussions will be held on ten Tuesdays throughout the Fall semester from 12:15 p.m.  1:10 p.m. in the Chapel Basement.',null);
