insert into hudsonu.event values(1136052,'Ski and Snowboard Club Trip to Vermont',cast('2017-01-27 17:00' as date),cast('2017-01-29 17:00' as date),'Mount Snow','Social',NULL,'HSSC','The Hudson Ski and Snowboard Club has planned an overnight trip to Mount Snow, a large mountain in Vermont, in order to give students the opportunity to ski and snowboard at a more challenging mountain. This trip will include transportation, lift tickets, rental equipment, and accommodations at no cost to participants. It will also give people the opportunity to learn more about the ski culture and form strong lifelong connections with each other. ',600);
insert into hudsonu.event values(1142604,'Ski and Snowboard Club Trip',cast('2017-02-03 16:00' as date),cast('2017-02-03 23:00' as date),'Toggenburg Mountain','Social',NULL,'HSSC','Join the Ski and Snowboard Club for a free trip to a local mountain! We offer trips to Toggenburg Mountain, Labrador Mountain, and Greek Peak. Transportation, lift tickets, rentals, and lessons for beginners are provided. Trips are open to all students.',null);
