insert into hudsonu.event values(3167775,'CAB - Valentine''s Day in Donovan''s',cast('2019-02-15 20:00' as date),cast('2019-02-15 22:00' as date),'Donovan''s Pub','Social',NULL,'SAA','Complete the Match-o-matics survey and meet your match in Donovan''s Pub. Complete competitions to win prizes to Maxwell''s Chocolates, Flour and Salt, and the Hudson Inn!'||chr(10)||' '||chr(10)||'Complete the Survey HERE!',400);
insert into hudsonu.event values(3230299,'POC Formal',cast('2019-02-28 21:00' as date),cast('2019-03-01 00:00' as date),'The Hourglass','Social',NULL,'BSU','In honor of Black History Month, the Black Student Union (BSU) and would like to host a formal at the Hourglass for the members of all recognized ALANA groups. This event will be a way to bring members of Hudsons multicultural groups together in a fun and memorable way. Attendees will have a chance to interact with new people, enjoy music from other cultures, and students who are 21+ will have the opportunity to purchase drinks throughout the night. As the second annual Black History Month formal, this event is highly anticipated due to its immense success last year and is hopefully on its way to becoming a BSU staple.',360);
insert into hudsonu.event values(3287587,'CAB Test',cast('2019-03-25 17:00' as date),cast('2019-03-25 17:00' as date),'CLSI','Social',NULL,'SAA','Testing...',480);
insert into hudsonu.event values(3308929,'Bollywood Karaoke Dance Party',cast('2019-04-12 19:00' as date),cast('2019-04-12 21:00' as date),'Edge Cafe','Social',NULL,'SACC','For SPW, SACC is hosting a Bollywood Karaoke Dance Party in the Edge Cafe!'||chr(10)||'Sing and dance with us! '||chr(10)||'Catering by Royal Indian Grill. '||chr(10)||' ',610);
insert into hudsonu.event values(3315866,'The Mat Presents: The Wrecks',cast('2019-04-12 19:00' as date),cast('2019-04-12 20:30' as date),'The Mat / Parker Commons','Social',NULL,'SAA','Join us at 7pm in The Mat (formally known as Parker Commons) for The Wrecks, a Los Angeles-based indie rock band. Popcorn and pizza will be served.'||chr(10)||' '||chr(10)||'There will be a Cash Bar for 21+ with two forms of ID.'||chr(10)||' '||chr(10)||'Zach Ceme ''19 will be taking the stage as our supporting act at 7:15pm with the Wrecks on at 8pm.',275);
insert into hudsonu.event values(3327910,'Delta Upsilon 2000s Social',cast('2019-04-20 16:00' as date),cast('2019-04-20 19:00' as date),'Delta Upsilon','Social',NULL,'DU','We would like to host an event at the Delta Upsilon house on Saturday, April 20th from 4pm to 8 pm. The event is 2000s themed so the music and outfits will reflect that decade. '||chr(10)||' ',240);
insert into hudsonu.event values(345509,'Bible Character Discussion Series',cast('2014-02-12 12:15' as date),cast('2014-02-12 13:15' as date),'Hudson Memorial Chapel Garden Level',NULL,'Religious/Spiritual','UC','In this series, a number of professors and Hudson staff members will lead discussion on certain characters of the Bible, including Ruth, Solomon, and Mary. They will look at how the character is portrayed in the Bible, and attendees will discuss how lessons from these verses and characters can be applied to life today.',390);
