insert into hudsonu.event values(459369,'Bible Character Discussion Series',cast('2014-09-17 12:15' as date),cast('2014-09-17 12:15' as date),'Chapel Garden Level',NULL,NULL,'UC','In this series, a number of professors and Hudson staff members will lead discussion on certain characters of the Bible, including Peter, Paul and John. They will look at how the character is portrayed in the Bible, and attendees will discuss how lessons from these verses and characters can be applied to life today.',350);
