insert into hudsonu.event values(485196,'Gatetown Connection',cast('2014-10-05 14:00' as date),cast('2014-10-05 16:00' as date),'Whitnall Field','Social',NULL,'BDS','Please join Hudson students and Hamilton residents on Whitnall Field for Hudson''s fifth town-gown event, celebrating the strong connection between the Hudson and Hamilton communities. At 2 p.m. on Sunday, October 5th, join us for Hamilton Eatery and ice cream, inflatables, music and activities with Hudson athletes.',380);
