insert into hudsonu.event values(4962786,'Delta Upsilon Fall Fest Social',cast('2019-09-21 22:00' as date),cast('2019-09-22 01:00' as date),'Delta Upsilon','Social',NULL,'DU','We would like to host an event at the Delta Upsilon House at 66 Broad Street on Saturday, September 21st from 10 pm to 2 am. The theme of the event is fall, so attendees should plan on wearing clothes that match the season (plaid shirts, jeans, boots etc.) ',350);
insert into hudsonu.event values(502954,'Maternal and Child Health in rural Uganda',cast('2014-10-16 11:30' as date),cast('2014-10-16 11:30' as date),'105 Lawrence (Ho lecture room)','Thoughtful Learning',NULL,'HGHC','Professor Ellen Kraly will speak on the results of her research in rural Uganda on maternal and child health and the challenge of the half-petty. Lunch will be served from Hamilton Eatery! ',500);
insert into hudsonu.event values(5063964,'Saturday Day Party',cast('2019-10-26 14:30' as date),cast('2019-10-26 17:30' as date),'Phi Delta Theta','Social',NULL,'PDT','We will have people mostly in the first floor of the house and spill over onto the front porch. We will also have the basement space open for people to enjoy dancing to some louder music. There will be food, water, and soda provided for the attendees. Socialization will also be occuring on the front porch for those who want a more quiet environment.',350);
insert into hudsonu.event values(5094516,'Nightmare on Broad Street',cast('2019-11-01 22:30' as date),cast('2019-11-02 01:00' as date),'Bunche House (80 Broad Street)','Social',NULL,'BROS','Wear a costume to this party as we dance to good music good vibes!',400);
insert into hudsonu.event values(5173668,'Beta Theta Pi Trivia Night',cast('2019-11-20 19:00' as date),cast('2019-11-20 20:30' as date),'Beta Theta Pi Fraternity','Fundraising','Volunteer and Community Service ','BTP','Come Join the Brother''s of Beta Theta Pi at 88 Broad Street for our annual Trivia Night on Wednesday, November 20th at 7:00 pm. While in past years, we have raised money and collected warm winter clothing in support of Claudia''s closet, we have decided to shift our efforts this year to support a close family friend of the chapter, Sean Doherty, who had just recently been diagnosed with cancer and has been undergoing chemotherapy for the past few months. Many of our members grew up very close to Sean and we are hoping to come together as a chapter to aid in his fight against cancer. In order to participate in the event, teams must register with 4+ members. There will be Chipotle catering available for all contestants and we strongly encourage donations from all those that attend. All proceeds collected from the event will directly benefit critical cancer research at Memorial Sloan Kettering Cancer Center in Sean''s name. Please donate either during the event or through the online link provided to support this amazing cause and to continue the fight against cancer. '||chr(10)||' '||chr(10)||' ',null);
insert into hudsonu.event values(518043,'Are You Smarter Than a Freshman Game Show',cast('2015-02-04 20:00' as date),cast('2015-02-04 22:00' as date),'Donovan''s Pub','Arts','Concert/Music','SAA','We are going to bring a game show to Donovan''s Pub that is an interactive trivia performance. With two hosts provided by GP Entertainment, the show would include pop culture and academic trivia questions looking to puzzle students and prove who is smarter than a freshman. Appetizers/snacks would be provided for participants.',500);
insert into hudsonu.event values(520122,'Strangers in Higher Ed: An Open Conversation about Asian Experiences at Hudson',cast('2014-11-10 12:15' as date),cast('2014-11-10 13:15' as date),'ALANA Lounge','Cultural',NULL,'ALANA','Come join us in an open discussion about Asian experiences at Hudson!'||chr(10)||' '||chr(10)||'Lunch is provided!',null);
insert into hudsonu.event values(5214538,'Thursday Night Dry Party in the House with Close Friends',cast('2019-12-05 22:00' as date),cast('2019-12-06 02:00' as date),'Beta Theta Pi','Social',NULL,'BTP','On Thursday December 5th, the brothers of Beta Theta Pi plan to host a dry event in their main entry, basement, and living room. Attendees for the event will include the brothers of the house and their close friends on campus. We will provide a variety of non-alcoholic beverages and snacks in the spaces being used for the event. While we will not have a theme for this event, our dining room setup will include include normal speakers, lighting fixtures, and natural light. We have one student planned to play music throughout the duration of the event as attendees can dance, play billiards, and catch up. Two student monitors will be placed at the door for the duration of the event and we will also provide light snacks for all guests. Attendance will not exceed 100. Sarvesh Kaul and Michael Caron will be the social hosts for the event.',75);
