insert into hudsonu.event values(533602,'ALANA-thon!',cast('2014-12-03 08:00' as date),cast('2014-12-03 20:00' as date),'ALANA Cultural Center','Cultural',NULL,'ALANA','Sophomores and Juniors  please join us for ALANA-THON! '||chr(10)||'Join us in the ALANA Cultural Center on Wednesday December 3 from 8am-8pm. Breakfast, lunch and dinner will be served throughout the day, along with raffles and give-aways. First come, first serve. We encourage your participation in completing the Diversity Learning Environment Survey. '||chr(10)||' '||chr(10)||'This national survey assesses conditions for student success on our campus and is administered by the Higher Education Research Institute at University of California, Los Angeles.'||chr(10)||' Your voice is important, and this survey will help us learn more about your interaction with faculty and peers, your participation in campus activities, your perceptions of the campus climate, and your use of campus services. In addition, our results will be combined with those from hundreds of colleges and universities in the United States as part of a national research project on student learning and development.',null);
