insert into hudsonu.event values(577739,'Student Senate',cast('2015-02-10 19:00' as date),cast('2015-02-10 20:30' as date),'Lawrence 105','Group Business',NULL,'SGA','The Student Senate holds regular meetings, open to all students, at which matters concerning the entire university community come under consideration. Senate meetings occur weekly on Tuesdays at 7 P.M. in Lawrence 105. Please come and join in on the discussions regarding important campus-wide issues and policies.',null);
