insert into hudsonu.event values(594801,'A Night of Sisterly Love',cast('2015-03-06 20:00' as date),cast('2015-03-07 08:00' as date),'WMST','Social',NULL,'SRT','This event is a part of our annual Africana Women''s Week(s). Joing Sister''s of the Round Table for a sleepover at Women Studies! We''ll be playing games, watching movies, and snacking all night long. Breakfast will be provided in the morning. All are welcome! Sleeping bags will be provided, bring pillows and blankets!'||chr(10)||' ',160);
