insert into hudsonu.event values(607725,'SGA Brown Bag Series: Campus Safety and Student Interactions',cast('2015-03-10 11:45' as date),cast('2015-03-10 12:00' as date),'Lawrence 105','Social',NULL,'SGA','The first SGA Brown Bag Series: Campus Safety and Student Interactions will be held on March 10th, from 11:45 A.M. - 1:00 P.M. in Lawrence Hall Room 105 and catered by ROYAL INDIAN GRILL. Come join the conversation regarding campus safety and student interactions. We will have an informal QandA along with a discussion. Topics include:'||chr(10)||'1. Diversity Training and its Implications'||chr(10)||'2. Fostering better relationships between students and campus safety officers '||chr(10)||'If you have any questions, please reach out to the SGA/CLSI Liaison to Student Organizations (sgaliaison@hudson.edu)',320);
insert into hudsonu.event values(615935,'Trivia Night Sponsored by Senior Class Gift Committee',cast('2015-03-30 20:00' as date),cast('2015-03-30 20:00' as date),'Hudson Inn','Social',NULL,'SGA','Trivia Night will be held 8:00 p.m. on March 30th, Monday in the Green Room of the Hudson Inn and is sponsored by the Senior Class Gift Committee! There is limited seating, so register early (Registration link will be sent shortly). Teams will be made up of 6 people - you can register as a team or individual and get placed on a team when you arrive. There will be free appetizers and cash bar, drink specials will be available. ',320);
