insert into hudsonu.event values(628117,'SGA Brown Bag Series: The Presidential Search',cast('2015-04-09 11:45' as date),cast('2015-04-09 12:00' as date),'COOP TV Room','Social',NULL,'SGA','Come have your voices heard regarding Hudson Universitys next president! We will have small group discussions led by student members of the Presidential Search Committee and SGA: '||chr(10)||'Joanna Howe 16'||chr(10)||'Sidney Parodie 16'||chr(10)||'Kelabe Tewolde 17'||chr(10)||'This brown bag serves as a purpose for the student body to have their voices heard throughout the Presidential Search process and to allow SGA to promote transparency across campus regarding administrative issues. It will be held in the COOP TV Room from 11:45 A.M. to 1:00 P.M. on Thursday, April 9th.'||chr(10)||' '||chr(10)||' '||chr(10)||' '||chr(10)||' ',200);
insert into hudsonu.event values(630681,'Karaoke Night',cast('2015-04-11 21:30' as date),cast('2015-04-11 22:00' as date),'Donovan''s Pub','Arts',NULL,'SAA','Take your singing skills from the shower to the stage at Karaoke Night, held weekly at Donovan''s Pub!',null);
insert into hudsonu.event values(632262,'Bible Study Discussion Series',cast('2015-09-09 12:15' as date),cast('2015-09-09 12:10' as date),'Chapel Garden Level','Spirituality',NULL,'UC','This series of nine lunch discussions will involve Hudson faculty, staff and members from the Hamilton community coming to talk to students about a particular topic from the Bible, including love/relationships, stress, service discussing what the Bible says about these different topics. Some of these faculty members include: Doug Hicks, Michael Hayes, and April Baptiste. Through analysis of Biblical texts, students will discuss how the given topic is portrayed in the Bible and how we can apply lessons from the Biblical text to daily life. These lunch discussions will be held on nine Wednesdays throughout the Fall semester from 12:15-1:10 pm in the Chapel Basement.',180);
insert into hudsonu.event values(636789,'SGA State of the Association',cast('2015-04-21 19:00' as date),cast('2015-04-21 19:00' as date),'Love Auditorium, Olin Hall','Social',NULL,'SGA','SGA is having it''s Spring 2015 State of the Association on Tuesday, April 21st, from 7:00 to 8:00 P.M. in Love Auditorium. Come join us as President Sarah Rende and respective Class Council Presidents address the initiatives they have completed throughout the year, and as President Elect Kegan Thompson gets inducted and speaks about his and VP Elect David''s upcoming SGA 2015 plans. Food will be served along with drinks! If you have any questions, feel free to reach out to Vice President Elect, David Kim (dkim@hudson.edu). ',400);
insert into hudsonu.event values(636792,'SGA Fireside Chats',cast('2015-04-21 18:15' as date),cast('2015-04-21 18:00' as date),'Love Auditorium, Olin Hall','Social',NULL,'SGA','The SGA Fireside Chats for Spring 2015 will be held in Love Auditorium this Tuesday (4/21) from 6:15 to 7:00 P.M.. Enjoy food and drinks while talking to your SGA Senators and Executive Board members about the past programs/initiatives they''ve completed and any student life/campus/administrative issues. If you have any more questions about the event, please reach out to President Elect, Kegan Thompson (kthompson@hudson.edu)',250);
