insert into hudsonu.event values(693017,'Take Two Presents Neighbors',cast('2015-08-28 21:00' as date),cast('2015-08-28 22:00' as date),'Coop TV Room','Social',NULL,'SAA','Come watch the first Take Two movie of the semester, Neighbors, at 9:00 PM in the Coop TV Room on the brand new plasma screen. ',70);
insert into hudsonu.event values(693344,'Welcome Back Karaoke Night',cast('2015-08-29 21:00' as date),cast('2015-08-29 22:00' as date),'Donovan''s Pub','Social',NULL,'SAA','Hudson Activities Board and the Class Affairs Committee is hosting a welcome back karaoke night in Donovan''s Pub from 9:00-11:00 on Saturday, August 29th. Come sing your favorite songs with your friends and sample some of the fabulous food on the new Pub menu. ',410);
insert into hudsonu.event values(695439,'Trivia Night',cast('2015-09-03 19:30' as date),cast('2015-09-03 20:30' as date),'Donovan''s Pub','Social',NULL,'SAA','Grab your friends and head to Donovan''s Pub for Trivia Night every Thursday! Teams will compete for SUN Cash prizes, winning up to $75 for a first-place victory! Donovan''s Pub accepts the meal plan, cash, credit/debit, and SUN Cash for payment, so swing by the kitchen for some snacks or a drink, then grab a table for some trivia!',400);
insert into hudsonu.event values(6985252,'COVE Bulletin Board Decorating!',cast('2021-03-08 12:00' as date),cast('2021-03-08 13:00' as date),'COVE Lounge','Community Service','Volunteer and Community Service ','RAK','Today DoRAK finish decorating the COVE bulletin board!!!',240);
insert into hudsonu.event values(7006798,'Sisterhood Event',cast('2021-03-20 11:00' as date),cast('2021-03-20 16:00' as date),'72 Broad Street','Social',NULL,'GPB','This event will between the hours of 11AM and 5PM on 3/20/21 and between 11AM and 3:45 on 3/27/21. There will be groups of max 10 members coming for hour blocks, with 15 minute grace periods in between to account for sanitizing and limiting overlap between groups. Due to the limited occupancy of the rooms in 72 Broad, we will be splitting the groups further between the dining room (max 6) and living room 2 (max 5). The splitting of the groups will also allow for the occupants to pass through these rooms as needed without going over capacity. The entrance to the event for the non-occupants of the house will be the front door, exiting through the door in the sunroom. For the members of the house, they will enter the house through the back door and leave through the door in the kitchen during the hours of the event. We will be providing beads for making bracelets as well as painting materials. In the house, we have many wipes and lysol bottles that will be used to sanitize personal spaces between uses as well as paintbrushes and bottles (due to the nature of the beads, and that they are single use, this will not be as necessary however the container can be sanitized between uses; we can also divide up beads per person at the start of the event to keep them as separate as possible). ',125);
insert into hudsonu.event values(7044103,'Trivia Night',cast('2021-04-22 17:00' as date),cast('2021-04-22 17:00' as date),'McGregory 217','Social',NULL,'PPGAC','We plan to do a trivia night where members of the club create a series of 50 question on Kahoot.  These questions will be informative about the Planned Parenthood organization, reproductive rights, and women''s empowerment. Attendees can play alone or with a team, leading to an eventual winner who will receive Planned Parenthood merchandise.',null);
insert into hudsonu.event values(705974,'Night Hike',cast('2015-09-04 22:00' as date),cast('2015-09-04 22:45' as date),'Front of Chapel','Social',NULL,'HCF','Join us for a Night Hike through the Hudson Hiking Trails on Friday night, glow-sticks provided.  A student astronomer will be leading a sky talk during the walk. We will meet in front of the chapel at 10pm and will leave for the hike shortly after. ',250);
