insert into hudsonu.event values(7532282,'Public Health Faculty Panel',cast('2021-10-21 12:15' as date),cast('2021-10-21 12:00' as date),'Ho 101','Thoughtful Learning',NULL,'PHI','The Public Health Initiatives is hosting a Brown Bag titled "Public Health Faculty Panel." Professors Abdul-Malak, Taye, and Upton will answer questions about the new Global, Public, and Environmental Health minor and any other questions that students have about the field. The event will take place on October 21 from 12:15pm-1pm in Ho 101. Hamilton Eatery lunch will be provided!',300);
