insert into hudsonu.event values(7558625,'Trick or Treat Around the Gate',cast('2021-10-29 14:00' as date),cast('2021-10-29 15:00' as date),'Women''s Studies Center, COVE, ALANA, KECK center, OISS, and Career Service','Social',NULL,'SAA','Join us on a trick or treat around different office buildings! Staff and students will hand out candies and a sticker for each office you visit. The first 5 students to collect all stickers will win prizes! Participating offices include Women''s Studies Center, COVE, ALANA, KECK center, OISS, and Career Services. (Grand prize: JBL Speaker) ',190);
insert into hudsonu.event values(756671,'Classics Society Coffee Hour',cast('2015-11-13 13:30' as date),cast('2015-11-13 15:00' as date),'Lawrence 114','Social',NULL,'HCS','Come hang out with the Hudson Classics Society and meet others interested in the ancient civilizations of ancient Greece and Rome!  Chat over coffee, tea, and sweet with other student and department faculty.  A great way to meet new people and make connections!',320);
