insert into hudsonu.event values(787709,'Dear Class of 2019 Dinner',cast('2015-11-02 17:45' as date),cast('2015-11-02 19:30' as date),'Hall of Presidents','Social',NULL,'SGA','Dear Class of 2016 Dinner Series'||chr(10)||'Senior/First-Year Tradition'||chr(10)||'Monday - Thursday at 5:45 to 7:00 P.M.'||chr(10)||'in the Hall of Presidents'||chr(10)||'Catered by Chartwells'||chr(10)||' '||chr(10)||' '||chr(10)||'Dear Class of 2019,'||chr(10)||'This week marks the beginning for a First-Year/Senior Tradition called the Dear Class of 2019 Dinner Series.'||chr(10)||' '||chr(10)||'These dinners are an avenue to hear from older students on their experiences at Hudson. There will be several phenomenal senior speakers, great conversation, and free food! You will be assigned to a day ranging from Monday to Thursday depending on your FSEM. The event is located in the Hall of Presidents from 5:45 to 7:00 PM.  Email the SGA account or ask your Link if you have any questions.'||chr(10)||' '||chr(10)||'The senior class is excited to see all of you there!'||chr(10)||' '||chr(10)||'Welcome to Hudson,'||chr(10)||' '||chr(10)||'The Class of 2016'||chr(10)||' ',80);
