insert into hudsonu.event values(801015,'The Hunger Games: Mockingjay Part 2 Midnight Premiere',cast('2015-11-19 23:45' as date),cast('2015-11-20 01:45' as date),'Hamilton Movie Theater','Social',NULL,'SAA',NULL||chr(10)||''||chr(10)||'Come watch the premiere of the anticipated The Hunger Games: Mockingjay Part 2 at the Hamilton Movie Theater this Thursday at midnight! Tickets are free, but limited. Come pick up your free ticket this Wednesday and Thursday in Frank between 11AM and 1PM in Frank, or in the COOP between 12PM and 1PM.  Realizing the stakes are no longer just for survival, Katniss Everdeen (Jennifer Lawrence) teams up with her closest friends, including Peeta (Josh Hutcherson), Gale (Liam Hemsworth) and Finnick for the ultimate mission. Together, they leave District 13 to liberate the citizens of war-torn Panem and assassinate President Snow, who''s obsessed with destroying Katniss. What lies ahead are mortal traps, dangerous enemies and moral choices that will ultimately determine the future of millions.s.'||chr(10)||''||chr(10)||'',400);
insert into hudsonu.event values(8012347,'Social Hour with LBGTIQA+ Alumni',cast('2022-03-29 18:00' as date),cast('2022-03-29 18:00' as date),'Rainbow Room','Social',NULL,'QTPC','The Office of LGBTQ+ Initiatives and QTPOC (Queer and Trans People of Color) invite you to join an informal conversation with LGBTIQA+ Alumni.'||chr(10)||'This is a great opportunity to mix and mingle, exchange your Hudson experiences, and get connected to alumni. '||chr(10)||' '||chr(10)||' '||chr(10)||'Zoom is available'||chr(10)||'https://hudson.zoom.us/j/94461541402',275);
