insert into hudsonu.event values(8062210,'Chess Tournament',cast('2022-04-17 12:00' as date),cast('2022-04-17 14:00' as date),'O''Connor Campus Center Conference Room','Social',NULL,'CC','A chess tournament hosted by Hudson Chess Club. All students are welcome to attend free of charge. A $100 prize pool will be distributed to the top 5 players. Please RSVP if you would like to attend. There are only 40 spots available.',null);
