insert into hudsonu.event values(8509135,'Dr. Raj Balkaran''s Visit to Hudson University',cast('2022-10-18 09:45' as date),cast('2022-10-19 17:00' as date),'Hudson University','Cultural','Religious/Spiritual','SACC','Join the Chapel House, SACC, and HSA in welcoming Dr. Raj Balkaran, a scholar of Indian Mythology and Yoga, storyteller, and life coach!'||chr(10)||'Dr. Balkaran will be giving lectures, joining the community for meals, and guiding the Wednesday open morning meditation at Chapel House (8:30am-9:00am). He will be discussing how to live a meaningful life, as well as exploring goddesses, karma, and the stories behind yoga postures. Here are a few events:'||chr(10)||'RSVP for Dinner (10/18) '||chr(10)||' '||chr(10)||'For the Tuesday, Oct 18th dinner from 6pm-8pm in the Coop Conference Room RSVP with this form: Dinner RSVP'||chr(10)||'RSVP for Lunch (10/19)  '||chr(10)||' '||chr(10)||'For the Wednesday, Oct 19th lunch from 11:45am-1:15pm in the Memorial Chapel Basement RSVP with this form: Lunch RSVP'||chr(10)||' '||chr(10)||''||chr(10)||'***Both the lunch and the dinner are opportunities to learn from his spiritual teachings and life wisdom. At both events, copies of Dr. Balkaran''s new book The Stories Behind the Poses: The Indian Mythology that Inspired 50 Yoga Postures will be raffled off!***'||chr(10)||' '||chr(10)||'Click here for the list of all the events!'||chr(10)||'',null);
insert into hudsonu.event values(851212,'Newman Lunch: "Catholic Journeys in Italy"',cast('2016-02-01 12:15' as date),cast('2016-02-01 13:15' as date),'Chapel Basement','Spirituality',NULL,'NC','The Newman Community proudly presents its 2016 Spring Lunch Series. This series will feature several outside speakers, Hudson faculty, and Hudson students leading discussions about the Catholic faith and the Church. Topics would vary each week, but always center on central teachings and practices of the Catholic Church. '||chr(10)||'This week, a panel of Newman students share their spiritual experiences while on their winter break trip to Rome and Assisi, Italy. '||chr(10)||'Join us in the Chapel Basement for some great conversation and a wonderful meal! ',null);
insert into hudsonu.event values(851224,'Newman Lunch: "An Alumni''s View on Catholicism in the World Beyond Hudson" presented by James Buttner ''15',cast('2016-02-08 12:15' as date),cast('2016-02-08 13:15' as date),'Chapel Basement','Spirituality',NULL,'NC','The Newman Community proudly presents its 2016 Spring Lunch Series. This series will feature several outside speakers, Hudson faculty, and Hudson students leading discussions about the Catholic faith and the Church. Topics would vary each week, but always center on central teachings and practices of the Catholic Church. '||chr(10)||'This week, James Buttner ''15 shares his views on Catholicism in the wider world beyond Hudson. '||chr(10)||'Join us in the Chapel Basement for some great discussion and a wonderful meal! ',null);
insert into hudsonu.event values(851247,'Newman Lunch: "A Catholic Perspective on Anxiety" presented by Professor Rebecca Shiner',cast('2016-02-15 12:15' as date),cast('2016-02-15 13:15' as date),'Chapel Basement','Spirituality',NULL,'NC','The Newman Community proudly presents its 2016 Spring Lunch Series. This series will feature several outside speakers, Hudson faculty, and Hudson students leading discussions about the Catholic faith and the Church. Topics would vary each week, but always center on central teachings and practices of the Catholic Church. '||chr(10)||'This week, Professor Rebecca Shiner will discuss: "A Catholic Perspective on Anxiety".'||chr(10)||'Join us in the Chapel Basement for some great conversation and a wonderful meal! ',null);
insert into hudsonu.event values(851270,'Newman Lunch: "Seniors Speak!"',cast('2016-02-22 12:15' as date),cast('2016-02-22 13:15' as date),'Chapel Basement','Spirituality',NULL,'NC','The Newman Community proudly presents its 2016 Spring Lunch Series. This series will feature several outside speakers, Hudson faculty, and Hudson students leading discussions about the Catholic faith and the Church. Topics would vary each week, but always center on central teachings and practices of the Catholic Church. '||chr(10)||'This week, a panel of Newman Seniors speak about their spiritual experiences on campus. '||chr(10)||'Join us in the Chapel Basement for some great conversation and a wonderful meal! ',null);
