insert into hudsonu.event values(903008,'Murder Mystery',cast('2016-02-26 20:00' as date),cast('2016-02-26 23:00' as date),'Hudson Memorial Chapel Basement','Arts',NULL,'MAT','Ever watched a detective show and thought "I could do that!" Then join us from 8-11 PM to put those sleuthing skills to the test! You''ll solve the mystery of the play "Murder at Dunmore Lodge," acted out by Hudson''s own Masque and Triangle, test your knowledge of the "History of Mystery" in a trivia tournament hosted by Brian D''Auteuil, and become a suspect in a game of Live Clue.'||chr(10)||'So, chanel your best Professor Plum or Miss Scarlet as you gather in the chapel basement for hors d''oeuvres and intrigue. '||chr(10)||'Sponsored by ''Gate Night, Masque and Triangle, Hudson Role Playing Game Society, and The Game''s Afoot.',null);
