insert into hudsonu.event values(9080927,'Boxer Shorts Open',cast('2023-04-29 12:00' as date),cast('2023-04-29 15:00' as date),'Theta Chi/Lower Campus','Social',NULL,'TC','In the late 80s and 90s, Theta Chi would annually run an event called the Boxer Short Open (BSO). The BSO consisted of a golf course with seven holes designated throughout campus. Each brother of Theta Chi would play this course with a tennis ball in place of a golf ball and one golf club. Teeing off from the front lawn of Theta Chi (52 Broad), the brothers would play a game of golf until, inevitably back at the house',350);
