insert into hudsonu.event values(9540662,'Fall on the Farm and Pumpkin Smash',cast('2023-10-21 14:00' as date),cast('2023-10-21 15:30' as date),'Donovan Pub','Social',NULL,'SAA','Looking for something to do this weekend away from campus?  Introduce the Fall on the Farm event! SAA is happy to sponsor students on a trip to Sugar Hill Farm. Admission covers tractor drawn hayrides, corn maze, access to the u-pick patch and pumpkin smash, lots of free barnyard games (hay bale tower, gravity wagon basketball, and candy corn ring toss), and one u-pick pumpkin (for you to smash or take home)!There is no sign up. Please show up to Donovan before 2pm this Saturday and bus will return to Hudson around 4:30pm.',300);
insert into hudsonu.event values(9542329,'Origami Lucky Stars Making Event',cast('2023-10-27 15:00' as date),cast('2023-10-27 15:00' as date),'Lawrence Room 107 - Japanese Studies Center','Social',NULL,'TTC','On Friday, October 27, we are hosting an Origami Lucky Stars Making event from 3 - 4 p.m. in Lawrence Room 107 Japanese Center (new location!) These origami lucky stars represent a special gift of love and good luck (more information here).'||chr(10)||'As always, everyone is welcome! We will have tea, snacks, origami papers, and jars for you to make these lovely star jars for yourself or gifts to friends and family members!',55);
insert into hudsonu.event values(9558536,'Nightmare on Broad St.',cast('2023-10-27 22:30' as date),cast('2023-10-28 01:00' as date),'Pink Haus','Social',NULL,'QTPC','Join us for a Halloween party! Everyone is welcome.',350);
insert into hudsonu.event values(9560395,'Friday Night Party With Friends',cast('2023-10-27 22:00' as date),cast('2023-10-28 01:00' as date),'88 Broad St','Social',NULL,'BTP',NULL||chr(10)||''||chr(10)||'Resubmission with Changed Sober Monitors'||chr(10)||'Friday, October 27th, the brothers of Beta Theta Pi plan to host a dry event in their library, main entry area, living room and dining room. Attendees will include the brothers of the house and close friends on campus. We will provide a variety of non-alcoholic beverages and snacks in the spaces being used for the event. There is no theme yet for this party, and our dining room setup will include speakers and lighting fixtures. We have one student planned to play music throughout the duration of the event, and attendees will be able to dance and catch up. Two student monitors will be at the door for the duration of the event, in addition to having sober monitors, and we will also provide snacks and water for all guests. Attendance will not exceed 190, and the event will run from 10:00PM to 2:00 AM. Jason Chapis, Ryan Bush, Everett Graves and Nick Enders will be the social hosts for the event.'||chr(10)||''||chr(10)||''||chr(10)||' ',180);
