insert into hudsonu.event values(9637080,'Endangered Species Talk and Trivia Night',cast('2023-11-29 18:30' as date),cast('2023-11-29 19:30' as date),'Alumni 107','Thoughtful Learning','Sustainability','SEA','Compete to win a stuffed animal and symbolic adoption of a whale shark while learning about the importance of saving endangered species! An overview of what endangered species are, why they''re at risk, and how people can help will be presented by SEA. Then, a fun trivia will take place based on endangered species that will give attendees a chance to win a special prize that helps work towards saving animals at risk! Join us in Alumni 107 at 6:30pm!',415);
