insert into hudsonu.event values(9871976,'Superbowl Pub Party',cast('2024-02-11 18:00' as date),cast('2024-02-11 23:30' as date),'Donovan''s Pub','Social',NULL,'DP','Join us for a Superbowl Party at the Pub. Come for the game, stay for the food! Free food will be catered by Chartwells and by Ray Brothers BBQ (RBQ). There will also be games and giveaways!'||chr(10)||' '||chr(10)||'Co-Sponsored by the Office of Student Involvement and the Shaw Wellness Institute. ',240);
insert into hudsonu.event values(9893676,'Lovin'' Bingo',cast('2024-02-16 20:00' as date),cast('2024-02-16 22:00' as date),'The Coop- O''Connor Campus Center, Coop TV Room','Social',NULL,'SAA','Get ready to feel the love at ''Lovin'' Bingo''!  Join us on Friday, Feb. 16th at 8 pm in the Coop TV room for a heartwarming evening filled with fun, laughter, and incredible prizes.  Indulge in delectable delights from Royal India Grill (''RIG'') as you try your luck for a chance to win a huggable 6ft Teddy Bear, Amazon Echo Dot, Keurig K-Mini, and adorable LEGO flowers.  Love is the name of the game, and we can''t wait to share the joy with you!',260);
insert into hudsonu.event values(9893695,'Casino Night',cast('2024-02-17 20:00' as date),cast('2024-02-17 23:00' as date),'The Coop- O''Connor Campus Center, Coop TV Room','Social',NULL,'SAA','Roll the dice and place your bets!  Join us for an unforgettable Casino Night on February 17th, from 8pm to 11pm. The excitement awaits with classic games like poker and blackjack, and delicious delights from Oliveri''s!  Stay tuned for a chance to win fantastic prizes, including town gift cards. Ante up for a night of thrills and good times! ',200);
insert into hudsonu.event values(9934147,'Movie Night',cast('2024-02-16 23:00' as date),cast('2024-02-17 00:30' as date),'Hamilton Theater','Social',NULL,'SAA','Y''all voted and we listened!  Get ready for an unforgettable movie night at the Hamilton Movie Theater on February 16th at 11:00 PM. We''re bringing Legally Blonde to the big screen by popular demand!  Don''t miss out on this fan-favorite flick! ',450);
insert into hudsonu.event values(9954417,'Barbie On Ice',cast('2024-02-24 21:00' as date),cast('2024-02-24 23:00' as date),'Class of 1965 Arena','Social',NULL,'SAA','Get ready to glide into a magical world with Barbie on Ice!  Join us on February 24th, 2024, at Class of 1965 Arena from 9pm to 11pm for an enchanting evening filled with twirls, spins, and dazzling performances!  Don''t miss out on this unforgettable experience!  Plus, enjoy delicious pizza from Oliveri! ',525);
insert into hudsonu.event values(9985327,'Ask A Catholic Priest Anything',cast('2024-02-28 18:00' as date),cast('2024-02-28 20:00' as date),'Reception Room - Garden Level','Spirituality','Religious/Spiritual','NC','The Hudson Newman Catholic Community invites everyone to our weekly Wednesday dinner featuring Fr. John Donovan. The theme this week will be ask a priest anything so come with your best questions and join us for italian food!',null);
insert into hudsonu.event values(9986796,'Movie Night',cast('2024-03-02 23:00' as date),cast('2024-03-03 01:30' as date),'Hamilton Theater','Social',NULL,'SAA',' NEW DATE ALERT  Join us for a cinematic journey like no other at Hamilton Movie Theater!  Experience the epic continuation of Dune Part 2 at our midnight movie screening on Saturday, March 2nd at 11:00 PM.  Get ready for an unforgettable adventure!',525);
insert into hudsonu.event values(998700,'Welcome Back Breakfast on the Quad',cast('2016-09-01 11:15' as date),cast('2016-09-01 12:15' as date),'Academic Quad','Social',NULL,'SAA','Ring in the first full month of the 2016-2017 academic year on the quad with breakfast from Quacks and field games provided by CAB!',null);
insert into hudsonu.event values(9990821,'2024 Milmoe Workshop in Investigative Journalism and Journalist Ethics',cast('2024-02-29 18:30' as date),cast('2024-02-29 20:00' as date),'Ho 101 Lecture Room','Thoughtful Learning',NULL,'HMN','Rebekah F. Ward, a multimedia journalist specializing in Climate and Environment at the Houston Chronicle and member of the Class of 2013 of Hudson University, will be visiting Hudson to share her extensive experience and knowledge in journalism. With a rich background in fact-checking, investigative reporting, and freelance writing for distinguished outlets such as France 24, Reuters, and the Overseas Crime and Corruption Reporting Project, Ward brings invaluable insights into investigative journalism''s ethics and integrity. Her session promises to enlighten Hudson''s current students, aspiring writers, and journalists with lessons from her extensive career. This event is sponsored by the Cornelius (Laddie) Milmoe ''30 endowment and the Office of Student Involvement and hosted by the Hudson Maroon-News. ',460);
insert into hudsonu.event values(1025799,'MSA Brown Bag Series',cast('2016-09-09 12:00' as date),cast('2016-12-09 13:00' as date),'Chapel Basement','Spirituality',NULL,'HMSA','A series of Brown Bag Talks on Topics related to Islam designed to educate Hudson students about Islam and it''s impact it has on our society today. ',420);
insert into hudsonu.event values(1025805,'Eid',cast('2016-04-29 18:00' as date),cast('2016-04-29 20:00' as date),'Hall of Presidents','Spirituality',NULL,'HMSA','The Eid Al-Fitr is yearly an Islamic Festival celebrated throughout the Islamic communities and is the epitome of Islamic Festival',null);
insert into hudsonu.event values(1089744,'Islam and Homosexuality',cast('2016-10-21 12:00' as date),cast('2016-10-21 12:00' as date),'Chapel Basement','Spirituality',NULL,'HMSA','Columbia University Chaplain Mouhamadou Diagne will talk about Islam and Homosexuality. He will also lead the Friday Prayer for the Muslim Students.',null);
insert into hudsonu.event values(1157515,'MSA Brown Bag Series',cast('2017-01-27 12:00' as date),cast('2017-04-28 12:00' as date),'Chapel Basement','Spirituality',NULL,'HMSA','A series of Brown Bag Talks on Topics related to Islam designed to educate Hudson students about Islam and it''s impact it has on our society today. The Brown Bags will focus on the topics of Sunni Shia Split, What Trump Presidency Means for Muslims, Sharia Law, Islam and other Abrahamic Religions. The topics are subjected to change based on speaker availability. ',500);
insert into hudsonu.event values(1157533,'Mehdi Hasan Talk',cast('2017-03-16 12:00' as date),cast('2017-03-16 12:00' as date),'Chapel','Spirituality',NULL,'HMSA','Mehdi Hasan is a renown British scholar. A graduate of Oxford, Mehdi Hasan moved on to become a political journalist, broadcaster, and author. He has two shows on Al Jazeera English, UpFront and Head to Head. Mehdi specializes in issues regarding Islam and Muslims and has a very strong fan base online.',760);
insert into hudsonu.event values(1204556,'Slush Fund',cast('2016-11-13 12:00' as date),cast('2016-11-13 13:00' as date),'Chapel Basement','Spirituality',NULL,'HMSA','Slush Fund',null);
insert into hudsonu.event values(1213394,'Passover',cast('2017-04-10 12:00' as date),cast('2017-04-18 12:00' as date),'SAP','Spirituality',NULL,'HJU','Passover is the 8 day long festival which commemorates the exodus of the Jews from Egypt. During this time, Jewish people eat only non-leavened foods which are certified as Kosher for Passover, and this food tends to be more expensive and not found at any of the Hudson Dining Facilities in quantities or varieties that are sufficient. Considering that the meal plan at Hudson costs students $36 per day, our $16 per day is more than reasonable. This event fed around 50 people last year for a week and has a projected upward participation rate.',270);
insert into hudsonu.event values(1227605,'CJU Other Events',cast('2017-01-27 12:00' as date),cast('2017-05-12 12:00' as date),'SAP','Spirituality',NULL,'HJU','Bagel Brunch: This event is community bonding at the Saperstein Center.  Surprisingly, attendance can top 100 and we unfortunately do run out of bagels some days.  Additionally, we serve a large number of non-Jews thus including the whole Hudson community.  In addition to Hudson students, we also serve a large number of the Hamilton community.'||chr(10)||'Havdalah: Havdalah is celebrating the end of the Sabbath (Shabbat).  We host a great group of community members to have a quick service with light food afterward. '||chr(10)||'Advertising: Costs to provide supplies to get the word out for the whole semesters events.',200);
insert into hudsonu.event values(525927,'Gospelfest 2015: Byron Cage',cast('2015-02-27 19:00' as date),cast('2015-02-27 21:00' as date),'Memorial Chapel','Spirituality',NULL,'SGC','Byron Cage will perform with Sojourner''s Gospel Choir.  This event will be viewable on Hudson University Livestream.  View here: http://new.livestream.com/hudsonuniversity/gospelfest2015'||chr(10)||' ',450);
insert into hudsonu.event values(691889,'Bonfire on the Old Golf Course',cast('2015-08-29 20:00' as date),cast('2015-08-29 21:00' as date),'Fire Pit Behind Stillman','Spirituality',NULL,'HCF','Come on by to a bonfire hosted by CCF for music, to meet new friends, and most importantly...S''MORES! Also, there will be a sky talk given by one of Hudson''s very own expert astronomy student',null);
insert into hudsonu.event values(745137,'Night Hike',cast('2015-09-25 22:00' as date),cast('2015-09-25 22:45' as date),'Chapel Steps','Spirituality',NULL,'HCF',NULL||chr(10)||'CCF will be hosting another Night Hike with glowsticks through the Hudson hiking trails starting at 10 PM Friday evening. Join us for a time of exploring Hudson''s beautiful property and enjoying the night sky. Stick around after the hike to have a campfire and s''mores in the field of dreams'||chr(10)||'',225);
insert into hudsonu.event values(898260,'Tuesday Night Bible Study With Dr. Nina Moore',cast('2016-02-23 17:00' as date),cast('2016-02-23 18:30' as date),'Hudson Memorial Chapel','Spirituality',NULL,'UC','Join Dr. Nina Moore in the Chapel basement as she steps outside of her role as a Hudson faculty member. She will join the Protestant Campus Ministry and share her faith, helping to spread the Word of the Lord through inspirational Bible-based insights.'||chr(10)||'Dr. Morre will use the story of Joseph to elucidate the Principles of Godly Living.'||chr(10)||'See you in the chapel basement for some great discussion and a wonderful meal catered by Curtain Call.',140);
insert into hudsonu.event values(901965,'Tuesday Night Bible Study With Dr. Nina Moore',cast('2016-03-22 17:00' as date),cast('2016-03-22 17:30' as date),'Hudson Memorial Chapel','Spirituality',NULL,'UC','Join Dr. Nina Moore in the Chapel basement as she steps outside of her role as a Hudson faculty member. She will join the Protestant Campus Ministry and share her faith, helping to spread the Word of the Lord through inspirational Bible-based insights. See you in the chapel basement for some great discussion and a wonderful meal catered by Curtain Call.',240);
insert into hudsonu.event values(902119,'Tuesday Night Bible Study With Dr. Nina Moore',cast('2016-04-05 17:00' as date),cast('2016-04-05 17:30' as date),'Hudson Memorial Chapel','Spirituality',NULL,'UC','Join Dr. Nina Moore in the Chapel basement as she steps outside of her role as a Hudson faculty member. She will join the Protestant Campus Ministry and share her faith, helping to spread the Word of the Lord through inspirational Bible-based insights.'||chr(10)||'See you in the chapel basement for some great discussion and a wonderful meal catered by Curtain Call.'||chr(10)||' ',340);
insert into hudsonu.event values(911797,'Islamic Indonesian Culture',cast('2016-03-04 12:30' as date),cast('2016-03-04 13:15' as date),'Chapel Basement','Spirituality',NULL,'HMSA','Esther Rosbrook will be delivering a Brown Bag on the Islamic Indonesian Culture on Friday, March 4th at the chapel basement.',null);
insert into hudsonu.event values(932746,'"Spiritual Security": A Twenty-First Century Concept of Islamic Governance',cast('2016-04-08 12:30' as date),cast('2016-04-08 12:15' as date),'Chapel Basement','Spirituality',NULL,'HMSA','Anthropology Professor Emilio Spadola will be delivering a talk on contemporary Maghrebi culture.',null);
insert into hudsonu.event values(945040,'Spoken Word Artist Micah Bournes',cast('2016-09-18 18:30' as date),cast('2016-09-18 18:30' as date),'Hudson Memorial Chapel','Spirituality',NULL,'UC','Acclaimed spoken word poet Micah Bournes will guest-lead University Churchs Sunday night worship, providing students and Hudson community members with the unique opportunity to worship God through a relatively newer medium. Micah will also lead a Monday lunch, during which he will perform some of his work and will discuss how being a Christian impacts his role as poet, as well as how he seeks to provide fellowship through his work.',445);
insert into hudsonu.event values(945041,'Spoken Word Artist Micah Bournes',cast('2016-09-19 12:15' as date),cast('2016-09-19 12:15' as date),'Chapel Basement','Spirituality',NULL,'UC','Acclaimed spoken word poet Micah Bournes will guest-lead University Churchs Sunday night worship, providing students and Hudson community members with the unique opportunity to worship God through a relatively newer medium. Micah will also lead a Monday lunch, during which he will perform some of his work and will discuss how being a Christian impacts his role as poet, as well as how he seeks to provide fellowship through his work.',445);
insert into hudsonu.event values(945049,'Hanukkah',cast('2016-12-16 12:00' as date),cast('2016-12-16 13:00' as date),'SAP','Spirituality',NULL,'HJU','Hanukkah is the 8 day festival of lights.  For these eight nights, we are requesting funding for celebratory food for menorah lighting ceremonies (which would also serve as study breaks). Here, we plan to have a pre-hanukkah event because hanukkah this year will fall during winter break.  This will include a catered party from Albany (to keep it kosher) and will be co-sponsored with BDS.',225);
insert into hudsonu.event values(945050,'CJU Fall Speaker',cast('2016-09-30 12:00' as date),cast('2016-09-30 12:00' as date),'SAP','Spirituality',NULL,'HJU','We are bringing two speakers to campus: David Makovsky and Ghaith al-Omari.  David is the Ziegler distinguished fellow and director of the Washington Institute for Near East Policy Project on the Middle East Peace Process and an adjunct professor at John Hopkins Universitys school of Advanced International Studies in the Middle Eastern Program.  He is the coauthor of Myths, Illusions, and Peace and appears on the PBS news hour with Jim Lehrer.  Ghaith is a senior fellow at The Washington Institute, is the former executive director of the American Task Force on Palestine. Previously, he served in various positions within the Palestinian Authority, including advisor to the negotiating team during the 1999-2001 permanent-status talks.'||chr(10)||'We are bringing in both experts to have a panel discussion about Israel and Palestine.  We hope that this will bring the campus together not just to have a great discussion but to promote positive dialogue about this issue post event.',570);
insert into hudsonu.event values(945051,'High Holidays 2016',cast('2016-10-02 12:00' as date),cast('2016-10-02 12:00' as date),'SAP','Spirituality',NULL,'HJU','Rosh Hashanah: Rosh Hashanah is the Jewish New Year. In most Jewish families, the meal is an integral part of the celebration. The Hudson Jewish Union is requesting funding for Rosh Hashanah dinner in order to honor this tradition following religious services.'||chr(10)||'Yom Kippur: Yom Kippur is part of the High Holidays along with Rosh Hashanah. This is a 25 hour fast marking the most solemn day of the Jewish Calendar.  This full fast (no food or water) is traditionally bracketed by two celebratory meals: one before the fast and a break-fast afterwards.'||chr(10)||'These two holidays are the most holy ones in the Jewish Calendar except for Shabbat. ',260);
insert into hudsonu.event values(945064,'Sukkot',cast('2016-10-16 12:00' as date),cast('2016-10-16 12:00' as date),'SAP','Spirituality',NULL,'HJU','Sukkot: Sukkot is the fall harvest festival.  We erect a large temporary structure on the quad and invite other groups to joins us for activities and dinner in it. We are requesting funding for these dinners and other events. We anticipate our BBQ to feed over 100 people as we are coordinating with the Muslims and Newman.',300);
insert into hudsonu.event values(954490,'CJU Fall Other Misc. Events and Items',cast('2016-09-01 12:00' as date),cast('2016-09-01 12:00' as date),'SAP','Spirituality',NULL,'HJU','Bagel Brunch: This event is community bonding at the Saperstein Center.  Surprisingly, attendance can top 100 and we unfortunately do run out of bagels some days.  Additionally, we serve a large number of non-Jews thus including the whole Hudson community.  In addition to Hudson students, we also serve a large number of the Hamilton community.'||chr(10)||'Havdalah: Havdalah is celebrating the end of the Sabbath (Shabbat).  We host a great group of community members to have a quick service with light food afterward.  '||chr(10)||'Advertising: Costs to provide supplies to get the word out for the whole semesters events.'||chr(10)||'Morning Minyon: Every week, we have a morning service.  This service needs to have at least 10 Jewish adults to happen.  During this service to attract people, we provide coffee and donuts.'||chr(10)||'Knife Sharpening/BBQ Brushes: In order to continue providing low-cost dinners at Shabbat and low-cost meals at our other events, we need to keep our knives sharp.  Due to the frugality of the CJU, we have neglected to sharpen our knives for many years.  We are requesting a small sum of money to sharpen them instead of buying new ones.  Additionally, we are requesting $10 to buy BBQ brushes.'||chr(10)||'Blender: We need a blender to continue providing low-cost dinners at Shabbat and other events.  This will increase the food quality and the speed at which we can operate.',200);
insert into hudsonu.event values(1025662,'NYC Immersion Trip',cast('2016-10-20 12:00' as date),cast('2016-10-22 13:45' as date),'New York City','Thoughtful Learning',NULL,'HWIB','This immersion trip will be an educational and networking opportunity for members of Hudson Women in Business, Hudson Consulting Club, and Hudson Finance Club.  Each club will take select, highly motivated members to visit companies in their specific industry and network with alumni.',150);
insert into hudsonu.event values(1025745,'Fall 2016 Model UN Conferences',cast('2016-10-13 12:00' as date),cast('2016-10-16 12:00' as date),'Boston, MA / Philadelphia, PA / Montreal, Quebec','Thoughtful Learning',NULL,'MUN','Hudson Model United Nations would like to attend three competitive conferences this fall: Boston Area Model United Nations (BarMUN) in Boston, run by Boston University, University of Pennsylvania Model UN Conference (UPMUNC) in Philadelphia, and McGill Model United Nations Assembly (McMUN) hosted by McGill University.',390);
insert into hudsonu.event values(1032777,'Mexico Public Health Immersion Trip',cast('2017-01-08 12:00' as date),cast('2017-01-19 13:00' as date),'Hudson University','Thoughtful Learning',NULL,'HGHC','The Hudson Global Health Initiative is sponsoring a trip from January 8-January 19 of 2017 where 8 students will be chosen to travel to Northern Mexico. While in Mexico the students will focus on issues of border health, indigenous health, foreign medical school requirements, rural healthcare and the non profit industry. The trip will travel to Juarez, Chihuahua City, the Sierra Tarahumara region, and a variety of other locations. ',210);
