insert into hudsonu.event values(1047940,'Hudson College Republicans Present: Milo Yiannopoulos',cast('2016-11-14 17:30' as date),cast('2016-11-14 19:00' as date),'Hudson University','Thoughtful Learning',NULL,'CR','Milo Yiannopolous will give a 20-25 minute lecture in which he will provide a critique of third-wave feminism as it relates to topics including, but not limited to, free speech, the gender wage gap, rape culture, social justice, cultural authoritarianism, and the emerging phenomenon of safe space, microaggression, and trigger warning culture on college campuses. He will also be sharing his experiences during his past tours on college campus across the nation. It will end with a 30-45 minute QandA session in which audience members will be able to ask Milo any question theyd like regarding his views, opinions, and/or experiences.',800);
