insert into hudsonu.event values(1109939,'Oxford IV Tournament',cast('2016-11-11 12:00' as date),cast('2016-11-13 13:00' as date),'Oxford University','Thoughtful Learning',NULL,'DS','The Oxford Inter-Varsity tournament is the eminent British Parliamentary Debate tournament. ',700);
insert into hudsonu.event values(1136055,'Region IX Medical Education Conference 2016',cast('2016-11-20 07:30' as date),cast('2016-11-20 18:00' as date),'Albert Einstein College of Medicine','Thoughtful Learning',NULL,'HMAPS','The Minority Association of Pre-Medical Students (MAPS) at Hudson University is a University chapter for the Student National Medical Association (SNMA). As a member of Region IX, we are required to attend at least two regional conferences that take place in New York City in order to maintain chapter recognition. This November, SNMA will be hosting a regional medical conference at Albert Einstein College of Medicine in New York City. This location would be the most cost-effective trip as it is the closest event to Hudson''s campus.'||chr(10)||'This event stands true to the mission of MAPS as it will focus on health disparities in communities of color and foster relationships amongst prospective and current medical students from marginalized backgrounds. The conference comprised of multiple seminars, panel discussions, medical school preparation classes. '||chr(10)||'This event will benefit the Hudson MAPS community and give us a first-hand experience into our futures in medicine. Although only six members will be able to attend, we will bring back the knowledge we''ve gained and be able to share it with the rest of our members. '||chr(10)||' ',400);
insert into hudsonu.event values(1140995,'Slush',cast('2016-12-06 11:30' as date),cast('2016-12-06 13:00' as date),'WMST','Thoughtful Learning',NULL,'OASIS','OASIS would like to apply for $100 slush funding as a buffer for our Helen Zia brown bag. ',null);
insert into hudsonu.event values(1157534,'Harvard Africa Business Conference',cast('2017-02-17 12:00' as date),cast('2017-02-20 13:00' as date),'Boston Massachusetts','Thoughtful Learning',NULL,'AS','The Africa Business Conference at Harvard University is an annual conference that brings together 1500 people interested in learning about business and entrepreneurship on the continent. This is the 19th Annual Africa Business Conference, scheduled to be held in Boston, MA from February 17th to February 20th, 2016. The theme for the business conference is "Partnerships for Prosperity: Working Together for a Strong and Inclusive Africa.',800);
insert into hudsonu.event values(1213349,'2017 Pan American Universities Debating Championship',cast('2017-03-10 00:00' as date),cast('2017-03-12 22:45' as date),'La Verne University','Thoughtful Learning',NULL,'SLDC','The Pan-American Universities Debating Championship (PUDC) is a hemispheric debating championship for debating teams at universities in North, South and Central America and the Caribbean regions. The format of debate is the British Parliamentary (BP) format.  The winners are crowned the Pan-American Champions.'||chr(10)||'Robust debate is not limited to any one language. To celebrate debate in the two dominant languages in the Western Hemisphere, Pan-Ams is a bilingual tournament. It offers two separate debating divisions: one English-speaking division and one Spanish-speaking division. Debates are conducted in the language of the respective division. Both divisions debate the same motions simultaneously.',550);
insert into hudsonu.event values(1213397,'Beyond the Bagel: Non-European Jewish Cultures Around the World',cast('2017-03-03 12:00' as date),cast('2017-03-03 13:00' as date),'SAP','Thoughtful Learning',NULL,'HJU','In keeping with the universitys goal of exploring diversity, the CJU is sponsoring a series which we are calling Beyond the Bagel: Non-European Jewish Cultures Around the World.  It will consist of the following speakers:'||chr(10)||' '||chr(10)||'Rabbi Gad Capela - The Exodus of the Yemenite Jewish Community'||chr(10)||'Ravi Juan Mejia - The Jews of South America'||chr(10)||'Maron Shevach - Mizrachi Cuisine'||chr(10)||'More details in proposal'||chr(10)||' ',280);
insert into hudsonu.event values(1227603,'MOSAiC Weekend Keynote Speaker: TJ Holmes',cast('2017-03-25 16:30' as date),cast('2017-03-25 16:45' as date),'Hudson Memorial Chapel','Thoughtful Learning',NULL,'BROS','This event is the headlining portion of MOSAiC Weekend spanning from March 24-March 26. TJ Holmes is a respected and prominent journalist and will deliver his remarks on the afternoon of the 25th. This keynote address will then break into sessions with the leaders of student groups representing students of color, and with the organizers of the event who assisted the Dept. of Advancement by providing input on a selective committee. '||chr(10)||'Holmes is an ABC News anchor/correspondent. Joining ABC in December of 2014, he reports for all the networks broadcasts and platforms. Primarily, Holmes contributes daily to Good Morning America, the most-watched network morning news show. His experience, personality and unique storytelling were a good fit to GMAs blend of breaking news, in-depth reporting, and family-focused fun.'||chr(10)||'In his 17-year journalism career, Holmes has reported around the country and the world on major news events, from the poaching crisis in South Africa and the Olympics in Athens and Rio, to presidential elections and political conventions.'||chr(10)||'Prior to joining ABC, Holmes spent 5 years as anchor of CNN Saturday/Sunday Morning and anchored significant news stories including Saddam Husseins execution in 2006, the terrorist attacks in Mumbai, India in 2008 and at Glasgow Airport in 2007. He also reported from the scene of the devastating Joplin, Missouri tornadoes, the Deepwater Horizon oil spill in New Orleans, and the tragic shootings on the Virginia Tech campus in Blackburg, Virginia. He secured some of the first accounts from the survivors of the US Airways Flight 1549 that crash-landed in New Yorks Hudson River in January 2009 and reported from the campus of the University of Mississippi during the first presidential debate between Senators John McCain and Barack Obama. Holmes also anchored from Ground Zero to commemorate the emotional 10th Anniversary of the September 11th attacks.',490);
insert into hudsonu.event values(1241848,'SurvJustice at Gate: Cultivating Sexual Respect on Campus',cast('2017-03-23 15:45' as date),cast('2017-03-23 17:15' as date),'Love Auditorium Olin Hall','Thoughtful Learning',NULL,'TN','SurvJustice is a national not-for-profit organization that increases the prospect of justice for all survivors of sexual violence through effective legal assistance, policy advocacy, and institutional training. Laura Dunn, the organizations director and founder, has agreed to come to Hudson. Ms. Dunns facilitation for students, faculty and administrators will discuss the culture shift necessary on campus to move away from risk reduction on women to inclusive efforts focused on preventing perpetration and bystander intervention to ensure sexual respect becomes the norm on campus. The event will open up discussion about on-campus sexual assault, and how the university can continue cultivating on-campus sexual respect and understanding. ',400);
insert into hudsonu.event values(1248441,'Democracy Matters Spring 2017 Budget',cast('2017-03-03 19:00' as date),cast('2017-03-03 20:00' as date),'Lawrence TV Room','Thoughtful Learning',NULL,'DM','Democracy Matters is a group that tries to restrict money''s influence on the political system. This issue is prevalent now more than ever with the current political situation. Thus, Democracy Matters will be trying its hardest to raise awareness throughout Hudson''s campus regarding the issue. We are seeking BAC approval for advertising costs as well as food costs that we believe are integral to the success of our events. Most of our events are traditional brown bags, where we bring in notable speakers to help increase students'' knowledge and interest in the issue. Our brown bags in the past have been quite successful events and we anticipate continued success this upcoming semester. We have significantly cut down our costs from last semester to better align with new BAC procedures and precedents. ',400);
insert into hudsonu.event values(1257100,'Opening Round of Championships',cast('2017-03-16 12:00' as date),cast('2017-03-19 12:00' as date),'Elizabethtown College','Thoughtful Learning',NULL,'MT','The Opening Round of Championships, or ORCs is a tournament occurring in several locations across the US for Mock Trial Teams that have qualified in their regional tournaments. For the first time in seven years, Hudson Mock Trial has successfully secured a bid. Rounds will begin on Friday, March 17, and end on Sunday, March 19. ',290);
insert into hudsonu.event values(1265412,'DC Climate March Sponsored by Democracy Matters',cast('2017-04-28 12:00' as date),cast('2017-04-29 19:00' as date),'Washington D.C.','Thoughtful Learning',NULL,'DM','Democracy Matters is leading the way in organizing a trip to Washington D.C. from April 28th-29th to participate in the "People''s Climate Movement 2017." By promoting healthy activism, we are also promoting political participation. We are also trying to broaden our scope as a group and reach a wider audience and organizing an event like this will be very beneficial towards achieving that goal. ',300);
insert into hudsonu.event values(1283490,'Syracuse Law School Visit',cast('2017-04-08 10:00' as date),cast('2017-04-08 15:00' as date),'Syracuse Law School','Thoughtful Learning',NULL,'HPLS','We will be visiting Syracuse Law School to meet with the admissions department and receive information sessions and a tour.  ',145);
insert into hudsonu.event values(4841074,'Hudson Speaking Union Info Night',cast('2019-09-09 19:00' as date),cast('2019-09-09 19:00' as date),'207 Lathrop','Thoughtful Learning',NULL,'SPEAK','Find out more about the teams within the CSU:  Harry C. Behler Debate Society, Spanish Language Debate Society, Mock Trial, Model Arab League, Model United Nations',505);
insert into hudsonu.event values(4878623,'Recruitment Information Session for Potential New Members',cast('2019-09-11 19:00' as date),cast('2019-09-11 20:00' as date),'Love Auditorium','Thoughtful Learning',NULL,'CPC','The Panhellenic Council will hold an information session for Potential New Members to attend. Potential New Members are people who are interested in participating in the recruitment process. We will explain the overall logistics of the events each night and the general recruitment process. They will then meet with their Recruitment Counselor for further details and activities.',615);
insert into hudsonu.event values(5160763,'Trip to the Utica Zoo',cast('2019-11-16 11:00' as date),cast('2019-11-16 17:00' as date),'Utica Zoo','Thoughtful Learning',NULL,'PVC','I am thrilled to announce that the Pre-Vet Club will be visiting the Utica Zoo on Saturday, November 16! At the zoo, we will meet with a veterinary technician, tour the veterinary facility, meet with a zoo educator, meet an ambassador animal, and have some free time to walk around. We will leave Hudson at 11:00 am and return around 5:00 pm.',555);
