insert into hudsonu.event values(520987,'Model United Nations Spring Conferences',cast('2015-02-12 12:00' as date),cast('2015-02-12 12:15' as date),'Domestic and international universities','Thoughtful Learning',NULL,'MUN','Hudson Model United Nations would like to attend four competitive conferences this spring: Harvard WorldMUN in Seoul, South Korea; University of California Berkeley MUN (UCBMUN); Chicago MUN (ChoMUN) at the University of Chicago; and Princeton Interactive Crisis Simulation (PICSim).',360);
insert into hudsonu.event values(520992,'National Debate Championships',cast('2015-04-10 12:00' as date),cast('2015-04-13 12:00' as date),'University of Alaska Anchorage','Thoughtful Learning',NULL,'DS','University of Alaska Achorage will be hosting US Universities BP Nationals Debating Championship this year on its campus from April 11th to 13th. The tournament will host more than 200 teams, including teams from every corner of the US, as well as teams from outside US. Hudson will be sending four teams and three judges to the event. US Nationals is the most prestigious and well-attended tournament in US for the past few decades. ',550);
insert into hudsonu.event values(520993,'North Eastern Regional Debate Championships',cast('2015-02-20 12:00' as date),cast('2015-02-22 13:00' as date),'Western Connecticut State University','Thoughtful Learning',NULL,'DS','Western Connecticut University will be hosting a British Parliamentary (BP) debate tournament, which will be running from 02/20/2015 to 02/22/2015. The tournament will have six preliminary rounds on Saturday and Sunday, followed by out rounds, including finals, on Sunday. As the North Eastern Regional Championships, this debate tournament regularly features top quality debaters and judges from the US. Hudson will be sending 4 debate teams and 3 judges to Regionals. Debaters will leave for Regionals on Friday, after classes, and get back to campus by Sunday evening.',360);
insert into hudsonu.event values(520995,'Hudson Open Debate Tournament',cast('2015-03-27 17:00' as date),cast('2015-03-29 18:00' as date),'Olin Hall','Thoughtful Learning',NULL,'DS','The 6th annual Hudson Open Debate Tournament will be held March 27 - 29. Teams and judges will come to Hudson from around the globe to train Hudson students in debating, encourage intellectual discourse on campus, and promote Hudson as a global university. There will be over 200 particpants including top ranked participants from the World Universities Debating Championship.'||chr(10)||' ',430);
insert into hudsonu.event values(5563323,'Hudson Open',cast('2020-04-11 08:00' as date),cast('2020-04-12 18:00' as date),'GA: Love Auditorium, Finals: Golden Auditorium','Thoughtful Learning',NULL,'DS','The Harry C. Behler Debate Society will be hosting Hudson''s very own debate tournament, the Hudson Open, from April 11-12. Teams from all around the world will come to participate in the tournament and argue extemporaneously about diverse and interesting issues.'||chr(10)||'Students are encouraged to attend the final round at 4:30 PM in Golden Auditorium in Little Hall on Sunday, April 12. The four highest-performing teams from the tournament will compete against each other to become the champions of the Hudson Open.',700);
insert into hudsonu.event values(630214,'Democracy Matters Brown Bag',cast('2015-04-09 11:15' as date),cast('2015-04-09 11:30' as date),'Lathrop 207','Thoughtful Learning',NULL,'DM','Lunchtime brownbag presentations by university professors on topics relevent to Democracy Matters. Provides catering and an environment for disucssion on these topics. '||chr(10)||'Rescheduled: '||chr(10)||'Professor Jay Mandle, Department of Economics - "Economic Inequality/Political Inequality: Where Are We Heading?"'||chr(10)||'Lathrop 207 '||chr(10)||' ',500);
insert into hudsonu.event values(636756,'Model UN Fall 2015 Conferences',cast('2015-08-24 12:00' as date),cast('2015-08-24 11:15' as date),'Hudson','Thoughtful Learning',NULL,'MUN','Hudson Model United Nations would like to attend four competitive conferences this fall: Security Council Simulation at Yale (SCSY) in New Haven, Boston Area Model United Nations (BarMUN) in Boston, run by Boston University, University of Pennsylvania Model UN Conference (UPMUNC) in Philadelphia, and the Harvard National Model UN Latin America (HNMUN LA) in South America.',370);
insert into hudsonu.event values(6527983,'Speech by Robert D. Kaplan: COVID-19''s effects on globalization',cast('2020-10-15 17:00' as date),cast('2020-10-15 17:30' as date),'Online','Thoughtful Learning',NULL,'HODC',' A speech presented by foreign policy analyst Robert D. Kaplan is planned for Thursday, October 15th at 5:00 PM EST. In his address via Zoom, foreign policy analyst Robert D. Kaplan will explain his views on the COVID-19 pandemic''s influence on globalization and foreign policy decisions in the decades ahead. Mr. Kaplan has written for numerous publications including Bloomberg, Foreign Policy Magazine, and the Wall Street Journal, having specifically written an article concerning this subject for Bloomberg, titled Coronavirus Ushers in the Globalization We Were Afraid Of. We hope the speech will be of interest to anyone concerned about the long term effects of the pandemic currently altering our lives.',350);
insert into hudsonu.event values(6557184,'SRMUN Virtual Conference',cast('2020-10-23 11:00' as date),cast('2020-10-25 19:30' as date),'Online','Thoughtful Learning',NULL,'MUN','SRMUN Virtual Conference. ',550);
insert into hudsonu.event values(6631009,'Speech by Martin Gilens: Is America a Democratic Country?',cast('2020-11-17 17:00' as date),cast('2020-11-17 19:30' as date),'Online','Thoughtful Learning',NULL,'HODC','Professor Martin Gilens, of UCLA''s Luskin School of Public Affairs, will discuss the relative influence of economic elites, special interest groups, and ordinary Americans on policy outcomes. This speech will be followed by a QandA session.',null);
insert into hudsonu.event values(6891777,'Resume and Cover Letter Workshop with Anthony Dongfack',cast('2021-02-16 17:30' as date),cast('2021-02-16 19:30' as date),'Online','Thoughtful Learning',NULL,'BSU','We will be working virtually with a career consultant and resume writer that will share effective resume writing and career development strategies over the course of one hour. Students who have indicated interest will have the opportunity to have one-on-one conversations with Anthony Dongfack to personally revise their resume after the initial presentation. ',200);
insert into hudsonu.event values(6965465,'Movies for Mental Health Workshop',cast('2021-03-03 18:30' as date),cast('2021-03-03 20:30' as date),'Online','Thoughtful Learning',NULL,'AM','Join us as we virtually host Art with Impact for a workshop on exploring mental health through the realm of art. Art with Impact is a nonprofit that helps college students creatively explore their own mental health through the arts, with an emphasis on intersectionality, community building, and mental wellness and cultural stigma within marginalized communities. The workshop will both be informative and interactive!'||chr(10)||' '||chr(10)||'Sponsored by Active Minds, SGA and Shaw Wellness.',575);
insert into hudsonu.event values(700340,'Yale University Debate Tournament',cast('2015-10-01 17:00' as date),cast('2015-10-04 16:00' as date),'New Haven, CT','Thoughtful Learning',NULL,'DS','The debate society will be traveling to Yale University to compete in their debate tournament.',null);
insert into hudsonu.event values(7038648,'Tina VanSteenbergen Keynote',cast('2021-03-25 19:00' as date),cast('2021-03-25 19:00' as date),'Online','Thoughtful Learning',NULL,'CPC','Discussion on Greek Life with Tina Vansteenbergen',null);
insert into hudsonu.event values(7038653,'Open Conversation w/ Members of IFC and Panhellenic',cast('2021-03-31 19:00' as date),cast('2021-03-31 19:00' as date),'Online','Thoughtful Learning',NULL,'CPC','Opportunity to speak with leaders from each Greek Organization about their experience and what is to come in the future.',null);
insert into hudsonu.event values(7042382,'Introduction to Lobbying with DM Executive Director Dr. Joan Mandle',cast('2021-04-06 17:00' as date),cast('2021-04-06 17:00' as date),'Online','Thoughtful Learning',NULL,'DM','In conjunction with Mable Dart Colgrove Commons, we are very excited to host Democracy Matters Executive Director (and former Hudson Professor!) Dr. Joan Mandle for our Introduction to Lobbying Workshop on Tuesday, April 6th from 5-6 pm. '||chr(10)||' '||chr(10)||'In this workshop, we hope to train students on how to effectively lobby their elected officials about calling, letter writing, petitioning, and other strategies. Dont worry if you don''t have any experience with lobbying before. We want to empower you to advocate for the issues you care about and will work to give you the tools you need to be an effective and engaged citizen!',550);
insert into hudsonu.event values(7050144,'USUDC 2021',cast('2021-04-17 10:30' as date),cast('2021-04-18 20:00' as date),'Lathrop Hall','Thoughtful Learning',NULL,'DS','The US'' National Debate Tournament. It features eight rounds of debates with teams from around the country.',null);
insert into hudsonu.event values(7079079,'Prof. Gad Saad Digital Speech on "The Parasitic Mind: How Infectious Ideas Are Killing Common Sense"',cast('2021-04-19 17:00' as date),cast('2021-04-19 17:30' as date),'Online','Thoughtful Learning',NULL,'HODC','A speech presented by Dr. Gad Saad, a Lebanese-Canadian evolutionary psychologist and professor at the John Molson School of Business at Concordia University, is planned for Monday, April 19th at 5:00 PM EDT. Along with his important work as a public intellectual and host of "The Saad Truth," Dr. Saad is the author of the 2020 book, "The Parasitic Mind: How Infectious Ideas Are Killing Common Sense," a criticism of pervasive political ideology that ignores reason and scientific principles.During his speech via Zoom, Dr. Saad will discuss several issues central to "The Parasitic Mind". Specifically, he will focus on "idea pathogens," ideologically tempting ideas, largely sprouting in academia, that damage our civilization and its potential for free speech and open discussion. This speech will be followed by a QandA session.',275);
insert into hudsonu.event values(721258,'From Test Case to Development Paradox: The Bangladesh Story',cast('2015-09-24 16:30' as date),cast('2015-09-24 17:00' as date),'Persson Hall Auditorium','Thoughtful Learning',NULL,'SACC','Bangladesh has beaten all odds and have recently been declared a Low Middle Income Country (LMIC) by the World Bank with a per capita GDP of over $1300 in 2015, a life expectancy at birth of 68.3 years, close to universal school enrollment at the primary level, gender equality at both primary and secondary levels, a vibrant manufacturing sector based on ready-made garments and female labor, a sustained growth rate of over 6 percent, and a robust balance of payments and foreign exchange reserves position. The country has come a long way from the time when it was normal to refer to it as a basket case or more euphemistically, as a test case of development. Dr. Murshid traces Bangladeshs unique development journey and points to key factors that have contributed to it. Is the Bangladeshi case an exceptional one or is there a model that can be replicated elsewhere successfully? '||chr(10)||' ',610);
insert into hudsonu.event values(722323,'Mock Trial Tournament',cast('2015-10-23 12:00' as date),cast('2015-10-25 12:00' as date),'Umass Amherst','Thoughtful Learning',NULL,'MT','This event is a Mock Trial Tournament to UMass Amherst. ',400);
insert into hudsonu.event values(722324,'Mock Trial Tournament',cast('2015-11-06 12:00' as date),cast('2015-11-08 13:00' as date),'Saint Bonaventure University','Thoughtful Learning',NULL,'MT','This event is a Mock Trial Tournament to Saint Bonneventure Universtiy.',null);
insert into hudsonu.event values(722327,'Hudson Classic: Mock Trial Tournament',cast('2015-11-14 06:00' as date),cast('2015-11-15 18:45' as date),'Hudson University','Thoughtful Learning',NULL,'MT','This is the 6th Annual Hudson Classic, a Mock Trial Tournament. The event uses the AMTA case problem and allows teams from all over the region to compete in and invitational tournament.',null);
insert into hudsonu.event values(722328,'7th Annual Hudson Classic',cast('2015-11-14 05:00' as date),cast('2015-11-15 19:00' as date),'Campus','Thoughtful Learning',NULL,'MT','This event is the 7th Annual Hudson Classic. It is a Mock Trial competition that we host every year. We have teams from around the country come to try the American Mock Trial Association''s annual case against Hudson''s team.',null);
insert into hudsonu.event values(725453,'Hudson Women in Business Immersion Trip',cast('2015-10-01 12:00' as date),cast('2015-10-03 12:00' as date),'New York City','Thoughtful Learning',NULL,'HWIB','This is a two-day trip to New York City to allow our members to make valuable connections with alumnae and gain insights into the opportunities that lie ahead post-graduation. ',320);
insert into hudsonu.event values(725526,'Hudson Marketing Club Immersion Trip',cast('2016-01-11 12:00' as date),cast('2016-01-13 13:00' as date),'Boston','Thoughtful Learning',NULL,'HSMC','The event is going to be an immersion trip to Boston for 12 students.  There will be an open application for all students who are interested.  The event will probably take place toward the end of winter break, but before sophoMORE Connections.  The bus or train will take these sophomores to Hudson in time for sophoMORE Connections, and other class years will apply the funding to their personal mode of transportation.  All students will receive funding for their roundtrip personal mode of transportation.  '||chr(10)||' '||chr(10)||'Then, there will be a networking event with alumni in the Communications field either that night or the night after, which requires an event fee of $20 per person.  We would like to include students who live in Boston because this is a great opportunity for them to network with local alumni.  We are expecting about 30 students from Boston to join for the networking reception.',200);
insert into hudsonu.event values(7599629,'Behind The Scenes - Financial Innovation and the 2008 Financial Crisis: In-Person Speaker Event',cast('2021-11-17 19:00' as date),cast('2021-11-17 21:00' as date),'Love Auditorium - Olin Hall','Thoughtful Learning',NULL,'HIG','What: Christian Spieler, a German top banker with years of experience in the boards of Wall Street''s big banks, will be hosting an in-person speaker event with extended QandA on the financial innovation driving the 2008 financial crisis. Mr. Spieler will offer an insider''s front-seat perspective on the financial innovation in the fixed income and derivative space behind the combustible mixture that led to the Great Recession and then hold a 45 minute open QandA session. Until 2008, Mr. Spieler was employed at Lehman Brothers in Frankfurt, Germany, as Head of Capital Markets for all Equities and Fixed Income Business with German and Austrian clients, as well as overseeing the activities of the branches of Lehman Brothers Bankhaus in Milan, London, and Seoul (Korea). He also served on the boards of Citigroup and J.P. Morgan in Germany. '||chr(10)||'Faculty attendance and tricky questions are encouraged. No prior knowledge of the subject is required, though individuals with an interest in finance and economics are strongly encouraged to attend.   '||chr(10)||'The event will be exclusive to Hudson and completely off the record. As the event is in-person, participants will have to attend physically if they want to participate. Mask wearing will be mandatory indoors, and social distancing and other health and safety guidelines should be followed as prescribed on university grounds.'||chr(10)||'Brought to you by the Hudson Investment Group.'||chr(10)||'When and Where:'||chr(10)||'Wednesday, November 17t - 07:00 pm -09:00 pm - Olin Hall, Love Auditorium. ',375);
insert into hudsonu.event values(772317,'Konosioni Coffee Hour',cast('2015-11-15 20:00' as date),cast('2015-11-15 22:00' as date),'Case Library','Thoughtful Learning',NULL,'THS','Konosioni Coffee Hour is hosted every year and is the most effective way of informing Juniors about the Konosioni application process, acceptance process, and membership. The application process is long, and complicated. This year especially, we are prioritizing transparency and inclusivity. This coffee hour will help us achieve those priorities. ',380);
insert into hudsonu.event values(7939027,'Pre-Med Strategies: Freshman and Sophomore Year',cast('2022-03-02 17:00' as date),cast('2022-03-02 18:00' as date),'ALANA Cultural Center','Thoughtful Learning',NULL,'ALANA','This upcoming Wednesday, MAPS is holding an event specifically for freshman in OUS-First that are interested or have taken steps to pursing a Pre-Med track. We invite you to come to ALANA cultural center on March 2nd from 5-6PM and join current upperclassmen OUS scholars as they talk about the pre-med journey. '||chr(10)||' '||chr(10)||'We know first hand that being pre-med, its really hard to navigate all the required aspects, networking and shadowing at Hudson, and finding the best path for you, especially coming from a cultural minority or being first gen. We hope to offer some guidance as well as tips and tricks for your upcoming years, and also to join MAPS, The Minority Association of Pre-Med Students!'||chr(10)||' '||chr(10)||'You dont have to be 100% committed to pre-med, so if youre just thinking about it, please join us as well! ',380);
insert into hudsonu.event values(8061962,'MAPS Workshop: Understanding Scientific Literature',cast('2022-04-13 16:20' as date),cast('2022-04-13 16:30' as date),'ALANA Cultural Center','Thoughtful Learning',NULL,'HMAPS','Join MAPS and Professor Geoffrey Holm at ALANA Cultural Center this Wednesday, April 7th at 4:20PM! We will be holding a workshop regarding approaching scientific literature and discussing tips and tricks to best digest dense academic journal articles. ',490);
insert into hudsonu.event values(812663,'Post-Uganda Immersion Trip Dinner',cast('2016-02-10 18:30' as date),cast('2016-02-10 19:30' as date),'Coop TV Room','Thoughtful Learning',NULL,'HGHC','The students who go on the GHI-sponsored trip to Uganda over winter break will hold a panel/discussion dinner about what they learned on the trip.  The event will be open to any students who are intersted and is designed to educate the campus about Bwindi Community Hospital and the Indigo Foundation through the stories and experiences of those who participated in the trip.  Attendees will be able to ask questions about the trip and get a better understanding of Public Health in the developing world.',425);
insert into hudsonu.event values(821052,'Hudson Women in Business Coffee Hour Series',cast('2015-09-15 20:00' as date),cast('2015-09-15 20:00' as date),'Batza Room','Thoughtful Learning',NULL,'HWIB','Hudson Women in Business presents a Coffee Hour Series that will include four different events throughout the semester. They will take place on September 15 at 8pm, October 20 at 8pm, November 11 at 8pm, and December 1 at 8pm. Each event will have different focuses, including resume writing, LinkedIn profiles, networking, and how to negotiate your salary. These events are open to all members and non-members of CWIB, and will be held in the Batza Room. At each event we serve coffee, hot chocolate and snacks. ',360);
