insert into hudsonu.event values(8965712,'Tech Immersion Week',cast('2023-03-21 17:00' as date),cast('2023-03-28 17:00' as date),'McGregory Research Lounge (3rd floor)','Thoughtful Learning',NULL,'CODE','WiCS and <Hudson Coders> are happy to announce our biggest event of the semester! The Technology Immersion Week (March 21st - March 28th) is a series of programming workshops and career development sessions designed to offer ALL students a chance to gain practical skills with programming languages, frameworks, tools, and valuable career advice.'||chr(10)||' '||chr(10)||'Potential topics include Javascript, React, Git, Machine Learning, Networking in the tech industry, and Internship/Job-Searching advice.'||chr(10)||' '||chr(10)||'All sessions will be student-led, so we are looking for experienced students willing to teach a 1-hour practical workshop on a topic of their choice (see form for some examples). You do NOT need to be a CS major to be a workshop instructor, and any technology-related topic ideas are welcome!',280);
insert into hudsonu.event values(8965713,'Tech Immersion Week',cast('2023-04-04 17:00' as date),cast('2023-04-11 17:00' as date),'McGregory Research Lounge (3rd floor)','Thoughtful Learning',NULL,'CODE','WiCS and <Hudson Coders> are happy to announce our biggest event of the semester! The Technology Immersion Week (March 21st - March 28th) is a series of programming workshops and career development sessions designed to offer ALL students a chance to gain practical skills with programming languages, frameworks, tools, and valuable career advice.'||chr(10)||' '||chr(10)||'Potential topics include Javascript, React, Git, Machine Learning, Networking in the tech industry, and Internship/Job-Searching advice.'||chr(10)||' '||chr(10)||'All sessions will be student-led, so we are looking for experienced students willing to teach a 1-hour practical workshop on a topic of their choice (see form for some examples). You do NOT need to be a CS major to be a workshop instructor, and any technology-related topic ideas are welcome!',280);
insert into hudsonu.event values(9049294,'Gun Violence Panel',cast('2023-04-13 16:15' as date),cast('2023-04-13 16:30' as date),'Alumni 111','Thoughtful Learning',NULL,'DM','Join Professor Luttig and Professor Rosenfeld of Hudson''s Political Science Dept.  as they discuss a wide range of gun issues in the United States including the lack of legislation relating to gun violence, the accessibility of guns in the United States, and the mental health effects of mass incidents. '||chr(10)||'Thursday, April 13th'||chr(10)||'4:15pm - 5:30pm '||chr(10)||'Alumni 111',475);
insert into hudsonu.event values(9058731,'Values Week: Intro to Greek Life Panel',cast('2023-04-18 19:30' as date),cast('2023-04-18 19:30' as date),'Ho Science Center Rm. 101','Thoughtful Learning',NULL,'CPC','Interested in learning more about Fraternity and Sorority Life at Hudson? Join us Tuesday April 18th in the Ho Science Center rm 101 at 7:30pm. Come with your questions ready as our panel is eager to share their experiences. ',440);
insert into hudsonu.event values(926048,'A Tale of Two Sit-Ins',cast('2016-03-24 16:30' as date),cast('2016-03-24 17:00' as date),'Love Auditorium','Thoughtful Learning',NULL,'SGA','Please join us for "A Tale of Two Sit-ins" panel discussion. This event is open to the entire Hudson and Hamilton community. Look forward to learning about Hudson''s activist history, listening to remarks from the leaders and participants of Hudson''s two largest sit-ins, and hearing about the importance community organizing and building on campus. The panelists are: Jim Smith ''70, Naceo Giles ''69, Jon Romano ''70, Marc Rosenbaum ''70, Dennis Riordan ''70, Melissa Melendez ''15, Natasha Torres ''15, Shemuel Malave ''18, Mimi Ballard ''18.Join us this Thursday, March 24th @ 4:30pm in Love Auditorium. Special thanks to the following sponsors: Broad Street Association, Bunche House, Interfaith House, PAC House, Dean of the College, SGA, ALANA. *Dinner following the panel',470);
insert into hudsonu.event values(9280695,'Info Session: Turn Your Ideas Into Reality with @ Thought Into Action',cast('2023-09-06 11:30' as date),cast('2023-09-06 12:00' as date),'Center for Women''s Studies','Thoughtful Learning',NULL,'TIA','The Office of LGBTQ+ Initiatives in partnership with the Thought Into Action are holding an information session on how you can turn your creative ideas in to reality.'||chr(10)||'*If you have a great startup concept you''ve been meaning to pursue or an idea for a non-profit you''d like to start, TIA is for you! Even if you haven''t yet developed your "big idea" but are interested in exploring possibilities, TIA can help with that too. Perhaps you might be more interested in joining someone else''s venture than starting your own? Yup. You can do that at TIA as well. The TIA Incubator provides structure, mentorship, and resources to would-be world-changers here at Hudson. Not only does the program have a rich history of cultivating entrepreneurs and innovators who have taken ideas hatched here in Hamilton to great heights in the "real world", TIA has also helped countless Hudson students develop the entrepreneurial skills and experience that are highly sought after by startups, corporations, and social enterprises alike. ',410);
insert into hudsonu.event values(928177,'Taking Charge: Female Condom Facts',cast('2016-03-31 16:00' as date),cast('2016-03-31 15:45' as date),'Center for Women''s Studies, East Hall','Thoughtful Learning',NULL,'HGHC','Come and learn about the benefits of female condoms around the globe, how to use female condoms, the drawbacks to female condoms, and other fun facts! Food will be provided. ',400);
insert into hudsonu.event values(9284351,'Learn to turn your ideas into reality with Thought Into Action (TIA)',cast('2023-09-18 16:15' as date),cast('2023-09-18 16:15' as date),'McGregory Room 226','Thoughtful Learning',NULL,'TIA','Join us for our second of two TIA Entrepreneur Orientation sessions (you only need to attend one). Thought Into Action (TIA) is Hudsons flagship entrepreneurship and innovation co-curricular program. Do you have a great startup concept that you have been meaning to pursue, or an idea for a non-profit that you would love to start; we want you to know TIA is for you. BUT! even if you havent yet developed your big idea but are interested in exploring possibilities, TIA can help with that, too. Or, perhaps you are more interested in joining someone else''s venture than starting your own? Yup. You can do that in TIA as well.'||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||' '||chr(10)||'Click here to learn more and sign-up for the 2023-2024 TIA Incubator.The TIA Incubator provides structure, mentorship, and resources to would-be world-changers here at Hudson. Not only does the program have a rich history of cultivating entrepreneurs and innovators who have taken ideas hatched here in Hamilton to great heights in the real world, TIA has also helped countless Hudson students develop the entrepreneurial skills and experience that are highly sought after by startups, corporations, and social enterprises alike.If you or they have any questions about our program, please don''t hesitate to reach out to our Entrepreneur-in-Residence Travis Millman (tmillman@hudson.edu) or EandI Director Carolyn Strobel-Larsen (cstrobellarsen@hudson.edu).'||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'',300);
insert into hudsonu.event values(9284362,'Learn to turn your ideas into reality with Thought Into Action (TIA)',cast('2023-09-12 16:15' as date),cast('2023-09-12 16:15' as date),'McGregory Room 212','Thoughtful Learning',NULL,'TIA','Join us for our first of two TIA Entrepreneur Orientation sessions (you only need to attend one). Thought Into Action (TIA) is Hudsons flagship entrepreneurship and innovation co-curricular program. Do you have a great startup concept that you have been meaning to pursue, or an idea for a non-profit that you would love to start; we want you to know TIA is for you. BUT! even if you havent yet developed your big idea but are interested in exploring possibilities, TIA can help with that, too. Or, perhaps you are more interested in joining someone else''s venture than starting your own? Yup. You can do that in TIA as well.'||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||' '||chr(10)||'Click here to learn more and sign-up for the 2023-2024 TIA Incubator.The TIA Incubator provides structure, mentorship, and resources to would-be world-changers here at Hudson. Not only does the program have a rich history of cultivating entrepreneurs and innovators who have taken ideas hatched here in Hamilton to great heights in the real world, TIA has also helped countless Hudson students develop the entrepreneurial skills and experience that are highly sought after by startups, corporations, and social enterprises alike.If you or they have any questions about our program, please don''t hesitate to reach out to our Entrepreneur-in-Residence Travis Millman (tmillman@hudson.edu) or EandI Director Carolyn Strobel-Larsen (cstrobellarsen@hudson.edu).'||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'',380);
insert into hudsonu.event values(9284464,'2023-2024 TIA Incubator - Session 1',cast('2023-09-22 16:00' as date),cast('2023-09-24 11:30' as date),'Friday - The Hub (20 Utica St.); Saturday/Sunday - Atrium (Cunniff Commons), Ho Science','Thoughtful Learning',NULL,'TIA','Join us for our kickoff weekend of the 2023-2024 TIA Incubator! Guest speakers, panel discussions, activities, mentors ... this weekend will be the springboard you need to develop your idea into reality.'||chr(10)||' '||chr(10)||'Thought Into Action (TIA) is Hudsons flagship entrepreneurship and innovation co-curricular program. Whether you have a great startup concept that you have been meaning to pursue, or an idea for a non-profit that you would love to start, you are strongly encouraged to join us. Even if you havent yet developed your big idea, you are encouraged to join us to explore the many possibilities - bringing your unique experience and expertise to join another venture, or perhaps creating another venture on the spot with other like-minded individuals!'||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||' '||chr(10)||'Click here to learn more and sign-up for the 2023-2024 TIA Incubator.The TIA Incubator provides structure, mentorship, and resources to would-be world-changers here at Hudson. Not only does the program have a rich history of cultivating entrepreneurs and innovators who have taken ideas hatched here in Hamilton to great heights in the real world, TIA has also helped countless Hudson students develop the entrepreneurial skills and experience that are highly sought after by startups, corporations, and social enterprises alike.If you or they have any questions about our program, please don''t hesitate to reach out to our Entrepreneur-in-Residence Travis Millman (tmillman@hudson.edu) or EandI Director Carolyn Strobel-Larsen (cstrobellarsen@hudson.edu).'||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'',350);
insert into hudsonu.event values(938507,'The Milmoe Workshop in Journalism Presents QandA with Sacha Pfeiffer',cast('2016-04-06 18:00' as date),cast('2016-04-06 18:00' as date),'Love Auditorium, Olin Hall','Thoughtful Learning',NULL,'HMN','The Hudson Maroon-News, with funding from the Milmo Workshop of Journalism, is proud to welcome Sacha Pfeiffer from the Boston Globe. Pfeiffer was a member of the Boston Globe Spotlight Team that won the 2003 Pulitzer Prize for Public Service for its stories on clergy sex abuse in the Catholic Church. She was portrayed by Rachel McAdams in the 2015 movie Spotlight.'||chr(10)||'On April 6, join us in Love Auditorium from 6 - 7 p.m. for a QandA with the award-winning investigative journalist who broke the story and broke the silence. ',500);
