insert into hudsonu.event values(9588586,'Event-driven Programming with Sensors',cast('2023-11-03 14:00' as date),cast('2023-11-03 15:00' as date),'McGregory Hall','Thoughtful Learning',NULL,'HTT','Dive into the interactive world of robots with our hands-on "Event-Driven Programming with Sensors" workshop, tailor-made for beginners! The Robotics Club is thrilled to invite all budding roboticists to this beginner-friendly event, where the fusion of software and hardware comes to life through the exciting realm of event-driven programming.',460);
insert into hudsonu.event values(9820682,'Lewis Orator Prize Speaking Competition',cast('2024-02-16 16:30' as date),cast('2024-02-16 18:00' as date),'207 Lathrop Hall','Thoughtful Learning',NULL,'DS','Hudson Debate Society is hosting the annual Lewis Orator Prize Speaking Competition on February 16th at 4:30 PM. Participants must give a 5-7 minute speech centered around the word "enigma." This prompt must be used in the speech as a vehicle to elucidate some aspect of social reality in a new and memorable way. The top three speeches will be rewarded with a monetary prize. '||chr(10)||'For the rules and to sign up, use this link: https://forms.gle/8SUzzVeyNEF3ewHq6 '||chr(10)||'Sign-ups close on February 9th at 11:59 PM. Please email debatesociety@hudson.edu with any questions.',235);
insert into hudsonu.event values(9866775,'Hudson Open 2024 Open Finals',cast('2024-03-24 16:30' as date),cast('2024-03-24 17:00' as date),'Hudson University Memorial Chapel','Thoughtful Learning',NULL,'DS','Each year Hudson''s Debate Society hosts the Hudson Open - an international British Parliamentary debate tournament. The tournament culminates with the 4 highest performing teams participating in an open final. All are welcome to spectate!',null);
insert into hudsonu.event values(9866776,'Hudson Open 2024 Open Finals',cast('2024-03-24 16:30' as date),cast('2024-03-24 17:00' as date),'Hudson University Memorial Chapel','Thoughtful Learning',NULL,'DS','Each year Hudson''s Debate Society hosts the Hudson Open - an international British Parliamentary debate tournament. The tournament culminates with the 4 highest performing teams participating in an open final. All are welcome to spectate!',null);
insert into hudsonu.event values(9921417,'Event-driven Programming with Circuit Playground and Adafruit Cricket',cast('2024-02-09 14:30' as date),cast('2024-02-09 16:00' as date),'McGregory 314','Thoughtful Learning',NULL,'HTT','Join us for an exciting introductory workshop on Event-driven Programming with Circuit Playground and Adafruit Cricket!'||chr(10)||'In this hands-on session, you''ll dive into the world of event-driven programming using Circuit Playground and Adafruit Cricket. Learn how to create interactive projects that respond to various events and inputs.'||chr(10)||'No prior experience is needed! Whether you''re a beginner or have some programming knowledge, this workshop is designed to be inclusive and engaging for all levels.'||chr(10)||'Don''t miss this opportunity to explore the possibilities of event-driven programming and unleash your creativity with Circuit Playground and Adafruit Cricket!',500);
insert into hudsonu.event values(9984984,'Kingsford Speaking Competition',cast('2023-10-04 16:30' as date),cast('2023-10-04 17:30' as date),'Lathrop 207','Thoughtful Learning',NULL,'DS','The Kingsford Speaking Competition, established in 1881,  gives Hudson students the opportunity to deliver a speech that intends to persuade the immediate audience to take action as a step toward the solution of a problem made salient by the speech for a monetary prize. The action step must be generally within the means of the audience (i.e. possible), clearly linked to affecting the problems solution, motivated by needs/desires apparently aroused by the speech, andperceived as good (expedient, and appropriate) by virtue of its consistency with the audiences operative hierarchy of values.'||chr(10)||'Accordingly, the speech should be audience centered, anticipating as much as possible the interests and abilities of the audience. Given that the dominant group assembled for the speech consists of fellow students, the whole range of their common interests and abilities should becanvassed when attempting to address them as a group. Then, contestants should target what they consider to be the key demographic indices to address as prompts to action (e.g., age, gender, etc.). Contestants should not adapt their speeches solely to what they perceive to be the common or special interests and abilities of the judges (e.g. professors, parents, administrators, 25 years old and above, etc.).',310);
insert into hudsonu.event values(1032790,'HHM Kickoff Barbecue',cast('2016-09-10 17:00' as date),cast('2016-09-10 18:00' as date),'The quad','Cultural',NULL,'LASO','To kick-off Hispanic Heritage Month, LASO will be having a Barbecue for the entire hudson community.',null);
