insert into hudsonu.event values(1047926,'Family Banquet 2016',cast('2016-10-28 17:00' as date),cast('2016-10-28 18:00' as date),'ALANA Cultural Center','Cultural',NULL,'BSU','The Black Student Union annually host the Family Weekend Banquet. The event is intended to bring together the families of students on campus and anyone within the Hamilton community. The Black Student takes the banquet as an opportunity to showcase the strength and inclusivity of our organization.',360);
insert into hudsonu.event values(1047988,'African Appreciation Month',cast('2016-10-15 12:00' as date),cast('2016-11-12 13:00' as date),'Hudson University','Cultural',NULL,'AS','African Appreciation Month is a month long celebration of African history, cultures, foods, and music. The events for this month long celebration includes Nigerian author and poet Wole Soyinka and Gender theorist Oyewumi. The culminating event is the ASU fashion show. The fashion show depicts clothing from across the continent. This month is full of learning and entertainment.',515);
insert into hudsonu.event values(1062654,'Hudson Vietnam Society - Traditional Broken Rice and Pork Chop Cooking Event',cast('2016-10-14 17:00' as date),cast('2016-10-14 18:00' as date),'Alana Cultural Center','Cultural',NULL,'HVS','An exotic night with Vietnamese culture:'||chr(10)||'It will be a bonding activity, the first one of HVS in this semester, in which attendees will be taught to make two popular Vietnamese snacks: com suon and cha trung (Vietnamese grilled pork, served with Tamrice and egg meatloaf). The event is open to public. We will announce this event to our mailing list, and we are also putting it on GetInvolved (and hopefully, the calendar). We plan to do this in the ALANA kitchen, before moving to the lounge to bond over food and movie.',250);
insert into hudsonu.event values(1062691,'You Mean, There''s RACE in My Movie? The Complete Guide to Understanding Race in Mainstream Hollywood',cast('2016-10-05 17:30' as date),cast('2016-10-05 18:00' as date),'Love Auditorium','Cultural',NULL,'BROS','The Brothers of Hudson University and other sponsors have invited Dr. Frederick W. Gooding Jr. to talk about understanding racial implications in mainstream media on Tuesday October 5th at 5:30 pm at Love Auditorium.',null);
insert into hudsonu.event values(1109935,'Oktoberfest',cast('2016-10-21 20:00' as date),cast('2016-10-21 21:00' as date),'Donovan''s Pub','Cultural',NULL,'GC','A German cultural experience in Donovan''s Pub with great friends, food, and music!',null);
insert into hudsonu.event values(1163416,'Black History Month Keynote: Crunk Feminist, Dr. Brittney Cooper',cast('2017-02-08 17:00' as date),cast('2017-02-08 18:30' as date),'Love Auditorium','Cultural',NULL,'BSU','As per Hudson University tradition, the Black Student Union is presenting a series of events in celebration of Black History Month. We would like to bring Brittney Cooper as our keynote speaker as she coincides with our theme for this year: Black Girl Magic. Brittney Cooper, who identifies as a Crunk Feminist,  is Assistant Professor of Womens and Gender Studies and Africana Studies at Rutgers University. She is a Black feminist theorist who specializes in the study of Black womens intellectual history, Hip Hop generation feminism, and race and gender representation in popular culture. Her forthcoming book Race Women: Gender and the Making of a Black Public Intellectual Tradition (University of Illinois Press) examines the long history of Black womens thought leadership in the U.S., with a view toward reinvigorating contemporary scholarly and popular conversations about Black feminism.',550);
insert into hudsonu.event values(1213399,'Hudson Women in Business Coffee Hour Series',cast('2017-01-22 12:00' as date),cast('2017-01-22 13:00' as date),'Batza Room','Thoughtful Learning',NULL,'HWIB','Please join the Hudson Women in Business Organization for a monthly coffee hour to discuss different aspects of the field of business.  Meetings may include breakout sessions to discuss specific industries within the field of business, hearing tips from upperclassman who have experience in the business field, revising a resume or cover letter, speaking with alumni and established professions in the field of business, and more.  This semester we will target our topics to building a LinkedIn profiles and taking advantage of Hudson''s resources to pursue jobs and internships.',175);
