insert into hudsonu.event values(1241490,'OASIS Family Dinners 2017 Spring',cast('2017-01-29 12:00' as date),cast('2017-05-11 19:00' as date),'WMST','Cultural',NULL,'OASIS','OASIS Family Dinners aim to build a safe space and community within Asian students on campus. We invite all Asian-identifying students to join our Family Dinners. The Family Dinner allows students to share an Asian meal together, connect with other Asian students on campus, and engage in conversations about Asian identities in a relaxed atmosphere.',340);
insert into hudsonu.event values(1241491,'OASIS Brown Bag Series 2017 Spring',cast('2017-01-29 12:00' as date),cast('2017-05-07 16:00' as date),'WMST','Cultural',NULL,'OASIS','The Brown Bag Series consist of a speech by an invited speaker and discussion with attendees. It opens to all students and professors. The series will touch upon the topics involving gender, sexuality, Asian cultures, culture differences, activism, human rights, etc.. It aims to provide students with novel perspectives and create a safe space for free-talking.',500);
insert into hudsonu.event values(4892544,'Fraternity Recruitment Information Session',cast('2019-09-10 19:00' as date),cast('2019-09-10 19:00' as date),'Love Auditorium, Olin Hall','Cultural',NULL,'IFC','This will be the information session for all sophomore students interested in Fraternity life. We will inform them of the recruitment week schedule as well as give information about each of the houses that they could potentially join.',null);
insert into hudsonu.event values(4970072,'Hudson Vietnamese Society Family Dinner',cast('2019-09-28 18:00' as date),cast('2019-09-28 20:00' as date),'OISS kitchen','Cultural',NULL,'HVS','Hudson Vietnam Society Catered Dinner aims to present Vietnamese culture, particularly cuisine, in the cross-cultural context of different countries all over the world. Through this family dinner, we hope to engage Hudson students of diverse backgrounds in a relaxing environment to enhance their understanding and appreciation of a different and foreign culture. We also offer an opportunity for Hudson students to exchange stories about their own unique identities.'||chr(10)||'With the introduction of distinctly Vietnamese food, Hudson Vietnam Society invites people from different parts around the world to experience the story of our country through the exquisite signature dishes that have gained much love and admiration.',510);
insert into hudsonu.event values(5164824,'Vietnamese Traditional Games',cast('2019-11-16 19:00' as date),cast('2019-11-16 21:00' as date),'Jane Pinchin Common Space','Cultural',NULL,'HVS','Vietnamese Traditional Games Event introduces members of Hudson University to traditional Vietnamese games including figurine painting and rope skipping. By introducing these traditional games, we aim not only to deepen Hudson students understanding of the Vietnamese culture and traditions that have shaped Vietnamese culture today but also to establish an emotional connection with fellow Hudson students through exciting and engaging activities. ',290);
insert into hudsonu.event values(525929,'Release Night',cast('2015-02-20 18:45' as date),cast('2015-02-20 20:30' as date),'ALANA Lounge','Cultural',NULL,'BSU','Release Night is an opportunity for students on campus to express themselves and speak on so-cial, political, and economic concerns that they have been pondering. It is a welcoming and en-couraging space for dialogue to occur on the basis of the type of concerns, questions, and aspira-tions that Hudson students raise to one another. The Black Student Union takes great pride in celebrating students voices. Through the hosting of Release Nights we provide this platform.Essentially, it is a chance to gain support and recognition through others about the struggles and achievements that Hudson students may be enduring. Students are provided a support structure, which allows them to openly voice their thoughts without fear of being judged.',300);
insert into hudsonu.event values(525930,'Joy De Gruy',cast('2015-02-11 18:00' as date),cast('2015-02-11 19:15' as date),'Love Auditorium','Cultural',NULL,'BSU',NULL,null);
insert into hudsonu.event values(573293,'Anime Boston 2015 trip',cast('2015-04-03 19:00' as date),cast('2015-04-05 17:00' as date),'Hynes Convention Center','Cultural',NULL,'HAS','We will be travelling to Boston and spend two nights and two days at Anime Boston, the Northeast largest anime convention held annually in Massachusetts, USA. The event aims to promote an educational appreciation for Japanese animation, comics, and pop-culture.'||chr(10)||'Members will have the opportunities to explore their areas of interests through nearly 300 industry panels, hands-on workshops, informative interviews, all the while enjoying themselves with their favorite activities, such as drawing, cosplaying and writing.'||chr(10)||'Our event is open to all Hudson students, and we plan to provide transportation for a maximum of 20 people (the capacity of two Hudson vans) through an application form sent to all students in our mailing list and also available to the general student body.',400);
insert into hudsonu.event values(582660,'Brown Bag: The Indian Ocean World',cast('2015-04-09 12:00' as date),cast('2015-04-09 12:30' as date),'ALANA Cultural Center','Cultural',NULL,'SACC','The brown bag by Professor Balachandran is meant to spread awareness about South Asian Culture and the interconnectedness of this region in general. Professor Balachandran will talk about The Indian Ocean World which will specifically talk about how the Ocean connects the lives of the many different people living in South Asia and the relationship between these diverse cultures.',440);
insert into hudsonu.event values(593964,'Africana Women''s Week(s) Keynote: "Redefining Realness: Janet Mock"',cast('2015-03-02 19:00' as date),cast('2015-03-02 20:30' as date),'Love Auditorium','Cultural',NULL,'SRT','Join Sisters of the Round Table as we present Janet Mock. Mock is a writer, speaker, cultural commentator, prominent advocate for trans women''s rights and the New York Times bestselling author of Redefining Realness: My Path to Womanhood, Identity, Love and So Much More. This event will be an interactive discussion exploring womanhood, identity, and solidarity. All are welcome!'||chr(10)||' ',340);
insert into hudsonu.event values(6426553,'ALANAPalooza',cast('2020-09-11 18:00' as date),cast('2020-09-11 19:00' as date),'Online','Cultural',NULL,'ALANA','Join ALANA virtually for their signature ALANAPalooza event.  Hear from alumni as well.  This will be a livestream event!',400);
insert into hudsonu.event values(6508045,'Dolores Huerta Keynote Speaker',cast('2020-10-14 21:00' as date),cast('2020-10-14 21:30' as date),'Online','Cultural',NULL,'LASO','Join the Latin American Student Organization in welcoming their Fall 2020 Keynote Speaker, Dolores Huerta.'||chr(10)||'Dolores Huerta will speak on her Journey into Activism during the Civil Rights Movement as a Hispanic/Latina woman, her activism today, and her advice to current organizers and activists.'||chr(10)||'Biography'||chr(10)||'Dolores Huerta is a civil rights activist and community organizer. She has worked for labor rights and social justice for over 50 years. In 1962, she and Cesar Chavez founded the United Farm Workers union. She served as Vice President and played a critical role in many of the unions accomplishments for four decades. In 2002, she received the Puffin/Nation $100,000 prize for Creative Citizenship which she used to establish the Dolores Huerta Foundation (DHF). DHF is connecting groundbreaking community-based organizing to state and national movements to register and educate voters; advocate for education reform; bring about infrastructure improvements in low-income communities; advocate for greater equality for the LGBT community, and create strong leadership development. She has received numerous awards: among them The Eleanor Roosevelt Humans Rights Award from President Clinton in 1998. In 2012 President Obama bestowed Dolores with The Presidential Medal of Freedom, the highest civilian honor in the United States.',875);
insert into hudsonu.event values(6764831,'ALANA and Mosaic Present: Vietnamese Lantern Making',cast('2021-02-10 17:00' as date),cast('2021-02-10 18:00' as date),'Online','Cultural',NULL,'HVS','Join student leaders Alex Tran 22 and Flora Zhang 22 to learn how to make Vietnamese lanterns.  '||chr(10)||'Made possible by a generous gift to the Presidents Discretionary Fund from Gio 94 and Maree Cutaia in support of Mosaic programs.'||chr(10)||'Register for the event here.',450);
insert into hudsonu.event values(6764840,'ALANA and Mosaic Present: Chinese Calligraphy',cast('2021-02-10 18:00' as date),cast('2021-02-10 19:00' as date),'Online','Cultural',NULL,'HVS','Chinese Language Intern, Abby Hsu  (Hsu) , leads a Chinese Calligraphy lesson in honor of the Lunar New Year. During this session you will learn how to write Chinese Characters. Alumni are invited to purchase their own materials and follow along. '||chr(10)||'There will be an opportunity for a limited number of participants to receive immediate feedback, but all are still welcome to join in the lesson.'||chr(10)||'Register for the event here.'||chr(10)||'Please note: 15 calligraphy kits available by ALANA Cultural Center will be made available for current students only. Please sign up using the Google Form to reserve your kit.'||chr(10)||'Chinese Calligraphy Kit Reservation Form: https://forms.gle/nDH2gGcxNkyFv2XA6'||chr(10)||'Made possible by a generous gift to the Presidents Discretionary Fund from Gio 94 and Maree Cutaia in support of Mosaic programs.',185);
insert into hudsonu.event values(6764902,'ALANA and Mosaic Present: Dumpling Making',cast('2021-02-10 19:00' as date),cast('2021-02-10 20:00' as date),'Online','Cultural',NULL,'HVS','Prof. Song will teach us how to make two types of dumplings for Lunar New Year. Participants are invited to purchase items in advance to make alongside Prof. Song, who has provided non-vegetarian and vegetarian recipes. Organization of Asian Sisters in Solidarity (OASIS+) will share live commentary.'||chr(10)||'Register for the event here. All are welcome!',320);
insert into hudsonu.event values(6776672,'Lantern Release',cast('2021-02-12 17:00' as date),cast('2021-02-12 18:00' as date),'Taylor Lake','Cultural',NULL,'HVS','Celebrate the start of the Lunar New Year with us as we release the Vietnamese lanterns we make over Taylor Lake. '||chr(10)||'Please note: Space is limited to 10 people. Please register here. '||chr(10)||'If you are not able to join us in person, please click on the link to the Hudson Vietnamese Society Instagram page to view the release.'||chr(10)||'https://www.instagram.com/hudsonvietnamesesociety/',240);
insert into hudsonu.event values(6776680,'Happy Lunar New Year! Moving forward into the new year with diligence, persistence, and honesty.',cast('2021-02-12 19:00' as date),cast('2021-02-12 20:00' as date),'Online','Cultural',NULL,'HVS','Students from the various regions that celebrate this holiday will share the traditions that are specific to their culture.'||chr(10)||'Register for the event here.',null);
insert into hudsonu.event values(6776682,'ALANA and Mosaic Present: Japanese Calligraphy',cast('2021-02-12 16:00' as date),cast('2021-02-12 17:00' as date),'Online','Cultural',NULL,'HVS','Prof. Yukari Hirata   will lead a Japanese Calligraphy lesson in honor of Lunar New Year.  During this session you will learn how to write Japanese Characters.  Alumni are invited to purchase their own materials and follow along.   If you do not have materials, you can still participate in the lesson. '||chr(10)||'There will be an opportunity for only a limited number of participants to receive immediate feedback, but all are still welcome to join in the lesson.'||chr(10)||'Register for the event here.'||chr(10)||'Please note: 15 calligraphy kits will be made available for current students on campus only.  Please sign up using the Google Form to reserve your kit. '||chr(10)||'Japanese Calligraphy Kit Reservation Form: https://forms.gle/UfGwzPmLjjhs5QBg7'||chr(10)||'Made possible by a generous gift to the Presidents Discretionary Fund from Gio 94 and Maree Cutaia in support of Mosaic programs.',400);
