insert into hudsonu.event values(6945095,'Black History Month Everyone is a Scientist',cast('2021-02-24 19:00' as date),cast('2021-02-24 20:00' as date),'Online','Cultural',NULL,'ALANA','Join ASU and ALANA for a Black History Month dialogue about college social and academic navigation. ',230);
insert into hudsonu.event values(7065150,'Tea Club Boba Night',cast('2021-04-10 12:00' as date),cast('2021-04-10 12:00' as date),'Alana Cultural Center','Cultural',NULL,'TTC','Tea Club is having a boba event where we will be distributing boba-making kits to our members. Each person will come and pick up their pre-packaged boba and snacks, which they will be making and eating in their own homes. We will encourage our members to come to the corresponding event which will be held on zoom. Distribution of the boba and snacks will occur at ALANA and people will have to sign up for a time. ',250);
insert into hudsonu.event values(7072415,'Djali Brown-Cepeda Speaking Event',cast('2021-04-20 18:00' as date),cast('2021-04-20 18:00' as date),'Online','Cultural',NULL,'LASO','LASO invites you to come to speak with and meet Djali Brown Cepeda about unlearning colorism, racism, and machismo with the Latinx context and more! '||chr(10)||' '||chr(10)||'About Djali Brown Cepeda: Dominican-American filmmaker/archivist and racial justice advocate. Djali Brown Cepeda is the founder of Nueva Yorkinos which is an organization that aims to preserve Latinx history and culture in New York city through photography and storytelling.',420);
insert into hudsonu.event values(722896,'First Meeting',cast('2015-09-17 18:00' as date),cast('2015-09-17 17:30' as date),'Ho 238','Thoughtful Learning',NULL,'HTT','Come to our first meeting to learn what we''re all about and be introduced to our first project of the year',null);
insert into hudsonu.event values(751382,'African Appreciation week (Keynote and fashion show)',cast('2015-11-14 12:00' as date),cast('2015-11-14 13:00' as date),'HOP','Cultural',NULL,'AS','The ASU fashion show and the Keynote lecture are two very important events for the African Student Union. This year ASU  will be bringing Taiye Selasi author of Ghana Must go.  The ASU fashions is an annual event with fashions representative of many parts of the continent. There will be food and music. ',620);
insert into hudsonu.event values(7538875,'Anime Club x Tea Club: Tea Study Break',cast('2021-10-29 17:00' as date),cast('2021-10-29 18:00' as date),'ALANA Cultural Center Multipurpose Room','Cultural',NULL,'HAS','Before Halloween weekend kicks in, why not come, have a study break, and hang out with us in ALANA Cultural Center? We invited everyone to join us for a tea break, with snacks, and watch some videos!',null);
insert into hudsonu.event values(7598677,'Masala Chai Night',cast('2021-11-14 18:00' as date),cast('2021-11-14 19:00' as date),'ALANA MPR Room','Cultural',NULL,'TTC','Our Officer Sam Fleming will demonstrate the Art of making Masala Chai. All are welcomed to join!',null);
insert into hudsonu.event values(761684,'Alf Jacques (Onondaga): Lacrosse: The Creator''s Game',cast('2015-11-05 12:00' as date),cast('2015-11-05 13:00' as date),'Alana Cultural Center','Cultural',NULL,'NAIS','The Native American Student Association (NASA) is proposing an event to bring attention to Native American culture during November, which is Native American Heritage Month.  NASA wishes to bring Onondaga lacrosse stick maker, hall of fame player, and educator Alfred Jacques to campus to discuss the cultural significance of lacrosse for the Haudenosaunee (Iroquois) people.  This event is in keeping with NASAs mission to educate the campus and the public about Native American culture.  Alf is a charismatic person and excellent speaker whose presentation will enhance the spirit of NASA and enrich the experience of the Native American Studies Program at Hudson.  Alf, a master craftsman of lacrosse sticks, will demonstrate his craft and his creations, while explaining the history and cultural importance of lacrosse.',620);
insert into hudsonu.event values(7623635,'Board Game and Karaoke Night',cast('2021-12-03 18:00' as date),cast('2021-12-03 20:00' as date),'ALANA Cultural Center','Cultural',NULL,'HIC','Come to the study break event co-hosted by Hudson International Community (CIC) and Go+! Fetch some snacksanddrinks, play cards, and sing with your friends at this event to shake off your stress! Everyone is welcome!',null);
