insert into hudsonu.event values(7637305,'Dancefest After-Gathering',cast('2021-12-04 22:30' as date),cast('2021-12-05 01:30' as date),'CAH/ADH','Cultural',NULL,'LASO','Come join BSU, LASO and LAD in collaboration to celebrate the After-party for Dancefest! ',350);
insert into hudsonu.event values(7933330,'Black History Month End of Month Celebration at La Casa',cast('2022-02-26 22:30' as date),cast('2022-02-27 01:00' as date),'La Casa','Cultural',NULL,'LASO','Come join La Casa, LASO and BSU to close out Black History Month with a big celebration and a night full of DanceHall, Reggaeton, and AfroBeat dancing! '||chr(10)||' ',320);
insert into hudsonu.event values(8088562,'Loteria Night',cast('2022-09-17 20:00' as date),cast('2022-09-17 21:00' as date),'ALANA Cultural Center','Cultural',NULL,'LASO',NULL||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'Loteria is a game of chance similar to the American game Bingo, but using a deck of cards with images that relate to Mexican culture. '||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'',300);
insert into hudsonu.event values(8088565,'Posole Mixteco',cast('2022-09-30 18:00' as date),cast('2022-09-30 18:00' as date),'94 Broad St','Cultural',NULL,'LASO','Our event will help LASO accomplish our mission statement by centering indigenity and indigenous identities in conversations through traditional native food.',null);
insert into hudsonu.event values(8088566,'Tostoneo',cast('2022-10-06 17:00' as date),cast('2022-10-06 17:00' as date),'ALANA Cultural Center','Cultural',NULL,'LASO',NULL||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'For our event, we want to have a tostones eating contest. Tostones are plantain slices that have been fried twice and are popular in Latin American and Caribbean cuisines. They are a food that is popular among Latinx communities and would be a great way to represent Latinx identities on campus while commemorating Hispanic Heritage month through a commonly enjoyed food.'||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'',400);
insert into hudsonu.event values(8088571,'Fogata y Historias de Terror',cast('2022-09-16 19:00' as date),cast('2022-09-16 20:00' as date),'La Casa','Cultural',NULL,'LASO',NULL||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'For our event, we want to have a campfire and scary storytelling night. There are enough terrible mythological monsters and horror legends to scare us for a lifetime all over Latin America. Almost every country has its own ghosts and stories about them.'||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'',150);
insert into hudsonu.event values(821024,'Women in Ethnic and civil war in Sri Lanka',cast('2015-03-12 12:30' as date),cast('2015-03-12 12:30' as date),'ALANA Cultural Center','Cultural',NULL,'SACC','The idea of South Asia usually revolves around India. In the South Asian Cultural Club, we are trying to deconstruct this view, by expanding the definition of South Asia. To do this, we wish to have a brown bag by Professor Rajasingham to discuss the ongoing ethnic and civil war in Sri Lanka, primarily how it affects women. Professor Rajasingham is a peace activist and works closely with those affected in Sri Lanka. The aim is to inform and start a conversation about the conflict in Sri Lanka, as it has not been spoken about in the West but affects the lives of many in the East.',670);
insert into hudsonu.event values(8407998,'Keynote Speaker',cast('2022-10-13 18:00' as date),cast('2022-10-13 18:00' as date),'ALANA Cultural Center','Cultural',NULL,'LASO','For this event, we hope to have a dinner and conversation event with Vanessa Pezo - a Latinx Trauma Therapist. Our goal is to help destigmatize mental health topics and bring students together to engage in these important conversations.',null);
insert into hudsonu.event values(841835,'Anime Boston 2016 Trip',cast('2016-03-25 19:00' as date),cast('2016-03-27 18:00' as date),'Hynes Convention Center','Cultural',NULL,'HAS','Anime Boston 2016 is the Northeast largest anime convention held annually in Massachusetts. The event aims to promote an educational appreciation for Japanese animation, comics, and pop-culture.'||chr(10)||'Hudson Anime Society is organizing this trip to give attendees opportunities to explore their areas of interests through a wide variety of industry panels, hands-on workshops, informative interviews, all the while enjoying themselves with drawing, cosplaying and writing. The trip is open to all Hudson students (up to 12 people).',240);
insert into hudsonu.event values(841840,'LASO features Keynote Speaker Junot Diaz',cast('2016-01-26 19:00' as date),cast('2016-01-26 21:00' as date),'Love Auditorium, Olin','Cultural',NULL,'LASO','The Latin American Student Organization (LASO) and other sponsors have invited Professor Junot Diaz to talk about his novels, social justice advocacy, and international human right violations in the Dominican Republic on Tuesday January 26, after MLK week and before Black History Month , at 7pm at the Chapel.  '||chr(10)||'Junot Diaz was born in the Dominican Republic and raised in New Jersey. He is the author of the critically acclaimed Drown; The Brief Wondrous Life of Oscar Wao, which won the 2008 Pulitzer Prize and the National Book Critics Circle Award; and This Is How You Lose Her, a New York Times bestseller and National Book Award finalist. He is the recipient of a MacArthur Genius Fellowship, PEN/Malamud Award, Dayton Literary Peace Prize, Guggenheim Fellowship, and PEN/O. Henry Award.  A graduate of Rutgers College, Diaz is currently the fiction editor at Boston Review and the Rudge and Nancy Allen Professor of Writing at the Massachusetts Institute of Technology.'||chr(10)||' ',800);
insert into hudsonu.event values(8513721,'Queering Hudson',cast('2022-10-18 19:00' as date),cast('2022-10-18 19:00' as date),'Rainbow Room','Cultural',NULL,'QTPC','Come play a game and have a conversation surrounding the theme of celebrating queerness, embracing our intersectionalities, and coming out with guest speakers Professor Justin Helepololei and Professor Taryn Jordan! Donuts will be provided!',null);
insert into hudsonu.event values(8543690,'Haloween Party',cast('2022-10-28 22:00' as date),cast('2022-10-29 00:00' as date),'La Casa','Cultural',NULL,'KCA','Come join LASO, QTPOC, SORT, KCA, and Brothers to enjoy a spooktacular party at La Casa! All are welcome. ',250);
insert into hudsonu.event values(858993,'Wii Tournament',cast('2016-01-30 19:00' as date),cast('2016-01-30 23:00' as date),'Chapel Basement','Cultural',NULL,'HMSA','The Muslim Student Association will be hosting a Wii Tournament at the Chapel basement. The event is open to everyone. Food and refreshments will be served.',null);
insert into hudsonu.event values(866637,'Classics Coffee Hour',cast('2016-03-25 13:30' as date),cast('2016-03-25 14:00' as date),'Lawrence 114','Social',NULL,'HCS','Come hang out with the Hudson Classics Society and meet others interested in the ancient civilizations of ancient Greece and Rome!  Chat over coffee, tea, and sweets with other student and department faculty.  A great way to meet new people and make connections!',null);
insert into hudsonu.event values(883312,'OASIS Family Dinners',cast('2016-02-20 17:00' as date),cast('2016-02-20 19:00' as date),'Center for International Programs Kitchen','Cultural',NULL,'OASIS','OASIS Family Dinners aim to build a safe space and community within Asian students on campus. We invite all Asian-identifying students to join our Family Dinners. The Family Dinner allows students to share an Asian meal together, connect with other Asian students on campus, and engage in conversations about Asian identities in a relaxed atmosphere.',340);
