insert into hudsonu.event values(903179,'Challenges of Reading Quranic Arabic',cast('2016-02-26 16:00' as date),cast('2016-02-26 17:00' as date),'Chapel Basement','Cultural',NULL,'HMSA','As part of the Hudson''s Muslim Student Association Brown Bag Series, Professor Musa will be giving a talk on the challenges of reading Quranic Arabic at the Chapel Basement. Halal food from Taj Mahal will be served.',null);
insert into hudsonu.event values(9034125,'Lewis Orator Prize',cast('2023-04-05 16:30' as date),cast('2023-04-05 17:30' as date),'Lathrop 207','Cultural',NULL,'DS','Each contestant will deliver an original speech that is centered on a one-word prompt published by the competitions organizers prior to the competition.  The prompt must be used in the speech as a vehicle to elucidate some aspect of social reality in a new and memorable way.'||chr(10)||'Speeches will be evaluated by a panel of several faculty members, and the top several speeches for each class year will receive monetary prizes. '||chr(10)||'For further details or to sign up, please contact debatesociety@hudson.edu',360);
insert into hudsonu.event values(9075118,'Stevenson Prize for Expository Speaking',cast('2023-04-28 16:30' as date),cast('2023-04-28 17:30' as date),'Lawrence Auditorium 020','Cultural',NULL,'DS','The Stevenson Prize for Expository Speaking is open to all currently enrolled'||chr(10)||'Hudson students. Each contestant will present a research paper:'||chr(10)||''||chr(10)||'That is not co-authored'||chr(10)||'That is not the result of collaborative research'||chr(10)||'That is based on independent research conducted by the contestant at Hudson University in connection with coursework'||chr(10)||''||chr(10)||'The presentation will be expository. The speech should be audience centered, anticipating as much as possible the interests and abilities of the assembled audience. The audience should not be addressed as expert bearers of technical knowledge in the particular discipline wherein the research is grounded (e.g. Biology, History, Philosophy, etc.).'||chr(10)||'Presentations will be evaluated by a panel of several faculty members, and the top several presentations for each class year will receive monetary prizes. For further details or to sign up, please contact debatesociety@hudson.edu',410);
insert into hudsonu.event values(9394927,'Mid-Autumn Festival 2023',cast('2023-09-30 18:00' as date),cast('2023-09-30 19:00' as date),'ALANA Cultural Center','Cultural',NULL,'HVS','LETS CELEBRATE THE MID-AUTUMN FESTIVAL WITH US on Saturday, September 30 from 6-8 PM  A collaboration between HVS, CIA, and OASIS+. Join us for a night of food, moon cakes, lanterns, calligraphy, special performance arts, and more. Everyone is welcome!  ',300);
insert into hudsonu.event values(9467318,'German Music and Game Night',cast('2023-10-02 18:00' as date),cast('2023-10-02 18:30' as date),'Max Kade German Center','Cultural',NULL,'GC','Hudson students from any background are invited to come together and have fun around the German language and culture. Attendees to our game night will be able to participate in some super fun German board games like German Taboo, Mensch Argere Dich Nicht, Wizard, and Quartett, while listening to a playlist of German music. Snacks and refreshments are included, and no knowledge of the German language is necessary!',295);
insert into hudsonu.event values(9523444,'The CAS Gundam Building Event',cast('2023-10-21 16:00' as date),cast('2023-10-21 18:00' as date),'The Japan Room','Cultural',NULL,'HAS','Gundam, short for "Mobile Suit Gundam," created by Yoshiyuki Tomino is a multimedia franchise that originated in Japan and has become an iconic part of global pop culture. The original "Mobile Suit Gundam'''' consisted of a story set in a distant future, depicting a war and political drama between Earth and its colonies using giant humanoid robots called "mobile suits.". The series was a huge success from the start and in the 1990s marked a turning point as the franchise gained international recognition. Gundam models (Gunpla), which are DIY model kits based on the many Gundams featured in the shows and films, became highly popular collectibles, quickly becoming highly popular collectables even for those outside of the Gundam fan base and a main staple of Japanese Otaku culture. Throughout its history, Gundam has not only been a popular entertainment franchise but also a significant cultural phenomenon that has influenced other media, fashion, and even real-world robotics research. Its themes of war, technology, ethics, and identity have resonated with audiences worldwide, making it a lasting and iconic part of Japanese and global pop culture. We want to share this important staple in Japanese pop culture by allowing students and staff around campus, whether they are a Gundam expert or a fresh beginner, to explore and nurture their interests. Participants will be able to build their own Gundam sets during the workshop and their final products can either be reused or used as decoration in future events. The hands-on experience of creating an original set, alongside the chance to go see that work in future events will spark deeper interest in Japanese culture amongst students. We are expecting new fans of Gundam and Japanese culture and media to emerge from this event.',400);
insert into hudsonu.event values(9587386,'Bracelet-Making Extravaganza',cast('2023-11-04 16:30' as date),cast('2023-11-04 17:00' as date),'ALANA''s Multipurpose Room','Cultural',NULL,'HIC',NULL||chr(10)||'Join us in making bracelets with beads sourced from various nations in Africa and Asia! This event is open to all Hudson community members, regardless of their background. Let''s celebrate cross-cultural friendship by making bracelets together! '||chr(10)||' '||chr(10)||''||chr(10)||''||chr(10)||' '||chr(10)||'*We will also have traditional friendship bracelet beads, charms, and bangles!*'||chr(10)||' '||chr(10)||'Here''s a video of Ghanaian artisans making glass beads from recycled glass: '||chr(10)||'https://www.youtube.com/watch?v=jddwxwn6bFM'||chr(10)||' '||chr(10)||' '||chr(10)||' '||chr(10)||' '||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||' '||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'',110);
