insert into hudsonu.event values(181439,'Why Does God Matter to YOU?',cast('2012-10-16 19:00' as date),cast('2012-10-16 20:00' as date),'Memorial Chapel - Garden Level',NULL,'Religious/Spiritual','HCF','An Interfaith "Big Day" event where Christian students share why they beleive in God and how that faith has changed their lives.CCF is sponsoring a panel of students presenting on how they came to put their faith in Christ or one aspect of their life that has changed because of their faith. There will be time for questions afterwards. Dinner from Oliveri''s will be provided. ',450);
