insert into hudsonu.event values(1119428,'It''s The Great Pumpkin',cast('2016-10-29 15:30' as date),cast('2016-10-29 16:00' as date),'Curtis Clock','Fundraising',NULL,'BROS','This family weekend Brothers and the Ciccone Commons invite you to join us for some spooky festivities on Saturday, October 29 at 3:30pm. We encourage everyone to bring their families and to compete in a pumpkin craving contest. During the event, there will be frightening baked goods sold to fundraise for two families affected by flooding in Baton Rogue, LA. Come if you dare.',275);
insert into hudsonu.event values(1136048,'New York City Urban Project RECWeek',cast('2017-03-14 12:00' as date),cast('2017-03-19 12:00' as date),'New York City','Community Service',NULL,'HCF','This is an alternative Spring Break trip to New York City from March 14-19 with the goal of confronting sex trafficking, homelessness and racial injustice. Hudson students and students from other colleges and universities will participate in multiple programming events designed to tackle various relational and systemic injustices.',400);
