insert into hudsonu.event values(513435,'Haunted House and Halloween Party',cast('2014-10-31 18:00' as date),cast('2014-11-01 19:00' as date),'La Casa, 6pm-8pm PAC House, 110 Broad, 10-1am','Fundraising',NULL,'LASO',NULL||chr(10)||''||chr(10)||''||chr(10)||'LASO (Latin American Student Organization), BDS (Blue Diamond Society), KCA (Korean Cultural Association) are sponsporing its annual Haunted House and Halloween Party. The Haunted House will be in LA CASA from 6pm-8pm.Take a guided Scare Tour through the 3 stories of La Casa. Open to the public. Come at your own risk! Halloween Party will be in PAC HOUSE (110 Broad) from 10pm to 1am. It is: A Halloween themed party and philanthropic event to raise money for BDS charity of the year Innovation Africa. Suggested donations of $5 are happily accepted.TICKETS AVAILABLE AT COOP and FRANK THIS WEEK ONLY FROM 11:15AM-2:15PM! ONE TICKET for ADMISSION INTO BOTH EVENTSSuggested Donation of $5! Come, celebrate festivities, and bring friends! '||chr(10)||''||chr(10)||' '||chr(10)||' '||chr(10)||' '||chr(10)||''||chr(10)||''||chr(10)||' ',340);
insert into hudsonu.event values(528981,'Konosioni Senior Honor Society Induction Ceremony for the Class of 2016',cast('2015-02-13 15:00' as date),cast('2015-02-13 16:30' as date),'Hudson Memorial Chapel','Community Service',NULL,'THS','The Konosioni Senior Honor Society Class of 2015 is proud to present the Konosioni Senior Honor Society Class of 2016.  We invite the Hudson and Hamilton community to join us as we celebrate the achievement of these 26 leaders on campus.  There will be a short torchlight parade on the academic quad with the current and new members, followed by a ceremony and reception in the Chapel.  This event will be livestreamed and available to watch through the Hudson webpage.'||chr(10)||'Watch on Livestream',375);
insert into hudsonu.event values(528982,'Konosioni Senior Honor Society Brown Bag - Madison County Gives',cast('2015-04-07 12:00' as date),cast('2015-04-07 12:00' as date),'ALANA Multipurpose Room','Community Service',NULL,'THS','The Konosioni Senior Honor Society is hosting a brown bag discussion which will have short presentations by the eight not-for-profit organizations featured on the Madison County Gives website.  Each of these organizations received funding from the donations raised in Konosionis auction last year and have put the money towards meaningful projects.  This brown bag is designed to highlight the need for philanthropic giving in Madison County and to engage student and community interest in the 19th Annual Konosioni Charity Auction the following week.',140);
insert into hudsonu.event values(636773,'Global Health Initiative Parents Weekend Silent Auction and Raffle',cast('2015-10-30 20:00' as date),cast('2015-10-30 21:00' as date),'Donovan''s Pub, Hudson University','Fundraising',NULL,'HGHC','We will be fundraising for Bwindi Community Hospital Friday evening of parents weekend with a silent auction and raffle.  Prizes will be made up of donations from local businesses such as La Iguana, the Hudson Inn, and Hamilton Eatery.  Small deserts and non-alcoholic drinks will be provided, and other food and drinks will be available for purchase from Donovan''s Pub.',200);
insert into hudsonu.event values(6539653,'Hudson Caretakers Card Making',cast('2020-10-19 16:00' as date),cast('2020-10-19 16:00' as date),'Alumni 207','Community Service','Volunteer and Community Service ','HC','Hudson Caretakers is a service group that normally visits the Crouse Community Center and volunteers there. Since we cannot volunteer in person this semester, we will be making cards for the residents at the day center located closer to Hudson. Come join us!',200);
