insert into hudsonu.event values(6969659,'Digitize and Reeducate: Surveillance, Detention and Unfree Labor in Northwest China',cast('2021-03-16 16:00' as date),cast('2021-03-16 16:00' as date),'Online','Thoughtful Learning','Religious/Spiritual','HMSA','This short talk considers the economic factors that have produced protest and violence in Northwest China (Xinjiang). Because Uyghurs have been framed by state authorities as threatening, yet detainable, subject population, their existence offers technology companies space and funding that is unavailable in other parts of China to develop new data-intensive surveillance technologies. These new technologies can then be used to assist in the legal theft of their labor when they are assigned to work in unfree conditions. Building on analysis of labor exploitation in Eastern China and forms of development in other spaces in China, the talk describes the way state power is channeled through infrastructure and institutions to intensify ethno-racialization and produce a mass detention and a "reeducation labor regime" at a frontier of global capitalism. These systems impose a deprivation of liberty" or unfreedom that is systematic and targets individuals based on their ethnicity and faith thereby producing a contemporary and ongoing crime against humanity.',400);
insert into hudsonu.event values(698910,'Spy',cast('2015-09-04 19:00' as date),cast('2015-09-04 20:00' as date),'Love Auditorium','Social',NULL,'SAA','Take Two presents a free screening of the 2015 hit comedy, Spy! '||chr(10)||'Susan Cooper is an unassuming, deskbound CIA analyst, and the unsung hero behind the Agency''s most dangerous missions. But when her partner falls off the grid and another top agent is compromised, she volunteers to go deep undercover to infiltrate the world of a deadly arms dealer, and prevent a global crisis.',null);
insert into hudsonu.event values(7006843,'5K in A Day!',cast('2021-03-21 19:30' as date),cast('2021-03-22 18:30' as date),'Online','Fundraising',NULL,'DDD','This is a National Event hosted by Tri Delta''s throughout the country. It is a little boost to our fundraising efforts in which 100% of all proceeds raised go to benefit our philanthropic organization, St.Jude. It is a 24 hour event in which we reach out to our sisters, the community, friends, family, and alumni for donations totaling at least $5,000. It is an easy and low commitment way to get involved with local Greek Life and donate to a fantastic cause. ',425);
insert into hudsonu.event values(7043822,'Tri Hop!',cast('2021-04-10 12:00' as date),cast('2021-04-10 15:00' as date),'HUDSON UNIVERSITY','Fundraising',NULL,'BDS','On Saturday April 10th from 12-4pm Tri Delta will be hosting its annual Tri Hop pancake fundraiser in order to support our philanthropy, St. Jude Children''s Hospital. Due to the ongoing status of the pandemic this event has been switched to a more COVID friendly method. In order to still allow the fundraiser to occur, a delivery method will be employed in which sisters from Tri Delta will deliver pancakes to those who order them within hour time slots. All proceeds from this event go directly to St. Jude Children''s Hospital. All food will be individually packaged and made with silverware and tableware being individually packaged as well. All food will be to-go orders and there will be no consumption of food as a group or in group settings. Tickets for the pancakes are only $5 and must be purchased by 11:59 on April 5th. The ticket is bought in the form of a $5 donation directly to St. Jude Children''s Hospital through our link ( https://fundraising.stjude.org/site/Donation2?idb=467189759anddf_id=4880andFR_ID=130126andmfc_pref=TandPROXY_ID=130126andPROXY_TYPE=21and4880.donation=form1 ) Once you have bought a ticket it will be delivered to you within your selected time slot!',150);
insert into hudsonu.event values(7070241,'Poster Making, Take Back the Night March, Survivor Speakout',cast('2021-04-14 17:30' as date),cast('2021-04-14 20:00' as date),'Little 207','Community Service',NULL,'TN','Come join the Take Back the Night march at 6 pm on Wednesday, April 14th starting at the top of Willow Path by the library. Poster making will take place from 5:30 - 6:00 pm in Little 207 with materials provided. Following the march will be the Survivor Speakout from 7 pm to 9 pm in Little 207. This is a closed space and healing session for survivors and those they choose to bring in support. A counselor will be present. ',570);
