insert into hudsonu.event values(908725,'SGA Engagement Series: Social Hosting Policy Forum',cast('2016-03-02 11:45' as date),cast('2016-03-02 13:15' as date),'COOP TV Room','Community Service',NULL,'SGA','Come discuss Hudson''s social hosting policy with partying''s best friend, pizza. Director of Sorority and Fraternity affairs Kathryn Wojcik and Director of Residential Programs Kerra Hunter will be there to answer questions and explain how to host parties at Hudson for both greek and non-greek organizations. The event will be held on Wednesday, March 2nd from 11:45 A.M. to 1:20 P.M. in the COOP TV Room',50);
