insert into hudsonu.event values(175282,'Diwali',cast('2012-11-09 16:00' as date),cast('2012-11-09 22:00' as date),'Hall of Presidents',NULL,'Religious/Spiritual','HINDU','The Hindu Student Association (HSA) is requesting funding for the celebration of one of the most important Hindu festivals: Diwali, The "Festival of Lights". We plan to hold Diwali at The Hall of Presidents on Nov 9, 2012. The celebration of Diwali at Hudson will involve an Indian buffet, a presentation on Diwali, and a fireworks show meant to highlight the spirit and symbolism of Diwali. This is an annual event and is enthusiastically attended by a diverse Hudson population.',500);
insert into hudsonu.event values(245753,'Shine a Light on Slavery',cast('2013-04-08 15:00' as date),cast('2013-04-12 15:00' as date),'Coop, Lawrence, Chapel garden level',NULL,'Religious/Spiritual','HCF','A week of events (Brown Bag, film screening, coop tables) to raise awareness about modern day slavery and human trafficking in conjunction with the "End It" movement and to raise funds for non-profit organizations such as IJM, Love 146, and Not for Sale, which work to end trafficking and exploitation and help survivors.',450);
