insert into hudsonu.event values(384884,'Interfaith Lecture: Father George V. Coyne, SJ, on How Science Meets Religious Faith',cast('2014-03-06 19:00' as date),cast('2014-03-06 20:00' as date),'Love Auditorium',NULL,'Religious/Spiritual','NC','Our 2014 Baccalaureate speaker, astronomer and former director of the Vatican Observatory, Father George V. Coyne, SJ, will be giving a lecture on the space where science and religion meet. Fr. Coyne is a Jesuit priest and the McDevitt Chair of Religious Philosophy at Le Moyne College in Syracuse. Before the lecture, dinner will be served with Fr. Coyne at the Chapel Garden Level at 5:30. ',475);
