insert into hudsonu.event values(4889558,'Open Morning Meditations @ Chapel House',cast('2019-09-10 08:30' as date),cast('2019-09-10 08:00' as date),'Chapel House','Spirituality','Religious/Spiritual','CH','September 9th -- December 13th, except for October 14th-October 15th, and November 25th - November 29thProfessor Maureen Hays-Mitchell and Chapel House Assistant Director of Programming Rodney Agnant will be offering open meditation sessions every weekday morning from 8:30am-9:00am at Chapel House. This session is open to anyone of any religious or non-religious affiliation, as well as any level of expertise, are welcome to join! No experience required.This session provides you with 0.5 hours towards the Wellness Passport. Log in is required',160);
