insert into hudsonu.event values(1213356,'BSU present Fat Femme Yogi Jessamyn Stanley',cast('2017-02-28 11:30' as date),cast('2017-02-28 19:00' as date),'Center for Women''s Studies','Athletics',NULL,'BSU','As per Hudson University tradition, the Black Student Union is presenting a series of events in celebration of Black History Month. We would like to bring Jessamyn Stanley for a discussion and yoga session. Jessamyn Stanley is a yoga teacher, body positive advocate, and writer based in Durham, North Carolina. Jessamyn uses high energy vinyasa flow as a way to move past mental and emotional barriers. Her classes provide a body positive approach to yoga which celebrates students bodies and encourages them to ask How do I feel? rather than How do I look? when practicing yoga. This event has two parts. In the morning, Jessamyn will be the guest speaker at a Womens Studies brown bag and later that evening, she will teach a yoga class.',200);
insert into hudsonu.event values(235938,'CCF Big Day: Jesus and the Drama of Desire',cast('2013-03-26 19:00' as date),cast('2013-03-26 19:15' as date),'Persson Auditorium',NULL,'Religious/Spiritual','HCF','Dr. David Mahan (lecturer at Yale University) will speak for Hudson Christian Fellowship''s Big Day as part of the Interfaith "All Beliefs Community" initiative. In his talk, "Jesus and the Drama of Desire," he contends that desire and desiring lie at the heart of Jesus'' message, as they lie at the heart of our humanity.',425);
