insert into hudsonu.event values(458837,'HHM Keynote David Carrasco - Latino Springtime: Deep Heritage, Disruptions, and Choices of Hope',cast('2014-09-25 19:00' as date),cast('2014-09-25 20:00' as date),'Love Auditorium',NULL,'Religious/Spiritual','LASO','Dr. Carrasco is a renowned professor of Pre-Colombian history at Harvard University. He will be presenting the 2014 Hispanic Heritage Month Keynote Address, which focuses on the changing culture of the US-Mexico borderland, and how humans serve as cultural bridges. This event will discuss the historical and and comtemporary issues affecting the Latin American community and humans'' role in a world of global affairs.',575);
