insert into hudsonu.event values(9585894,'Pratt Falls Hike',cast('2023-11-05 13:00' as date),cast('2023-11-05 16:00' as date),'Pratt Falls','Athletics',NULL,'HIKE','As part of the Hiking Club''s PE credit program we are headed to Pratt Falls this weekend for a hike ! Unfortunately, this event is not open to all as we have limitations with transport - but there are often last minute changes and we often can get a few people on board! Look out for the hiking club groupme to get on the waitlist and/or watch out for openings to join us on this hike.',190);
