insert into hudsonu.event values(403608,'GateTown Connection',cast('2014-04-13 13:00' as date),cast('2014-04-13 15:00' as date),'Whitnall Field (rain location: Sanford)',NULL,'Concert/Music','BDS','Come down to Whitnall field and join Hudson students, faculty, and Hamilton residents on for BDS''s 3rd annual GateTown Connection, a tradition that celebrates the strong connection between the Hudson and Hamilton communities.'||chr(10)||'At 1:30 p.m. on Sunday, April 13th join us for:  FREE HAMILTON EATERY and ICE CREAM  INFLATABLES  LIVE MUSIC  KICKBALL and RELAY RACES with Hudsons athletes  PIE EATING CONTEST',240);
