insert into hudsonu.event values(508056,'CAB Club Series II',cast('2014-11-07 22:30' as date),cast('2014-11-08 01:00' as date),'Parker Commons','Arts','Concert/Music','SAA','Continued from last year, the CAB Club Series is a series of concerts held at the Palace Theater and other locations. They provide a great opportunity for students of all ages to attend a free concert in a local venue. '||chr(10)||'Hudson''s Protoculture DJ Group will be DJing this event!'||chr(10)||' ',575);
insert into hudsonu.event values(526883,'Hudson Ballet Nutcracker',cast('2014-11-20 19:00' as date),cast('2014-11-20 21:00' as date),'Brehmer Theater, Dana Arts Center','Arts','Concert/Music','BALLET','Please join the Hudson Ballet Company for their annual production of The Nutcracker.  This holiday favorite is student-directed, student-choreographed, and student-performed, with guest appearances by children from the Hamilton community. ',500);
insert into hudsonu.event values(7022973,'Lego Building Contest',cast('2021-04-01 16:00' as date),cast('2021-04-01 16:30' as date),'Batza Room','Fundraising','Volunteer and Community Service ','HFH','On Thursday, April 1st, Habitat for Humanity is having a Lego building competition! Sign up in teams of 2 to build a creation of your choosing for the chance to win a gift card to the Hamilton Eatery. Please show a proof of donation, minimum $3, to Syracuse Habitat at this link: https://www.habitat.org/donate/?affiliate=0072-1963andlink=6'||chr(10)||' '||chr(10)||'The contest will be held in the Batza Room from 4:00-5:30. Teams can sign up for a thirty-minute slot at 4:00, 4:30, or 5:00.',300);
insert into hudsonu.event values(7056470,'Random Act of Kindness',cast('2021-04-08 11:00' as date),cast('2021-04-08 11:00' as date),'Outside Lathrop Hall','Community Service','Volunteer and Community Service ','RAK','DoRAK will be doing a random act of kindness!!!',null);
insert into hudsonu.event values(781367,'Charred Goosebeak Family Weekend Show',cast('2015-10-30 19:00' as date),cast('2015-10-30 19:00' as date),'Donovan''s Pub','Spirituality',NULL,'CG','Charred Goosbeak, Hudson''s only performing improv group, is at it again with a celebration you won''t soon forget.  What''s the occassion?  Why the 280th birthday of John Adams of course!  Bring your friends, your families, your friends'' families and see Charred Goosebeak perform their unqiue brand of improv comedy which may or may not be at all relevent to everyone''s favorite lawyer-president.',null);
insert into hudsonu.event values(8552383,'Fall Fest Concert',cast('2022-10-29 21:30' as date),cast('2022-10-29 22:00' as date),'Cotterell Court','Arts','Concert/Music','BROS','SAA is excited to host the first ever Fall Fest Concert, featuring Sean Kingston and the Hudson Thirteen on Saturday, October 29th! The Hudson Thirteen will perform at 9:30pm, and Sean Kingston''s performance will begin at 10:00pm. We hope to see everyone in Cotterell Court for this amazing night!'||chr(10)||'This concert was done in collaboration with SGA, and co-sponsored by the Afrikan Diaspora House, Blue Diamond Society, Brothers, Black Student Union, Creative Arts Society, Delta Delta Delta, Delta Upsilon, Lambda, Latin American Student Organization, and Phi Delta Theta. ',450);
insert into hudsonu.event values(196130,'Poetry Open Mic Featuring Advocate',cast('2012-11-16 18:00' as date),cast('2012-11-16 21:00' as date),'Coop TV room',NULL,'Theater','DPS','We will be having guest poet from NYC Advocate host a student open mic, followed by a performance of his own work.  In addition to a public performance, he will be teaching a private workshop with Hudson students.',700);
insert into hudsonu.event values(244414,'Hudson Resolutions Akfest',cast('2013-04-06 20:00' as date),cast('2013-04-06 20:30' as date),'Hudson Memorial Chapel',NULL,'Concert/Music','HR','Join Hudson''s premier co-ed a cappella group, The Resolutions, for their 21st annual Spring concert, Akfest. Tickets are $5 and can be purchased at the Coop or at the door. Doors will open at 7:30 pm for an 8:00 pm show.',null);
insert into hudsonu.event values(270375,'Word On the Street',cast('2013-08-29 15:00' as date),cast('2013-08-29 15:30' as date),'Academic and Freshman Quad',NULL,'Theater','DPS','Help us welcome new first year students by writing couplets and short poems on the sidewalk of the Academic and Freshman Quad. Ice cream will be provided to all who choose to attend! ',210);
insert into hudsonu.event values(300911,'CABARET: Fall 2013',cast('2013-11-02 19:00' as date),cast('2013-11-02 19:30' as date),'The Palace Theatre',NULL,'Concert/Music','MAT','The Hudson Cabaret is an inherent part of musical theater at Hudson. The Cabaret has been a consistent production every semester for years now and is the main, and sometimes only musical theater event every semester. The cast of Cabaret is made up of a diverse crowd of people from different activities and grades all around campus. The cast is brought together through a love of singing, acting, and love of musical theater. The show is compiled of different musical theater songs that fall under a given theme. This semester we want everyone to have a say in what we sing and are opening up suggestions to the cast members and to the public.  Our show will include songs from musicals, glee, and general popular pop songs as well. The cast members are dedicated to making theatre at Hudson in a fun, relaxing environment. ',260);
insert into hudsonu.event values(325085,'The North Korean Refugee Problem and the NGOs- What is True and What is being done? Brown Bag',cast('2013-11-14 11:30' as date),cast('2013-11-14 13:00' as date),'ALANA Multipurpose Room',NULL,'Volunteer and Community Service ','KCA','Join us for a brown bag discussion on the North Korean refugee issues and prospect, ans well as the role of NGOs and the government. Following the film screening of Danny from North Korea, further discussion of the topic will be led by a panel of students who have interned at North Korean refugee-related organizations as well as Prof. Palmer, who has been actively involved in North Korean refugee education issues in Korea.'||chr(10)||' ',500);
insert into hudsonu.event values(371763,'Mantiphondrakes Valentine''s Day Concert',cast('2014-02-14 19:00' as date),cast('2014-02-14 20:00' as date),'Donovan''s Pub',NULL,'Concert/Music','MANTI','What better way is there to enjoy the day of roses, hearts and sweets with a night of song?Whether you want a romantic evening performance with your special someone, or you''re looking for someone to hold in your heart, or you just want to enjoy some good music, come down to DONOVAN''S PUB on ST. VALENTINE''S DAY at 7:00 PM.Let the Mantiphondrakes sing the night away for you ',380);
insert into hudsonu.event values(468706,'Native American Arts and Culture Festival',cast('2014-10-18 09:30' as date),cast('2014-10-18 16:00' as date),'Sanford Field House, Hudson University',NULL,'Concert/Music','NAIS','The Native American Arts and Culture Festival is a free event open to the public and the Native American Student Association''s biggest event all year. The festival will feature a craft market, live music and dancing, traditional food, children''s activities, and demonstrations. ',260);
insert into hudsonu.event values(475015,'Karaoke Night at Donovan''s Pub',cast('2014-09-19 19:00' as date),cast('2014-09-19 19:30' as date),'Donovan''s Pub','Arts','Concert/Music','SAA','Grab your friends for a fun night of karaoke at Donovan''s Pub! The kitchen will be open for food and drinks, the game room is stocked with air hockey, foosball, pool, and darts if your vocal cords need a break, and it is sure to be a good time!',null);
insert into hudsonu.event values(517177,'Battle of the Bands',cast('2014-11-14 19:00' as date),cast('2014-11-14 22:00' as date),'Donovan''s Pub','Arts','Concert/Music','SAA','Come watch student and faculty bands compete in CAB Music''s Battle of the Bands! The winning band will receive a CASH prize! Sponsored by CAB and the CAC',null);
insert into hudsonu.event values(8088639,'Goodbye La Casa Party',cast('2022-04-29 00:00' as date),cast('2022-04-30 01:00' as date),'La Casa','Cultural','Dance','LASO','Come say good bye to La Casa!',null);
insert into hudsonu.event values(9059070,'ASU Fashion Show After Party: Africa After Dark',cast('2023-04-15 22:00' as date),cast('2023-04-15 23:00' as date),'La Casa','Social','Concert/Music','LASO','African Student Union presents the ASU Fashion Show After Party with collaboration from Black Student Union, Latin American Student Association, and the Caribbean Students Association. Join us as we finish off the night with a fun celebration. We will be hosting DJ Mike Cook who will be playing music that will make you want to dance, sing, or simply appreciate the atmosphere. With the theme of a Night in Africa, be ready for good vibes and even better moves! Join us in this celebration of culture at La Casa on Saturday, April 15th at 10 pm.  ',450);
insert into hudsonu.event values(9750013,'Ballroom Waltz Auditions',cast('2024-02-11 19:00' as date),cast('2024-02-11 20:00' as date),'Ballroom Waltz Auditions','Arts','Concert/Music','HBD','Ballroom is doing a small group waltz this semester for DanceFest! This is an audition-based dance, but no experience or partner is necessary. We will teach you everything you need to know during the audition!',null);
insert into hudsonu.event values(1062693,'Hudson Vietnamese Society Family Dinner',cast('2016-11-11 18:00' as date),cast('2016-11-11 20:30' as date),'ALANA Center','Cultural',NULL,'HVS','Come join the Hudson Vietnamese Society for some delicious and authentic Vietnamese pho! '||chr(10)||'Having a meal together is an essential part of life in the Vietnamese culture. We hope our classic HVS tradition, Family Dinners, can help foster new bonds, strengthen personal connections, and provide an opportunity for others to learn and expand their understanding on the country, culture, and people of Vietnam through food and intimate conversations. ',null);
insert into hudsonu.event values(1265409,'Super Smash Bros Tournament',cast('2017-03-23 20:00' as date),cast('2017-03-23 22:30' as date),'Hamilton Theater','Athletics',NULL,'SAA','Compete in a Super Smash Bros tournament hosted by CAB Take Two and the Smash Bros Club at the Hamilton Theater and enjoy some food from Royal India Grill.',455);
insert into hudsonu.event values(165842,'Auditions: The Marriage of Bette and Boo',cast('2012-09-12 18:00' as date),cast('2012-09-13 19:00' as date),'Little 207',NULL,'Theater','MAT','Do you like wedding cake? Can you vacuum gravy? Ever play the kazoo? AUDITION FOR OUR SHOW! THE MARRIAGE OF BETTE AND BOO is a dark, hilarious comedy by Christopher Durang. It features a big cast, and we cannot wait to have you on board! AUDITIONS WILL BE HELD IN LITTLE 207 Wednesday, September 12 6-8pm Thursday, September 13 6-8pm Please prepare a short monologue. Interested in crew/tech work? Email dvonnegut! More information will be available at the Student Activities Fair on Sept. 5, or feel free to ask questions here! Directed by Coco Vonnegut Asst. Directed by Mary Rose Devine',420);
insert into hudsonu.event values(170933,'One Night Stand: Back to School',cast('2012-09-21 20:00' as date),cast('2012-09-21 20:00' as date),'Hall of Presidents',NULL,'Theater','MAT','Join us for the first One Night Stand of the school year! What''s a One Night Stand? It''s an afternoon of relaxed theater - actors and directors meet for the first time together at 5:30 to rehearse a short scene, and then at 8:00pm we put on a show with scripts in hand - no memorization necessary! If you''d like to act or direct (no theaterical experience needed!), email hgoldman or llaiks by 6pm Wednesday 9/19. Then you''ll come to the HOP on Friday 9/21 at 5:30pm. Don''t forget theater needs an audience too! Come watch the One Night Stand, with opening act Mantiphondrakes at: 8pm in the HOP!',255);
insert into hudsonu.event values(181433,'Hudson Ballet Company Holiday Showcase',cast('2012-11-26 17:00' as date),cast('2012-11-30 22:00' as date),'Palace Theater',NULL,'Dance','BALLET','This semester the Hudson Ballet Company will be holding a Holiday Showcase.  This event involves participation from Hudson students in addition to children from the Hamilton community.  Throughout the semester, classes are held for both Hudson students and Hamilton children that focus on teaching timeless choreography from The Nutcracker.'||chr(10)||'The Showcase will be advertised and open to both Hudson and Hamilton, and will hopefully take place at the Palace Theater.  ',null);
insert into hudsonu.event values(209025,'Vagina Monologues',cast('2013-02-14 19:00' as date),cast('2013-02-16 20:30' as date),'Palace Theater',NULL,'Theater','SRT','A performance of Eve Ensler''s play Vagina Monologues as part of the annual VDAY campaign to end violence against women and girls.'||chr(10)||'All members of the cast are members of the Hudson community including students, faculty, and staff.'||chr(10)||'Tickets will be $5 and all proceeds will benefit national (VDAY campaign) and local (Vera House and Victims of Violence) campaigns aimed at ending violence and assault.',330);
insert into hudsonu.event values(229604,'CABARET ROCKS! Spring 2013 Cabaret',cast('2013-02-28 19:00' as date),cast('2013-03-01 19:00' as date),'The Palace Theatre',NULL,'Concert/Music','MAT','The Hudson Cabaret is an inherent part of musical theater at Hudson. The Cabaret has been a consistent production every semester for years now and is the main, and sometimes only musical theater event every semester. The cast of Cabaret is made up of a diverse crowd of people from different activities and grades all around campus. The cast is brought together through a love of singing, acting, and love of musical theater. The show is compiled of different musical theater songs that fall under a given theme. This years theme is Cabaret Rocks. Our concept includes songs from rock musicals, glee, and general popular pop songs as well. ',300);
insert into hudsonu.event values(256176,'DANCEFEST',cast('2013-04-26 18:30' as date),cast('2013-04-26 20:00' as date),'Hudson Memorial Chapel',NULL,'Dance','GDT','Come to Dancefest on Friday, April 26 to watch the Hudson dance groups perform!  Doors open at 6:00 and show begins at 6:30 in the Chapel.  You won''t want to miss it!'||chr(10)||'Free admission.  Donations are greatly appreciated and will be collected at the Coop and Frank the week leading up to Dancefest.  All proceeds benefit Hamilton Center for the Arts.'||chr(10)||' ',null);
insert into hudsonu.event values(320643,'Dirt! the Movie',cast('2013-11-11 19:00' as date),cast('2013-11-11 21:00' as date),'Ho 101',NULL,'Sustainability','SEA',NULL,180);
insert into hudsonu.event values(338824,'Summer Brave: MandT Performance',cast('2013-12-07 13:00' as date),cast('2013-12-07 15:00' as date),'Brehmer Theater',NULL,'Theater','MAT','Summer Brave a play written by Pulitzer Prize winning playwright William Inge. It is one of two Masque and Triangle Fall Productions. The play will be performed in Brehmer Theater, at these times:'||chr(10)||'6:30pm, December 5th8pm, December 6th1pm, December 7th '||chr(10)||' ',200);
insert into hudsonu.event values(345506,'CAB Presents: Comedy Magician Joel Meyers',cast('2014-02-14 20:00' as date),cast('2014-02-14 21:00' as date),'Donovan''s Pub',NULL,'Theater','SAA','Joel Meyers is a young interactive comedy illusionist who has already taken the world by storm, performing a progressive brand of magic for audiences worldwide. Newsweek magazine says Joel quite simply "will capture your imagination.Joels varied and impressive resume includes star performances off Broadway, countless shows for corporations, charities, and universities, and a tour in China. He was named 2013 Best Rising Star and was nominated for two Campus Magazine awards for 2013.'||chr(10)||'Come see Joel''s fascinating performance this Friday night (Valentine''s Day!) in Donovan''s Pub, right after the Mantiphondrakes concert!',430);
insert into hudsonu.event values(398881,'A capella and Draughts for CURE',cast('2014-03-27 20:00' as date),cast('2014-03-27 22:00' as date),'Good Nature Brewing',NULL,'Concert/Music','HGHC','This will be a charity concert at Good Nature Brewing to benefit CURE International!! The Hudson 13 will be performing and the Global Health Initiative will be raising funds all night. CURE International is an organization that works to provide surgeries for children in multiple developing countries throughout the world.',275);
insert into hudsonu.event values(4871134,'Equestrian Team @ Hartwick',cast('2019-10-26 04:30' as date),cast('2019-10-26 18:00' as date),'Hartwick College','Athletics','Club Sports','EC','Equestrian Team at Hartwick for IHSA Hunt Seat Competition',460);
insert into hudsonu.event values(4943475,'Pre-Veterinary Club''s First Meeting',cast('2019-09-19 16:30' as date),cast('2019-09-19 16:00' as date),'Ho 326','Thoughtful Learning',NULL,'PVC','The Pre-Veterinary Club is hosting it''s first meeting of the year on Thursday, September 19 in Ho 326. The meeting serves as an introduction to the club and leadership. We also hold ice breakers and are keen to learn about the areas within the field of veterinary medicine that members are interested in to guide our planning for the semester. We hope you can make it!',370);
insert into hudsonu.event values(524608,'Plutus',cast('2014-11-19 19:30' as date),cast('2014-11-19 22:00' as date),'Ryan 209','Arts','Theater','MAT','Come down to Ryan 209 to see Aristophanes'' classic comedy come to life in the 21st Century. Watch the struggles of a citizen of Athens as she copes with the burdens of a poor life and stumbles upon Plutus, the God of Wealth. Performances are on:Tuesday, Nov. 18 and Wednesday, Nov. 19 at 7:30.With universal themes of the human struggle, the political controversy of economic inequality, literary irony, slapstick comedy and crude flatulent humor, PLUTUS is as thought-provoking and enjoyable as it was thousands of years ago. With the blessings of Zeus the Deliverer, we gladly invite you to this performance.'||chr(10)||'Directed by Karl Uywith Technical Manager, Jason Alexander,and Assistant Manager, Isabella Crowley.',440);
insert into hudsonu.event values(537098,'Barinholtz and Belushi Improv Comedy Show with Charred Goosebeak',cast('2015-01-31 12:00' as date),cast('2015-01-31 22:00' as date),'Brehmer Theater','Arts','Theater','CG','Rob Belushi and Jon Barinholtz are a highly successful improv comedy duo. They have performed at Hudson every year for at least the past three years. Rob and Jon will do a full day of workshopping and performing. During the afternoon, they will run an improv workshop with the members of Charred Goosebeak. Members almost unanimously name the annual workshop as the most valuable coaching they receive, and one of the most fun things they get to do all year. In the evening, Charred Goosebeak and Rob and Jon will perform at the Brehmer Theater. We have received very good crowds in the past. Rob and Jon also plan to bring a third performer, at no additional cost, as they have in past years. That performer will run an improv workshop for any Hudson students interested in improv comedy. Rob Belushi and Jon Barinholtz are successful professional comedians. Rob had a recurring character on the sitcom "How I Met Your Mother", and has recently acted on "The Mentalist" and in a series of Gatorade commercials with Peyton Manning. In the last year, Jon has had roles on the TV shows "New Girl" and "The McCarthys". The two also have a web series on Comedy Central called "Pie Guys". The chance to receive coaching from, perform with, and enjoy watching two such successful performers is truly unique.',1400);
insert into hudsonu.event values(5504802,'Women''s Club Water Polo Tournament @ Columbia',cast('2020-02-08 13:00' as date),cast('2020-02-09 18:30' as date),'Columbia University','Athletics','Club Sports','WPCW','Women''s Club Water Polo will compete in the NY State Division of the Collegiate Water Polo Association in this two-day tournament.',235);
insert into hudsonu.event values(582764,'But All My Friends Are: Black, Asian, Latino, Gay, Multiracial',cast('2015-02-20 19:00' as date),cast('2015-02-20 21:00' as date),'Brehmer Theater','Arts',NULL,'BROS','Brothers wants to bring the hereandnow theater company to present their famous show But All of my friends areBlack, Asian, Latino/a, Gay, Multi-Racial on Friday March 6, 2015 to perform at Brehmer Auditorium at 7pm.'||chr(10)||' But All of my friends areBlack, Asian, Latino/a, Gay, Multi-Racial is a collection of 10 plays performed in 90 minutes.  Each short play deals with an aspect of being a person of color in the US and is presented through comedy, poetry, and dance, as well as often true to life performances.  The show offers one of the most innovative means of examining diversity and tolerance from this critically acclaimed theatre of color.',550);
insert into hudsonu.event values(595351,'Figure Skating Spring Exhibition',cast('2015-03-01 17:30' as date),cast('2015-03-01 19:30' as date),'Starr Rink','Athletics',NULL,'FCS','Performances by Soloists, Speed Skaters and Synchronized Skating Team.  Followed by open skate until 7:30pm',590);
insert into hudsonu.event values(6494968,'Sunset Photography Workshop',cast('2020-10-01 17:30' as date),cast('2020-10-01 18:00' as date),'Willow Path','Arts',NULL,'PC','The Photography Club will be having our first hands-on workshop on Sunset Photography. We will provide all the professional cameras and gear needed to capture the beautiful outdoors by Taylor Lake. Members will have a brief introduction on how to handle and use the cameras, so we welcome all experience levels. We will meet near Willow Path which is right by Taylor Lake. In compliance with Hudson''s event safety guidelines, masks will always have to be worn and we will only be accepting the first eight people to rsvp/show up. Make sure you secure a spot asap and join our GroupMe for updates.',230);
insert into hudsonu.event values(7027811,'Caribbean Week LASO Family Dinner',cast('2021-04-03 18:00' as date),cast('2021-04-03 18:00' as date),'Online','Cultural',NULL,'LASO','LASO will be hosting a conversation about Caribbean Latinx culture and the erasure of Caribbean identities within Latinidad. We are hoping to be catering individually packaged Dominican food from Mi Casa that we will distribute to participants. ',null);
insert into hudsonu.event values(709532,'Take Two Movies: Pitch Perfect',cast('2015-09-11 19:00' as date),cast('2015-09-11 20:00' as date),'Love Auditorium','Social',NULL,'SAA','Come see a free screening of the 2012 hit, Pitch Perfect! '||chr(10)||'Synopsis: The Barden Bellas are a collegiate, all-girls a cappella singing group thriving on female pop songs and their perfect looks. After a disastrous failing at last year''s finals, they are forced to regroup. Among the new recruits is freshman Beca, an independent, aspiring DJ with no interest in the college life. But after she meets Jesse, from the rival all-male a cappella group, Beca has a new outlook and takes it upon herself to help the Bellas find their new look and sound and get back into the competition.',null);
insert into hudsonu.event values(722326,'Barinholtz and Belushi Improv Comedy Show',cast('2015-10-03 20:00' as date),cast('2015-10-03 20:30' as date),'Donovan''s Pub','Arts',NULL,'CG','Charred Goosebeak presents two of the best improvisational comedians around today: Rob Belushi and Jon Barinholtz. In the afternoon they will be doing an improvisation workshop with the members of Charred Goosebeak and perform with them in the evening. This has been an annual event for the past four years at least and one much cherished by the members of Charred Goosebeak and thoroughly enjoyed by the community. Rob Belushi and Jon Barinholtz are successful professional comedians. Rob had a recurring character on the sitcom "How I Met Your Mother", and has recently acted on "The Mentalist" and in a series of Gatorade commercials with Peyton Manning. In the last year, Jon has had roles on the TV shows "New Girl" and "The McCarthys". The two also have a web series on Comedy Central called "Pie Guys". The chance to receive coaching from, perform with, and see perform two such successful performers is a great opportunity for anyone.',450);
insert into hudsonu.event values(747659,'Hudson Portfolio Literary Magazine Submissions Due',cast('2015-12-01 08:00' as date),cast('2015-12-01 23:45' as date),'Hudson University','Arts',NULL,'PORT','The Hudson Portfolio, Hudsons official literary magazine, is looking for any art, non-fiction, poetry, or fiction pieces to display in our 28th annual publication. This is a great way to showcase the literary and artistic talent of Hudson. Submit to hudsonportfolio@hudson.edu by December 1, 2015!',220);
