insert into hudsonu.event values(7525907,'Social Justice Peer Education Brown Bag: Understanding Imposter Syndrome',cast('2021-10-21 12:00' as date),cast('2021-10-21 12:15' as date),'ALANA Cultural Center''s MPR Room','Thoughtful Learning',NULL,'ALANA','Join a conversation about ways and strategies to cope with and address imposter syndrome on Thursday from noon-1:15 pm. The dialogue will be facilitated by the ALANA Social Justice Peer Educators and Shaw Ambassador, and Royal Indian Grill will cater the lunch. This event is PE Credit hour eligible.'||chr(10)||'https://calendar.hudson.edu/event/thrive_lunch_imposter_syndrome#.YW2nbmZKhbV',400);
insert into hudsonu.event values(7531975,'Chili Cook-Off',cast('2021-10-22 15:00' as date),cast('2021-10-22 16:00' as date),'Gamma Phi Beta','Fundraising','Philanthropy','GPB','This event is such a fun way for everyone in the community and even our parents to get involved in Gamma Phi philanthropy. Anyone can form a team and cook chili to see who wins best chili! The fundraising will come from a tasting free for the chili. It will be next week on Family Weekend at 72 Broad, in the backyard of Gamma Phi Beta from 3:00-5:00pm. This year 100% of proceeds will go to Madison County Children''s camp in Eaton, NY.'||chr(10)||' '||chr(10)||' ',240);
