insert into hudsonu.event values(821023,'Club Series Events, Spring Semester 2015',cast('2015-02-13 22:30' as date),cast('2015-02-14 01:00' as date),'Palace Theater','Arts','Concert/Music','SAA',NULL||chr(10)||'Continued from last year, the Club Series is a series of concerts held at the Palace Theater. They provide a great opportunity for students of all ages to attend a free concert in a local venue. '||chr(10)||''||chr(10)||' ',470);
insert into hudsonu.event values(821029,'Interfaith Dinners',cast('2015-03-12 18:00' as date),cast('2015-03-12 18:00' as date),'Chapel Basement','Thoughtful Learning',NULL,'NC','The Interfaith Dinners are an opportunity for students to come together, talk about their different beliefs and share a meal. Each dinner has a theme and there are discussions or presentations that are related to that theme for students to participate in during the dinner. These dinners have been extremely successful in the past.',null);
insert into hudsonu.event values(821045,'Dr. Strangelove or: How I Learned to Stop Worrying and Love the Atomic Bomb',cast('2015-09-05 17:00' as date),cast('2015-09-05 18:00' as date),'Golden Auditorium','Arts',NULL,'HFS','Come join the Hudson Film Society in Little Hall for our first screening of the semester! Stanley Kubrick''s 1964 comedy, set during the Cold War, seeks to permeate the tension by asking, "what if the wrong person pushed the wrong button?" Running time is 1 hr and 43 minutes.'||chr(10)||'Trailer',500);
