insert into hudsonu.event values(8383315,'Homecoming Concert',cast('2022-09-24 21:00' as date),cast('2022-09-24 21:00' as date),'Hall of Presidents','Arts','Concert/Music','SAA','Hello everyone! SAA, Delta Delta Delta, Gamma Phi Beta, and Kappa Kappa Gamma are excited to announce that Echosmith will be performing on September 24th, 2022 for our Homecoming Concert! The concert will be at 9:00pm at the Hall of Presidents, with doors opening at 8:30pm. We hope to see you there!'||chr(10)||' ',500);
insert into hudsonu.event values(8562282,'Open Party',cast('2022-11-05 22:00' as date),cast('2022-11-05 23:00' as date),'The Creative Arts Society (CAS)','Arts','Concert/Music','BSU','The Creative Arts Society, Afrikan Diaspora House, Black Student Union, and Student Activities Sound have decided to throw an open party at 80 Broad.',370);
insert into hudsonu.event values(8618656,'DanceFest AfterParty',cast('2022-12-03 22:00' as date),cast('2022-12-04 01:00' as date),'LaCasa','Social','Dance','BROS','Continue the party after DanceFest at LaCasa celebrating the performances and members of the multicultural dance groups on campus!',null);
insert into hudsonu.event values(881912,'Darwin''s Living Legacy',cast('2016-02-12 14:30' as date),cast('2016-02-12 15:30' as date),'HO 101','Thoughtful Learning',NULL,'SASS','Celebrate Charles Darwin''s Birthday with SASS (the Secular Association of Skeptical Students)! '||chr(10)||'Professor Soja will be giving brief talk on "Darwin''s Living Legacy", then we will eat CAKE!'||chr(10)||'Did we mention, there will be cake?',360);
insert into hudsonu.event values(8920343,'Pie a Phi',cast('2023-03-03 15:00' as date),cast('2023-03-03 17:00' as date),'Phi Delta Theta - Inside House','Fundraising','Philanthropy','PDT','Fundraising event for the Live Like Lou Foundation, which works towards raising money for ALS research, assists families with a member diagnosed with ALS, and funding towards medical expenses. Pie a Phi allows Hudson students to hear a live band and select a brother to pie at a cost that would go towards the Live Like Lou foundation. There will also be optional hotdogs and other grilled foods to purchase, along with an optional t-shirt!',155);
insert into hudsonu.event values(8946573,'TriHOP  Tri Delta Fundraiser for St.Jude Children''s Research Hospital',cast('2023-04-15 14:00' as date),cast('2023-04-15 17:00' as date),'Tri Delta House','Fundraising','Philanthropy','DDD','An amazing fundraising event for St.Jude Children''s Research Hospital which provides support for families and ensures they never have to pay for pediatric cancer treatment. The $5 tickets for TriHOP can be purchased in advance or at the event to try our all-you-can-eat pancake buffet hosted on our front lawn with all of our proceeds going to St.Jude!',280);
insert into hudsonu.event values(9824408,'Baking Against Bigotry',cast('2024-03-01 16:00' as date),cast('2024-03-01 18:00' as date),'Pink Haus','Social',NULL,'LAMBDA','Come decorate cupcakes and discuss marriage in LGBTQ+ and Disabled communities with us! All are welcome <3'||chr(10)||' '||chr(10)||'Please fill out this form if you interested in decorating pride cupcakes at Pink Haus in collaboration with Hudson Disability Activists, Hudson LAMBDA, and the Baking Club on March 1st!',null);
insert into hudsonu.event values(1032793,'Undocupoets series: Sonia Guinanseca',cast('2016-10-14 20:00' as date),cast('2016-10-14 22:00' as date),'Bunche House','Arts',NULL,'LASO','The Latin American Student Organization (LASO), in conjunction with Lounge, has invited Sonia Guinansaca to come and perform during the 2016 Fall semester for Hispanic Heritage Month celebration.'||chr(10)||' Sonia is a Queer Migrant Feminist Poet , Cultural Organizer, and Activist from Harlem by way of Ecuador. Born in Ecuador, at the age of 5 migrated to the United States to reunite with her parents in NY. Since 2007, Guinansaca has been public about her status as an undocumented immigrant. She is the co-founder of some of the largest undocumented organizations in the country, coordinating and participating in groundbreaking civic actions in the immigrant rights movement. She has also founded some of the first creative artistic projects by and for undocumented writers/artists. She has emerged as a national leader in the undocumented migrant artistic and political communities.  She seeks to look into deconstructing borders, and blowing up migration discourse so that tiny radical seeds can grow from that gravel.',350);
insert into hudsonu.event values(1048019,'Blair Witch Project',cast('2016-10-15 17:00' as date),cast('2016-10-15 18:00' as date),'Golden Auditorium','Arts',NULL,'HFS','Come to Hudson Film Society''s spooky screening of this 1999 cult classic! Pizza and good times included',240);
insert into hudsonu.event values(173303,'Hudson University Sponsors Student Bus Transportation to the Tiesto/Dada Life Concert at the Syracuse Oncenter',cast('2012-10-02 19:30' as date),cast('2012-10-03 13:30' as date),'Oncenter, Syracuse, NY',NULL,'Concert/Music','SAA','Hudson will provide bus transport for up to 55 students to the Tiesto/Dada Life concert at the Syracuse Oncenter on Tuesday, October 2.'||chr(10)||' ',425);
insert into hudsonu.event values(285662,'Men''s Rugby Home Opener',cast('2013-09-07 13:00' as date),cast('2013-09-07 15:00' as date),'Academy Field (Below Oak DR)',NULL,'Club Sports','RFCM','Come support Hudson Rugby as the Men start the season against Rival Hamilton College.  Kickoff is at 1PM',420);
insert into hudsonu.event values(300906,'MandT Fall Production, Bad Things Happen',cast('2013-12-05 17:00' as date),cast('2013-12-07 18:00' as date),'Brehmer Theatre',NULL,'Theater','MAT','One of two fall productions. Bad Things Happen is about six college freshmen coming to college and dealing with the baggage of their past when meeting new people.',300);
insert into hudsonu.event values(325725,'MandT: One Night Stand',cast('2013-10-26 20:00' as date),cast('2013-10-26 20:00' as date),'Brehmer Theater, Dana Arts Center',NULL,'Theater','MAT','This ONS is scheduled for Saturday, October 26th, starting at 5pm.  The performance will go on at 8pm.  This event is over Family Weekend and is a great opportunity to introduce your family to the Masque and Triangle community, or just to have a great time!  We will be performing front of curtain in Brehmer Theater, so there will be plenty of seats and all are welcome.'||chr(10)||' '||chr(10)||'This time around, participants can sign up to act or direct.  You will then be divided into scenes, and will have approximately three hours to learn as much as possible.  Don''t worry if that seems stressful or downright impossible it''s all in good fun, andperfection is boring anyway!'||chr(10)||' '||chr(10)||'If you are looking for an easy way to stay connected or get involved in student theater here on campus, this event is for you!  '||chr(10)||' '||chr(10)||'To sign up, email Caitlyn Hartigan at chartigan@hudson.edu with your name and whether you want to act or direct.  You can also include a note on the preferred size of the scene you would like to be placed in, and we will try to take that into account.  Feel free to email as well with any questions.',380);
insert into hudsonu.event values(328221,'Hudson Winter Olympics',cast('2013-11-16 14:00' as date),cast('2013-11-16 16:00' as date),'Sanford Field House',NULL,'Club Sports','SAA','We''re bringing back one of Hudson''s favorite traditions for the first time in years! Sign up with this form in groups of 8-10 to compete in a good old-fashioned field day, complete with dodgeball, tug-of-war, capture the flag and many more. T-shirts will be provided for participating teams and pizza will be served after the games are done. Sign-ups due by November 12th.'||chr(10)||'Sponsered by the Hudson Activities Board and the Athletics Department',325);
insert into hudsonu.event values(329703,'Hudson''s Got Talent',cast('2013-11-08 18:30' as date),cast('2013-11-08 20:30' as date),'The Palace Theater',NULL,'Concert/Music','SAA','Come see Hudson''s most talented performers at the second annual Hudson''s Got Talent! Catering from Rusch''s will be provided. Doors open at 6:30 for dinner, show begins at 7:00. ',400);
insert into hudsonu.event values(338826,'Summer Brave: MandT Performance',cast('2013-12-06 20:00' as date),cast('2013-12-06 22:00' as date),'Brehmer Theater',NULL,'Theater','MAT','Summer Brave a play written by Pulitzer Prize winning playwright William Inge. It is one of two Masque and Triangle Fall Productions. The play will be performed in Brehmer Theater, at these times:'||chr(10)||'6:30pm, December 5th8pm, December 6th1pm, December 7th '||chr(10)||' ',200);
insert into hudsonu.event values(366327,'Taming of The Shrew Auditions',cast('2014-01-28 18:00' as date),cast('2014-01-29 20:30' as date),'Little 207',NULL,'Theater','MAT','This semester MandT is putting on a production of the Shakespearean comedy Taming of the Shrew directed by Allison Spanyer! '||chr(10)||'Auditions will be held Tuesday January 28 and Wednesday January 29 from 6-8:30 PM in Little 207. '||chr(10)||'Please prepare 10-15 lines of Shakespearean text, not from Taming of the Shrew. '||chr(10)||'If you cannot find a monologue, some wil be provided. '||chr(10)||'Please contact aspanyer@hudson.edu with any questions or concerns. '||chr(10)||' '||chr(10)||'Don''t miss out on this amazing opportunity to be involved in a Shakespearean production at Hudson!!',280);
insert into hudsonu.event values(383933,'Brothers 15th Anniversary Charity Week',cast('2014-04-07 12:00' as date),cast('2014-04-12 16:00' as date),'Various locations',NULL,'Volunteer and Community Service ','BROS','Brothers Charity Week is an event composed of several activities throughout the week in order to raise money for the surrounding Hamilton community and other worthwhile global charitable organizations.Starting on Monday, we hold a bake sale in the Coop, giving away homemade goods for a suggested donation and there will be a poker tournament held that evening in collaboration with Games Afoot.On Tuesday, we will run a BBQ on the academic quad during lunchtime.On Wednesday, we are cooperating with BDS and Games Afoot for our 5th annual Super Smash Bros. Tournament, for which there will be a suggested donation for entry.On Thursday, we will hold a bachelors auction, usually our highest grossing event of the week.And concluding on Saturday, we will hold a 3 on 3 basketball tournament in Huntington Gym.Throughout the week, we will be accepting donations at every event and at our Coop table in order to maximize our fund generation.',300);
insert into hudsonu.event values(468684,'Hudson Ballet Nutcracker',cast('2014-11-19 19:00' as date),cast('2014-11-19 21:00' as date),'Brehmer Theater, Dana Arts Center','Arts','Dance','BALLET','Please join the Hudson Ballet Company for their annual production of The Nutcracker.  This holiday favorite is student-directed, student-choreographed, and student-performed, with guest appearances by children from the Hamilton community.  '||chr(10)||' ',450);
insert into hudsonu.event values(484770,'Hudson''s Got Talent',cast('2014-11-13 18:00' as date),cast('2014-11-13 21:00' as date),'PALACE THEATER','Arts',NULL,'SAA','Hudson students will display their array of talents in a competition-style show hosted by CAB Special Events.  Three celebrity judges will be selected to offer critiques and applause for each act, and there will be three audience-voted winners at the end of the show!  Food will be provided by Rusch''s and will be available before and during the show in the space just outside the theater.',590);
insert into hudsonu.event values(525925,'Mardi Gras Dinner and Dance',cast('2015-02-17 18:00' as date),cast('2015-02-17 20:00' as date),'Hall of Presidents and Clark Room','Spirituality','Concert/Music','UC','University Church, along with the other Religious Life communities, will once again be hosting the Mardi Gras Dinner and Dance! This event aims to bring together the Hudson and Hamilton communities and bring awareness to the history of Fat Tuesday, Mardi Gras and the season of Lent in the Christian faith.'||chr(10)||'This event will take place on Fat Tuesday (February 17th) at 6:00 pm in the Hall of Presidents.  Food will be catered by Michael''s and a live jazz band will be playing music through dinner and while we dance!'||chr(10)||'Student tickets can be reserved in the Chapel Basement or at the COOP for a suggested donation of $5.  Hamilton community members can reserve their tickets for a suggested donation of $15 by calling 315-228-7682 or e-mailing chaplainsoffice@hudson.edu',410);
