insert into hudsonu.event values(9025284,'A Cappella Fest',cast('2023-04-21 19:00' as date),cast('2023-04-21 19:30' as date),'Palace Theater','Arts','Concert/Music','MANTI','Join Christian Vischi, assistant director of entrepreneurship and innovation, and the Blue Parsley Boys at their second annual a cappella concert. The concert features all five of Hudson''s a cappella student organizations: Hudson Dischords, Hudson 13, Hudson Resolutions, Hudson Mantiphondrakes, and the Swinging Gates. ',450);
insert into hudsonu.event values(937904,'Mantiphondrakes Spring Concert',cast('2016-04-07 21:00' as date),cast('2016-04-07 21:15' as date),'Memorial Chapel','Arts',NULL,'MANTI','The Mantiphondrakes present their annual Spring Concert on Thursday, April 7th at 9:15 PM in the Chapel! They will perform a variety of vocal arrangements, featuring covers of The Neighborhood, Michael Jackson, Rob Cantor, and Sia. New members Danielle Paynter ''18 and Kayla Sturgeon ''17 will make their solo debuts. "It''ll be #lit." - Karl''s words. Hope to see you there! Doors open at 9:00.    ',550);
