insert into hudsonu.event values(509210,'Exploring Identity Concert and Storytelling by Greane and Magdalen',cast('2014-11-01 21:00' as date),cast('2014-11-01 21:30' as date),'Donovan''s Pub','Arts','Concert/Music','SAA','November 1st 2014, Donovan''s Pub, 9pm.'||chr(10)||'True Colours  Finding Identity, Concert and Storytelling, seek to bring diverse communities together, raise awareness on campuses, and inform about multicultural topics while providing entertainment for college audiences. Greane has performed for numerous Campus Activities Board music or Coffeehouse events, Womens Studies, Womens Center, Multicultural Affairs, art gallery openings and Orientation and Welcome Weeks. ',670);
