insert into hudsonu.event values(7624532,'Dancefest - Fall 2021',cast('2021-12-04 18:30' as date),cast('2021-12-04 20:30' as date),'The Chapel','Arts','Dance','HDT','It''s your favorite high-energy Hudson tradition! Now in our 24th year, we invite you to get ready for celebrating a "higher love" through dance. '||chr(10)||'Doors open at 6pm, show starts at 6:30pm.'||chr(10)||'Warning: Some songs in the show may contain explicit language that may be perceived as inappropriate or offensive. Dancefests mission is to create a space for dancers to express themselves freely and exercise creative freedom in their choice of music. If you have any other further questions, please contact saa@hudson.edu',550);
