insert into hudsonu.event values(8552384,'Fall Fest Concert',cast('2022-10-29 21:30' as date),cast('2022-10-29 22:00' as date),'Cotterell Court','Arts','Concert/Music','BROS','SAA is excited to host the first ever Fall Fest Concert, featuring Sean Kingston and the Hudson Thirteen on Saturday, October 29th! The Hudson Thirteen will perform at 9:30pm, and Sean Kingston''s performance will begin at 10:00pm. We hope to see everyone in Cotterell Court for this amazing night!'||chr(10)||'This concert was done in collaboration with SGA, and co-sponsored by the Afrikan Diaspora House, Blue Diamond Society, Brothers, Black Student Union, Creative Arts Society, Delta Delta Delta, Delta Upsilon, Lambda, Latin American Student Organization, and Phi Delta Theta. ',450);
insert into hudsonu.event values(8552387,'The Nutcracker',cast('2022-11-13 14:00' as date),cast('2022-11-13 15:30' as date),'Palace Theater','Arts','Dance','BALLET','This November, the Hudson Ballet Company will be performing the Nutcracker. The story centers around a young girl named Clara who befriends her Uncle Drosselmeyer''s nephew at a Christmas Eve party. Later that night the Nutcracker she receives as a present from her Drosselmeyer comes to life, battling the evil Mouse, and saving her. The victorious Nutcracker transforms into the nephew, who then walks with her through the Land of Snow and introduces her to the Land of Sweets, where the Sugar Plum Fairy and her court celebrate by performing a series of dances for them.'||chr(10)||'Admission is free but tickets are required. ',325);
