insert into hudsonu.event values(9261013,'Hudson Dance Team: Zoom Info Session',cast('2023-08-25 16:30' as date),cast('2023-08-25 16:30' as date),'Online','Athletics','Club Sports','HDT','Hey y''all! The Hudson Dance Team is hosting an info session to answer all your questions regarding what we do, time commitment, community dynamics, school spirit, and more! Captains Caroline Collins ''25 and Courtney Peryer ''25, as well as more team members, will be in attendance to converse! If you have any questions, feel free to contact us! And go follow our Instagram @hudsondanceteam for updates and more information about try-outs and our performance schedule!',320);
