insert into hudsonu.event values(2937284,'Kappa Kickball',cast('2018-11-30 18:00' as date),cast('2018-11-30 19:30' as date),'Huntington Gymnasium','Fundraising','Volunteer and Community Service ','KKG','Come join Kappa Kappa Gamma in supporting Reading is Fundamental, the nation''s largest children''s literacy nonprofit. Reading is Fundamental aims to create a literate America through creating and installing quality content and programs designed to give every child the fundamentals for success. All proceeds raised will go towards Reading is Fundamental and the Kappa Kappa Gamma Foundation. Please join us on November 30th at the Sanford Field House from 6:00 -7:30 PM with a team of 6-8 people. Each player will be asked to make a $5 donation. We hope to see you there!',70);
