insert into hudsonu.event values(883301,'Chinatown',cast('2016-03-26 17:00' as date),cast('2016-03-26 18:15' as date),'Golden Auditorium, Little Hall','Arts',NULL,'HFS','Starring Jack Nicholson and Fay Dunaway, Chinatown follows a private detective in 1937 Los Angeles as he attempts to understand the circumstances surrounding a murder of an engineer. The American Film Institute identified Chinatown as the second best mystery film in 2008, and the film was selected for preservation by the United States National Film Registry for being "culturally, historically or aesthetically significant." Runninng time is approximately 2 hrs and 10 mins. A link to the trailer is provided below. '||chr(10)||'https://www.youtube.com/watch?v=T37QkBc4IGY',650);
