insert into hudsonu.event values(287423,'HWS Fall Classic',cast('2013-10-26 10:00' as date),cast('2013-10-27 19:00' as date),'Hobart and William Smith Colleges',NULL,'Volunteer and Community Service ','DS','The HWS Fall Classic is a regional debate tournament that is held in the World Universities Debating Championship (WUDC) style which will take place at Hobart and William Smith Colleges in Geneva, New York on Saturday, October 26 and Sunday, October 27. The tournament will consist of five preliminary rounds, followed by a varsity semifinals break and a novice final round. ',535);
insert into hudsonu.event values(594020,'Art As Resistance: Faviana Rodriguez',cast('2015-03-03 16:30' as date),cast('2015-03-03 18:00' as date),'ALANA','Arts',NULL,'SRT','This event is a part of Sisters of the Round Table''s Africana Women''s Week(s). Favianna Rodriguez is an Afro-Peruvian American artist from Oakland, California. She uses her perspective as a child of migrant workers growing up  in a high crime area to forge her identity as a feminist and activist. Growing  up she did not witness positive images of women of color in the media which inspired her to work around issues of equality, race, interdependence, youth activism, and sexuality. Rodriguez will be giving a lecture followed by a QandA on her work and process. ',500);
insert into hudsonu.event values(6531476,'DoRAK Outreach Project',cast('2020-10-14 17:00' as date),cast('2020-10-14 17:00' as date),'415 Case Geyer Library','Community Service','Volunteer and Community Service ','RAK','On Wednesday, October 14th, we will be hosting one of our most loved activities of the year... making DoRAK buttons. This activity will spread kindness to both club members and Hudson''s broader community alike! This activity is a perfect way to unwind and destress during the midterm season!',350);
