insert into hudsonu.event values(722314,'Birdman: Or (The Unexpected Virtue of Ignorance)',cast('2015-09-26 17:00' as date),cast('2015-09-26 18:00' as date),'Golden Auditorium, Little Hall','Arts',NULL,'HFS','Join the Hudson Film Society for an evening of humor and excitement as we watch Birdman: Or (The Unexpected Virtue of Ignorance). The film follows Michael Keaton as an aging action film star as he attempts to make his debut on the stage. Keaton''s, Emma Stone''s, and Edward Norton''s performances all earned them Oscar nominations and Alejandro Gonzalez Inarritu was awarded Best Achievement in Directing. Running time is 1hr and 59 minutes.  ',400);
insert into hudsonu.event values(735264,'Ballet Classes',cast('2015-09-15 19:30' as date),cast('2015-09-15 20:00' as date),'Huntington 303','Arts',NULL,'BALLET','The Hudson Ballet Company provides classes taught by Paris Wilcox, a former principal dancer with the Kansas City Ballet, for students of all levels of experience. The classes help develop students'' technique, flexibility, strength, and artistic expression. Classes take place Tuesdays and Thursdays.',260);
insert into hudsonu.event values(8084444,'Open Mic Night',cast('2022-04-28 19:00' as date),cast('2022-04-28 19:00' as date),'Donovans Pub','Arts',NULL,'HSU','2-minute standup comedy performances by Club Members to entertain diners at Donovan''s Pub.',550);
insert into hudsonu.event values(9584435,'The Nutcracker',cast('2023-11-11 18:30' as date),cast('2023-11-11 20:00' as date),'Arts at the Palace','Arts','Dance','BALLET','The Nutcracker is a widely-known holiday performance and tradition for people all across the world, enjoyed by both the audiences and the performers. This ballet shares the story of a young girl who is gifted a Nutcracker that transforms into a prince and together they travel to a land of fantasy and sweets. The production is performed by Hudson students and dancers from the Hamilton community. Tickets are free and available through this link: https://www.hamiltoncreates.com/registration ',430);
