insert into hudsonu.event values(7057288,'Bengali New Year Celebrations',cast('2021-04-14 16:00' as date),cast('2021-04-14 18:00' as date),'ALANA Cultural Center','Cultural',NULL,'SACC','In celebration of the Bengali New Year, the South Asian Cultural club is planning to hold a small, in-person celebration at the ALANA Cultural Center courtyard on April 14 from 4-7 pm. It will be a casual, casual-socially distance block-printing event where participants can come and decorate bandanas or T-shirts with traditional south Asian block printing patterns as they enjoy the New Year festivities at Bangladesh on a projector screen. There will also be RIG to-go for people who sign up early for the event. People can also opt to bring their own T-shirt or piece of clothing to decorate with block-printing.'||chr(10)||'The Bengali New Year, or Pahela Baisakh is a celebration of a new year of harvest and prosperity in Bangladesh and by people of Bengali heritage in the Indian States of West Bengal, and Assam, irrespective of religious faith. It is generally celebrated on April 14 and 15 of every year and marks the beginning of the seasons in the Bengali Lunar Calendar. It is a celebration where people come together to appreciate the colors and prosperity that spring brings with it, irrespective of their religious or cultural background.',null);
insert into hudsonu.event values(7389925,'Homecoming Comedian Adam Conover',cast('2021-09-25 21:30' as date),cast('2021-09-26 21:30' as date),'Hudson Memorial Chapel','Arts',NULL,'SAA','Adam Conover, comedian and star of Adam Ruins Everything, will be performing in the Hudson Memorial Chapel! Doors open at 8:30pm and Adam will go live on stage at 9:30pm. This is an event you don''t want to miss!'||chr(10)||'HUES Card or wristband are required for entry!',null);
insert into hudsonu.event values(7527176,'Parents Weekend Brunch!',cast('2021-10-23 10:00' as date),cast('2021-10-23 12:00' as date),'Tri Delta House','Fundraising','Philanthropy','DDD','Tri Delta is back and better than ever with hosting their annual event for family weekend, the Family Weekend Brunch! Join us for a morning of delicious food crafted by our skillful chef, Eric Thomas and plentiful socialization with other members and their families. Tickets will be $5 per person at the door with donations welcome as 100% of proceeds raised will go to supporting our wonderful philanthropy St.Jude Children''s Research Hospital. This event will be held etirely outside underneath a tent in the backyard. We can''t wait to welcome you!!',null);
