insert into hudsonu.event values(756668,'CVS Cooking Night',cast('2015-10-23 19:00' as date),cast('2015-10-23 20:00' as date),'ALANA Cultural Center','Cultural',NULL,'HVS','HVS Cooking Night will be a night of bonding and good food: attendees will be taught to make two popular Vietnamese snacks: com suon and cha trung (Vietnamese grilled pork, served with Tam rice and egg meatloaf). The event will be in the ALANA Center and is open to public.',null);
