insert into hudsonu.event values(7847469,'Caffeiene',cast('2022-02-05 18:30' as date),cast('2022-02-05 21:30' as date),'Coop TV Room','Social','Concert/Music','SAA','Caffeine is an open mic and game night where students can get to know each other through hearing stories and poems from classmates. In addition, in the main room in the Coop there will be a coffee cup decorating competition where the top three cups will be awarded a prize. Games will be spread out around the Coop and snacks and drinks will be provided. Feel free to come in your PJs!',null);
