insert into hudsonu.event values(7866698,'CWiB Coffee Hour #1',cast('2022-02-07 19:00' as date),cast('2022-02-07 20:00' as date),'Case Geyer 560 Batza room','Thoughtful Learning',NULL,'HWIB','For our first Coffee Hour of the semester we will be doing a resume + LinkedIn + Handshake workshop. We suggest bringing in a copy of your resume and/or profile draft, so that we can give you feedback from the different stations. We will also be available to answer any general questions about resumes, interviews, networking, internships, anything!'||chr(10)||' ',null);
insert into hudsonu.event values(7967134,'7th-Day Study Break',cast('2022-03-20 12:00' as date),cast('2022-03-20 12:00' as date),'Michael Saperstein Jewish Center','Social','Religious/Spiritual','SASS','It''s said that the world was made in six days and the seventh was a day of rest. Join us in resting for six days over break and doing all of your homework on the seventh, or just enjoy a chill environment before classes start back up. And we''ll have food!',null);
