insert into hudsonu.event values(821022,'Fall Fest',cast('2014-10-22 19:00' as date),cast('2014-10-22 19:00' as date),'Chapel Garden Level','Social','Religious/Spiritual','UC','Join University Church as we celebrate fall with various Fall themed treats, carving of a pumpkin, socializing, and fellowship!',null);
insert into hudsonu.event values(8552386,'The Nutcracker',cast('2022-11-11 19:00' as date),cast('2022-11-11 20:30' as date),'Palace Theater','Arts','Dance','BALLET','This November, the Hudson Ballet Company will be performing the Nutcracker. The story centers around a young girl named Clara who befriends her Uncle Drosselmeyer''s nephew at a Christmas Eve party. Later that night the Nutcracker she receives as a present from her Drosselmeyer comes to life, battling the evil Mouse, and saving her. The victorious Nutcracker transforms into the nephew, who then walks with her through the Land of Snow and introduces her to the Land of Sweets, where the Sugar Plum Fairy and her court celebrate by performing a series of dances for them.'||chr(10)||'Admission is free but tickets are required. ',null);
insert into hudsonu.event values(8931162,'German Music and Game Night',cast('2023-02-27 18:00' as date),cast('2023-02-27 19:30' as date),'Max Kade German Center, 115 Lawrence Hall','Cultural',NULL,'GC','This event allows Hudson students from any background to come together and have fun around the German language and culture. Attendees to our game night will be able to participate in numerous German board games, such as German Taboo, Mensch Argere Dich Nicht, Wizard, and Quartett, while listening to a playlist of German music. Snacks and refreshments are included, and no knowledge of the German language is necessary!  ',null);
insert into hudsonu.event values(926462,'University Church Good Friday Dinner',cast('2016-03-25 17:00' as date),cast('2016-03-25 17:00' as date),'Chapel Basement','Spirituality',NULL,'UC','Join University Church for a meatless, fast-breaking dinner on Good Friday before students share their faith in personal testimonies on the chapel stage.'||chr(10)||'All are welcome!'||chr(10)||'Co-sponsored by the Hudson Newman Community. ',null);
insert into hudsonu.event values(927702,'Latke Hamentashen Debate',cast('2016-03-27 12:00' as date),cast('2016-03-27 12:00' as date),'Saperstein Jewish Center','Spirituality',NULL,'HJU','Participate in the revival of the age old debate: "Which is better, Latke or Hamentashen?"'||chr(10)||'Hudson Jewish Union Presidents Chelsea Mohr ''17 and Jack Polikoff ''17 will go head to head in debate, but everyone can cast their vote as you sample both traditional treats. '||chr(10)||'Bagels and lox will be served as well.',null);
insert into hudsonu.event values(927737,'Purim',cast('2016-03-23 19:00' as date),cast('2016-03-23 20:00' as date),'Saperstein Jewish Center','Spirituality',NULL,'HJU',' '||chr(10)||'It''s time for our annual town-gown celebration of Purim, a joyous commemeration of the story of Esther''s defeat of Haman''s plot to eliminate the Jewish people in Persia. Purim is typically observed with an interactive reading of the Book of Esther, plays with fun costumes, and a delicious feast. We will serve up a spectacular BBQ. '||chr(10)||'Costumes are encouraged but optional. '||chr(10)||' ',null);
insert into hudsonu.event values(9342593,'Pink Haus Study Night',cast('2023-09-11 19:00' as date),cast('2023-09-11 21:00' as date),'Pink Haus','Thoughtful Learning',NULL,'QTPC','Join us for an evening of productivity at the Pink Haus that''s set to take place this coming Monday, September 11th, from 7:00 PM to 10:00 PM. We invite you to immerse yourself in a calm and cozy atmosphere, perfect for focusing on your tasks and achieving your goals. There will be donuts, coffee, and hot chocolate from Dunkin'' Donuts!',null);
insert into hudsonu.event values(9390691,'IGD Student Training',cast('2023-09-30 10:00' as date),cast('2023-09-30 15:00' as date),'ALANA MPR','Thoughtful Learning',NULL,'ALANA',NULL||chr(10)||'The IGD Council and the ALANA Cultural Center present the second Student Inter-Group Dialogue Train-the-Trainer, Part I! If you are interested in learning how to facilitate difficult conversations and to build interpersonal or structural awareness in your own student groups or other community contexts, please join us!'||chr(10)||' '||chr(10)||'Intergroup Dialogue is a research-based approach to face-to-face facilitated conversation between members of two or more social identity groups that strives to create new levels of understanding, relating, and action" (Zuniga 2003). Upon completion of the two-day training, students will receive an IGD Experience Training Certificate, Part I. Part I will equip you with a foundational set of tools for dialogue and includes ten training hours; students must commit to both sessions to be accepted to the Training.'||chr(10)||' '||chr(10)||''||chr(10)||'This training is open to all Hudson students and those who are (or plan to be) student leaders on and/-or outside the campus. There are limited seats so please sign up early. Part II of the training will begin in mid-October. At the end of Part I and Part II, students will be equipped, under continued supervision and mentorship, to plan and facilitate Intergroup Dialogue events in their student groups.'||chr(10)||' '||chr(10)||'Note: Meals will be provided. But please bring your water bottle to the training. ',null);
insert into hudsonu.event values(954527,'Brown Bag sponsored by SACC',cast('2016-09-13 12:00' as date),cast('2016-09-13 12:00' as date),'Chapel Basement','Cultural',NULL,'SACC','In the past, the SACC has organized brown bags to spread awareness of the cultural diversity of the countries in South Asia. Particular topics in the past have been about the importance of International  Mother Language Day. The brown bag planned for this coming semester will be continuing on the same trend to attract more interest from the Hudson population.',null);
insert into hudsonu.event values(9566419,'Dunkins and Bricks',cast('2023-10-27 14:00' as date),cast('2023-10-27 15:00' as date),'McGregory Hall','Social',NULL,'HTT','Join us for a delightful afternoon at Hudson Technic Titans social event - grab a donut, play around with Lego bricks, and/or get to know some people who share the same passion for engineering and robotics! This event serves to be a warm-up for the upcoming workshops; by putting some bricks and blocks together creatively in a relaxed setting, we want to make people more comfortable with engineering and more prepared with the more challenging parts of engineering.',null);
insert into hudsonu.event values(9880348,'Midnight Philosophy Society Meeting',cast('2024-02-10 22:00' as date),cast('2024-02-11 01:00' as date),'Donovan''s Pub','Social',NULL,'MPS','Midnight Philosophy is a vibrant community of inquisitive and curious students who are excited to explore diverse and relevant philosophical topics! We host welcoming student-to-student conversations about morality, society, religion, metaphysics, and epistemology. Our members are diverse in their beliefs, and we are open to absolutely anyone, with no philosophical experience or major declaration necessary. ',null);
