insert into hudsonu.event values(9893788,'On Campus Hike (with Hot Cocoa!)',cast('2024-02-10 13:00' as date),cast('2024-02-10 14:00' as date),'Frank Dining Hall','Athletics','Outdoor Education','HIKE','Join Hiking Club for a stroll on the XC trails on Saturday, February 10th. We''ll meet outside of Frank at 1pm. Enjoy some hot cocoa and snacks! The hike should be approximately 2 miles long. Please RSVP by filling out this form so we know how much food/drinks to buy: https://docs.google.com/forms/d/e/1FAIpQLSdq6y-9AF0jbOuRxK2wzULWWBmLwGW5SjqOCBCFoACLYoAIMA/viewform?usp=sf_link',null);
insert into hudsonu.event values(9923506,'KCA Ya-Sik Event!',cast('2024-02-23 20:00' as date),cast('2024-02-23 22:00' as date),'The Mat','Cultural',NULL,'KCA','In Korea, contemporary social culture amongst students has become increasingly intertwined with cuisine. Ya-sik, or late-night snack is a quintessential part of the Korean student life experience. Yasik often includes foods such as tteokbokki (spicy rice cakes), ramen, and Bibimbap (mixed rice) and serves as a space where people can come together to catch up with friends, talk about the days work, or share the comfort of eating a core childhood snack (children begin to eat ya-sik from a young age, often elementary school). '||chr(10)||'In this event, we hope to introduce contemporary Korean evening cultures and routines shared by Korean students of all age groups. We will introduce tteokbokki, a spicy rice cake dish and introduce its tradition as an after-school evening snack through its presence at bun-sik-jip (snack restaurant) all around school districts. In addition, we will serve home-made Korean bibimbap and explain the historical origins of bibimbap and discuss how rice dishes vary from cuisine to cuisine depending on the local produce and diverse food traditions unique to each geographical region. ',null);
insert into hudsonu.event values(9934543,'Taughannock Falls Hike (CIC Collab)',cast('2024-02-17 12:30' as date),cast('2024-02-17 19:00' as date),'Taughannock Falls State Park','Athletics','Outdoor Education','HIC','Hiking Club will be collaborating with Hudson International Community for a hike to Taughannock Falls in Ithaca. Taughannock Falls is the TALLEST (single drop) WATERFALL EAST OF THE MISSISSIPPI RIVER!! We expect the hiking itself to be moderate, lasting around 2 hours. There are always some trails open, while others may close due to ice, thus, we cannot be sure of the exact length of the hike. While traveling to and from Ithaca, enjoy foods from many different cultures, including kulfi (Persian Ice Cream) and other international snacks. We can take this as an opportunity to learn about the diverse backgrounds of fellow students. '||chr(10)||' '||chr(10)||'To sign up for this event, please fill out this form. However, please be aware that spots are being filled very fast! https://docs.google.com/forms/d/e/1FAIpQLSdhMqcrpmorOrg8NAtUXJLFcZdWIOw_GdN8fAUCpcB6HPNdjQ/viewform',null);
insert into hudsonu.event values(9953063,'Pronoun Pin Making',cast('2024-02-16 18:00' as date),cast('2024-02-16 20:00' as date),'Women''s Studies Center','Arts',NULL,'TAG','Join us in WMST to make pronouns pins!',null);
insert into hudsonu.event values(9983641,'Baby Tate After Party',cast('2024-03-01 23:00' as date),cast('2024-03-02 01:30' as date),'The MAT','Social','Dance','QTPC','Join us for the after-party to Baby Tate''s concert! All are welcome!',null);
insert into hudsonu.event values(5225765,'Last Fall 2019 Open Mic',cast('2019-12-11 20:00' as date),cast('2019-12-11 21:00' as date),'Donovan''s Pub','Arts',NULL,'HSU','Come down to Donovan''s Pub for the last Hudson Stand Up Open Mic of the semester! Hosted by Patrick Toohey',null);
insert into hudsonu.event values(735265,'Ballet Classes',cast('2015-09-17 19:30' as date),cast('2015-09-17 20:00' as date),'Huntington 303','Arts',NULL,'BALLET','The Hudson Ballet Company provides classes taught by Paris Wilcox, a former principal dancer with the Kansas City Ballet, for students of all levels of experience. The classes help develop students'' technique, flexibility, strength, and artistic expression. Classes take place Tuesdays and Thursdays.',null);
insert into hudsonu.event values(7516527,'The Nutcracker',cast('2021-11-12 19:30' as date),cast('2021-11-12 21:00' as date),'Arts at the Palace','Arts','Dance','BALLET','This November, the Hudson Ballet Company will be performing the Nutcracker. The story centers around a young girl named Clara who befriends her Uncle Drosselmeyer''s nephew at a Christmas Eve party. Later that night the Nutcracker she receives as a present from her Drosselmeyer comes to life, battling the evil Mouse, and saving her. The victorious Nutcracker transforms into the nephew, who then walks with her through the Land of Snow and introduces her to the Land of Sweets, where the Sugar Plum Fairy and her court celebrate by performing a series of dances for them.',null);
insert into hudsonu.event values(756670,'Classics Society Movie Night',cast('2015-12-03 19:00' as date),cast('2015-12-03 21:00' as date),'Persson 27','Cultural',NULL,'HCS','Join Hudson Classics Society in watching one of our favorite films inspired by the history and culture of ancient Greece and Rome!  See how these ancient civilizations still influence our world today.  Refreshments provided!',null);
insert into hudsonu.event values(10003190,'Charred Goosebeak Imrpov Show',cast('2024-03-06 19:00' as date),cast('2024-03-06 20:30' as date),'The MAT','Arts',NULL,'CG','Charred Goosebeak will host an Improv show to bring together campus community through laughter and fun. ',null);
insert into hudsonu.event values(594031,'Art as Resistance: Faviana Rodriguez Workshop',cast('2015-03-03 19:00' as date),cast('2015-03-03 20:30' as date),'ALANA','Arts',NULL,'SRT','This event is a part of Sisters of the Round Table''s Africana Women''s Week(s). Favianna Rodriguez is an Afro-Peruvian American artist from Oakland, California. She uses her perspective as a child of migrant workers growing up  in a high crime area to forge her identity as a feminist and activist. Growing  up she did not witness positive images of women of color in the media which inspired her to work around issues of equality, race, interdependence, youth activism, and sexuality. During this workshop, Rodriguez will be sharing her artistic process with the Hudson community. All are welcome. ',null);
insert into hudsonu.event values(7396249,'Mat Series: Quinton Brock',cast('2021-09-17 21:30' as date),cast('2021-09-18 00:00' as date),'Hall of Presidents','Arts',NULL,'SAA','Rescheduled 9/17 HDBeenDope in Mat to Quinton Brock in HOP.',null);
insert into hudsonu.event values(10015030,'Zine Making',cast('2024-03-26 18:00' as date),cast('2024-03-26 19:00' as date),'Women''s Studies Center (Lounge)','Arts',NULL,'LAMBDA','Come join QTPOC, TAG, and Hudson LAMBDA for a night of fun, community, and creativity through zine making! All zine ideas are welcome <3',null);
insert into hudsonu.event values(1025789,'Native American Culture Festival',cast('2016-10-22 08:00' as date),cast('2016-10-22 19:00' as date),'Sanford Field House','Cultural',NULL,'NAIS','The Native American Arts and Culture Festival is a public event that is a precursor to Native American Heritage Month (November). The festival is NASAs biggest event of the year and has been very successful in the past. '||chr(10)||'NASA would like to invite two music and dance groups to perform at the Native American Arts and Culture Festival on Saturday, October 22nd.  One group, the Haudenosaunee Singers and Dancers, represents Indigenous peoples of North America and specifically our local region, while the other group, Ayazamana, represents the Indigenous cultures of South America.  Both groups perform traditional social dances that educate the audience through explanatory narrative and participation.',null);
insert into hudsonu.event values(1062653,'Korean Culture Association presents: Make Your Own Kimbap!',cast('2016-10-11 11:30' as date),cast('2016-10-11 12:00' as date),'COOP','Cultural',NULL,'KCA','Kimbap is one of the most popular foods in Korean culture to make with friends and family. It is a Korean dish made from steamed white rice and various other ingredients, rolled in gim (edible seaweed) and served in bite-size slices. Kimbap is often eaten during picnics or outdoor events, or as a light lunch. So come learn how to make this simple dish with KCA so you can prepare it for your next picnic or when you''re craving some Korean food!',null);
insert into hudsonu.event values(1076998,'OASIS Speaker - Helen Zia',cast('2016-12-06 11:30' as date),cast('2016-12-06 13:00' as date),'Women''s Studies Center','Thoughtful Learning',NULL,'OASIS','OASIS Brown Bag series invites Helen Zia, who is an award-winning journalist and renowned activist who has been involved in Asian American racial justice movements as well as social justice work on the intersectionality of race, gender, and sexuality. She has been instrumental in fighting for justice on the racially-charged murder of Vincent Chin. She is also involved in activist work against date rape and in supporting Asian American survivors of domestic violence. Helen Zia has written a well-known book on Asian identity and serves on White House Initiative on Asian Americans and Pacific Islanders, among many other involvements. We are hoping to bring her to campus to share about her valuable work and insights on Asian American identity, activism, representation and feminism. Helen Zia  ',null);
insert into hudsonu.event values(1128321,'St. Nikolaus Day',cast('2016-12-05 08:30' as date),cast('2016-12-05 15:00' as date),'Lawrence Hall','Cultural',NULL,'GC','To celebrate St. Nikolaus Day like German children do, we are planning an event during which we will ask students with classes in Lawrence Hall to leave their shoes outside the classroom and during class, we will fill the shoes with candy. This event will be a fun way to educate students about a common holiday tradition in Germany. Students love candy so this event has been a big hit in the past!',null);
insert into hudsonu.event values(1246693,'House Party Part III',cast('2017-02-11 22:00' as date),cast('2017-02-12 02:00' as date),'Creative Arts House','Arts',NULL,'HDJ','Social event at Creative Arts House. Food and refreshments will be served to those in attendance. ',null);
insert into hudsonu.event values(1248467,'University Church Board Game Night',cast('2017-02-23 21:00' as date),cast('2017-02-24 00:00' as date),'Interfaith House','Social',NULL,'UC','Enjoy a night of fellowship and fun with board games and dessert every Thursday, 9pm until midnight, at Interfaith House (104 Broad Street). Typical favorites include games like Avalon, Settlers of Catan, Blokus, Scrabble, and more! Feel free to bring your own games, as well. ',null);
insert into hudsonu.event values(3294448,'Crawfish Boil',cast('2019-04-19 14:00' as date),cast('2019-04-19 19:00' as date),'Theta Chi Backyard','Fundraising','Concert/Music','TC','We are hoping to host our annual Crawfish Boil a week after SPW on Friday, April 19. The proceeds for the event will go towards the Hamilton Fire Department, and we intend on fundraising by both tabling in the week prior and asking for donations at the door. The event will take place in the Theta Chi backyard. We plan on hiring a band, ordering a dunk tank, and hopefully acquiring permission to have alcohol for anyone 21+. We would also be very appreciative if BandG could drop off tables and chairs that we could set up in the backyard. '||chr(10)||'It is important that we lock down a date well in advance so that we can begin our preparations. I (Jesse) am meeting with Kayla later this afternoon to review our budget plan and receive any advice she may have for setting up the event. If you have any questions about the event, please let me know, but at the very least we would love to get the date of 4/19 set in stone. ',null);
insert into hudsonu.event values(3349600,'One Love Foundation - Fundraising Event at Beta Theta Pi',cast('2019-04-26 17:00' as date),cast('2019-04-26 18:30' as date),'88 Broad Street (Beta Theta Pi Fraternity)','Fundraising',NULL,'BTP','The brothers of Beta Theta Pi invite all students to help support Team One Love at Hudson University and raise awareness for domestic violence. We will be hosting an event in our back yard with the One Love team here on Hudson''s campus. Those who wish to come and support the cause are welcome to participate in fun activities such as volleyball, basketball, spike-ball and more. We will also be presenting some tasty barbecue options that will be open to all students along with a variety of beverages. Our chapter is happy to be partnering with such a meaningful group at Hudson and promoting a very important cause on college campuses. We look forward to this event and hope for warm weather and a great turnout!  ',null);
insert into hudsonu.event values(4878616,'Panhellenic Ice Cream Social',cast('2019-09-16 17:00' as date),cast('2019-09-16 18:00' as date),'Gamma Phi Beta Lawn','Social',NULL,'CPC','The Panhellenic Council will be hosting an Ice Cream Social for all affiliated women. Members can come to meet others and enjoy free Gilligan''s Ice Cream.',null);
