insert into hudsonu.event values(517173,'The 7th Annual Guy Fawkes Masquerade Ball',cast('2014-11-14 21:00' as date),cast('2014-11-15 00:00' as date),'Clark Room, Second Floor HOP','Arts','Dance','HBD','You are cordially invited to the 7th Annual Guy Fawkes Masquerade Ball! Friday November 14th, 9pm-midnight in the Clark Room, 2nd floor of the HOP.'||chr(10)||'Hosted by Hudson Ballroom Dancers, the Masquerade is a ballroom tradition every fall semester around the 5th of November, representing the day of an uprising led by Guy Fawkes, a masked anarchist who became a pop culture symbol after the movie V for Vendetta. The Masquerade is a formal dance party with multiple styles of ballroom dance music (as well as popular music).  Formal attire is requested, masks will be provided, and refreshments will be served.    ',null);
insert into hudsonu.event values(518041,'Final''s Study Break',cast('2015-05-03 16:00' as date),cast('2015-05-03 18:00' as date),'Academic Quad','Social',NULL,'SAA','Hudson Activities Board will be hosting a final''s study break and celebration of the end of year by hosting a field day on the academic quad, ending with a BBQ from Holy Smokes. There will be a wide variety of team games that participants can come and play when they have a convenient break from studying. The games will begin around 4 PM and the BBQ will come around 5 or 6 PM',null);
