insert into hudsonu.event values(5574262,'Teddies and Treats Valentine''s Day Celebration',cast('2020-02-13 18:00' as date),cast('2020-02-13 20:00' as date),'Case-Geyer Library, Batza Room','Social',NULL,'SAA','Make Valentine''s Day extra sweet this year! Create a cute stuffed animal for someone special (or yourself) while enjoying our DIY candy bar, fresh-made cotton candy, and gourmet chocolate samplings from Hamilton''s own Maxwells Chocolates.  '||chr(10)||'Hosted by the Hudson Activities Board.',null);
insert into hudsonu.event values(623084,'Interfaith Dinners',cast('2015-11-12 18:00' as date),cast('2015-11-12 19:00' as date),'Chapel Basement','Thoughtful Learning',NULL,'NC','The Interfaith Dinners are an opportunity for students to come together, talk about their different beliefs and share a meal. Each dinner has a theme and there are discussions or presentations that are related to that theme for students to participate in during the dinner. These dinners have been extremely successful in the past.',null);
