insert into hudsonu.event values(8011470,'Red Cross Blood Drive',cast('2022-03-31 12:00' as date),cast('2022-03-31 17:00' as date),'Hall of Presidents','Community Service','Philanthropy','PDT','Phi Delta Theta is working with the Red Cross to host a blood drive on the Hudson campus.',null);
insert into hudsonu.event values(806124,'Gospel Fest 2016',cast('2016-02-19 19:00' as date),cast('2016-02-19 21:00' as date),'Hudson University Chapel','Spirituality',NULL,'SGC','Hudson Universitys Gospel Fest is an annual two-hour choral performance featuring a special guest gospel artist along with Hudson Sojourners Gospel Choir and gospel choirs from regional colleges and/or churches. This year we will be bringing back Walt Whitman and the Soul Children of Chicago (SCC) to headline Gospel Fest 2016. '||chr(10)||'Over the past four years, Gospel Fest has seen much success, hosting celebrated gospel artists/groups such as Kirk Franklin, Marvin Sapp, The Harlem Gospel Choir, Walt Whitman and his Soul Children of Chicago, and Byron Cage. Along with the headlining group The Soul Children of Chicago, invitations will be extended to choirs from the surrounding towns and colleges such as the Utica College Gospel Choir and Syracuse University, Black Celestial Singers. Gospel Fest is known to draw in large, diverse crowds from both within the Hamilton area and all over Central New York.',null);
insert into hudsonu.event values(821042,'Brown bag "Silent Spring Continues: The Impact of the Industrial Food System on our Health"',cast('2015-04-09 11:30' as date),cast('2015-04-09 11:30' as date),'Lawrence 105, Hudson University','Thoughtful Learning',NULL,'HGHC','Brown bag featuring Professor Carrie Woods, hosted by Global Health Initiative ',null);
insert into hudsonu.event values(8244372,'"Pink Haus" BBQ at Cushman House',cast('2022-08-26 18:00' as date),cast('2022-08-26 19:00' as date),'Pink Haus','Social',NULL,'QTPC','We are excited to induct the first-ever LGBTQ+ house at Hudson - "PinkHaus"! '||chr(10)||'Join us for a BBQ on August 26 at 6 pm (102 Broad St., Cushman House, Ciccone Commons).'||chr(10)||'Come through for a good time, everyone is welcome!',null);
insert into hudsonu.event values(8493118,'Halloween 3D Midnight Double Feature',cast('2022-10-29 00:00' as date),cast('2022-10-30 02:00' as date),'Hamilton Theater','Arts','Movie/Film','HFS','Come on down to Hamilton Theater this Halloween weekend for a retro styled 3D double feature of Creature From the Black Lagoon and Friday the 13th Part 3 complete with free pizza, interstitial 3D trailers between and before the films, and most importantly of all, classic paper red-blue style 3D glasses! See these films in ways that you''ve never seen them before and likely won''t be able to again for a while!'||chr(10)||'Our programming decisions were made to highlight the legacy of two very underappreciated eras of commercial cinema. Creature From the Black Lagoon represents the tail-end of the 50''s schlocky gimmicky era of 3D and cinema, while being one of the classics of cinema with its 3D nature often being forgotten by mass cultural memory. Friday the 13th Part 3 represents the 80''s resurgence of 3D as gimmicks often in horror sequels, while also being the film that defined the image of Jason Voorhees as is commonly seen.',null);
insert into hudsonu.event values(854547,'Battle of the Bands',cast('2016-01-23 20:00' as date),cast('2016-01-23 22:00' as date),'Donovan''s Pub','Arts',NULL,'SAA','Come watch student and faculty bands compete in CAB Music''s Battle of the Bands! The winning band will receive a prize! There will also be FREE DONOVAN''S PUB food for all!',null);
