insert into hudsonu.event values(8912439,'POC Formal',cast('2023-02-24 21:30' as date),cast('2023-02-25 00:00' as date),'Hudson Palace Theatre','Social','Dance','BSU','The Hudson Black Student Union will be hosting the annual POC formal on Friday, February 24, 2023. The formal is BSU''s largest event this year, where we will have food, drinks, music, and a good time. Dress up and show out! We''re currently at full capacity, but you can join our waitlist by filling out the registration form and by turning in your acknowledgment of risk and responsibility form (at the bottom of the google form).'||chr(10)||'https://docs.google.com/forms/d/e/1FAIpQLSet8gcqKqD12dfWU4FmNFNXIL5EuLkaX6DuDK3xBs3-_hscbg/viewform'||chr(10)||'We hope to see you there!'||chr(10)||'BSU Core',null);
insert into hudsonu.event values(9058806,'Values Week:DEI Panel',cast('2023-04-20 11:30' as date),cast('2023-04-20 11:30' as date),'ALANA Multipurpose Room','Thoughtful Learning',NULL,'CPC','Come meet with the DEI chairs from each of the Fraternities and Sororities on campus to have a discussion about each chapter''s diversity, equity, and inclusion efforts, including but not limited to supporting members with marginalized identities, chapter programming, and membership education. ',null);
insert into hudsonu.event values(931241,'Queerfest presents The Closet SWAP',cast('2016-04-01 16:00' as date),cast('2016-04-01 17:00' as date),'Creative Arts House','Social',NULL,'LAMBDA','Do you have lightly used clothes that you don''t wear anymore? Bring your spare items and swap with others! For example, come in with 4 items and you can leave with up to 4 items.Everything that is left will be donated to The Closet Shop which is a clothing store supported by the Hudson LGBTQ Initiatives Office which serves to provide transgender students with a low-cost option to begin transitioning their wardrobe to more adequately coincide with their gender identity.We will also be accepting cash donations for The Closet Shop that will provide financial assistance for students wishing to purchase more personal items that support transgender identities, such as binders, breast forms, and packers.',null);
insert into hudsonu.event values(9612137,'Baking with a Taste of Asia!',cast('2023-12-02 14:00' as date),cast('2023-12-02 15:00' as date),'Alana Kitchen and Multipurpose Room','Cultural',NULL,'OASIS','Join us for a fun, engaging event where we''ll be baking and decorating cookies with a taste of Asia! We hope to exchange culture through food, with flavors such as matcha, taro, and black sesame, and discussion about food, community, belonging, and more. We hope to see you there! ',null);
insert into hudsonu.event values(9880346,'Midnight Philosophy Society Meeting',cast('2024-01-27 22:00' as date),cast('2024-01-28 01:00' as date),'Donovan''s Pub','Social',NULL,'MPS','Midnight Philosophy is a vibrant community of inquisitive and curious students who are excited to explore diverse and relevant philosophical topics! We host welcoming student-to-student conversations about morality, society, religion, metaphysics, and epistemology. Our members are diverse in their beliefs, and we are open to absolutely anyone, with no philosophical experience or major declaration necessary. ',null);
