insert into hudsonu.event values(9897151,'February LGBTQ+ Book Club',cast('2024-02-29 18:00' as date),cast('2024-02-29 19:00' as date),'The Rainbow Room (Bryan Complex Basement)','Arts',NULL,'LAMBDA','Join us in reading the anthology, Common Bonds, for LGBTQ+ Initatives February Book Club (in celebration of ASAW) on the 29th at 6pm in the Rainbow Room! '||chr(10)||'Common Bonds is an anthology of speculative short stories and poetry featuring aromantic characters. At the heart of this collection are the bonds that impact our lives from beginning to end: platonic relationships. Within this anthology, a cursed seamstress finds comfort in the presence of a witch, teams of demon hunters work with their rival to save one of their own, a peculiar scholar gets attached to those he was meant to study, and queerplatonic shopkeepers guide their pupil as they explore their relationship needs and desires. Through nineteen stories and poems, Common Bonds explores the ways platonic relationships enrich our lives.'||chr(10)||' '||chr(10)||'We only have so many copies, so it is first come, first served (if you want to purchase your own copy or get one from a library, you can still join us in the discussion! Just email R at rhunsicker@hudson.edu and let em know!).',null);
