insert into hudsonu.event values(5015539,'Ron Baker Memorial Fundraiser',cast('2019-10-05 19:30' as date),cast('2019-10-05 20:30' as date),'Class of 1965 Arena','Fundraising',NULL,'BTP','Come join the mens hockey team at the home opening game of the 2019-20 season on October 5th against RIT at 7:30 PM. The game will be in memory of long-time supporter and community member, Ron Baker. To honor Rons remarkable impact over the past 30+ years at Hudson, the brothers of Beta Theta Pi will be hosting a fundraiser with men''s hockey during their home opener, and all proceeds will directly benefit the Baker Family. There will be plenty of ways to donate during the game such as a 50/50 raffle, Chuck a Puck (after the 1st period), raffle giveaways and more. You can also donate directly to the Baker family with credit/debit/HUES Cards through the online link provided. Hope to see everyone there! ',null);
