insert into hudsonu.event values(593954,'The Thickness: Aja Monet',cast('2015-02-27 21:00' as date),cast('2015-02-28 00:00' as date),'CAH (100 Broad St.)','Arts',NULL,'SRT','Sisters of the Round Table in collaboration with Lounge and Broad Street Association, present The Thickness: Aja Monet. The Thickness is a traditional part of SORT''s Africana Women''s Week(s). Hudson students will have the opportunity to listen to and engage with an award-winning spoken word artist, whose words will be sure to inspire, spread love, encourage, and most of all heal. Not only that, they will be able to share a meal with her and ask questions in the name of pursuing their own poetry, activism, art and love. There will be an open mic afterwards. All are welcome!',null);
