insert into hudsonu.event values(623083,'Interfaith Dinners',cast('2015-10-08 18:00' as date),cast('2015-10-08 18:00' as date),'Chapel Basement','Thoughtful Learning',NULL,'NC','The Interfaith Dinners are an opportunity for students to come together, talk about their different beliefs and share a meal. Each dinner has a theme and there are discussions or presentations that are related to that theme for students to participate in during the dinner. These dinners have been extremely successful in the past.',null);
