insert into hudsonu.event values(749089,'OASIS in the Night',cast('2015-11-14 20:30' as date),cast('2015-11-14 23:45' as date),'Bunche House','Social',NULL,'OASIS','OASIS in the Night is an end-of-the-semester formal for members of the club that is also open to other students on campus. The formal will commence with performances by OASIS members, which will involve poetry, music and monologues (8:30-9:30 pm). The performances will be followed by a dance (9:30 pm - 12 am). Appetizers and desserts from various Asian countries will be available.  ',null);
insert into hudsonu.event values(7561381,'Black Solidarity Dinner',cast('2021-11-15 19:00' as date),cast('2021-11-15 21:00' as date),'Edge Cafe','Cultural','Concert/Music','BSU','Black Solidarity Day is a national holiday observed on the first Monday in November. This dinner is meant to commemorate it! The day is supposed to bring Black people together to discuss their political status and their future. On the Hudson campus, the BSU uses this as an opportunity to celebrate solidarity between everyone regardless of race, gender, sexuality etc. This year, as we have in the past few years we will host the event in the Edge Cafe, which is close to the Harlem Renaissance Center, a community learning center dedicated to African-American culture and heritage. We will most likely have a professor speak as well as a few student performances.',null);
