insert into hudsonu.event values(8542245,'CSA Vibe Session',cast('2022-10-27 18:00' as date),cast('2022-10-27 18:30' as date),'Harlem Renaissance Center (Basement of Crawshaw Hall in Bryan Complex)','Cultural',NULL,'CSA','The Caribbean Students Association in collaboration with the HRC will be hosting a Vibe Session on October 27th at 6 pm in the Harlem Renaissance Center, this is an event based around "vibing to"/ enjoying good music, along with some of our favorite cultural foods, and providing people with a safe space to unwind and get to know each other.'||chr(10)||'This event is sponsored by Hancock Commons.',null);
insert into hudsonu.event values(8590418,'Grill Club Taqueria',cast('2022-11-12 13:00' as date),cast('2022-11-12 15:00' as date),'Parker Commons','Social',NULL,'HGC','Our third meating of the semester, featuring pulled pork, chicken, steak, and veggie tacos! Sides include: chips and guac/salsa, refreshments.',null);
insert into hudsonu.event values(8883088,'Ramentine',cast('2023-02-11 17:00' as date),cast('2023-02-11 19:00' as date),'ALANA Cultural Center','Cultural',NULL,'KCA','Asian Cultural Club (SACC), Hudson International Club (CIC), Korean Culture Association (KCA), and Hudson Vietnamese Society (HVS), Hudson Japanese Cultural Community (CJCC) wishes to cultivate a cross-cultural understanding of Asian culture through Ramentine, an event where participants can gather, share their stories, and enjoy a common dish in Asia: instant ramen noodles. Through this annual event, we hope Hudson students are reminded of their connection with the Asian culture through the familiar taste of ramen, while cultivating an understanding of our shared culture, thereby creating a community for all and strengthening the bond among members of the Hudson community. Besides having the opportunity to try out noodles of different Asian cultures, Hudson students will also get the chance to make noodles to their own liking. Besides understanding the Asian culture of gathering and food-sharing, we believe this event will be meaningful to Hudson members because they can also learn about various ramen noodle customs, as well as relax, chat with friends, and enjoy a hot meal amidst a cold winter day; thus, this event will bring people together and strengthen interconnections among participants through the common language of cuisine and cross-cultural holidays. Events will be in three different rooms where students can choose different activities including card writing and ramen-enjoying. This event is inclusive to all campus members who are interested in Japanese or Asian culture!',null);
insert into hudsonu.event values(9041548,'13 Days of Green Kickoff Event',cast('2023-04-10 16:00' as date),cast('2023-04-10 17:00' as date),'Academic Quad','Social','Outdoor Education','GEG','Kick-off the Office of Sustainabilitys 13 Days of Green series on the Academic Quad with a celebration of sustainability at Hudson. Enjoy the warmth of spring while meeting members of Hudson organizations focused on sustainability and environmental issues. Tabling organizations and topics include:'||chr(10)||''||chr(10)||'Outdoor Education'||chr(10)||'Sustainability Graduation Pledge'||chr(10)||'Beekeeping Club'||chr(10)||'STEM/Sustainability Career Advisors'||chr(10)||'Sustainability Representatives (S-Reps)'||chr(10)||''||chr(10)||'After you visit tables from campus partners to learn how to get involved, you can listen to live music, play lawn games and grab a Maxwells ice cream cone for a low-waste treat! Vegan and gluten-free options available.'||chr(10)||'We cant wait to see you there!'||chr(10)||'Rain Location: Coop Media RoomThis event is part of the Office of Sustainabilitys 13 Days of Green series leading up to Earth Day.',null);
insert into hudsonu.event values(9056875,'Be the Match Donor Registry',cast('2023-04-25 10:00' as date),cast('2023-04-25 14:00' as date),'Frank Dining Hall and Library Patio','Community Service','Volunteer and Community Service ','COVE','Volunteer to help table with the Hudson Football Team and Public Health Initiatives on April 25 and 26 or stop by to join the Be The Match donor registry. The national Be The Match registry pairs volunteer blood stem cell donors with thousands of patients diagnosed with life-threatening blood cancers. By giving 1-hour of your time as a volunteer or signing-up as a potential donor, you are increasing the chance to save a life. Visit the tables outside Frank Dining Hall and the Library Patio between 10am - 3pm for free giveaways, more information on Be The Match, and to join the registry. '||chr(10)||' '||chr(10)||'Sign-up here to volunteer!',null);
insert into hudsonu.event values(954488,'Burritos con los Santitos',cast('2016-10-27 18:00' as date),cast('2016-10-27 19:00' as date),'COOP TV room','Social',NULL,'NC','Come celebrate All Saints Day with the Newman Community! We will be learning about the saints, learning about what it means to be a saint, and eating great burritos!',null);
insert into hudsonu.event values(9880349,'Midnight Philosophy Society Meeting',cast('2024-02-17 22:00' as date),cast('2024-02-18 01:00' as date),'Donovan''s Pub','Social',NULL,'MPS','Midnight Philosophy is a vibrant community of inquisitive and curious students who are excited to explore diverse and relevant philosophical topics! We host welcoming student-to-student conversations about morality, society, religion, metaphysics, and epistemology. Our members are diverse in their beliefs, and we are open to absolutely anyone, with no philosophical experience or major declaration necessary. ',null);
