insert into hudsonu.event values(1227633,'Ballet Class',cast('2017-02-16 19:30' as date),cast('2017-02-16 21:00' as date),'Huntington 303','Arts',NULL,'BALLET','The Hudson Ballet Company provides classes taught by Paris Wilcox, a former principal dancer with the Kansas City Ballet, for students of all levels of experience. The classes help develop students'' technique, flexibility, strength, and artistic expression. Classes take place Tuesdays and Thursdays.',null);
