insert into hudsonu.event values(623162,'Here and Now Theater Company Presents "But All My Friends Are..."',cast('2015-04-09 19:00' as date),cast('2015-04-09 19:30' as date),'Golden Auditorium, Little Hall','Arts',NULL,'BROS','Brothers in collaboration with the Theater Depaartment are bringing Here and Now Theater Company to perform a 90-minute show of 10 short acts, each act concerning an aspect of being a minority in America through comedy, song, and acting. ',null);
insert into hudsonu.event values(702781,'DDT Auditions',cast('2015-09-05 16:30' as date),cast('2015-09-05 17:00' as date),'Ryan Studio 212','Arts',NULL,'DDT','We are looking for new members for DDT, a high energy, fierce, and talented dance group! We perform at DanceFest every semester, and additionally perform at other Hudson events throughout the year. Nothing is needed in preparation. For further information, please contact Kristen Weymouth at kweymouth@hudson.edu',null);
insert into hudsonu.event values(7516528,'The Nutcracker',cast('2021-11-13 14:00' as date),cast('2021-11-13 15:30' as date),'Arts at the Palace','Arts','Dance','BALLET','This November, the Hudson Ballet Company will be performing the Nutcracker. The story centers around a young girl named Clara who befriends her Uncle Drosselmeyer''s nephew at a Christmas Eve party. Later that night the Nutcracker she receives as a present from her Drosselmeyer comes to life, battling the evil Mouse, and saving her. The victorious Nutcracker transforms into the nephew, who then walks with her through the Land of Snow and introduces her to the Land of Sweets, where the Sugar Plum Fairy and her court celebrate by performing a series of dances for them.',null);
insert into hudsonu.event values(9584434,'The Nutcracker',cast('2023-11-10 19:30' as date),cast('2023-11-10 21:00' as date),'Arts at the Palace','Arts','Dance','BALLET','The Nutcracker is a widely-known holiday performance and tradition for people all across the world, enjoyed by both the audiences and the performers. This ballet shares the story of a young girl who is gifted a Nutcracker that transforms into a prince and together they travel to a land of fantasy and sweets. The production is performed by Hudson students and dancers from the Hamilton community. Tickets are free and available through this link: https://www.hamiltoncreates.com/registration ',null);
insert into hudsonu.event values(1109945,'Cabaret Fall 2016',cast('2016-11-10 19:00' as date),cast('2016-11-10 21:00' as date),'The Palace Theater','Arts',NULL,'MAT','Cabaret is a bi-yearly event that brings a musical theater showcase to the Hudson and Hamilton Community. Performed downtown at the Palace Theater, Cabaret puts on a show that includes great renditions by students of pop music and musical theater alike.',null);
insert into hudsonu.event values(513835,'Dancefest',cast('2014-12-05 18:00' as date),cast('2014-12-05 20:00' as date),'Hudson Memorial Chapel','Arts',NULL,'GDT','Come watch your peers perform in the student organized and choreographed event, Dancefest!The doors will open at 5:30, and the show begins at 6!',null);
insert into hudsonu.event values(5196030,'Dancefest Fall 2019',cast('2019-12-07 18:30' as date),cast('2019-12-07 21:00' as date),'Hudson Memorial Chapel','Arts','Dance','GDT','It''s your favorite high-energy Hudson tradition! Now in our 22nd year, Groove Dance Troupe invites you to get ready for celebrating a "higher love" through dance. '||chr(10)||'Doors open at 6pm, show starts at 6:30pm.'||chr(10)||'Warning: Some songs in the show may contain explicit language that may be perceived as inappropriate or offensive. Dancefests mission is to create a space for dancers to express themselves freely and exercise creative freedom in their choice of music. If you have any other further questions, please contact Groove Dance Troupe at groove@hudson.edu.',null);
insert into hudsonu.event values(623116,'Newman Retreat',cast('2015-10-30 15:30' as date),cast('2015-11-01 13:00' as date),'Good News Center, Utica, NY','Spirituality',NULL,'NC','The Newman Community provides this retreat as a way for Catholics and non-Catholics alike to grow in their awareness of the Catholic faith through a weekend of prayer and activities.',null);
insert into hudsonu.event values(708409,'Island Touch: Introduction to Latin American Dance',cast('2015-09-17 19:00' as date),cast('2015-09-17 20:00' as date),'Huntington Gym','Arts',NULL,'LASO','The Latin American Student Organization (LASO) and the Latin American Dance Company (LAD) have invited the Island Touch Dance Academy and its founders, Jorge Burgos and Tanja Kensinger, to perform and lead a dance workshop in honor of Hispanic Heritage Month (HHM) tentatively on Thursday September 17. Internationally renowned Latin dancers, Jorge and Tanja have performed and taught at Salsa Congresses and Bachata Festivals in over 25 different countries, and shared the stage with top Latin dancers, including Eddie Torres, Griselle Ponce, Yamulee, and Victor and Burju. They have choreographed for noted bachata artists such as Toby Love, Prince Royce, Xtreme, Dominic Marte, and Carlos y Alejandra. In 2011, Jorge and Tanja founded the Island Touch Dance Academy in Rockville, Maryland to instruct students in salsa, bachata, merengue, and cha cha dance styles; the academy now has competitive bachata teams in 14 U.S. cities and 16 around the world performing the directors choreographies.'||chr(10)||' '||chr(10)||'The event, which aims to both celebrate Latin American styles of dance in honor of Hispanic Heritage Month and encourage a greater appreciation for dance on campus, will feature a bachata performance by the New York Touch dance team and a salsa routine by its directors, Jorge and Tanja. Jorge and Tanja will follow these performances with a two hour-long, beginner-level workshop that will introduce event participants to the bachata style of dance. The directors will instruct participants in the footwork, partnerwork, styling, and technique to a segment of their own bachata choreography. Island Touchs workshops have been commonly characterized as high-energy, dynamic, and easy to follow. This event will expose participants to two widely popular styles of Latin dance and provide them with the fundamentals of dancing bachata. The performances and workshop will be open to the entire Hudson community, members of the Hamilton community, and interested members of surrounding schools. Dancers of all skills levels will be encouraged to attend.',null);
insert into hudsonu.event values(772310,'Public Health in Rural Uganda Immersion Trip',cast('2016-01-01 06:00' as date),cast('2016-01-16 18:00' as date),'Indigo Foundation and Bwindi Community Hospital','Thoughtful Learning',NULL,'HGHC','Global Health Initiative is hosting an immersion trip that will focus on the local health complexities of rural Uganda, where students would spend the first week volunteering at Indigo Foundation and then spend a second week at the Bwindi Community Hospital. The goal of the trip is to engage and educate students on public health, as well as expose students to a future career in health and related fields.',null);
insert into hudsonu.event values(902759,'Stone a Heathen',cast('2016-04-18 16:00' as date),cast('2016-04-18 17:00' as date),'Academic Quad','Community Service',NULL,'SASS','For this event anyone can volunteer to be pelted with water balloons as penance for heinous acts such as eating shellfish and wearing a cotton-polyester blend t-shirt. The purpose of this event is to raise awareness of religious persecution while bringing our thriving religious community together for an afternoon of fun in the lovely spring weather (or whatever it is we have here in Hamilton).'||chr(10)||'Anyone can come over and purchase water balloons to throw at your heathen friends. Proceeds will go to the Interfaith Alliance. Their website is: http://interfaithalliance.org.',null);
