insert into hudsonu.event values(1136044,'Interfaith Dinner',cast('2017-02-09 18:00' as date),cast('2017-02-09 19:00' as date),'Chapel Basement','Thoughtful Learning',NULL,'NC','The Interfaith Dinners are an opportunity for students to come together, talk about their different beliefs and share a meal. Each dinner has a theme and discussion of this theme is co-led by members from two different Chaplaincy groups. This discussion-based style allows students who attend to participate during the dinner. These dinners have been extremely successful in the past.',null);
insert into hudsonu.event values(1248474,'University Church Board Game Night',cast('2017-04-20 21:00' as date),cast('2017-04-20 23:00' as date),'Interfaith House','Social','Religious/Spiritual','UC','Enjoy a night of fellowship and fun with board games and dessert every Thursday, 9pm until midnight, at Interfaith House (104 Broad Street). Typical favorites include games like Avalon, Settlers of Catan, Blokus, Scrabble, and more! Feel free to bring your own games, as well. ',null);
