insert into hudsonu.event values(1283525,'Keynote Speaker: Ebony Mcgee',cast('2017-04-07 15:00' as date),cast('2017-04-07 15:30' as date),'Love Auditorium','Thoughtful Learning',NULL,'HMAPS','The proposed event is a keynote speaker who will be discussing mental health disparities faced by underrepresented and marginalized groups on college campuses. The MAPS Executive Board recently attended the Steve Fund Conference at Washington University at St. Louis where we spent the entire day interacting with professionals and voicing our ideas about the steps universities must take when addressing mental health. As agents of change and students inspired by these meaningful discussions, we prioritized reaching out to this speaker and bringing her to Hudson, in hopes of promoting cultural competency and awareness in the realm of mental health. This panel discussion would benefit all marginalized communities pursuing a career in the medical/health care delivery field, and would equip students with the tools necessary to receive support. Promoting awareness about the importance of mental health destigmatization would directly reinforce MAPS mission on this campus.This discussion will assist students in their educational pursuits and focus on fostering an environment where students can achieve academic excellence and personal fulfillment.',null);
