insert into hudsonu.event values(518026,'Midterm Study Break',cast('2015-03-08 19:00' as date),cast('2015-03-08 20:00' as date),'Hall of Presidents','Social',NULL,'SAA','A Midterm Study Break will be held in the Hall of Presidents for all students seeking stress relief on March 8th! Attendees will be invited to enjoy the jazz and rock stylings of Hudson student band No Standards, a collection of guitar, bass, drum, saxophone, keyboard and trumpet!  Fresh pizza and mozz sticks from Oliveri''s will be served while students jam out together.',null);
