insert into hudsonu.event values(539355,'Hug-A-Thon Study Break',cast('2014-12-14 18:00' as date),cast('2014-12-14 19:30' as date),'Case Library Batza Room 560','Social',NULL,'BROS','Brothers wants to dismantle the fear of men of color and gender stereotypes that men do not talk about their feelings, especially in light of recent global, national, and campus events.We will offer free coffee, hot chocolate,tea, slices,wings, snacks, and hugs. It will be on Sunday Dec. 14 in Case Library Room 560 from 6:00pm until 7:30pm. Brandon Doby will play vibrational, soul music. ',null);
insert into hudsonu.event values(623090,'Welcome Back BBQ',cast('2015-08-27 17:00' as date),cast('2015-08-27 18:00' as date),'Academic Quad','Social',NULL,'SAA','The Welcome Back BBQ, held on the half-day of classes, is a time for members of the Hudson community to come together and enjoy Holy Smokes BBQ. This event is meant to spark excitement for the upcoming semester and create an opportunity for first-years and upperclassmen to get to know each other, all the while enjoying delicious food on a beautiful night at Hudson. ',null);
insert into hudsonu.event values(634254,'Konosioni Field Day',cast('2015-08-26 13:00' as date),cast('2015-08-26 14:30' as date),'The Old Golf Course (Field of Dreams)','Social',NULL,'THS','Konosioni Field Day is a Hudson tradition for incoming first-year students. All Konosioni members will be available supply food and run games on the Old Golf Course (Field of Dreams) to build dorm cohesion and get people to meet eachother in a fun setting. Dorms will compete in challenges like tug of war, capture the flag and other large team games.',null);
insert into hudsonu.event values(6878561,'Junior and Senior Care Packages',cast('2021-02-05 11:30' as date),cast('2021-02-05 13:30' as date),'The Mat at Parker Commons','Social',NULL,'SAA','The 2021 and 2022 Class Councils have put together care packages for members of the councils to pick up and enjoy from Parker Commons between 11:30 and 1:30. Packages are first come, first serve as there is a limited amount. ',null);
insert into hudsonu.event values(7026463,'Open Art-Making with the Senior Honor Society',cast('2021-04-06 20:00' as date),cast('2021-04-06 21:00' as date),'Hall of Presidents','Arts','Volunteer and Community Service ','THS','Join the Senior Honor Society Class of 2021 and 2022 to make some original artwork! Follow a guided lesson from a Hudson art professor in one side of the room or hang out and listen to music and work on independent pieces on the other side of the room. There will be Senior Honor Society members floating around to help guide you on technique, help you come up with ideas, and make art alongside you.',null);
insert into hudsonu.event values(723331,'MIDNIGHT MOVIE! Maze Runner: Scorch Trials',cast('2015-09-18 23:45' as date),cast('2015-09-18 23:45' as date),'Hamilton Movie Theater','Social',NULL,'SAA','CAB Take Two presents this semester''s first Midnight Movie, Maze Runner: Scorch Trials! Come with your HUES Card for free admission, popcorn, and slices! '||chr(10)||'Synopsis: Transported to a remote fortified outpost, Thomas and his fellow teenage Gladers find themselves in trouble after uncovering a diabolical plot from the mysterious and powerful organization WCKD. With help from a new ally, the Gladers stage a daring escape into the Scorch, a desolate landscape filled with dangerous obstacles and crawling with the virus-infected Cranks. The Gladers only hope may be to find the Right Hand, a group of resistance fighters who can help them battle WCKD.',null);
insert into hudsonu.event values(7411046,'LASO Loteria Night',cast('2021-09-24 20:00' as date),cast('2021-09-24 21:00' as date),'Donovan''s Pub','Cultural',NULL,'LASO','Join LASO in Loteria Night on September 24th from 6:00 pm-8:00 pm! We will have grand prizes like the Nintendo Switch, Mexican Candy Care Packages, and more! Loteria is a game of chance similar to the American game Bingo, but using a deck of cards with images and is a lot of fun to play with friends and community!',null);
insert into hudsonu.event values(7583171,'Summer Experience Student Panel',cast('2021-12-02 17:00' as date),cast('2021-12-02 18:30' as date),'COOP Conference Room','Thoughtful Learning',NULL,'HGHC','Meet GHC Seniors with summer experience in the global public health field. Learn about on-campus and off-campus opportunities for research, internships, and full-time positions.',null);
insert into hudsonu.event values(7583175,'Fall 2021 Public Health Seminar: Collaborative Research with the Bwindi Community Hospital in Uganda',cast('2021-11-09 17:00' as date),cast('2021-11-09 19:00' as date),'Batza Room, Case Library','Thoughtful Learning',NULL,'HGHC','We are excited for our Fall 2021 Public Health Seminar: Collaborative Research with the Bwindi Community Hospital in Uganda. Professor Frank Frey will be joining us to discuss a decade worth of public health research and ways to get involved with the Global Public and Environmental Health field inside and outside of the classroom. '||chr(10)||'Dinner will be catered by Rio Grande. RSVP here! ',null);
insert into hudsonu.event values(7641075,'Teacher''s Day Dinner Celebration',cast('2021-12-08 18:30' as date),cast('2021-12-08 19:30' as date),'ALANA Cultural Center','Cultural',NULL,'HVS','Every year on the 20th of November, millions of people in Vietnam celebrate this day with flowers and gifts to express gratitude to some of the most important figures in their lives - their teachers. Recognizing that Teacher''s Day is a very important day in many cultures, Hudson Vietnamese Society (HVS) would like to invite students and teachers alike on campus to come and celebrate this special day together. There will be Vietnamese food served by New Century Viet at the event. Additionally, there will be cards and flowers for students to give to their professors the following days as a token of appreciation.',null);
insert into hudsonu.event values(7680397,'Springo!',cast('2022-02-19 21:00' as date),cast('2022-02-19 23:00' as date),'Coop TV Room','Social',NULL,'SAA','RESCHEDULED FOR FEBRUARY 19TH!!'||chr(10)||'Like bingo, but with spring rolls and Chinese food! Come to the Coop TV Room for a chance to win awesome prizes.'||chr(10)||'Wear your masks!',null);
