insert into hudsonu.event values(800500,'Hudson Women in Business Coffee Hour Series',cast('2016-04-19 20:00' as date),cast('2016-04-19 20:00' as date),'Batza Room, Case Library','Group Business',NULL,'HWIB','This series involves monthly coffee hours to educate members on different aspects of the business industry. ',null);
insert into hudsonu.event values(8035435,'Suture Event',cast('2022-04-13 18:30' as date),cast('2022-04-13 18:30' as date),'101 Ho','Thoughtful Learning',NULL,'PVC','The Suture Event is hosted by the Pre-Veterinary club and Pre-Health Pathways. A veterinarian from a local clinic will come to Hudson University to demo the basic suturing techniques used ubiquitously in medicine. As the veterinarian demonstrates, students will have the opportunity to follow along on their individual suture kits and ask questions. ',null);
insert into hudsonu.event values(821043,'Stone a Heathen',cast('2015-04-21 16:00' as date),cast('2015-04-21 17:00' as date),'Academic Quad','Community Service',NULL,'SASS','Support protection from religious discrimination by having some snacks and fun in the sun! Buy a t-shirt or some water balloons and stone your favorite heathens! All proceeds go to the Interfaith Alliance for protecting faith and freedom.',null);
insert into hudsonu.event values(8374772,'New Student Club Meeting',cast('2022-09-22 18:00' as date),cast('2022-09-22 18:00' as date),'Ho 101','Thoughtful Learning',NULL,'HUSPS','The meeting is aimed at retaining new students who have expressed interest in our club. We will discuss past events, upcoming events, and more ways to get involved.',null);
insert into hudsonu.event values(874176,'Brothers Charity Week 2016',cast('2016-03-28 12:00' as date),cast('2016-04-01 22:45' as date),'Hudson University','Fundraising',NULL,'BROS','Brothers Charity Week is composed of several activities placed throughout the week, with the intent of raising money for the surrounding Hamilton community and/or a worthwhile, larger global charitable organization beginning March 28 until April 1, 2016.'||chr(10)||'On Monday, March 28, Brothers will start the week with a BBQ and Bake Sale supported by the Office of the Chaplains on the academic quad during lunchtime, in conjunction with a homemade bake sale occurring in the Coop.'||chr(10)||'On Tuesday, March 29, Brothers will have a video gaming tournament in conjunction with ResLife  and The Games Afoot at Donovans Pub at 7pm.'||chr(10)||'On Wednesday March 30, Brothers will host a basketball tournament with the aid of the Mens Basketball team and BDS at Huntington Gym at 7pm. '||chr(10)||'On Thursday March 31, Brothers will have a Karaoke night at Donovans Pub at 7pm. '||chr(10)||'On Friday April 1, the Brothers Charity Auction will take place at 6pm in the Hall of Presidents and our  fundraising party will begin at 10pm in the 80 Broad Street (subject to change). '||chr(10)||'All throughout the week, we will accept suggested donations at all events in addition to our Coop table, where the Bake Sale will be ongoing. We will be selling t-shirts throughout the week as well.',null);
insert into hudsonu.event values(9044958,'13 Days of Green - Afternoon of Service (Wellness Passport Credit!)',cast('2023-04-14 13:30' as date),cast('2023-04-14 15:00' as date),'COVE Lounge - Lathrop 109','Community Service','Sustainability','COVE','Interested in getting outside for a good cause this spring? After the ENST Brown Bag, join us in giving back to your community through volunteering with local, environmentally-focused organizations. You we have the choice of getting your hands dirty with invasive plant removal, trail maintenance, garden preparation, or supporting the COVE Salvage Program by painting the donation boxes. Check out the community partners we will be supporting here:'||chr(10)||''||chr(10)||'Hudson Community Garden'||chr(10)||'Roger''s Environmental Education Center'||chr(10)||'Chenengo Trail Association'||chr(10)||'Spring Farm CARES Nature Sanctuary'||chr(10)||'COVE Salvage Program'||chr(10)||''||chr(10)||'Sign up here before Wednesday, April 12th!'||chr(10)||'Snacks provided, but please bring your own reusable water bottle.'||chr(10)||'Participants can also receive 2 hours of credit toward their PE Wellness Passport!'||chr(10)||'This event is co-sponsored by the Hudson Center for Outreach, Volunteerism, and Education as part of the Office of Sustainabilitys 13 Days of Green series leading up to Earth Day.',null);
insert into hudsonu.event values(9580630,'Halloweekend@Donnies',cast('2023-11-03 23:00' as date),cast('2023-11-04 00:00' as date),'Donovan''s Pub','Social','Concert/Music','SAA','Free food, student DJ, and giveaways! ',null);
insert into hudsonu.event values(9866839,'CWiB Coffee Hour #1',cast('2024-02-12 19:00' as date),cast('2024-02-12 20:00' as date),'Case Geyer 560 Batza Room','Thoughtful Learning',NULL,'HWIB','Please join the Hudson Women in Business Organization for a monthly coffee hour to discuss different aspects of the field of business.  Meetings may include breakout sessions to discuss specific industries within the field of business, hearing tips from upperclassman who have experience in the business field, revising a resume or cover letter, speaking with alumni and established professions in the field of business, and more.  ',null);
insert into hudsonu.event values(9880356,'Midnight Philosophy Society Meeting',cast('2024-04-20 22:00' as date),cast('2024-04-21 00:00' as date),'Donovan''s Pub','Social',NULL,'MPS','Midnight Philosophy is a vibrant community of inquisitive and curious students who are excited to explore diverse and relevant philosophical topics! We host welcoming student-to-student conversations about morality, society, religion, metaphysics, and epistemology. Our members are diverse in their beliefs, and we are open to absolutely anyone, with no philosophical experience or major declaration necessary. ',null);
insert into hudsonu.event values(9954247,'QTPOC Presents: Baby Tate',cast('2024-03-01 22:00' as date),cast('2024-03-01 23:00' as date),'The MAT','Arts','Concert/Music','WHUR','Baby Tate is always evolving, fuelled by self-love and manifested dreams. The Atlanta-based musician''s sound remains expansive. Summery pop, passionate RandB, and hard-hitting hip-hop all coexist in a single body of work. ROYGBIV, Baby Tate''s debut album, saw her exerting complete creative autonomy as a singer, songwriter, rapper, producer, and engineerindependent skills she''s honed since she was a child. She''s released concept albums as well as unrestricted songs, all while emphasizing female empowerment and joy, as seen by her unified, yet varied 2020 EP After the Rain, which contains her viral, confidence-boosting hit "I Am." Twinged with influence from her southern roots, Baby Tate has a drawled-out rapping style that streamlines her rap persona to another level, gaining around 5 million monthly streams on Spotify.'||chr(10)||' '||chr(10)||'Please join us for a night of party-banger music brought to you by Baby Tate!',null);
insert into hudsonu.event values(593454,'Cabaret',cast('2015-02-26 19:00' as date),cast('2015-02-26 21:00' as date),'Brehmer Theater','Arts',NULL,'MAT',' The theme for this year''s musical theatre Cabaret is "Come Together Cabaret," which celebrates the Hudson community coming together to appreciate some feel-good songs despite the tension of last semester. So come join us in enjoying some great songs performed by lots of talented Hudson students at this year''s Cabaret!',null);
insert into hudsonu.event values(722313,'Butch Cassidy and the Sundance Kid',cast('2015-09-12 17:00' as date),cast('2015-09-12 18:00' as date),'Golden Auditorium','Arts',NULL,'HFS','Come and see a classic Western with the Hudson Film Society! A tale of two men, their wild adventures, and remarkable friendship in the American frontier. Starring Paul Newman and Robert Redford. Running time is 1 hr 53 minutes. '||chr(10)||' '||chr(10)||'Trailer',null);
insert into hudsonu.event values(781476,'The Hudson Thirteen and Swinging ''Gates Family Weekend Concert',cast('2015-10-30 19:00' as date),cast('2015-10-30 20:00' as date),'Chapel','Arts',NULL,'HT','Hudsons premier all-male and all-female acapella groups, The Hudson Thirteen and Swinging ''Gates, will take the chapel stage on Friday October 30th for their annual Family Weekend concert. Each groups preformance will feature soloists from the class of 2016 singing a mix of brand new songs and group classics as they celebrate their final Family Weekend. Tickets for the whole family can be purchased in Frank Dinning Hall and the Coop starting Monday October 26th. ',null);
insert into hudsonu.event values(6571308,'Photo Editing Workshop',cast('2020-10-30 15:00' as date),cast('2020-10-30 16:00' as date),'DLMC Room','Arts',NULL,'PC','Are the colors a bit drab in your photo? Want to remove that annoying fly or person from your group pic? Then the Photo Club has the solution for you as we will be teaching you the essentials of photo editing in Photoshop! Adjust colors, merge photos, and create scenes that would be impossible otherwise. When you sign up, we''ll send an email on how to upload your photos so we can get started quickly.',null);
insert into hudsonu.event values(821047,'Platoon',cast('2015-10-24 17:00' as date),cast('2015-10-24 18:00' as date),'Golden Auditorium, Little Hall','Arts',NULL,'HFS','Join the Hudson Film Society and see Oliver Stone''s harrowing tale of a platoon of soldiers as they encounter the stressors and chaos of combat. Based off of Stone''s own service, the film is the first major production to have been directed by a Vietnam veteran, perhaps contributing to his being awarded the 1986 Academy Award for best director. Running time is 2 hours.',null);
