insert into hudsonu.event values(1048027,'OASIS Brown Bag Series',cast('2016-10-17 11:30' as date),cast('2016-10-17 12:00' as date),'WMST','Thoughtful Learning',NULL,'OASIS','OASIS is hosting two brown bags where we invite female Asian American scholars, writers, and professors to share about their research work and activism experience that revolve around Asian American literature, culture, representation, and Asian American feminist studies.',null);
insert into hudsonu.event values(1119415,'Gospel Fest',cast('2017-02-17 19:00' as date),cast('2017-02-17 21:00' as date),'Hudson Memorial Chapel','Arts',NULL,'SGC','Hudson Universitys Gospel Fest is an annual two-hour choral performance featuring a special guest gospel artist along with Hudson Sojourners Gospel Choir and other choirs, such as the Chamber Singers. This year we will be bringing back Walt Whitman and the Soul Children of Chicago (SCC) to headline Gospel Fest 2017. Over the years, Gospel Fest has seen much success, hosting celebrated gospel artists/groups such as Kirk Franklin, Marvin Sapp, The Harlem Gospel Choir and Byron Cage. ',null);
insert into hudsonu.event values(1283488,'Stories of the Prophet Series',cast('2017-04-06 19:00' as date),cast('2017-04-06 19:00' as date),'Chapel Basement','Spirituality','Religious/Spiritual','HMSA','The Muslim Student Association would like to have a series of events to raise awareness about Islam and dispel common myths and misunderstandings surrounding Islam. This series is also geared towards having a space for an open discussion about the different cultural, religious and moral aspects of Islam, and how differently they are perceived by people in different regions of the world. A series of three dinner discussions over the period of a month, these events would encourage interfaith learning by inviting different religious groups and discussing intersecting values and differences in thought.',null);
insert into hudsonu.event values(168715,'Take Two: The Five-Year Engagement',cast('2012-09-15 22:00' as date),cast('2012-09-15 23:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','One year after meeting, Tom proposes to his girlfriend, Violet, but unexpected events keep tripping them up as they look to walk down the aisle together.'||chr(10)||'Jason Segel, Emily Blunt, and Chris Pratt; R; 124 min.; 2012.',null);
insert into hudsonu.event values(194093,'Take Two: Brave',cast('2012-10-27 19:00' as date),cast('2012-10-27 20:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','Determined to make her own path in life, Princess Merida defies a custom that brings chaos to her kingdom. Granted one wish, Merida must rely on her bravery and her archery skills to undo a beastly curse.'||chr(10)||'Kelly Macdonald, Billy Connolly and Emma Thompson; Rated PG; 100 min.; 2012.',null);
insert into hudsonu.event values(196932,'Take Two: The Dark Knight',cast('2012-11-02 22:00' as date),cast('2012-11-02 23:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','When Batman, Gordon and Harvey Dent launch an assault on the mob, they let the clown out of the box, the Joker, bent on turning Gotham on itself and bringing any heroes down to his level.'||chr(10)||'Christian Bale, Heath Ledger and Aaron Eckhart; Rate PG-13; 152 min.',null);
insert into hudsonu.event values(200466,'Take Two: The Amazing Spider-Man',cast('2012-11-09 22:00' as date),cast('2012-11-10 00:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','Peter Parker finds a clue that might help him understand why his parents disappeared when he was young. His path puts him on a collision course with Dr. Curt Connors, his father''s former partner.'||chr(10)||'Andrew Garfield, Emma Stone and Rhys Ifans; PG-13; 136 min.'||chr(10)||'from imdb.com',null);
insert into hudsonu.event values(205933,'Photography Club: First Meeting!',cast('2012-11-30 17:00' as date),cast('2012-11-30 17:30' as date),'Coop Conference Room',NULL,NULL,'PC','Come to our first ever Photography Club meeting! If you have any interest in joining the club, you should join us to learn about what our plans are for the remainder of this semester and next semester. Also, if you would like to run for an executive board position, it is important that you attend this first meeting.',null);
insert into hudsonu.event values(228734,'Staff Meeting',cast('2013-02-21 19:00' as date),cast('2013-02-21 20:00' as date),'COOP Conference Room',NULL,NULL,'RAG','Come out and write for the Rag! During these meetings, we get together and throw out story ideas, generate articles, and have everyone volunteer to write whatever they''re interested in. These meetings are open and completely non-committed (unless you commit to a story.) '||chr(10)||' '||chr(10)||'Complimentary oxygen provided. ',null);
insert into hudsonu.event values(230543,'CAB Take Two: The Twilight Saga: Breaking Dawn - Part 2',cast('2013-02-23 19:00' as date),cast('2013-02-23 21:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two presents The Twilight Saga: Breaking Dawn - Part 2:'||chr(10)||'After the birth of Renesmee, the Cullens gather other vampire clans in order to protect the child from a false allegation that puts the family in front of the Volturi.'||chr(10)||'from imdb.com',null);
insert into hudsonu.event values(244421,'CAB Take Two: Lincoln',cast('2013-03-22 22:00' as date),cast('2013-03-22 22:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents:'||chr(10)||'Zero Dark Thirty at 7:00PM and Lincoln at 10:00PM in Love Auditorium on Friday, March 22nd, and again at opposite times on Saturday, March 23rd.'||chr(10)||'Zero Dark Thirty:'||chr(10)||'A chronicle of the decade-long hunt for al-Qaeda terrorist leader Osama bin Laden after the September 2001 attacks, and his death at the hands of the Navy S.E.A.L. Team 6 in May 2011.'||chr(10)||'Lincoln:'||chr(10)||'As the Civil War continues to rage, America''s president struggles with continuing carnage on the battlefield and as he fights with many inside his own cabinet on the decision to emancipate the slaves.'||chr(10)||' ',null);
insert into hudsonu.event values(281685,'CAB Take Two: Snitch',cast('2013-05-04 22:00' as date),cast('2013-05-04 22:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'Snitch (Fri 7pm and Sat 10pm):'||chr(10)||'A father goes undercover for the DEA in order to free his son who was imprisoned after being set up in drug deal.'||chr(10)||'Oz the Great and the Powerful (Fri 10pm and Sat 7pm):'||chr(10)||'A small-time magician is swept away to an enchanted land and is forced into a power struggle between three witches.',null);
insert into hudsonu.event values(287425,'Yale IV 2013',cast('2013-10-04 10:15' as date),cast('2013-10-05 22:30' as date),'Yale University, New Haven, CY',NULL,'Volunteer and Community Service ','DS','Yale Intervarsity Parliamentary Debate Tournament 2013 is an international debate tournament that is held in the British Parliamentary style which will take place at Yale University in New Haven, Connecticut on Friday, October 4 and Saturday, October 5. '||chr(10)||'The tournament will consist of five preliminary rounds, followed by a varsity quarters break and a novice* final round. All rounds will be debated in the British Parliamentary style. This will be an excellent opportunity for teams to prepare for Worlds. The judging pool at the tournament will feature some of the best adjudicators available.',null);
insert into hudsonu.event values(302819,'CAB Take Two: Monster''s University',cast('2013-10-04 22:00' as date),cast('2013-10-04 22:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Despicable Me 2 at 7:00PM and Monsters University at 10:00PM in Love Auditorium on Friday, Oct 4th, and again at opposite times on Saturday, Oct 5th.'||chr(10)||'Despicable Me 2 (Fri 7pm/Sat 10pm)'||chr(10)||'Gru is recruited by the Anti-Villain League to help deal with a powerful new super criminal.'||chr(10)||'Monster''s University (Fri 10pm/Sat 7pm)'||chr(10)||'A look at the relationship between Mike and Sulley during their days at Monsters University -- when they weren''t necessarily the best of friends.'||chr(10)||' ',null);
insert into hudsonu.event values(325353,'SORT Sleepover',cast('2013-11-08 20:00' as date),cast('2013-11-09 10:00' as date),'Center for Women''s Studies',NULL,NULL,'SRT','A Night of Sisterly Love sleepover will be  held on Friday November 8, 2013 from 8:00PM-10:00PM in the common area of The Womens Studies Center. The concept of the sleepover is that it is a night where members of the organization and our allies can partake in food, conversation, movies, and games. It also serves as an opportunity for the upperclassmen members of the organization to bond with the younger generation. With our records showing an average of 28 individuals per SORT meeting, and given the success of this event in previous years, we are confident that this event will bring in more members. This event will also help all members become more comfortable with the Center for Womens Studies.',null);
insert into hudsonu.event values(3279355,'Inaugural Meeting',cast('2019-03-27 16:15' as date),cast('2019-03-27 16:15' as date),'Lawrence 304','Social',NULL,'HODC','The Hudson Open Discussion club, during its first meeting, will welcome new members into the organization. The Club will also go through basic administrative duties. ',null);
insert into hudsonu.event values(338845,'CAB Take Two Saturday Matinee: American Pie',cast('2013-12-07 14:00' as date),cast('2013-12-07 15:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','NEW THIS YEAR!'||chr(10)||'CAB Take Two presents Saturday Matinee! Saturday (Dec 7th) 2:00 pm, the classic comedy American Pie will be shown in Love Auditorium.'||chr(10)||'American Pie (starring: Jason Biggs, Chris Klein, Thomas Ian Nicholas)'||chr(10)||'Four teenage boys enter a pact to lose their virginity by prom night.'||chr(10)||' ',null);
insert into hudsonu.event values(365707,'CAB Take Two: The Best Man Holiday',cast('2014-02-01 22:00' as date),cast('2014-02-01 23:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'The Best Man Holiday at 8:00 PM and The Fifth Estate at 10:00 PM in Love Auditorium on Friday, Jan 31th.'||chr(10)||'On Saturday Feb 1st: The Fifth Estate at 7:00PM and The Best Man Holiday at 10:00 PM'||chr(10)||' '||chr(10)||'The Best Man Holiday (Fri 8:00PM and Sat 10:00PM)'||chr(10)||'When college friends reunite after 15 years over the Christmas holidays, they discover just how easy it is for long-forgotten rivalries and romances to be reignited.'||chr(10)||' '||chr(10)||'The Fifth Estate (Fri 10:00 PM and sat 7:00PM)'||chr(10)||'A dramatic thriller based on real events that reveals the quest to expose the deceptions and corruptions of power that turned an Internet upstart into the 21st century''s most fiercely debated organization.',null);
insert into hudsonu.event values(403612,'CAB Take Two: Her',cast('2014-03-29 19:00' as date),cast('2014-03-29 20:15' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'About Time at 7:00PM and Her at 10:00 PM in Love Auditorium on Friday, Mar 28th.'||chr(10)||'On Saturday Mar 29th: Her at 7:00PM and About Time at 10:00 PM'||chr(10)||' '||chr(10)||'About Time (Fri 7:00PM and Sat 10:00PM)'||chr(10)||'Starring  Domhnall Gleeson, Rachel McAdams, Bill Nighy'||chr(10)||'At the age of 21, Tim discovers he can travel in time and change what happens and has happened in his own life. His decision to make his world a better place by getting a girlfriend turns out not to be as easy as you might think.'||chr(10)||'Her (Fri 10:00 PM and sat 7:00PM)'||chr(10)||'Starring Joaquin Phoenix, Amy Adams, Scarlett Johansson '||chr(10)||'A lonely writer develops an unlikely relationship with his newly purchased operating system that''s designed to meet his every need.',null);
insert into hudsonu.event values(404089,'Video Series - Why Democracy Matters: "Inequality for All"',cast('2014-04-10 16:30' as date),cast('2014-04-10 17:30' as date),'Lathrop 212',NULL,'Movie/Film','DM','Why should students care about the state of politics in America, or dysfunction in the government? In a series of three films, apolitical nonprofit Democracy Matters attempts to get to the root causes of everything from student debt to economic- and gender-based inequality, covering environmental spoilage and racial tensions along the way. April 10: Inequality for All April 17: The Corporation April 24: Priceless',null);
insert into hudsonu.event values(464297,'CAB Take Two movie: 22 Jump Street',cast('2014-09-12 19:00' as date),cast('2014-09-12 20:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'22 Jump Street at 7:00PM and Neighbors at 10:00 PM in Love Auditorium on Friday, Sep 12th.'||chr(10)||'On Saturday Sep 13th: Neighbors at 7:00PM and 22 Jump Street at 10:00 PM'||chr(10)||' '||chr(10)||'22 Jump Street (Fri 7:00PM and Sat 10:00PM) Click Here for the Trailer of 22 Jump Street!'||chr(10)||''||chr(10)||'Starring: Channing Tatum, Jonah Hill'||chr(10)||'After making their way through high school (twice), big changes are in store for officers Schmidt and Jenko when they go deep undercover at a local college.'||chr(10)||'Neighbors (Fri 10:00 PM and sat 7:00PM) Watch Neighbors trailer now!'||chr(10)||''||chr(10)||'Starring: Zac Efron, Seth Rogen, Rose Byrne'||chr(10)||'A couple with a newborn baby face unexpected difficulties after they are forced to live next to a fraternity house.',null);
