insert into hudsonu.event values(7026464,'Open Art-Making with the Senior Honor Society',cast('2021-04-13 20:00' as date),cast('2021-04-13 21:00' as date),'Hall of Presidents','Arts','Volunteer and Community Service ','THS','Join the Senior Honor Society Class of 2021 and 2022 to make some original artwork! Follow a guided lesson from a Hudson art professor in one side of the room or hang out and listen to music and work on independent pieces on the other side of the room. There will be Senior Honor Society members floating around to help guide you on technique, help you come up with ideas, and make art alongside you.',null);
