insert into hudsonu.event values(708370,'South Asian Game Night',cast('2015-10-17 20:00' as date),cast('2015-10-17 20:00' as date),'ALANA Cultural Center','Social',NULL,'SACC','Join the SACC for a night of Carom and Ludu, which are both time honored board games of South Asian origin. Learn how to play these simple but addictive games from seasoned players, enjoy good conversations and South Asian snacks. The whole campus body is invited to participate!'||chr(10)||' ',null);
