insert into hudsonu.event values(7407286,'Meet Your Class President!',cast('2021-09-25 11:00' as date),cast('2021-09-25 12:00' as date),'Practice Field','Social',NULL,'SAA','Class Council elections are being held THIS WEEK!! Don''t forget to VOTE!'||chr(10)||'Come meet your Class President at the Homecoming Tailgate under the Student Activities Association Tent! We''ll have amazing desserts from Curtain Call, a dunk booth, inflatable jousting, and some fun giveaways. '||chr(10)||'The Homecoming Tailgate will be taking place on the grass practice field on the west side of Andy Kerr Stadium. '||chr(10)||' '||chr(10)||' ',null);
