insert into hudsonu.event values(7583865,'Thrive Lunch: Menstrual Activism',cast('2021-11-04 12:00' as date),cast('2021-11-04 12:00' as date),'ALANA Cultural Center','Thoughtful Learning',NULL,'ALANA','Please join the ALAN Social Justice Peer Educators, Progress Period, and Shaw Wellness as we have a conversation about Menstrual Activism and dive into personal and cultural experiences this Thursday, November 4, from 12-1 pm in the ALANA Cultural Center. This event will be catered by RIG and is PE eligible! ',null);
insert into hudsonu.event values(7597999,'Queering Latinidad',cast('2021-11-11 19:00' as date),cast('2021-11-11 20:00' as date),'CAH','Cultural',NULL,'LASO','LASO and QTPOC come together during Hispanic Heritage Month to collaborate on an interactive educational event to honor the Queer Latin Icons of our histories! Join us for games of charades, education on Queer Icons of our generation and empandas!'||chr(10)||' ',null);
insert into hudsonu.event values(7608669,'Phi Delta Theta Blood Drive',cast('2021-12-02 12:00' as date),cast('2021-12-02 18:00' as date),'Hall of Presidents','Community Service','Philanthropy','PDT','Phi Delta Theta is hosting a blood drive in partnership with the Red Cross on December 2nd from 12:00-6:00 PM in the Hall of Presidents. Thank you for your support! ',null);
insert into hudsonu.event values(772318,'Konosioni Open Application Coffee Hour',cast('2015-12-01 21:00' as date),cast('2015-12-01 22:00' as date),'Case Guyer, 560 Batza Room','Thoughtful Learning',NULL,'THS','The Konosioni (Kono) Society hosts two annual coffee hours specifically targeted for Juniors who are interested in applying or learning more about Kono''s mission, goals, and membership application process. This is a great time for interested juniors to meet all of the current kono members and ask any questions or get first hand information about Kono from a variety of people. The purpose of having two coffee hours is to reach as many interested juniors as possible. We are a campus full of busy people, so we want to ensure that we are being inclusive throughout our entire application outreach process and accommodate for potential conflict. We only host two events because we believe that is the most fiscally reasonable and responsible. This proposal is for one coffee hour that we would like to have the day after applications open for the entire junior class.',null);
