insert into hudsonu.event values(8342020,'Welcome to Hudson Debate Society! (Interest Meeting)',cast('2022-09-09 16:30' as date),cast('2022-09-09 16:30' as date),'Lawrence 105','Thoughtful Learning',NULL,'DS','If you:'||chr(10)||'- Love to think critically and discuss important topics'||chr(10)||'- Want to gain skills in forming arguments, public speaking, and more'||chr(10)||'- Have won many arguments by yourself in the shower'||chr(10)||'- Or just plain love to debate'||chr(10)||'You should join Hudson Debate Society! '||chr(10)||'At this meeting, we will be providing information about Hudson Debate Society, including: '||chr(10)||'- What is British Parliamentary (BP) Debate?'||chr(10)||'- Travel opportunities (including two international tournaments!)'||chr(10)||'- Why debate? What''s the point?'||chr(10)||'- Meet the Eboard Officers and other members'||chr(10)||'No experience required! Please reach out with any questions! '||chr(10)||'Hope to see you there :)',null);
