insert into hudsonu.event values(9514573,'Meditation Night Hike',cast('2023-10-12 18:45' as date),cast('2023-10-12 19:30' as date),'Hudson Chapel House','Athletics',NULL,'HIKE','We are glad to announce that our next hiking club event will be on next Thursday October 12th at 6:45pm. After meeting outside of Frank, We will be walking up to the Chapel House where we will have a meditation session at 7pm before continuing up onto the XC trails for a night hike! Were looking forward to seeing you all there!'||chr(10)||'Bring a flashlight or headlamp if you have one, although a phone flashlight is probably good enough. '||chr(10)||'Join the Hiking Club Groupme here for up-to-date information on hiking club events-  https://groupme.com/join_group/89114067/leHjjOU5',null);
insert into hudsonu.event values(9619078,'Social Media Marketing - Lecture and Discussion',cast('2023-11-15 19:00' as date),cast('2023-11-15 20:00' as date),'Persson 210','Group Business',NULL,'HSMC','This will be a quick meeting going over the fundamentals of social media marketing. Anyone is welcome to join!',null);
insert into hudsonu.event values(9642606,'Festivus (for the Rest of Us)',cast('2023-12-02 14:00' as date),cast('2023-12-02 17:00' as date),'Coop TV Room','Cultural','Religious/Spiritual','SASS','Inspired by Seinfeld, Festivus (for the rest of us) is a secular holiday that aims to create a space away from the religiosity and consumerism of other winter holidays. We will have a large aluminum pole, an airing of the grievances, feats of strength, and a hearty meal, as tradition.'||chr(10)||'The event will take place Saturday, December 2nd, in the Coop TV Room from 2-4. Everyone is welcome, so please drop by!',null);
insert into hudsonu.event values(9866807,'Coffee Hour #3',cast('2024-04-01 19:00' as date),cast('2024-04-01 19:00' as date),'Case Geyer 560 Batza Room','Thoughtful Learning',NULL,'HWIB','Please join the Hudson Women in Business Organization for a monthly coffee hour to discuss different aspects of the field of business.  Meetings may include breakout sessions to discuss specific industries within the field of business, hearing tips from upperclassman who have experience in the business field, revising a resume or cover letter, speaking with alumni and established professions in the field of business, and more. ',null);
insert into hudsonu.event values(9866811,'Coffee Hour #2',cast('2024-03-04 19:00' as date),cast('2024-03-04 20:00' as date),'Case Geyer 560 Batza Room','Thoughtful Learning',NULL,'HWIB','Please join the Hudson Women in Business Organization for a monthly coffee hour to discuss different aspects of the field of business.  Meetings may include breakout sessions to discuss specific industries within the field of business, hearing tips from upperclassman who have experience in the business field, revising a resume or cover letter, speaking with alumni and established professions in the field of business, and more. ',null);
insert into hudsonu.event values(9949002,'Craft and Create: An Afternoon With LEGO and Circuits',cast('2024-02-16 14:30' as date),cast('2024-02-16 16:00' as date),'McGregory 314, Hamilton, New York','Social','Sustainability','HTT',NULL||chr(10)||'HELLO ROBOTICISTS,'||chr(10)||''||chr(10)||''||chr(10)||' '||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'GOOD AFTERNOON! Hope your guys'' weeks are going great! Just a quick reminder that our meeting will be on Friday 2:30-onwards at McGregory 314. Same place. Same time. This week, we''re inviting you and your friends to a laid-back yet engaging session where the simplicity of LEGO meets the innovation and the interactivity of Circuit Playgrounds.'||chr(10)||''||chr(10)||'',null);
insert into hudsonu.event values(735202,'French Club Coffee Hour',cast('2015-11-11 16:15' as date),cast('2015-11-11 17:00' as date),'Lawrence Hall 2nd floor','Cultural',NULL,'FC','Come enjoy a presentation on a Francophone topic with snacks included such as croissants every month with a Francophone film screening to follow that weekend.',null);
insert into hudsonu.event values(404759,'French Club Coffee Hour',cast('2014-09-17 16:15' as date),cast('2014-09-17 16:15' as date),'Lawrence 205',NULL,NULL,'FC','French Club Coffee Hours are meant to promote French language and culture in a non-academic environment. At each of the four Coffee Hours, French Club leaders give a presentation on an aspect of French culture, for example student life at French universities, followed by questions and vocabulary relevant to the topic to encourage conversation amongst participants. These questions are broad enough for all French speakers at any level to comprehend and elaborate on.'||chr(10)||'With Coffee Hours, participants can work on their French speaking skills outside of the classroom, while also learning more about French culture and meeting new people. We also provide French snacks, such as crepes and croissants, for participants get a taste of French cuisine that they might not get otherwise.',null);
insert into hudsonu.event values(168720,'Take Two: Seeking a Friend for the End of the World',cast('2012-09-08 19:00' as date),cast('2012-09-08 20:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','As an asteroid nears Earth, a man finds himself alone after his wife leaves in a panic. He decides to take a road trip to reunite with his high school sweetheart. Accompanying him is a neighbor who inadvertently puts a wrench in his plan.'||chr(10)||'Steve Carrell, Keira Knightly, and Melanie Lynskey; R; 101 min.; 2012.',null);
insert into hudsonu.event values(194091,'Take Two: Brave',cast('2012-10-26 22:00' as date),cast('2012-10-26 22:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','Determined to make her own path in life, Princess Merida defies a custom that brings chaos to her kingdom. Granted one wish, Merida must rely on her bravery and her archery skills to undo a beastly curse.'||chr(10)||'Kelly Macdonald, Billy Connolly and Emma Thompson; Rated PG; 100 min.; 2012.',null);
