insert into hudsonu.event values(281689,'CAB Take Two: Silver Linings Playbook',cast('2013-04-27 22:00' as date),cast('2013-04-27 22:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two present:'||chr(10)||'Silver Linings Playbook (Fri 7pm, Sat 3:30pm and 10pm) '||chr(10)||'After a stint in a mental institution, former teacher Pat Solitano moves back in with his parents and tries to reconcile with his ex-wife. Things get more challenging when Pat meets Tiffany, a mysterious girl with problems of her own.'||chr(10)||'The Hobbit: An Expected Journey (Fri 10pm, Sat 7pm) '||chr(10)||'A younger and more reluctant Hobbit, Bilbo Baggins, sets out on an "unexpected journey" to the Lonely Mountain with a spirited group of Dwarves to reclaim their stolen mountain home from a dragon named Smaug.'||chr(10)||' ',null);
insert into hudsonu.event values(285842,'CAB Take Two: The Great Gatsby',cast('2013-09-07 22:00' as date),cast('2013-09-07 22:45' as date),'Love Auditorium (Olin 300)',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: The Great Gatsby at 7:00PM and Now You See Me at 10:00PM in Love Auditorium on Friday, Sept 6th, and again at opposite times on Saturday, Sept 7th.'||chr(10)||'The Great Gatsby (Fri:7pm, Sat:10pm): A Midwestern war veteran finds himself drawn to the past and lifestyle of his millionaire neighbor.'||chr(10)||'Now You See Me (Fri:10 pm, Sat:pm): An FBI agent and an Interpol detective track a team of illusionists who pull off bank heists during their performances and reward their audiences with the money.    ',null);
insert into hudsonu.event values(289239,'CAB Take Two: The Lone Ranger',cast('2013-09-21 22:00' as date),cast('2013-09-21 22:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: The Lone Ranger at 7:00PM and This is the End at 10:00PM in Love Auditorium on Friday, Sept 20th, and again at opposite times in on Saturday, Sept 21st.'||chr(10)||'The Lone Ranger (Fri 7pm and Sat 10pm)'||chr(10)||'Native American warrior Tonto recounts the untold tales that transformed John Reid, a man of the law, into a legend of justice. (starring Johnny Depp, Armie Hammer, William Fichtner)'||chr(10)||'This is the End (Fri 10pm and Sat 7pm)'||chr(10)||'While attending a party at James Franco''s house, Seth Rogen, Jay Baruchel and many other celebrities are faced with the apocalypse. (starring James Franco, Jonah Hill, Seth Rogen)'||chr(10)||' '||chr(10)||'from imdb.com'||chr(10)||' ',null);
insert into hudsonu.event values(289251,'CAB Take Two: This is the End',cast('2013-09-20 22:00' as date),cast('2013-09-20 22:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: The Lone Ranger at 7:00PM and This is the End at 10:00PM in Love Auditorium on Friday, Sept 20th, and again at opposite times in on Saturday, Sept 21st.'||chr(10)||'The Lone Ranger (Fri 7pm and Sat 10pm)'||chr(10)||'Native American warrior Tonto recounts the untold tales that transformed John Reid, a man of the law, into a legend of justice. (starring Johnny Depp, Armie Hammer, William Fichtner)'||chr(10)||'This is the End (Fri 10pm and Sat 7pm)'||chr(10)||'While attending a party at James Franco''s house, Seth Rogen, Jay Baruchel and many other celebrities are faced with the apocalypse. (starring James Franco, Jonah Hill, Seth Rogen)'||chr(10)||' '||chr(10)||'from imdb.com'||chr(10)||' ',null);
insert into hudsonu.event values(314901,'CAB Take Two: Pacific Rim',cast('2013-10-18 19:00' as date),cast('2013-10-18 20:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Pacific Rim at 7:00PM and White House Down at 10:00PM in Love Auditorium on Friday, Oct 18th, and again at opposite times on Saturday, Oct 19th.'||chr(10)||'Pacific Rim (Fri 7pm/Sat 10pm)'||chr(10)||'As a war between humankind and monstrous sea creatures wages on, a former pilot and a trainee are paired up to drive a seemingly obsolete special weapon in a desperate effort to save the world from the apocalypse.'||chr(10)||' '||chr(10)||'White House Down (Fri 10pm/Sat 7pm)'||chr(10)||'While on a tour of the White House with his young daughter, a Capitol policeman springs into action to save his child and protect the president from a heavily armed group of paramilitary invaders.'||chr(10)||' ',null);
insert into hudsonu.event values(337524,'CAB Take Two: We''re the Millers',cast('2013-11-16 19:00' as date),cast('2013-11-16 21:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Elysium at 7:00PM and We''re the Millers at 10:00PM in Love Auditorium on Friday, Nov 15th, and again at opposite times on Saturday, Nov 16th.'||chr(10)||'Elysium (Fri 7pm and Sat 10pm)'||chr(10)||'In the year 2154, the very wealthy live on a man-made space station while the rest of the population resides on a ruined Earth. A man takes on a mission that could bring equality to the polarized worlds. '||chr(10)||'We''re the Millers (Fri 10pm and Sat 7pm)'||chr(10)||'A veteran pot dealer creates a fake family as part of his plan to move a huge shipment of weed into the U.S. from Mexico.',null);
insert into hudsonu.event values(365704,'CAB Take Two: The Fifth Estate',cast('2014-01-31 22:00' as date),cast('2014-01-31 23:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'The Best Man Holiday at 8:00 PM and The Fifth Estate at 10:00 PM in Love Auditorium on Friday, Jan 31th.'||chr(10)||'On Saturday Feb 1st: The Fifth Estate at 7:00PM and The Best Man Holiday at 10:00 PM'||chr(10)||' '||chr(10)||'The Best Man Holiday (Fri 8:00PM and Sat 10:00PM)'||chr(10)||'When college friends reunite after 15 years over the Christmas holidays, they discover just how easy it is for long-forgotten rivalries and romances to be reignited.'||chr(10)||' '||chr(10)||'The Fifth Estate (Fri 10:00 PM and sat 7:00PM)'||chr(10)||'A dramatic thriller based on real events that reveals the quest to expose the deceptions and corruptions of power that turned an Internet upstart into the 21st century''s most fiercely debated organization.',null);
insert into hudsonu.event values(380608,'CAB Take Two: The Hobbit 2',cast('2014-03-07 19:00' as date),cast('2014-03-07 21:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'The Hobbit: The Desolation of Smaug at 7:00PM and Frozen at 10:00 PM in Love Auditorium on Friday, Mar 7th.'||chr(10)||'On Saturday Mar 8th: Frozen at 7:00PM and The Hobbit: The Desolation of Smaug at 10:00 PM'||chr(10)||' '||chr(10)||'The Hobbit: The Desolation of Smaug (Fri 8:00PM and Sat 10:00PM)'||chr(10)||'Starring Ian McKellen, Martin Freeman, Richard Armitage'||chr(10)||'The dwarves, along with Bilbo Baggins and Gandalf the Grey, continue their quest to reclaim Erebor, their homeland, from Smaug. Bilbo Baggins is in possession of a mysterious and magical ring. '||chr(10)||'Frozen (Fri 10:00 PM and sat 7:00PM)'||chr(10)||'Starring  Kristen Bell, Josh Gad, Idina Menzel'||chr(10)||' '||chr(10)||'Fearless optimist Anna teams up with Kristoff in an epic journey, encountering Everest-like conditions, and a hilarious snowman named Olaf in a race to find Anna''s sister Elsa, whose icy powers have trapped the kingdom in eternal winter.',null);
insert into hudsonu.event values(464303,'Neighbors',cast('2014-09-12 22:00' as date),cast('2014-09-12 23:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'22 Jump Street at 7:00PM and Neighbors at 10:00 PM in Love Auditorium on Friday, Sep 12th.'||chr(10)||'On Saturday Sep 13th: Neighbors at 7:00PM and 22 Jump Street at 10:00 PM'||chr(10)||' '||chr(10)||'22 Jump Street (Fri 7:00PM and Sat 10:00PM) Click Here for the Trailer of 22 Jump Street!'||chr(10)||''||chr(10)||'Starring: Channing Tatum, Jonah Hill'||chr(10)||'After making their way through high school (twice), big changes are in store for officers Schmidt and Jenko when they go deep undercover at a local college.'||chr(10)||'Neighbors (Fri 10:00 PM and sat 7:00PM) Watch Neighbors trailer now!'||chr(10)||''||chr(10)||'Starring: Zac Efron, Seth Rogen, Rose Byrne'||chr(10)||'A couple with a newborn baby face unexpected difficulties after they are forced to live next to a fraternity house.',null);
insert into hudsonu.event values(476915,'CAB Take Two Midnight Movie: Maze Runner',cast('2014-09-19 11:45' as date),cast('2014-09-20 01:00' as date),'Hamilton Theatre',NULL,'Movie/Film','SAA','CAB Take Two Presents Midnight Movie: Maze Runner'||chr(10)||'Come to Hamilton Theatre at 11:45 PM on Friday (Sep. 19) and enjoy the brand new movie Maze Runner!!! '||chr(10)||'Free Slices Pizza and Pop Corn served! '||chr(10)||'Maze Runner Friday Sep. 19 11:45 PM'||chr(10)||'Starring Dylan O''Brien, Kaya Scodelario, Will Poulte.'||chr(10)||'Thomas is deposited in a community of boys after his memory is erased, soon learning they''re all trapped in a maze that will require him to join forces with fellow "runners" for a shot at escape.',null);
insert into hudsonu.event values(477344,'CAB Take Two: A Million Ways to Die in the West',cast('2014-09-27 19:00' as date),cast('2014-09-27 20:30' as date),'COOP',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'Jersey Boys at 7:00PM and A Million Ways to Die in the West at 10:00 PM in COOP on Friday, Sep 26th.'||chr(10)||'On Saturday Sep 27th: A Million Ways to Die in the West at 7:00PM and Jersey Boys at 10:00 PM'||chr(10)||' '||chr(10)||'Jersey Boys (Fri 7:00PM and Sat 10:00PM) Click here for the trailer of Jersey Boys'||chr(10)||'Starring: John Lloyd Young, Erich Bergen, Michael Lomenda'||chr(10)||'The story of four young men from the wrong side of the tracks in New Jersey who came together to form the iconic 1960s rock group The Four Seasons.'||chr(10)||'A Million Ways to Die in the West (Fri 10:00 PM and sat 7:00PM) Watch the trailer for A Million Ways to Die in the West here!'||chr(10)||'Starring: Seth MacFarlane, Charlize Theron, Liam Neeson'||chr(10)||'As a cowardly farmer begins to fall for the mysterious new woman in town, he must put his new-found courage to the test when her husband, a notorious gun-slinger, announces his arrival.',null);
