insert into hudsonu.event values(289237,'CAB Take Two: The Lone Ranger',cast('2013-09-20 19:00' as date),cast('2013-09-20 20:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: The Lone Ranger at 7:00PM and This is the End at 10:00PM in Love Auditorium on Friday, Sept 20th, and again at opposite times in on Saturday, Sept 21st.'||chr(10)||'The Lone Ranger (Fri 7pm and Sat 10pm)'||chr(10)||'Native American warrior Tonto recounts the untold tales that transformed John Reid, a man of the law, into a legend of justice. (starring Johnny Depp, Armie Hammer, William Fichtner)'||chr(10)||'This is the End (Fri 10pm and Sat 7pm)'||chr(10)||'While attending a party at James Franco''s house, Seth Rogen, Jay Baruchel and many other celebrities are faced with the apocalypse. (starring James Franco, Jonah Hill, Seth Rogen)'||chr(10)||' '||chr(10)||'from imdb.com'||chr(10)||' ',null);
insert into hudsonu.event values(299677,'CAB Take Two: Hangover 3',cast('2013-09-27 19:00' as date),cast('2013-09-27 20:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Hangover 3 at 7:00PM and Fast and Furious 6 at 10:00PM in Love Auditorium on Friday, Sept 27th, and again at opposite times in on Saturday, Sept 28th.'||chr(10)||'Hangover 3 (Starring Bradley Cooper, Zach Galifianakis, Ed Helms)'||chr(10)||'When one of their own is kidnapped by an angry gangster, the Wolf Pack must track down Mr. Chow, who has escaped from prison and is on the lam.'||chr(10)||'Fast and Furious 6 (Starring Vin Diesel, Paul Walker, Dwayne Johnson)'||chr(10)||'Hobbs has Dom and Brian reassemble their crew in order to take down a mastermind who commands an organization of mercenary drivers across 12 countries. Payment? Full pardons for them all.'||chr(10)||' '||chr(10)||' ',null);
insert into hudsonu.event values(302814,'CAB Take Two: Monster''s University',cast('2013-10-05 19:00' as date),cast('2013-10-05 20:15' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Despicable Me 2 at 7:00PM and Monsters University at 10:00PM in Love Auditorium on Friday, Oct 4th, and again at opposite times on Saturday, Oct 5th.'||chr(10)||'Despicable Me 2 (Fri 7pm/Sat 10pm)'||chr(10)||'Gru is recruited by the Anti-Villain League to help deal with a powerful new super criminal.'||chr(10)||'Monster''s University (Fri 10pm/Sat 7pm)'||chr(10)||'A look at the relationship between Mike and Sulley during their days at Monsters University -- when they weren''t necessarily the best of friends.'||chr(10)||' ',null);
insert into hudsonu.event values(314899,'CAB Take Two: Kick-Ass 2',cast('2013-11-01 22:00' as date),cast('2013-11-01 22:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: R.I.P.D. at 7:00PM and Kick-Ass 2 at 10:00PM in Love Auditorium on Friday, Nov 1st, and again at opposite times on Saturday, Nov 2nd.'||chr(10)||' '||chr(10)||'R.I.P.D. (Fri 7pm and Sat 10pm)'||chr(10)||'A recently slain cop joins a team of undead police officers working for the Rest in Peace Department and tries to find the man who murdered him.'||chr(10)||' '||chr(10)||'Kick-Ass 2 (Fri 10pm and Sat 7pm)'||chr(10)||'The costumed high-school hero Kick-Ass joins with a group of normal citizens who have been inspired to fight crime in costume. Meanwhile, the Red Mist plots an act of revenge that will affect everyone Kick-Ass knows.'||chr(10)||' '||chr(10)||' ',null);
insert into hudsonu.event values(337521,'CAB Take Two: Elysium',cast('2013-11-16 22:00' as date),cast('2013-11-16 23:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Elysium at 7:00PM and We''re the Millers at 10:00PM in Love Auditorium on Friday, Nov 15th, and again at opposite times on Saturday, Nov 16th.'||chr(10)||'Elysium (Fri 7pm and Sat 10pm)'||chr(10)||'In the year 2154, the very wealthy live on a man-made space station while the rest of the population resides on a ruined Earth. A man takes on a mission that could bring equality to the polarized worlds. '||chr(10)||'We''re the Millers (Fri 10pm and Sat 7pm)'||chr(10)||'A veteran pot dealer creates a fake family as part of his plan to move a huge shipment of weed into the U.S. from Mexico.',null);
insert into hudsonu.event values(365709,'CAB Take Two: Rush',cast('2014-02-08 19:00' as date),cast('2014-02-08 21:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Moviespresents: Last Vegas at 7:00PM and Rushat 10:00PM in Love Auditoriumon Friday, Feb 7th, and again at opposite times on Saturday, Feb 8th.'||chr(10)||' '||chr(10)||'Last Vegas (Fri 7PM and Sat 10PM)'||chr(10)||'Three sixty-something friends take a break from their day-to-day lives to throw a bachelor party in Las Vegas for their last remaining single pal. '||chr(10)||' '||chr(10)||'Rush (Fri 10PM and Sat 7PM)'||chr(10)||'The merciless 1970s rivalry between Formula One rivals James Hunt and Niki Lauda.'||chr(10)||' '||chr(10)||' ',null);
insert into hudsonu.event values(477341,'CAB Take Two: Jersey Boys',cast('2014-09-26 19:00' as date),cast('2014-09-26 20:30' as date),'COOP',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'Jersey Boys at 7:00PM and A Million Ways to Die in the West at 10:00 PM in COOP on Friday, Sep 26th.'||chr(10)||'On Saturday Sep 27th: A Million Ways to Die in the West at 7:00PM and Jersey Boys at 10:00 PM'||chr(10)||' '||chr(10)||'Jersey Boys (Fri 7:00PM and Sat 10:00PM) Click here for the trailer of Jersey Boys'||chr(10)||'Starring: John Lloyd Young, Erich Bergen, Michael Lomenda'||chr(10)||'The story of four young men from the wrong side of the tracks in New Jersey who came together to form the iconic 1960s rock group The Four Seasons.'||chr(10)||'A Million Ways to Die in the West (Fri 10:00 PM and sat 7:00PM) Watch the trailer for A Million Ways to Die in the West here!'||chr(10)||'Starring: Seth MacFarlane, Charlize Theron, Liam Neeson'||chr(10)||'As a cowardly farmer begins to fall for the mysterious new woman in town, he must put his new-found courage to the test when her husband, a notorious gun-slinger, announces his arrival.',null);
