insert into hudsonu.event values(1136046,'Interfaith Dinner',cast('2017-04-06 18:00' as date),cast('2017-04-06 18:00' as date),'Chapel Basement','Thoughtful Learning','Religious/Spiritual','NC','The Interfaith Dinners are an opportunity for students to come together, talk about their different beliefs and share a meal. Each dinner has a theme and discussion of this theme is co-led by members from two different Chaplaincy groups. This discussion-based style allows students who attend to participate during the dinner. These dinners have been extremely successful in the past.',null);
