insert into hudsonu.event values(521094,'Polynesian Awareness Week',cast('2014-11-10 11:00' as date),cast('2014-11-14 19:00' as date),'ALANA Cultural Center','Cultural',NULL,'ALANA','Do you know where Samoa is? What about Tonga, Aotearoa, or Tahiti? And what, if anything, do these places have to do with Hawaii? If you didnt know: they are all located in the Polynesian Triangle, and their specific peoples are known as Polynesians. The ALANA Cultural Center, Native American Studies Department, Office of Residential Life, and Hawaii Club have joined together to host the first-ever Polynesian Awareness Week! From Monday, November 10 through Friday, November 14, please join in on the fun and culturally immersive activities planned, and while youre at it learn about a new culture or two!Monday 11/10 (11a-1p): Polynesian Awareness Week Kick-Off in the Coop.Tuesday 11/11 (5p-7p): Tongan Cooking Demo facilitated by Salote Tenisi in the ALANA kitchen.Wednesday 11/12 (5p-7p): Hula/Tahitian Dance Workshop taught by Lokelani Cummings in the ALANA Cultural Center. Yummy snacks will be provided!Thursday 11/13 (7p-9p): "Hawaiian as a Culture" Dinner Discussion. Come join in on the conversation revolving around cultural appropriation and how it affects people of Native Hawaiian descent. This event will be catered by Oliveri''s, featuring assorted apps and pasta dishes.Friday 11/14 (5p-7p): Aloha Friday Paina! Join us in the MPR room of ALANA to celebrate a successful week of cultural education! Music, dancing, food, and friendships will be plentiful!',null);
insert into hudsonu.event values(564181,'Tea Club Study Break',cast('2015-05-05 19:30' as date),cast('2015-05-05 20:30' as date),'Coop Main Lounge/Fireplace','Cultural',NULL,'TTC','Take a break from finals to enjoy a well-needed break from the clamor of final exams, as well as some of the best East-Asian tea Hudson has to offer (for free!). Drop by the Coop fireplace room anytime between 7:30 and 9:30 PM to enjoy this event. Highly recommended for those who are planning to stay up late!',null);
insert into hudsonu.event values(619702,'Beyond Ebola',cast('2015-04-02 11:30' as date),cast('2015-04-02 11:30' as date),'Lawrence 205, Hudson University','Thoughtful Learning',NULL,'HGHC','Beyond Ebola: Emerging Infectious Diseases and the Future of U.S. Public HealthFears of Ebola in the U.S. have faded, but does that mean Americans can stop worrying about infectious disease? In this brown bag lecture, Prof. Geoff Holm will discuss other emerging diseases, and what the (near) future may hold for the U.S. public health system.',null);
insert into hudsonu.event values(623085,'Interfaith Dinners',cast('2015-12-03 18:00' as date),cast('2015-12-03 19:00' as date),'Chapel Basement','Thoughtful Learning',NULL,'NC','The Interfaith Dinners are an opportunity for students to come together, talk about their different beliefs and share a meal. Each dinner has a theme and there are discussions or presentations that are related to that theme for students to participate in during the dinner. These dinners have been extremely successful in the past.',null);
