insert into hudsonu.event values(7021105,'Tea Club X Korean Culture Association',cast('2021-03-26 15:00' as date),cast('2021-03-26 15:30' as date),'Alana Cultural Center','Cultural',NULL,'KCA','Tea Club will be distributing pre-packaged Korean Snacks to a group of students who sign up. The Pre-packaged tea and snacks will be distributed at ALANA via the tea club and KCA core. All items will be pre-packaged and officers will be distributing the items while wearing gloves and masks. People will come in during their assigned time and will collect their items and then attend the cultural event, where KCA will present about Korean tea, on Zoom. ',null);
