insert into hudsonu.event values(7939030,'Red Cross Blood Drive',cast('2022-02-03 12:00' as date),cast('2022-02-03 18:00' as date),'Hall of Presidents','Fundraising','Philanthropy','PDT','Red Cross will be coming to the Hall of Presidents on February 3, 2022 to collect blood donations. Anyone is welcome to donate.',null);
insert into hudsonu.event values(798448,'Torchlight Brown Bag',cast('2015-11-12 12:00' as date),cast('2015-11-12 13:30' as date),'ALANA Multipurpose Room','Thoughtful Learning',NULL,'THS','The Konosioni Senior Honor Society is proud to host the Torchlight Brown Bag. This event will begin with the history of the Torchlight Ceremony at Hudson: when and why it began. From there, concerns, thoughts, and feelings over the ceremony will be acknowledged and open for discussion. We hope to generate dialogue on what this tradition means to the Hudson community today. Join us to add to the conversation! ',null);
insert into hudsonu.event values(8603063,'Kathak Dance Workshop',cast('2022-11-18 11:30' as date),cast('2022-11-18 16:00' as date),'301 Huntington Gymnasium (Session 1) or Chapel (Session 2)','Arts','Concert/Music','HINDU','Kathak is a versatile Indian classical dance form with challenging footwork, expressive facial expressions, and graceful hand movements. As kathaka means storyteller, performers convey stories through dance and offer entertainment in both religious and non-religious settings. In an interactive workshop, kathak artist and guru Pallavi Degwekar will discuss the history of kathak, introspection via music, math through rhythm, as well as teach beginner-level movements and spin techniques. '||chr(10)||'Please join us in celebrating this art form. Snacks will be catered by Royal Indian Grill. All are welcome and please register! Session 1 is 11:30-1:00 at 301 Huntington. Session 2 is 2:30-4:00 at Chapel.',null);
insert into hudsonu.event values(8840569,'Spring 2023 Public Health Seminar: Patients, Providers, and the Experience of Care in the United States',cast('2023-02-02 12:00' as date),cast('2023-02-02 13:00' as date),'Batza Room','Thoughtful Learning',NULL,'HGHC','Please join us on Tuesday, February 7, from 5-7 pm in the Batza Room, for the Global Health Coalition''s Spring 2023 Public Health Seminar Health Inequality: Patients, Providers, and the Experience of Care in the United States by Professor Rebecca Upton. This event is co-sponsored by the Global Public and Environmental Health Program and the Hudson Pre-Health Pathways. ',null);
insert into hudsonu.event values(9041575,'13 Days of Green - ALANA Spring Cleaning Swap',cast('2023-04-11 16:30' as date),cast('2023-04-11 19:30' as date),'ALANA Multipurpose Room','Community Service','Sustainability','COVE','Join us for the Spring Cleaning Swap hosted by ALANA and the Office of Sustainability.'||chr(10)||'Everyone is welcome to bring usable household goods, books, and clothes to ALANA during the donation drop-off time, and then come back to shop FOR FREE that evening!'||chr(10)||'By circulating reusable items, we can decrease our landfill waste at move-out, support fellow students needing items, and build connections within our community.'||chr(10)||'Donation Drop-off: 4:30 p.m. to 6:30 p.m.'||chr(10)||'Free Sale: 7 p.m. to 8:30 p.m.'||chr(10)||'Items accepted must be small enough to be carried by one person. Examples include:'||chr(10)||''||chr(10)||'Household items, such as hangers, plants, table fans, extension cords, etc.'||chr(10)||'Kitchen goods, such as pans, silverware, small appliances, etc.'||chr(10)||'Room decor, such as posters, tapestries, string lights, etc.'||chr(10)||'Clothing, including shoes and accessories'||chr(10)||''||chr(10)||'This event is part of the Office of Sustainabilitys 13 Days of Green series leading up to Earth Day.',null);
insert into hudsonu.event values(909288,'Real Talk with Diane Ciccone',cast('2016-03-10 18:00' as date),cast('2016-03-10 19:30' as date),'Love Auditorium','Cultural',NULL,'SRT','Every year SORT hosts a series of events called Africana Womens Week in celebration of women of color, their diverse narratives, and their accomplishments. This years Africana Womens Week Keynote speaker is Diane Ciccone. Diane was not only a part of the first class of women to graduate from Hudson, but also one of the few black women.  Diane Ciccone has been an advocate for students of color and a support system for women of  color on Hudsons campus.  SORT invites all of Hudson campus to hear Dianes Story.'||chr(10)||' ',null);
insert into hudsonu.event values(9511261,'Farm To Table Dinner',cast('2023-10-16 16:30' as date),cast('2023-10-16 17:30' as date),'Chapel House','Social','Sustainability','CH','Attention all chefs, gardeners, or foodies: Come get cozy at Chapel House, learn how to make a beautiful soup, and delight in the fruits of your labor! Ingredients used will come from Hudson''s own organic garden. Email Kathy (kkeyes@hudson.edu) if youd like to come. Space is limited.',null);
insert into hudsonu.event values(9824414,'Cupid''s Fever: Sex Toys Bingo',cast('2024-02-14 18:30' as date),cast('2024-02-14 20:30' as date),'COOP','Social',NULL,'ALANA','Welcome to another Sex Toys Bingo!'||chr(10)||'We would like to invite you to our annual Cupid''s Fever to celebrate Valentine''s Day. A lot of prizes (sex toys) await you along with the great information about healthy relationships, sexual pleasure, intimate hygiene, various body practices, and more!'||chr(10)||'Desserts, pastries, chocolate-covered strawberries and other aphrodisiacs will be served. '||chr(10)||'Grab a friend, partner, date, peer and come to enjoy cupid''s festivities and 15 rounds of bingo.'||chr(10)||'This event is being held in partnership with Shaw Wellness Institute, ALANA Cultural Center, First @ Hudson, Health and Wellness, Haven, Office of Equity and Diversity. ',null);
insert into hudsonu.event values(8992318,'Pride Walk',cast('2023-03-29 18:30' as date),cast('2023-03-29 18:30' as date),'Center for Women''s Studies','Social',NULL,'HRPB','Join us for our 2023 Pride Walk led by our own Pep Band as we celebrate Queer Fest Week. '||chr(10)||'This year Queer Fest''s theme (as well as of the Lavender Graduation) is "With Pride We Thrive." This is a reminder to all of us that every single voice matters and that every single step we take in supporting each other fills the gap in the bridge of allyship. Following the maroon brick road, we must proceed with courage, patience, and pride - finding a place in our hearts for everyone. Pride is not only a feeling of being comfortable with who we are, but this is also a practice of sharing the confidence with others in need. By embracing this understanding of Pride, we will keep thriving for the decades to come.'||chr(10)||'The walk will begin at the Center for Women''s Studies and end at the Rainbow Room.',null);
insert into hudsonu.event values(735198,'French Club Coffee Hour and Film Screenings',cast('2015-09-23 16:15' as date),cast('2015-09-23 16:00' as date),'Lawrence Hall 2nd floor','Cultural',NULL,'FC','Come enjoy a presentation on a Francophone topic with snacks included such as croissants every month with a Francophone film screening to follow that weekend.',null);
