insert into hudsonu.event values(289240,'CAB Take Two: This is the End',cast('2013-09-21 19:00' as date),cast('2013-09-21 20:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: The Lone Ranger at 7:00PM and This is the End at 10:00PM in Love Auditorium on Friday, Sept 20th, and again at opposite times in on Saturday, Sept 21st.'||chr(10)||'The Lone Ranger (Fri 7pm and Sat 10pm)'||chr(10)||'Native American warrior Tonto recounts the untold tales that transformed John Reid, a man of the law, into a legend of justice. (starring Johnny Depp, Armie Hammer, William Fichtner)'||chr(10)||'This is the End (Fri 10pm and Sat 7pm)'||chr(10)||'While attending a party at James Franco''s house, Seth Rogen, Jay Baruchel and many other celebrities are faced with the apocalypse. (starring James Franco, Jonah Hill, Seth Rogen)'||chr(10)||' '||chr(10)||'from imdb.com'||chr(10)||' ',null);
