insert into hudsonu.event values(338852,'CAB Take Two: One Direction: This is Us',cast('2013-12-06 22:00' as date),cast('2013-12-06 23:45' as date),'love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: The Mortal Instruments: City of Bones at 7:00PM and One Direction: This is Us at 10:00PM in Love Auditorium on Friday, Dec 6th, and again at opposite times on Saturday, Dec 7th.'||chr(10)||'The Mortal Instruments: City of Bones (Fri 7pm and Sat 10pm)'||chr(10)||'When her mother disappears, Clary Fray learns that she descends from a line of warriors who protect our world from demons. She joins forces with others like her and heads into a dangerous alternate New York called Downworld.'||chr(10)||'One Direction: This is Us (Fri 10pm and Sat 7pm)'||chr(10)||'A look at Niall, Zayn, Liam, Louis, and Harry''s meteoric rise to fame, from their humble hometown beginnings and competing on the X-Factor, to conquering the world and performing at London''s famed O2 Arena.',null);
insert into hudsonu.event values(338856,'CAB Take Two: The Mortal Instruments',cast('2013-12-06 19:00' as date),cast('2013-12-06 21:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: The Mortal Instruments: City of Bones at 7:00PM and One Direction: This is Us at 10:00PM in Love Auditorium on Friday, Dec 6th, and again at opposite times on Saturday, Dec 7th.'||chr(10)||'The Mortal Instruments: City of Bones (Fri 7pm and Sat 10pm)'||chr(10)||'When her mother disappears, Clary Fray learns that she descends from a line of warriors who protect our world from demons. She joins forces with others like her and heads into a dangerous alternate New York called Downworld.'||chr(10)||'One Direction: This is Us (Fri 10pm and Sat 7pm)'||chr(10)||'A look at Niall, Zayn, Liam, Louis, and Harry''s meteoric rise to fame, from their humble hometown beginnings and competing on the X-Factor, to conquering the world and performing at London''s famed O2 Arena.',null);
insert into hudsonu.event values(345592,'The 13th Annual Green Summit',cast('2014-02-06 17:30' as date),cast('2014-02-06 19:30' as date),'Ho Atrium',NULL,'Sustainability','GEG','The Green Summit aims to gather Hudson students, professors, faculty, and Hamilton Community members for a two hour long event that will function as a think tank for environmental action in the Hudson area. There will be approximately eight groups that will have a green project that they hope to get accomplished by the end of the year. We will have existing green groups present in addition to new initiatives. All groups will utilize the Green Summit event as a way to propel their group with a clearly outlined plan of action. With a diverse population participating, we will increase the momentum of the established groups, while also jump-starting some new ones at the same time. This event will be held in the Ho Atrium on February 6th 2014 at 6PM. '||chr(10)||'We hope that every group will create a substantial action plan that will ultimately end up with its completion end of the semester/early spring semester in time for the annual green awards in which these groups will be recognized. We also hope that our new initiatives will be successful and follow through into whatever capacity they feel important.'||chr(10)||' ',null);
insert into hudsonu.event values(346159,'"Trashed" presented by Students for Environmental Action',cast('2014-02-19 19:00' as date),cast('2014-02-19 21:00' as date),'Ho 101',NULL,'Movie/Film','SEA','The 2012 documentary "Trashed" looks at the impacts of air, land, and water pollution at the global scale, specifically pollution caused by human overconsumption and waste.  The Students for Environmental Action spring film series will be continued with "Plasticized", a film about plastic pollution in the South Atlantic, next week.',null);
insert into hudsonu.event values(365703,'CAB Take Two: The Best Man Holiday',cast('2014-01-31 20:00' as date),cast('2014-01-31 22:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'The Best Man Holiday at 8:00 PM and The Fifth Estate at 10:00 PM in Love Auditorium on Friday, Jan 31th.'||chr(10)||'On Saturday Feb 1st: The Fifth Estate at 7:00PM and The Best Man Holiday at 10:00 PM'||chr(10)||' '||chr(10)||'The Best Man Holiday (Fri 8:00PM and Sat 10:00PM)'||chr(10)||'When college friends reunite after 15 years over the Christmas holidays, they discover just how easy it is for long-forgotten rivalries and romances to be reignited. '||chr(10)||' '||chr(10)||'The Fifth Estate (Fri 10:00 PM and sat 7:00PM)'||chr(10)||'A dramatic thriller based on real events that reveals the quest to expose the deceptions and corruptions of power that turned an Internet upstart into the 21st century''s most fiercely debated organization.',null);
insert into hudsonu.event values(403607,'CAB Take Two Midnight Movie: Captain America 2',cast('2014-04-05 00:00' as date),cast('2014-04-05 01:00' as date),'Hamilton Theater',NULL,'Movie/Film','SAA','CAB Take Two presents Midnight Movie: Captain America: The Winter Soldier on April 5th, 12:00AM (Friday night) in Hamilton Theater'||chr(10)||'Captain America: The Winter Soldier (2014)'||chr(10)||'Starring Chris Evans, Samuel J. Jackson, Scarlett Johansson, and Sebastian Stan'||chr(10)||'Steve Rogers struggles to embrace his role in the modern world and battles a new threat from old history: the Soviet agent known as the Winter Soldier.'||chr(10)||'Free admission, pizza, and pop-corn with HUES Card.'||chr(10)||'Ware your super-hero outfit and win a prize!'||chr(10)||' ',null);
insert into hudsonu.event values(403610,'CAB Take Two: About Time',cast('2014-03-29 22:00' as date),cast('2014-03-29 22:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'About Time at 7:00PM and Her at 10:00 PM in Love Auditorium on Friday, Mar 28th.'||chr(10)||'On Saturday Mar 29th: Her at 7:00PM and About Time at 10:00 PM'||chr(10)||' '||chr(10)||'About Time (Fri 7:00PM and Sat 10:00PM)'||chr(10)||'Starring  Domhnall Gleeson, Rachel McAdams, Bill Nighy'||chr(10)||'At the age of 21, Tim discovers he can travel in time and change what happens and has happened in his own life. His decision to make his world a better place by getting a girlfriend turns out not to be as easy as you might think.'||chr(10)||'Her (Fri 10:00 PM and sat 7:00PM)'||chr(10)||'Starring Joaquin Phoenix, Amy Adams, Scarlett Johansson '||chr(10)||'A lonely writer develops an unlikely relationship with his newly purchased operating system that''s designed to meet his every need.',null);
