insert into hudsonu.event values(206945,'Take Two: Total Recall',cast('2012-11-30 22:00' as date),cast('2012-12-01 00:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','Last set of Take Two Movies for the semester!'||chr(10)||'A factory worker, Douglas Quaid, begins to suspect that he is a spy after visiting Rekall - a company that provides its clients with implanted fake memories of a life they would like to have led - goes wrong and he finds himself on the run.'||chr(10)||'Colin Farrell, Bokeem Woodbine and Bryan Cranston; 2012; Rated PG-13; 118 min.',null);
