insert into hudsonu.event values(233080,'CAB Take Two: Les Miserables',cast('2013-03-01 22:00' as date),cast('2013-03-01 23:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two presents Les Miserables:'||chr(10)||'In 19th-century France, Jean Valjean, who for decades has been hunted by the ruthless policeman Javert after he breaks parole, agrees to care for factory worker Fantine''s daughter, Cosette. The fateful decision changes their lives forever.'||chr(10)||'from imdb.com.'||chr(10)||' ',null);
