insert into hudsonu.event values(376249,'CAB Take Two: Hunger Games Marathon',cast('2014-02-15 19:00' as date),cast('2014-02-15 23:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two presents Hunger Games Marathon on Saturday night starting at 7pm.'||chr(10)||'Re-visit the exciting adventures of Katniss Everdeen!'||chr(10)||'Hunger Games Sat 7 pm'||chr(10)||'Katniss Everdeen voluntarily takes her younger sister''s place in the Hunger Games, a televised fight to the death in which two teenagers from each of the twelve Districts of Panem are chosen at random to compete.'||chr(10)||'Catching Fire Sat 9:30pm'||chr(10)||' '||chr(10)||'Katniss Everdeen and Peeta Mellark become targets of the Capitol after their victory in the 74th Hunger Games sparks a rebellion in the Districts of Panem.',null);
insert into hudsonu.event values(403629,'"Sons of Lwala" Film Screening',cast('2014-04-02 19:00' as date),cast('2014-04-02 19:00' as date),'Persson Auditorium',NULL,'Movie/Film','HGHC','Dr. Fred Ochieng and his brother, Dr. Milton Ochieng, started a community health clinic in their village of Lwala, Kenya after losing both of their parents to AIDS. This 45 minute documentary depicts their journey as they open their clinic and documents some of the amazing work that they have done to improve health outcomes in their village. Dr. Fred Ochieng was the keynote speaker at the Wolk Medical Conference this semester. Pizza will be served.',null);
insert into hudsonu.event values(467873,'The Departed',cast('2014-10-18 17:00' as date),cast('2014-10-18 18:00' as date),'Golden Auditorium, Little Hall','Arts','Movie/Film','HFS','Looking for a grueling crime thriller? Look no further! Come down to Golden Auditorium to watch Martin Scorcese''s The Departed.'||chr(10)||' '||chr(10)||'Description from IMDB: An undercover state cop who has infiltrated an Irish gang and a mole in the police force working for the same mob race to track down and identify each other before being exposed to the enemy, after both sides realize their outfit has a rat.',null);
insert into hudsonu.event values(521886,'Global health Initiative Film Screening: "The Human Experiment"',cast('2014-11-18 18:30' as date),cast('2014-11-18 20:30' as date),'Persson Auditorium','Thoughtful Learning','Movie/Film','HGHC','"The Human Experiment lifts the veil on the shocking reality that thousands of untested chemicals are in our everyday products, our homes and inside of us. Simultaneously, the prevalence of many diseases continues to rise. From Oscar winner Sean Penn and Emmy winning journalists Dana Nachman and Don Hardy, The Human Experiment tells the personal stories of people who believe their lives have been affected by chemicals and takes viewers to the front lines as activists go head-to-head with the powerful and well-funded chemical industry. These activists bring to light a corrupt system thats been hidden from consumers... until now"'||chr(10)||'Global Health Initiative will screen this film in Persson Auditorium at 6:30 and there will be pizza and garlic knots from VJs!'||chr(10)||' '||chr(10)||' '||chr(10)||' ',null);
insert into hudsonu.event values(742633,'Screening of Sundance Film Festival Hit: Dope',cast('2015-09-25 22:00' as date),cast('2015-09-25 22:45' as date),'Love Auditorium','Social',NULL,'SAA','Come watch the screening of the Sundance Film Festival hit, Dope! Showings are this weekend on Friday at 10PM and Saturday at 7PM in Love Auditorium!'||chr(10)||' '||chr(10)||'Synopsis:Life changes for Malcolm, a geek who''s surviving life in a tough neighborhood, after a chance invitation to an underground party leads him and his friends into a Los Angeles adventure.'||chr(10)||' '||chr(10)||' '||chr(10)||' ',null);
insert into hudsonu.event values(7887161,'Charade Screening',cast('2022-02-26 13:00' as date),cast('2022-02-26 15:30' as date),'020 Lawrence Auditorium','Cultural','Movie/Film','HFS','Come on down to Hudson Film Society''s first screening of the semester for a showing of Stanley Donen''s 1963 classic, Charade, starring Cary Grant and Audrey Hepburn!',null);
insert into hudsonu.event values(9044999,'13 Days of Green - Hamilton Movie Theatre Film Screening: "To The End"',cast('2023-04-17 19:00' as date),cast('2023-04-17 19:00' as date),'Hamilton Movie Theatre','Arts','Movie/Film','DM','The Hamilton Movie Theatre, The Vis Lab, the Democracy Matters Club, and the Office of Sustainability have joined forces to offer a screening of an award-winning environmental film, To The End. Tickets are free, so mark your calendars! Watch the trailer here.'||chr(10)||'Filmed over four years of hope and crisis, To the End captures the emergence of a new generation of leaders and the movement behind the most sweeping climate change legislation in U.S. history. The award-winning team behind Knock Down the House follows four exceptional young women  Rep. Alexandria Ocasio-Cortez, activist Varshini Prakash, climate policy writer Rhiana Gunn-Wright, and political strategist Alexandra Rojas as they grapple with new challenges of leadership and power and work together to defend their generations right to a future. From street protests to the halls of Congress, these bold leaders fight to shift the narrative around climate, revealing the crisis as an opportunity to build a better society. Including up-to-the-minute footage that culminates in 2022s landmark climate bill. To the End lifts the veil on the battle for the future of our world, and gives audiences a front seat view of history in the making.'||chr(10)||'This screening is part of the Office of Sustainabilitys 13 Days of Green series leading up to Earth Day. ',null);
insert into hudsonu.event values(1227655,'Africana Women''s Week(s) 2017',cast('2017-02-28 12:00' as date),cast('2017-03-08 20:00' as date),'Hudson University','Cultural',NULL,'SRT','Sisters of the Round Table (SORT) is a feminist organization whose mission is to provide a safe space for women of color to talk about issues that pertain to us locally and globally. Every Spring during the last week of February and the first week of March to celebrate the journey from Black history month to Women''s History month, we hold an event series entitled Africana Womens Week(s). SORT takes pride in strong sisterhood by providing outlets that foster bonding and support for women of color. A central component is to educate the community about the issues that women face. AWW will not only cover issues facing women but also issues surrounding inequality, identity, and inclusivity, thus attracting a diverse audience. SORT allows people from different backgrounds to discuss and bring awareness to these issues. These events will be a catalyst for greater and more meaningful discussions on campus. This year''s theme is Moving Past Survival; Healing as a Catalyst for Growth. Our feature keynote is: Diane Guerrero: known for her roles as inmate Maritza Ramos on the Netflix series Orange Is the New Black and Lina on Jane the Virgin. She is a strong and vocal advocate for immigration reform. Her role on Orange Is the New Black has twice contributed to wins for the Screen Actors Guild Award for Outstanding Performance by an Ensemble in a Comedy Series.',null);
insert into hudsonu.event values(1248472,'University Church Board Game Night',cast('2017-04-06 21:00' as date),cast('2017-04-06 23:00' as date),'Interfaith House','Social','Religious/Spiritual','UC','Enjoy a night of fellowship and fun with board games and dessert every Thursday, 9pm until midnight, at Interfaith House (104 Broad Street). Typical favorites include games like Avalon, Settlers of Catan, Blokus, Scrabble, and more! Feel free to bring your own games, as well. ',null);
insert into hudsonu.event values(189315,'Take Two: Ted',cast('2012-10-20 22:00' as date),cast('2012-10-20 23:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','As the result of a childhood wish, John Bennett''s teddy bear, Ted, came to life and has been by John''s side ever since - a friendship that''s tested when Lori, John''s girlfriend of four years, wants more from their relationship.'||chr(10)||'Mark Wahlberg, Mila Kunis and Seth MacFarlane'||chr(10)||'Rated R, 106 min, 2012.'||chr(10)||'from imdb.com',null);
insert into hudsonu.event values(189317,'Take Two: Moonrise Kingdom',cast('2012-10-19 22:00' as date),cast('2012-10-19 23:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','A pair of young lovers flee their New England town, which causes a local search party to fan out and find them.'||chr(10)||'Jared Gilman, Kara Hayward and Bruce Willis.'||chr(10)||'Rated PG-13, 94 min, 2012.'||chr(10)||'from imdb.com',null);
insert into hudsonu.event values(196141,'"Lost in Paradise" Movie Screening',cast('2012-11-15 19:00' as date),cast('2012-11-15 22:00' as date),'ALANA Multipurpose Room',NULL,'Movie/Film','HVS','Responding to the recent incident on campus during National Coming Out Week, Hudson Vietnam Society would like to present "Lost in Paradise," a "first Vietnamese gay film" and the winner of 2010 Technicolor Award (AFP). The story breaks new ground in its Vietnamese setting and the subject of homosexual relationship. Through this event, HVS would like to contribute in a meaningful way to the conversation on campus. It is also a way for non-Vietnamese Hudson students to learn about the emergence of the LGBTQ community in Vietnam in the last few years.',null);
insert into hudsonu.event values(196933,'Take Two: Batman Begins',cast('2012-11-02 19:00' as date),cast('2012-11-02 20:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','Bruce Wayne loses his philanthropic parents to a senseless crime, and years later becomes the Batman to save the crime-ridden Gotham City on the verge of destruction by an ancient order.'||chr(10)||'Christian Bale, Michael Caine and Ken Watanabe; Rated PG-13; 140 min.',null);
insert into hudsonu.event values(206946,'Take Two: Total Recall',cast('2012-12-01 19:00' as date),cast('2012-12-01 21:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','Last set of Take Two Movies for the semester!'||chr(10)||'A factory worker, Douglas Quaid, begins to suspect that he is a spy after visiting Rekall - a company that provides its clients with implanted fake memories of a life they would like to have led - goes wrong and he finds himself on the run.'||chr(10)||'Colin Farrell, Bokeem Woodbine and Bryan Cranston; 2012; Rated PG-13; 118 min.',null);
insert into hudsonu.event values(220014,'CAB Take Two: The Perks of Being a Wallflower',cast('2013-01-26 22:00' as date),cast('2013-01-26 23:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB take two presents The Perks of Being a Wallflower:'||chr(10)||'An introvert freshman is taken under the wings of two seniors who welcome him to the real world.'||chr(10)||'from imdb.com',null);
insert into hudsonu.event values(244416,'"American Meat" as part of SEA''s Environmental Film Series',cast('2013-03-25 19:00' as date),cast('2013-03-25 20:00' as date),'Love Auditorium',NULL,'Movie/Film','SEA','Screening of documentary American Meat followed by discussion with the director and panel. Food provided by Good Food Forum!',null);
insert into hudsonu.event values(281690,'CAB Take Two: The Hobbit',cast('2013-04-27 19:00' as date),cast('2013-04-27 20:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two present:'||chr(10)||'Silver Linings Playbook (Fri 7pm, Sat 3:30pm and 10pm) '||chr(10)||'After a stint in a mental institution, former teacher Pat Solitano moves back in with his parents and tries to reconcile with his ex-wife. Things get more challenging when Pat meets Tiffany, a mysterious girl with problems of her own.'||chr(10)||'The Hobbit: An Expected Journey (Fri 10pm, Sat 7pm) '||chr(10)||'A younger and more reluctant Hobbit, Bilbo Baggins, sets out on an "unexpected journey" to the Lonely Mountain with a spirited group of Dwarves to reclaim their stolen mountain home from a dragon named Smaug.'||chr(10)||' ',null);
insert into hudsonu.event values(292169,'Carl Sagan Day',cast('2013-11-09 16:00' as date),cast('2013-11-09 18:00' as date),'Persson 027',NULL,'Movie/Film','SASS','Join us in celebration of one of the best science educators there has ever been. We will watch an episode of Cosmos, talk about Carl Sagan, and have snacks.',null);
insert into hudsonu.event values(299680,'CAB Take Two: Fast and Furious 6',cast('2013-09-27 22:00' as date),cast('2013-09-27 22:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Hangover 3 at 7:00PM and Fast and Furious 6 at 10:00PM in Love Auditorium on Friday, Sept 27th, and again at opposite times in on Saturday, Sept 28th.'||chr(10)||'Hangover 3 (Starring Bradley Cooper, Zach Galifianakis, Ed Helms)'||chr(10)||'When one of their own is kidnapped by an angry gangster, the Wolf Pack must track down Mr. Chow, who has escaped from prison and is on the lam.'||chr(10)||'Fast and Furious 6 (Starring Vin Diesel, Paul Walker, Dwayne Johnson)'||chr(10)||'Hobbs has Dom and Brian reassemble their crew in order to take down a mastermind who commands an organization of mercenary drivers across 12 countries. Payment? Full pardons for them all.'||chr(10)||' '||chr(10)||' ',null);
insert into hudsonu.event values(314897,'CAB Take Two: R.I.P.D.',cast('2013-11-02 22:00' as date),cast('2013-11-02 22:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: R.I.P.D. at 7:00PM and Kick-Ass 2 at 10:00PM in Love Auditorium on Friday, Nov 1st, and again at opposite times on Saturday, Nov 2nd.'||chr(10)||' '||chr(10)||'R.I.P.D. (Fri 7pm and Sat 10pm)'||chr(10)||'A recently slain cop joins a team of undead police officers working for the Rest in Peace Department and tries to find the man who murdered him.'||chr(10)||' '||chr(10)||'Kick-Ass 2 (Fri 10pm and Sat 7pm)'||chr(10)||'The costumed high-school hero Kick-Ass joins with a group of normal citizens who have been inspired to fight crime in costume. Meanwhile, the Red Mist plots an act of revenge that will affect everyone Kick-Ass knows.'||chr(10)||' '||chr(10)||' ',null);
insert into hudsonu.event values(337522,'CAB Take Two: We''re the Millers',cast('2013-11-15 22:00' as date),cast('2013-11-15 23:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Elysium at 7:00PM and We''re the Millers at 10:00PM in Love Auditorium on Friday, Nov 15th, and again at opposite times on Saturday, Nov 16th.'||chr(10)||'Elysium (Fri 7pm and Sat 10pm)'||chr(10)||'In the year 2154, the very wealthy live on a man-made space station while the rest of the population resides on a ruined Earth. A man takes on a mission that could bring equality to the polarized worlds. '||chr(10)||'We''re the Millers (Fri 10pm and Sat 7pm)'||chr(10)||'A veteran pot dealer creates a fake family as part of his plan to move a huge shipment of weed into the U.S. from Mexico.',null);
insert into hudsonu.event values(477342,'CAB Take Two: Jersey Boys',cast('2014-09-27 22:00' as date),cast('2014-09-27 23:30' as date),'COOP',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'Jersey Boys at 7:00PM and A Million Ways to Die in the West at 10:00 PM in COOP on Friday, Sep 26th.'||chr(10)||'On Saturday Sep 27th: A Million Ways to Die in the West at 7:00PM and Jersey Boys at 10:00 PM'||chr(10)||' '||chr(10)||'Jersey Boys (Fri 7:00PM and Sat 10:00PM) Click here for the trailer of Jersey Boys'||chr(10)||'Starring: John Lloyd Young, Erich Bergen, Michael Lomenda'||chr(10)||'The story of four young men from the wrong side of the tracks in New Jersey who came together to form the iconic 1960s rock group The Four Seasons.'||chr(10)||'A Million Ways to Die in the West (Fri 10:00 PM and sat 7:00PM) Watch the trailer for A Million Ways to Die in the West here!'||chr(10)||'Starring: Seth MacFarlane, Charlize Theron, Liam Neeson'||chr(10)||'As a cowardly farmer begins to fall for the mysterious new woman in town, he must put his new-found courage to the test when her husband, a notorious gun-slinger, announces his arrival.',null);
insert into hudsonu.event values(5000743,'Ballers and Shotcallers',cast('2019-10-04 22:30' as date),cast('2019-10-05 01:00' as date),'creative arts house','Social',NULL,'BSU','Homecoming Party',null);
insert into hudsonu.event values(527594,'HSA Brown Bag',cast('2014-12-05 12:15' as date),cast('2014-12-05 13:30' as date),'Hudson Chapel Basement','Spirituality','Religious/Spiritual','HINDU','Join us for our HSA Brown Bag Lunch!  '||chr(10)||'Our topic for this week will be: "Hindu fundamentalism, caste and race." We will explore the rise of the politics of "Hindutva" in recent years, the relationship between caste hierarchies in India, and racism, by way of Arundhati Roy''s recent critiques of Gandhi.',null);
insert into hudsonu.event values(5470150,'Casino Night',cast('2020-01-24 19:00' as date),cast('2020-01-24 22:00' as date),'Coop TV room','Social',NULL,'SAA','Casino City is coming to back to Hudson! For one night only, we''ll have blackjack, poker, and roulette. '||chr(10)||'Play and win big! The most chips at the end of the night can be cashed in for amazing prizes.  ',null);
insert into hudsonu.event values(5590201,'Gate Night The Great Pizza Debate: Oliveri''s vs. Slices',cast('2020-02-20 21:00' as date),cast('2020-02-20 23:00' as date),'Coop TV Room','Social',NULL,'DS','Which pizza is Hudson''s favorite pizza: Oliveri''s or Slices? We are settling it once and for all! Come sample both pizzas, choose your favorite, and support the Debate Team as they agrue the virtues and drawbacks of each.  '||chr(10)||' '||chr(10)||'Sponsored by ''Gate Night ',null);
insert into hudsonu.event values(564183,'Tea Club Study Break',cast('2015-03-10 19:30' as date),cast('2015-03-10 20:30' as date),'Coop Main Lounge/Fireplace','Cultural',NULL,'TTC','Take a break from finals to enjoy a well-needed break from the clamor of mid-terms, as well as some of the best East-Asian tea Hudson has to offer (for free!). Drop by the Coop fireplace room anytime between 7:30 and 9:30 PM to enjoy this event. Highly recommended for those who are planning to stay up late!',null);
insert into hudsonu.event values(623617,'Global Health Initiative brown bag "Beyond Ebola: Emerging Infectious Diseases and the Future of U.S. Public Health"',cast('2015-04-02 11:30' as date),cast('2015-04-02 11:30' as date),'Lawrence 205, Hudson University','Thoughtful Learning',NULL,'HGHC','Fears of Ebola in the U.S. have faded, but does that mean Americans can stop worrying about infectious disease? In this brown bag lecture, Prof. Geoff Holm will discuss other emerging diseases, and what the (near) future may hold for the U.S. public health system.',null);
insert into hudsonu.event values(625058,'Inside Llewyn Davis',cast('2015-04-04 17:00' as date),cast('2015-04-04 18:00' as date),'Golden Auditorium','Arts',NULL,'HFS','Whether you''re a fan of the Cohen Brothers or just a fan of folk music, come on down to Golden Auditorium to watch Inside Llewyn Davis and eat some pizza with the Hudson Film Society!  The film is the fictional story of a folk musician who struggles to make a name for himself in the early 1960s.  Starring Oscar Isaac, Justin Timberlake, and Carey Mulligan.  Running time is 1 hr 50 mins.   ',null);
insert into hudsonu.event values(642400,'Cinco De Mayo Celebration Study Break!',cast('2015-05-06 13:00' as date),cast('2015-05-06 14:00' as date),'The Quad','Cultural',NULL,'LASO','Come join LASO in celebrating Cinco de Mayo during the study break! There will be food, mexican sodas and juices, music, a pinata, and even a traditional mexican dance performance!'||chr(10)||'All events will occur at The Quad, at 1pm on May 6th.',null);
insert into hudsonu.event values(7026465,'Open Art-Making with the Senior Honor Society',cast('2021-04-20 20:00' as date),cast('2021-04-20 21:00' as date),'Hall of Presidents','Arts','Volunteer and Community Service ','THS','Join the Senior Honor Society Class of 2021 and 2022 to make some original artwork! Follow a guided lesson from a Hudson art professor in one side of the room or hang out and listen to music and work on independent pieces on the other side of the room. There will be Senior Honor Society members floating around to help guide you on technique, help you come up with ideas, and make art alongside you.',null);
insert into hudsonu.event values(7320625,'Club Spikeball Practice',cast('2021-09-08 16:30' as date),cast('2021-09-08 16:30' as date),'Whitnall','Athletics','Club Sports','HRNC','This will be our first practice. All are welcome and encouraged to come!',null);
insert into hudsonu.event values(735215,'Tantra with Professor Bordeaux',cast('2015-11-10 12:15' as date),cast('2015-11-10 13:15' as date),'Chapel Garden Level','Cultural',NULL,'SACC','Professor Bordeaux will lead a discussion on tantra, or tantrism, which is an Asian tradition of beliefs and meditation and ritual practices that seeks to channel the divine energy of the macrocosm or godhead into the human microcosm. Professor Bordeaux teaches a class on tantra, and thus can give great insight into the meanings and motivations of the diverse practices of different tantric sects, such as yoga.'||chr(10)||'   ',null);
