insert into hudsonu.event values(7847384,'UPDATE: Spring 2022 Involvement Fair',cast('2022-02-09 17:00' as date),cast('2022-02-09 19:00' as date),'Huntington Gym','Social','Dance','COVE','UPDATE: Due to weather concerns, the Involvement Fair has been rescheduled for next WEDNESDAY, FEBRUARY 9TH.'||chr(10)||'Stop by the Huntington Gym for the Student Involvement Fair to find different ways to get involved on campus!',null);
