insert into hudsonu.event values(7941361,'Gun Violence: A Public Health Crisis',cast('2022-03-02 17:00' as date),cast('2022-03-02 18:00' as date),'ALANA Cultural Center MPR','Thoughtful Learning',NULL,'HGHC','Join us for our first event of the semester in partnership with the ALANA Cultural Center. Presenting "Gun Violence: A Public Health Crisis," a dialogue centered around issues of social justice and community wellness. ',null);
insert into hudsonu.event values(7957464,'SpringFest Carne Asada',cast('2022-04-30 12:30' as date),cast('2022-04-30 15:00' as date),'La Casa','Cultural',NULL,'LASO',NULL||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'The event that we hope to host is a "Carne Asada". Carne Asada''s are a tradition celebrated amongst many Latinx communities, much like cookouts or barbecues, where Mexican dishes are cooked on a grill with various games and music being played throughout the event. This event would be vital to components of our mission statement which aims to foster a deeper understanding and a greater exposure to Latinx cultures within the Hudson community.'||chr(10)||''||chr(10)||''||chr(10)||''||chr(10)||'',null);
insert into hudsonu.event values(821031,'Interfaith Dinners',cast('2015-04-30 18:00' as date),cast('2015-04-30 18:00' as date),'Chapel Basement','Thoughtful Learning',NULL,'NC','The Interfaith Dinners are an opportunity for students to come together, talk about their different beliefs and share a meal. Each dinner has a theme and there are discussions or presentations that are related to that theme for students to participate in during the dinner. These dinners have been extremely successful in the past.',null);
insert into hudsonu.event values(8421249,'Don''t Worry Darling Midnight Movie',cast('2022-09-23 23:30' as date),cast('2022-09-24 00:30' as date),'Hamilton Movie Theater','Arts','Movie/Film','SAA','The Student Activities Association invited you to the first movie of the midnight movie series! Come enjoy a free movie, pizza, popcorn, and drinks on us! ',null);
insert into hudsonu.event values(862814,'University Church Bible Study Dinner with Dr. Nina Moore',cast('2016-02-09 17:00' as date),cast('2016-02-09 18:30' as date),'Chapel Basement','Spirituality',NULL,'UC','Join Dr. Nina Moore in the Chapel basement as she steps outside of her role as a Hudson faculty member. She will join the Protestant Campus Ministry and share her faith, helping to spread the Word of the Lord through inspirational Bible-based insights.'||chr(10)||'See you in the chapel basement for some great discussion and a wonderful meal catered by Curtain Call. '||chr(10)||' '||chr(10)||' ',null);
insert into hudsonu.event values(870845,'Holi 2016',cast('2016-04-23 13:00' as date),cast('2016-04-23 14:00' as date),'Whitnall Field','Cultural',NULL,'HINDU','Holi is the Hindu festival of colors, organized every spring by the Hindu Students'' Association on campus. This year, the entire event will be held outside on Whitnall Field! There will be a small presentation explaining to the attendess why and how Holi is celebrated. Then, everyone can start playing with the dry, powdered colors on Whitnall Field! People will also enjoy some delicious Indian snacks!'||chr(10)||' ',null);
insert into hudsonu.event values(893386,'Buddhist Lunch: The Five Demons Pride, Craving, Anger, Stinginess and Ignorance with Virginia Moore',cast('2016-02-16 12:15' as date),cast('2016-02-16 13:15' as date),'Chapel Basement Lounge','Spirituality',NULL,'HBC','The Hudson Buddhist Community will have a discussion of The Five Demons Pride, Craving, Anger, Stinginess and Ignorance with our very own Virginia Moore!'||chr(10)||'Come to the Chapel lounge for some great food by Hamilton Whole Foods and a fascinating discussion. ',null);
insert into hudsonu.event values(9000608,'Glow and Grow Night Event!!!',cast('2023-04-21 20:00' as date),cast('2023-04-21 20:00' as date),'Coop TV Room','Community Service','Volunteer and Community Service ','RAK','DoRAK will be hosting an evening event for glow in the dark succulent planting and pot painting! Snacks will be provided!',null);
insert into hudsonu.event values(9469500,'Night Market 2023',cast('2023-10-14 17:00' as date),cast('2023-10-14 18:00' as date),'ALANA Cultural Center','Cultural',NULL,'KCA','JOIN OUR ANNUAL NIGHT MARKET THIS HOMECOMING WEEKEND, organized by KCA and HVS! This year, we broke the participation record with 12 organizations/individual participating in the event and presenting cuisines from their culture!!!    With the participation of SACC, CJCC, ASU, Tea Club, OASIS+, LASO, Arabic Culture Club, BSU, and our amazing advisor Esther IMPORTANT UPDATE: Based on the previous years feedback, this year, we will implement 3 tickets per-person system, so each participant can try food from MAX 3 DIFFERENT ORGANIZATIONS. We want to accommodate as many people coming to the event as possible. Hope to see you there ',null);
insert into hudsonu.event values(954514,'Brownbags',cast('2016-08-22 12:00' as date),cast('2016-12-16 13:00' as date),'Chapel Basement','Spirituality',NULL,'HINDU','The HSA organizes brownbags every semester as part of our brown bag series. They usually pertain to significant religious and cultural practices of Hinduism. In the past, we have spoken about the rise of Hindu fundamentalism, the role of women in Indian society and religious pluralism in India. This semester, the HSA wants to reach out to other departments at the University and continue this conversation.',null);
insert into hudsonu.event values(9859926,'KCA Ramen Social',cast('2024-02-02 18:00' as date),cast('2024-02-02 20:00' as date),'ALANA Cultural Center','Cultural',NULL,'KCA','We plan to host a welcome back ramen social at the start of the spring semester. The purpose of this event is to host an open space where people are able to come together and meet other members of KCA at the event. In addition, we hope that our welcome back ramen social will attract new members to our organization. During this event we seek to 1) create an open space for people to interact, 2) introduce KCA as an organization and its mission, and 3) gain insight on what goals and direction KCA members would like the organization to move towards during the upcoming semester. '||chr(10)||'For this event, we will use ramen as a theme that ties people together. Starting off with ramen-themed icebreakers, our goal is to use a common like amongst college studentsramento bring people to a shared space where they are able to interact and create lasting friendships of care and support. Finally, we will utilize this event as a platform to announce future KCA events and gauge audience interests so as to best tailor our events to our members needs.',null);
insert into hudsonu.event values(9880347,'Midnight Philosophy Society Meeting',cast('2024-02-03 22:00' as date),cast('2024-02-04 01:00' as date),'Donovan''s Pub','Social',NULL,'MPS','Midnight Philosophy is a vibrant community of inquisitive and curious students who are excited to explore diverse and relevant philosophical topics! We host welcoming student-to-student conversations about morality, society, religion, metaphysics, and epistemology. Our members are diverse in their beliefs, and we are open to absolutely anyone, with no philosophical experience or major declaration necessary. ',null);
insert into hudsonu.event values(9885868,'Lunar New Year Celebration',cast('2024-02-10 17:00' as date),cast('2024-02-10 18:00' as date),'ALANA Cultural Center','Fundraising',NULL,'KCA','ALANA, HVS, KCA, OASIS+ and CIC would like to invite everyone to join our Lunar New Year Celebration on Saturday, February 10 at 5 PM in ALANA Cultural Center. We have food from Main Moon, Indonesian cuisine, and lucky envelopes!',null);
insert into hudsonu.event values(9981562,'Congress to Campus - Open Dialogue',cast('2024-02-26 17:30' as date),cast('2024-02-26 18:30' as date),'Little Hall 114','Community Service','Volunteer and Community Service ','DM','Monday, February 26th, 5:30pm, Little Hall 114'||chr(10)||'Join the debate and hear from former Members of Congress, Mike Capuano (D-MA) and John Faso (R-NY) on topics such as the role citizens play in our democracy, the workings of Capitol Hill, and the function of debate on the House and Senate floors. '||chr(10)||' '||chr(10)||'Dinner provided by Royal Indian Grill!'||chr(10)||' '||chr(10)||'Co-sponsored by the Hudson Vote Project and Democracy Matters.'||chr(10)||' ',null);
insert into hudsonu.event values(735204,'French Club Coffee Hour',cast('2015-12-02 16:15' as date),cast('2015-12-02 17:00' as date),'Lawrence Hall 2nd floor','Cultural',NULL,'FC','Come enjoy a presentation on a Francophone topic with snacks included such as croissants every month with a Francophone film screening to follow that weekend.',null);
insert into hudsonu.event values(196931,'Take Two: The Dark Knight Rises',cast('2012-11-03 19:00' as date),cast('2012-11-03 20:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','Eight years on, a new terrorist leader, Bane, overwhelms Gotham''s finest, and the Dark Knight resurfaces to protect a city that has branded him an enemy.'||chr(10)||'Christian Bale, Tom Hardy and Anne Hathaway; Rated PG-13; 165 min.'||chr(10)||'from imdb.com',null);
insert into hudsonu.event values(206944,'Take Two: Expendables 2',cast('2012-12-01 22:00' as date),cast('2012-12-02 00:00' as date),'Love Auditorium',NULL,'Movie/Film','SAA','Last set of Take Two Movies for the semester!'||chr(10)||'Mr. Church reunites the Expendables for what should be an easy paycheck, but when one of their men is murdered on the job, their quest for revenge puts them deep in enemy territory and up against an unexpected threat.'||chr(10)||'Sylvester Stallone, Liam Hemsworth and Randy Couture; 2012; Rated R; 103 min.'||chr(10)||'-from imdb.com',null);
insert into hudsonu.event values(235945,'Vincent Who? Film Screening and Discussions with Curtis Chin',cast('2013-03-20 18:00' as date),cast('2013-03-20 20:00' as date),'Persson 027',NULL,'Movie/Film','KCA','A documentary film screening followed by dinner and discussion with the movie producer Curtis Chin ',null);
insert into hudsonu.event values(281692,'CAB Take Two: The Hobbit',cast('2013-04-26 22:00' as date),cast('2013-04-26 22:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two present:'||chr(10)||'Silver Linings Playbook (Fri 7pm, Sat 3:30pm and 10pm) '||chr(10)||'After a stint in a mental institution, former teacher Pat Solitano moves back in with his parents and tries to reconcile with his ex-wife. Things get more challenging when Pat meets Tiffany, a mysterious girl with problems of her own.'||chr(10)||'The Hobbit: An Expected Journey (Fri 10pm, Sat 7pm) '||chr(10)||'A younger and more reluctant Hobbit, Bilbo Baggins, sets out on an "unexpected journey" to the Lonely Mountain with a spirited group of Dwarves to reclaim their stolen mountain home from a dragon named Smaug.'||chr(10)||' ',null);
insert into hudsonu.event values(289247,'CAB Take Two Midnight Movie: Prisoners',cast('2013-09-20 23:45' as date),cast('2013-09-21 00:45' as date),'Hamilton Movie Theater',NULL,'Movie/Film','SAA','CAB Take Two Movies presents Prisoners: The new movie Prisoners will be screen at the Hamilton Movie theater for free on Friday, September 20th at midnight!'||chr(10)||' '||chr(10)||'The priorities will go to Hudson Students with their HUES Card. Then it''ll be open to public (First comes first served - Maximum 240 seats)'||chr(10)||' '||chr(10)||'Prisoners starring Hugh Jackman, Jake Gyllenhaal, Viola Davis'||chr(10)||'When Keller Dover''s daughter and her friend go missing, he takes matters into his own hands as the police pursue multiple leads and the pressure mounts. But just how far will this desperate father go to protect his family?'||chr(10)||'trailer link: http://www.youtube.com/watch?v=bpXfcTF6iVk',null);
insert into hudsonu.event values(333914,'CAB Take Two Classic Movies Weekend: Rocky',cast('2013-11-08 19:00' as date),cast('2013-11-08 21:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents CLASSIC MOVIES WEEKEND: Rocky at 7:00PM and Shawshank Redemption at 10:00PM in Love Auditorium on Friday, Nov 8th, and again at opposite times on Saturday, Nov 9th.'||chr(10)||'Rocky (Fri 7pm and Sat 10pm)'||chr(10)||'A small-time boxer gets a supremely rare chance to fight the heavy-weight champion in about in which he strives to go the distance for his self-respect.'||chr(10)||' '||chr(10)||'Shawshank Redemption (Fri 10pm and Sat 7pm)'||chr(10)||'Two imprisoned men bond over a number of years, finding solace and eventual redemption through acts of common decency.',null);
insert into hudsonu.event values(345514,'"The Cove" presented by Students for Environmental Action',cast('2014-02-05 19:00' as date),cast('2014-02-05 21:00' as date),'Ho 101',NULL,'Movie/Film','SEA','The first film in the Students for Environmental Action film series during the spring semester, "The Cove" is a 2009 documentary discussing dolphin hunting in the Far East.  Films to follow include Trashed, which discusses the impact of American overconsumption on the global environment, and Plasticized, a film about plastic pollution specifically in the South Atlantic ocean.',null);
insert into hudsonu.event values(365711,'CAB Take Two: Last Vegas',cast('2014-02-08 22:00' as date),cast('2014-02-08 23:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Moviespresents: Last Vegas at 7:00PM and Rushat 10:00PM in Love Auditoriumon Friday, Feb 7th, and again at opposite times on Saturday, Feb 8th.'||chr(10)||' '||chr(10)||'Last Vegas (Fri 7PM and Sat 10PM)'||chr(10)||'Three sixty-something friends take a break from their day-to-day lives to throw a bachelor party in Las Vegas for their last remaining single pal.'||chr(10)||' '||chr(10)||'Rush (Fri 10PM and Sat 7PM)'||chr(10)||'The merciless 1970s rivalry between Formula One rivals James Hunt and Niki Lauda.'||chr(10)||' '||chr(10)||' ',null);
insert into hudsonu.event values(380610,'CAB Take Two: Frozen',cast('2014-03-07 22:00' as date),cast('2014-03-07 23:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'The Hobbit: The Desolation of Smaug at 7:00PM and Frozen at 10:00 PM in Love Auditorium on Friday, Feb 28th.'||chr(10)||'On Saturday Mar 1st: Frozen at 7:00PM and The Hobbit: The Desolation of Smaug at 10:00 PM'||chr(10)||' '||chr(10)||'The Hobbit: The Desolation of Smaug (Fri 8:00PM and Sat 10:00PM)'||chr(10)||'Starring Ian McKellen, Martin Freeman, Richard Armitage'||chr(10)||'The dwarves, along with Bilbo Baggins and Gandalf the Grey, continue their quest to reclaim Erebor, their homeland, from Smaug. Bilbo Baggins is in possession of a mysterious and magical ring. '||chr(10)||'Frozen (Fri 10:00 PM and sat 7:00PM)'||chr(10)||'Starring  Kristen Bell, Josh Gad, Idina Menzel'||chr(10)||' '||chr(10)||' '||chr(10)||' '||chr(10)||'Fearless optimist Anna teams up with Kristoff in an epic journey, encountering Everest-like conditions, and a hilarious snowman named Olaf in a race to find Anna''s sister Elsa, whose icy powers have trapped the kingdom in eternal winter.',null);
insert into hudsonu.event values(396131,'Movie Screening of the Canary Effect',cast('2014-04-02 17:00' as date),cast('2014-04-02 17:30' as date),'Lawrence Auditorium (Room 105)',NULL,'Movie/Film','HHOP','The Canary Effect is a 2006 documentary that follows the broadly overlooked and horrific abuses instilled on our Indigenous communities and details the genocidal practices of US government, as well as its continuing affects on present day Native American populations.  As you''re watching the film, start to think about the ways in which institutionalized racism, discrimination, and structural violence contribute to the poverty, hunger, and abuse of this population.  We are sure this is going to be a powerful film from which we hope to take away a more cultivated and informed critical consciousness. ',null);
insert into hudsonu.event values(404085,'Film Series - Why Democracy Matters: "Priceless"',cast('2014-04-24 16:30' as date),cast('2014-04-24 17:30' as date),'Lathrop 212',NULL,'Movie/Film','DM','Why should students care about the state of politics in America, or dysfunction in the government? In a series of three films, apolitical nonprofit Democracy Matters attempts to get to the root causes of everything from student debt to economic- and gender-based inequality, covering environmental spoilage and racial tensions along the way. April 10: Inequality for All April 17: The Corporation April 24: Priceless',null);
insert into hudsonu.event values(404086,'Film Series - Why Democracy Matters: "The Corporation"',cast('2014-04-17 16:30' as date),cast('2014-04-17 17:30' as date),'Lathrop 212',NULL,'Movie/Film','DM','Why should students care about the state of politics in America, or dysfunction in the government? In a series of three films, apolitical nonprofit Democracy Matters attempts to get to the root causes of everything from student debt to economic- and gender-based inequality, covering environmental spoilage and racial tensions along the way. April 10: Inequality for All April 17: The Corporation April 24: Priceless',null);
insert into hudsonu.event values(467929,'Psycho',cast('2014-11-01 20:00' as date),cast('2014-11-01 21:00' as date),'Golden Auditorium, Little Hall','Arts','Movie/Film','HFS','Come and see Alfred Hitchcock''s classic horror/mystery in Golden Auditorium, hosted by the Hudson Film Society! '||chr(10)||' '||chr(10)||'Description from IMDB: A Phoenix secretary steals $40,000 from her employer''s client, goes on the run and checks into a remote motel run by a young man under the domination of his mother.',null);
insert into hudsonu.event values(7037140,'SACC Queer Movie Night',cast('2021-04-10 19:00' as date),cast('2021-04-10 20:30' as date),'Golden Auditorium','Cultural','Movie/Film','SACC','SACC presents queer movie night on April 10 Saturday (7:30 - 9 PM). To celebrate the recent legalization of LGBTQ+ communities in India, SACC will hold a movie night featuring one of the first queer Bollywood movies from last year: "Subh Mangal Zyaada Saavdhan". The event will be held in a hybrid manner. SACC members and the members of the Hudson community will be able to sign up to be one of the first 15 people to enjoy the movie at Golden Auditorium (Social Distancing Capacity: 27). Those who can''t make it in person will also be able to join in over at Zoom, where the event will be streamed. Golden Auditorium has already been reserved for the time period of the event.',null);
