insert into hudsonu.event values(244422,'CAB Take Two: Zero Dark Thirty',cast('2013-03-22 19:00' as date),cast('2013-03-22 20:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents:'||chr(10)||'Zero Dark Thirty at 7:00PM and Lincoln at 10:00PM in Love Auditorium on Friday, March 22nd, and again at opposite times on Saturday, March 23rd.'||chr(10)||'Zero Dark Thirty:'||chr(10)||'A chronicle of the decade-long hunt for al-Qaeda terrorist leader Osama bin Laden after the September 2001 attacks, and his death at the hands of the Navy S.E.A.L. Team 6 in May 2011.'||chr(10)||'Lincoln:'||chr(10)||'As the Civil War continues to rage, America''s president struggles with continuing carnage on the battlefield and as he fights with many inside his own cabinet on the decision to emancipate the slaves.'||chr(10)||' ',null);
insert into hudsonu.event values(244424,'Film Screening of Kaleb',cast('2013-03-21 19:00' as date),cast('2013-03-21 20:00' as date),'Golden Auditorium, Little Hall',NULL,'Movie/Film','CSA','The movie Kaleb was part of the Haitian Film Festival and has won several awards. The director being of Haitian descent wanted to make a movie of important aspects of the world we live in and the importance of family. In addition to the film screening the producer Kervan Bartholomew will be here for a discussion afterwards and Caribbean food will be catered!!!! Summary: Kaleb has been kicked out of his home in Long Island, N.Y. for almost a year. His familys tense demeanor is apparent as they try to ignore the fact that Kaleb is not there. One day Jacque, Kalebs father, sees Kaleb in a local newspaper accused of raping a young girl. The police search for Kaleb and his friends while the incident sparks friction within the family, demanding Jacque to respond to his wifes ultimatum: FIND KALEB or LOSE THE REST OF HIS FAMILY. To learn more: http://kalebthemovie.com/ Hosted by CSA',null);
insert into hudsonu.event values(252655,'CAB Midnight Movie: 42',cast('2013-04-12 23:45' as date),cast('2013-04-12 23:00' as date),'Hamilton Movie Theater',NULL,'Movie/Film','SAA','CAB Take Two and Brothers present:'||chr(10)||'42'||chr(10)||'The life story of Jackie Robinson and his history-making signing with the Brooklyn Dodgers under the guidance of team executive Branch Rickey.'||chr(10)||'First Admission: Hudson students with HUES Card'||chr(10)||'Second Admission: Public',null);
insert into hudsonu.event values(285847,'CAB Take Two: The Great Gatsby',cast('2013-09-06 19:00' as date),cast('2013-09-06 20:45' as date),'Love Auditorium (Olin 300)',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: The Great Gatsby at 7:00PM and Now You See Me at 10:00PM in Love Auditorium on Friday, Sept 6th, and again at opposite times on Saturday, Sept 7th. '||chr(10)||'The Great Gatsby (Fri:7pm, Sat:10pm): A Midwestern war veteran finds himself drawn to the past and lifestyle of his millionaire neighbor.'||chr(10)||'Now You See Me (Fri:10 pm, Sat:pm): An FBI agent and an Interpol detective track a team of illusionists who pull off bank heists during their performances and reward their audiences with the money.    ',null);
insert into hudsonu.event values(289253,'CAB Take Two: Iron Man 3',cast('2013-09-14 22:00' as date),cast('2013-09-14 22:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents SUPER HERO WEEKEND:Iron Man 3 at 7:00PM and Man of Steel at 10:00PM in Love Auditorium on Friday, Sept 13th, and again at opposite times in on Saturday, Sept 14th.'||chr(10)||'Iron Man 3 (Fri 7pm and Sat 10pm)'||chr(10)||'When Tony Stark''s world is torn apart by a formidable terrorist called the Mandarin, he starts an odyssey of rebuilding and retribution. (starring Robert Downey Jr., Guy Pearce, Gwyneth Paltrow)'||chr(10)||'Man of Steel (Fri 10pm and Sat 7pm)'||chr(10)||'A young itinerant worker is forced to confront his secret extraterrestrial heritage when Earth is invaded by members of his race. (starring Henry Cavill, Amy Adams, Michael Shannon)'||chr(10)||' '||chr(10)||'from imdb.com'||chr(10)||' ',null);
insert into hudsonu.event values(302813,'CAB Take Two: Despicable Me 2',cast('2013-10-05 22:00' as date),cast('2013-10-05 22:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Despicable Me 2 at 7:00PM and Monsters University at 10:00PM in Love Auditorium on Friday, Oct 4th, and again at opposite times on Saturday, Oct 5th.'||chr(10)||'Despicable Me 2 (Fri 7pm/Sat 10pm)'||chr(10)||'Gru is recruited by the Anti-Villain League to help deal with a powerful new super criminal.'||chr(10)||'Monster''s University (Fri 10pm/Sat 7pm)'||chr(10)||'A look at the relationship between Mike and Sulley during their days at Monsters University -- when they weren''t necessarily the best of friends.'||chr(10)||' ',null);
insert into hudsonu.event values(338854,'CAB Take Two: The Mortal Instruments',cast('2013-12-07 22:00' as date),cast('2013-12-07 23:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: The Mortal Instruments: City of Bones at 7:00PM and One Direction: This is Us at 10:00PM in Love Auditorium on Friday, Dec 6th, and again at opposite times on Saturday, Dec 7th.'||chr(10)||'The Mortal Instruments: City of Bones (Fri 7pm and Sat 10pm)'||chr(10)||'When her mother disappears, Clary Fray learns that she descends from a line of warriors who protect our world from demons. She joins forces with others like her and heads into a dangerous alternate New York called Downworld.'||chr(10)||'One Direction: This is Us (Fri 10pm and Sat 7pm)'||chr(10)||'A look at Niall, Zayn, Liam, Louis, and Harry''s meteoric rise to fame, from their humble hometown beginnings and competing on the X-Factor, to conquering the world and performing at London''s famed O2 Arena.',null);
insert into hudsonu.event values(346160,'"Plasticized" presented by Students for Environmental Action',cast('2014-02-12 19:00' as date),cast('2014-02-12 21:00' as date),'Ho 101',NULL,'Movie/Film','SEA','"Plasticized" is a 2011 film about plastic pollution in the Southern Atlantic Ocean.',null);
insert into hudsonu.event values(378425,'CAB Take Two: Mean Girls',cast('2014-03-01 19:00' as date),cast('2014-03-01 21:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two presents The Classics Week. Come and enjoy some of the best classic movies of all time. On Friday Feb 28th, Fight Club at 7pm and Mean Girls at 10pm, and Saturday, Mar 1st, again at the opposite time.'||chr(10)||'Fight Club Friday 7pm and Sat 10 PM'||chr(10)||'An insomniac office worker looking for a way to change his life crosses paths with a devil-may-care soap maker and they form an underground fight club that evolves into something much, much more...'||chr(10)||'Mean Girls Friday 10 PM and Sat 7 PM'||chr(10)||'Cady Heron is a hit with The Plastics, the A-list girl clique at her new school, until she makes the mistake of falling for Aaron Samuels, the ex-boyfriend of alpha Plastic Regina George.',null);
insert into hudsonu.event values(380613,'CAB Take Two: The Hobbit 2',cast('2014-03-08 22:00' as date),cast('2014-03-08 23:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'The Hobbit: The Desolation of Smaug at 7:00PM and Frozen at 10:00 PM in Love Auditorium on Friday, Feb 28th.'||chr(10)||'On Saturday Mar 1st: Frozen at 7:00PM and The Hobbit: The Desolation of Smaug at 10:00 PM'||chr(10)||' '||chr(10)||'The Hobbit: The Desolation of Smaug (Fri 8:00PM and Sat 10:00PM)'||chr(10)||'Starring Ian McKellen, Martin Freeman, Richard Armitage'||chr(10)||'The dwarves, along with Bilbo Baggins and Gandalf the Grey, continue their quest to reclaim Erebor, their homeland, from Smaug. Bilbo Baggins is in possession of a mysterious and magical ring. '||chr(10)||'Frozen (Fri 10:00 PM and sat 7:00PM)'||chr(10)||'Starring  Kristen Bell, Josh Gad, Idina Menzel'||chr(10)||' '||chr(10)||' '||chr(10)||' '||chr(10)||'Fearless optimist Anna teams up with Kristoff in an epic journey, encountering Everest-like conditions, and a hilarious snowman named Olaf in a race to find Anna''s sister Elsa, whose icy powers have trapped the kingdom in eternal winter.',null);
