insert into hudsonu.event values(791412,'Take Two: DIVERGENT (2014)',cast('2015-11-07 22:00' as date),cast('2015-11-07 23:00' as date),'Love Auditorium','Social',NULL,'SAA','In a world divided by factions based on virtues, Tris learns she''s Divergent and won''t fit in. When she discovers a plot to destroy Divergents, Tris and the mysterious Four must find out what makes Divergents dangerous before it''s too late.'||chr(10)||'Screenings are Friday 11/6 @ 7PM, and 11/7 @10PM in Love Auditorium, Free Admission!',null);
insert into hudsonu.event values(1109936,'Konosioni Coffee Hours',cast('2016-11-17 11:30' as date),cast('2016-11-17 13:30' as date),'Coop TV Room','Community Service',NULL,'THS','The Konosioni Senior Honors Society hosts two annual coffee hours specifically targeted for juniors who are interested in applying for or learning more about Kono''s mission, goals, and membership application process. This is a great time for interested juniors to meet all of the current Kono members, and ask any questions or get first hand information.'||chr(10)||'Our first coffee hour will be November 17th from 11:30am to 1:30pm in the Coop TV Room, and will function as a "Meet and Greet" of sorts. It will provide the opportunity for current juniors to speak with and meet the current Konosioni class!'||chr(10)||'Our second coffee hour will be December 1st from 7:00pm to 8:30pm in the Batza Room in Case Library. This is the same day that our applications open and will provide an opportunity for interested juniors to ask more explicitly about the application process, deliberations, and the inner workings of Kono!',null);
insert into hudsonu.event values(1109937,'Konosioni Coffee Hours',cast('2016-12-01 19:00' as date),cast('2016-12-01 20:30' as date),'Batza Room - Case Library','Community Service',NULL,'THS','The Konosioni Senior Honors Society hosts two annual coffee hours specifically targeted for juniors who are interested in applying for or learning more about Kono''s mission, goals, and membership application process. This is a great time for interested juniors to meet all of the current Kono members, and ask any questions or get first hand information.'||chr(10)||'Our first coffee hour will be November 17th from 11:30am to 1:30pm in the Coop TV Room, and will function as a "Meet and Greet" of sorts. It will provide the opportunity for current juniors to speak with and meet the current Konosioni class!'||chr(10)||'Our second coffee hour will be December 1st from 7:00pm to 8:30pm in the Batza Room in Case Library. This is the same day that our applications open and will provide an opportunity for interested juniors to ask more explicitly about the application process, deliberations, and the inner workings of Kono!',null);
insert into hudsonu.event values(1119423,'This Is Not A Talk About Feminism',cast('2016-10-28 12:30' as date),cast('2016-10-28 12:30' as date),'Lathrop 207','Arts',NULL,'LAMBDA','This student-led discussion will open up space for individuals in the community to talk about and work through some of the scenes from This Is Not A Play About Sex, which recently underwent its annual showing. The play poses many questions and highlights concerns and issues within the Hudson community, but the conversation shouldn''t stop there. As students who were genuinely changed and affected by the play, members of the cast and crew would be honored to talk with our community about how we interpret parts of the play, and why particular scenes were produced and directed as they were. This play starts the conversation, and we feel the need to keep it going.'||chr(10)||'As creator Poppy Liu said: "In order to survive, we need one another."',null);
insert into hudsonu.event values(1136047,'Interfaith Dinner',cast('2017-05-04 18:00' as date),cast('2017-05-04 18:00' as date),'Chapel Basement','Thoughtful Learning','Religious/Spiritual','NC','The Interfaith Dinners are an opportunity for students to come together, talk about their different beliefs and share a meal. Each dinner has a theme and discussion of this theme is co-led by members from two different Chaplaincy groups. This discussion-based style allows students who attend to participate during the dinner. These dinners have been extremely successful in the past.',null);
