insert into hudsonu.event values(236442,'Issa Rae Lecture and QandA',cast('2013-04-14 19:00' as date),cast('2013-04-14 20:00' as date),'Persson Auditorium',NULL,'Movie/Film','BSU','Writer, Actress, and Producer Issa Rae is coming to talk about her critically acclaimed youtube webseries the MisAdventures of an Awkward Black Girl.  There is a screening of the webisodes Wednesday April 8th in the HRC library at 7pm.',null);
insert into hudsonu.event values(287422,'Vermont Huber Debate Tournament',cast('2013-11-02 10:30' as date),cast('2013-11-03 23:30' as date),'University of Vermont',NULL,'Volunteer and Community Service ','DS','The University of Vermont Huber Debate Tournament is an annual debate tournament for both Varsity and Novice Debaters that runs this year from Saturday November 2 to Sunday November 3. It consists of 6 rounds of debate and breaks to both varsity and novice finals. The Huber Debate Tournament is one of the most widely attended debate tournaments in the northeast and is attended by schools from around the country and around the world. Debaters and Judges from Hudson will leave after classes on Friday November 1 and return to campus on Sunday November 3.  ',null);
insert into hudsonu.event values(287424,'Hart House IV 2013',cast('2013-10-18 12:30' as date),cast('2013-10-20 12:30' as date),'Hart House, University of Toronto, Ontario, CA',NULL,'Volunteer and Community Service ','DS','The Hart House Debates Club and Committee will be hosting inaugural North American British Parliamentary Championship. The tournament will take place from October 18-20, 2013. The tournament will consist of five open rounds of debate in the British Parliamentary style. Speeches will be 7 minutes in length. ',null);
insert into hudsonu.event values(293727,'The Nutcracker',cast('2013-11-20 19:00' as date),cast('2013-11-20 21:00' as date),'Brehmer Theatre',NULL,'Dance','BALLET','Please join the Hudson Ballet Company for their annual production of The Nutcracker.  This holiday favorite is student-directed, student-choreographed, and student-performed, with guest appearances by children from the Hamilton community.  ',null);
insert into hudsonu.event values(325113,'Midnight Movie - Rocky Horror Show',cast('2013-10-25 23:45' as date),cast('2013-10-26 13:00' as date),'Hamilton Theatre',NULL,'Movie/Film','SAA','"A newly engaged couple have a breakdown in an isolated area and must pay a call to the bizarre residence of Dr. Frank-N-Furter." (from IMDB)Stars Tim Curry, Susan Sarandon and Barry Bostwick; Rated R; 100 min.; 1975.'||chr(10)||'Come to the Hamilton Movie Theater at 11:45PM this Friday to enjoy this cult classic in time for Halloween! It will also be a great source of fun for the entire family this Family Weekend. Come dress up!**FREE ADMISSION WITH HUES Card**',null);
insert into hudsonu.event values(337520,'CAB Take Two: Elysium',cast('2013-11-15 19:00' as date),cast('2013-11-15 21:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Elysium at 7:00PM and We''re the Millers at 10:00PM in Love Auditorium on Friday, Nov 15th, and again at opposite times on Saturday, Nov 16th.'||chr(10)||'Elysium (Fri 7pm and Sat 10pm)'||chr(10)||'In the year 2154, the very wealthy live on a man-made space station while the rest of the population resides on a ruined Earth. A man takes on a mission that could bring equality to the polarized worlds. '||chr(10)||'We''re the Millers (Fri 10pm and Sat 7pm)'||chr(10)||'A veteran pot dealer creates a fake family as part of his plan to move a huge shipment of weed into the U.S. from Mexico.',null);
