insert into hudsonu.event values(403614,'CAB Take Two: Her',cast('2014-03-28 22:00' as date),cast('2014-03-28 22:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Presents:'||chr(10)||'About Time at 7:00PM and Her at 10:00 PM in Love Auditorium on Friday, Mar 28th.'||chr(10)||'On Saturday Mar 29th: Her at 7:00PM and About Time at 10:00 PM'||chr(10)||' '||chr(10)||'About Time (Fri 7:00PM and Sat 10:00PM)'||chr(10)||'Starring  Domhnall Gleeson, Rachel McAdams, Bill Nighy'||chr(10)||'At the age of 21, Tim discovers he can travel in time and change what happens and has happened in his own life. His decision to make his world a better place by getting a girlfriend turns out not to be as easy as you might think.'||chr(10)||'Her (Fri 10:00 PM and sat 7:00PM)'||chr(10)||'Starring Joaquin Phoenix, Amy Adams, Scarlett Johansson '||chr(10)||'A lonely writer develops an unlikely relationship with his newly purchased operating system that''s designed to meet his every need.',null);
insert into hudsonu.event values(502944,'Oktoberfest 2014',cast('2014-10-17 19:00' as date),cast('2014-10-17 20:00' as date),'Creative Arts House','Cultural',NULL,'GC','Come celebrate Oktoberfest with some great German food, drinks and music!',null);
insert into hudsonu.event values(5029762,'BSU De-Stress Night',cast('2019-10-18 20:00' as date),cast('2019-10-18 21:00' as date),'Donovan''s Pub','Social',NULL,'BSU','Join the Black Student Union for our first De-Stress Night of the year! Come by Donovan''s Pub for a fun evening of Song Association and karaoke.',null);
insert into hudsonu.event values(518077,'Young Alumni Weekend',cast('2015-02-21 15:30' as date),cast('2015-02-21 21:30' as date),'Batza Meeting Room, 560 Case Library','Social',NULL,'HWIB','Hudson University is bringing three young alumni on campus from various backgrounds, such as investment banking, business development and private equity. In the interactive panel, alumni will share their career expereinces and give advice to students. A formal dinner event at the Hudson Inn will be followed after the panel. ',null);
insert into hudsonu.event values(537099,'Konosioni Senior Honor Society Charity Auction',cast('2015-04-10 20:00' as date),cast('2015-04-10 21:00' as date),'The Hall of Presidents and Clark Room','Fundraising',NULL,'THS','The Konosioni Charity Auction is an annual event hosted to raise funds for local not-for-profit organizations. Last year, through the generosity of many donors, Konosioni was able to award more than $14,000 to local groups to develop new projects and increase their capacity to help and support the community. This yearly tradition aligns with our mission in being leaders in promoting charitable and philanthropic efforts as stewards of the greater Hudson community. The event will be cocktail reception styled with a silent and live auction and entertainment provided by several Hudson groups.  ',null);
insert into hudsonu.event values(573294,'Holi 2015',cast('2015-04-19 12:00' as date),cast('2015-04-19 14:00' as date),'Hall of Presidents','Cultural',NULL,'HINDU','Holi is the Hindu festival of colors, organized every spring by the Hindu Students'' Association on campus. The event involves a small presentation explaining to the attendees why, and how Holi is celebrated. This presentation will be followed by a full fledged Indian meal for everyone in attendance after which everyone will head outside to Whitnall field to play with dry, powdered colors and water guns.',null);
insert into hudsonu.event values(582763,'Brothers Charity Week',cast('2015-03-31 00:00' as date),cast('2015-04-04 22:45' as date),'Hudson University','Fundraising',NULL,'BROS','Brothers Charity Week is composed of several activities placed throughout the week, with the intent of raising money for the surrounding Hamilton community and/or a worthwhile, larger global charitable organization. Monday will start the week with a BBQ supported by the Office of the Chaplains on the academic quad during lunchtime, in conjunction with a homemade bake sale occurring in the Coop. On Tuesday, we will run a Super Smash Bros. Tournament in conjunction with ResLife  and The Games Afoot. Wednesdays event will be a Worldly Banquet that we organize in collaboration with a large portion of the groups advised by Alana. On Thursday, Brothers will host a basketball tournament with the aid of the Mens Basketball team and BDS. The Brothers Charity Auction will take place on Friday evening, rounding out and concluding the week. All throughout the week, we will accept suggested donations at all events in addition to our Coop table, where the Bake Sale will be ongoing.'||chr(10)||' ',null);
insert into hudsonu.event values(605460,'CAB Presents: Josh Rabinowitz Stand-Up at Donovan''s Pub',cast('2015-03-07 20:00' as date),cast('2015-03-07 21:00' as date),'Donovan''s Pub','Social',NULL,'SAA','Comedian Josh Rabinowitz is performing stand-up at 8 PM on Saturday, March 7th at Donovan''s Pub! Josh has appeared on comedy shows such as Friends of the People, I Just Want My Pants Back, and Adam Devine''s House Party, and has been featured on the "Comedy Central On Campus College Tour" and the "CollegeHumor.com" Live Tour. He has been named one of Comedy Central''s "Comics to Watch".',null);
insert into hudsonu.event values(642063,'Broad Street Gallery Grand Re-Opening',cast('2015-04-11 11:00' as date),cast('2015-04-11 20:00' as date),'Broad Street Gallery','Arts',NULL,'HSMC','The Broad Street Gallery is hosting a cocktail hour this Saturday from 4-9pm with drinks and refreshments. Hudson Marketing Club has been working with the Gallery to help promote the business and plan this event.',null);
insert into hudsonu.event values(735175,'Diwali 2015',cast('2015-11-07 17:00' as date),cast('2015-11-07 21:00' as date),'The Hall of Presidents','Cultural',NULL,'HINDU','Diwali is the Hindu festival of lights, organized every fall by the Hindu Students'' Association on campus. The event involves a small presentation where HSA member students explain to the professors and attendees why, and how Diwali is celebrated. This presentation will be followed by a full fledged Indian meal for everyone in attendance after which everyone will head outside to the Whitnall field to observe the fireworks, which are lit from the old golf course.',null);
insert into hudsonu.event values(750228,'CAB Midterm COOKIE Study Break',cast('2015-10-04 21:30' as date),cast('2015-10-04 21:30' as date),'Batza Room 560','Social',NULL,'SAA','Take a break from stuyding and head up to the Batza Room 560 in the Library at 9:30- 10:30 PM for free cookies and drinks!! We will have a wide variety of Quacks cookies to choose from! ',null);
insert into hudsonu.event values(7593684,'Democracy and Donuts with Professor Henke',cast('2021-11-11 18:00' as date),cast('2021-11-11 19:00' as date),'O''Connor Campus Center Conference/Meeting Room','Thoughtful Learning',NULL,'DM','Professor Henke will present and answer questions about the intersection of nature, culture, and politics. Specifically focusing on how it relates to voting rights and money in politics. ',null);
insert into hudsonu.event values(7908767,'Thrive Dinner: Boundaries to Minority Mental Health',cast('2022-02-16 17:00' as date),cast('2022-02-16 18:00' as date),'Alana Cultural Center','Thoughtful Learning',NULL,'ALANA','Join MAPS and the ALANA SJPE for an informal conversation on boundaries in seeking mental health care for minority communities. Were excited to announce our first event of the semester! Head to ALANA on Wednesday at 5pm for this thrive lunch. '||chr(10)||' '||chr(10)||'ALANA Seminar Room '||chr(10)||' Wednesday, Feb 16th, 5PM'||chr(10)||' Bring your Friends '||chr(10)||' Dinner will be provided!'||chr(10)||'Event Link',null);
insert into hudsonu.event values(8064677,'BSU Karaoke Night',cast('2022-04-21 21:00' as date),cast('2022-04-21 21:30' as date),'Donovan''s Pub','Arts','Concert/Music','BSU','Bringing back a fun BSU tradition of a night of karaoke in Donovan''s Pub!',null);
insert into hudsonu.event values(8087190,'RIG Food Truck at Gamma Phi Beta',cast('2022-04-30 15:00' as date),cast('2022-04-30 17:00' as date),'Gamma Phi Beta','Social',NULL,'GPB','RIG food truck will be serving people free food in the parking lot at the Gphi house from 3-6pm.',null);
insert into hudsonu.event values(814157,'Club Hudson Presents DJ Enferno at the Palace',cast('2015-12-11 21:30' as date),cast('2015-12-12 01:30' as date),'Palace Theater','Social',NULL,'SAA','Dress to impress at the end of the year party at the Palace Theater. Club Hudson presents student DJ Jordan Henderson and headliner DJ Enferno. Door prized include tickets to the Hamilton Movie Theater, gift cards to No. 10 tavern, and a one night stay at the Hudson Inn for Family Weekend.'||chr(10)||' '||chr(10)||'Specially marked cruisers with direct transportation to the Palace Theatre (upper campus and lower campus)'||chr(10)||'Doors open at 9:30, please enter on the side of the building'||chr(10)||'Free Food, Beer, Wine, Champagne - Must Be 21 To Be Served Alcohol'||chr(10)||'21+ must show two forms of ID at the door for a wristband'||chr(10)||'Red Carpet package photo booth. Last year''s was excellent (http://clients.leotim.com/hudson_2015_full_resolution)'||chr(10)||'One guest per Hudson student permitted'||chr(10)||' '||chr(10)||'SCHEDULE- Doors Open At 9:30 PM- 9:30 PM - 10:00 PM: Pre Party with host Tyler Maxie ''18 - 10:00 PM - 11:00 PM: Opening Act - Jordan Henderson ''17- 10:30 PM - 10:40 PM: Community champagne toast- 11:00 PM - 1:30 AM: After Party with DJ Enferno',null);
insert into hudsonu.event values(856668,'CAB Take Two Presents Midnight Movie: The Finest Hours',cast('2016-01-29 23:45' as date),cast('2016-01-30 02:00' as date),'Hamilton Movie Theater','Social',NULL,'SAA','Grab your friends this Friday and come down to the Hamilton Movie Theater for the midnight premiere of The Finest Hours! Admission is free with a HUES Card, and free slices and popcorn will be provided! '||chr(10)||'Starring Chris Pine and Casey Affleck, the movie follows the story of the Coast Guard making a daring rescue attempt off the coast of Cape Cod after a pair of oil tankers are destroyed during a blizzard in 1952. ',null);
insert into hudsonu.event values(863037,'Winter Wonderland',cast('2016-01-29 14:00' as date),cast('2016-01-29 23:00' as date),'Whitney Field, HOP, Clark Room','Social',NULL,'HCF','Do you want to build a snowman? Or create a fierce dragon or a friendly bear out of snow? YOU CAN! Grab a group of friends and head out to Whitnall field on Friday, January 29th from 2-5pm to unleash your imagination for our Winter Wonderland Event! We will even have snow molds for building igloos if you are up for the challenge!'||chr(10)||'Then, come back later that same night for our late night program (7pm-11pm) when we will light up your creations for a night time wintry spectacle. We will have even more fun inside the HOP/Clarkroom (once it gets a little too cold to be outside) with snacks, hot chocolate, our "Dressing for Winter at Hudson" comedy fashion show, crafts, a Disney''s FROZEN sing-a-long, and an INDOOR SNOWBALL FIGHT!'||chr(10)||'This event is sponsored by Gate Night, Ski andSnowboarding Club, The Games Afoot, Crafters Club, Hudson Christian Fellowship and Photography Club.',null);
insert into hudsonu.event values(8657078,'Trip to Interskate 88',cast('2023-01-04 10:00' as date),cast('2023-01-04 14:00' as date),'Interskate 88','Social',NULL,'COVE','Join the COVE on Wednesday, January 4th at Interskate 88 in Oneonta, NY for a couple hours of roller skating, dancing, laser tag and more! We will depart from the COVE (Lathrop 109) at 10am. We will skate from 11am-1pm and then head back to campus around 2pm. Pizza and drinks will be provided at Interskate 88.There is a snack bar and arcade on site as well that you will be responsible for if you would like to partake in either. Transportation provided.'||chr(10)||'For more information about, you can go to this link or go to the University events calendar. '||chr(10)||' '||chr(10)||'Please note some events require registration in advance as space is limited. For any trips, you must complete an Acknowledgment of Risk and Responsibility form and bring it with you to the bus when you are traveling. Any approved guests must do the same. You are welcome to wear masks while riding on shuttles or in vans. ',null);
insert into hudsonu.event values(866638,'Classics Coffee Hour',cast('2016-04-22 13:30' as date),cast('2016-04-22 13:30' as date),'Lawrence 114','Social',NULL,'HCS','Come hang out with the Hudson Classics Society and meet others interested in the ancient civilizations of ancient Greece and Rome!  Chat over coffee, tea, and sweets with other student and department faculty.  A great way to meet new people and make connections!',null);
insert into hudsonu.event values(9390690,'IGD Student Training',cast('2023-09-29 16:30' as date),cast('2023-09-29 19:30' as date),'ALANA MPR','Thoughtful Learning',NULL,'ALANA',NULL||chr(10)||'The IGD Council and the ALANA Cultural Center present the second Student Inter-Group Dialogue Train-the-Trainer, Part I! If you are interested in learning how to facilitate difficult conversations and to build interpersonal or structural awareness in your own student groups or other community contexts, please join us!'||chr(10)||' '||chr(10)||'Intergroup Dialogue is a research-based approach to face-to-face facilitated conversation between members of two or more social identity groups that strives to create new levels of understanding, relating, and action" (Zuniga 2003). Upon completion of the two-day training, students will receive an IGD Experience Training Certificate, Part I. Part I will equip you with a foundational set of tools for dialogue and includes ten training hours; students must commit to both sessions to be accepted to the Training.'||chr(10)||' '||chr(10)||''||chr(10)||'This training is open to all Hudson students and those who are (or plan to be) student leaders on and/-or outside the campus. There are limited seats so please sign up early. Part II of the training will begin in mid-October. At the end of Part I and Part II, students will be equipped, under continued supervision and mentorship, to plan and facilitate Intergroup Dialogue events in their student groups.'||chr(10)||' '||chr(10)||'Note: Meals will be provided. But please bring your water bottle to the training. '||chr(10)||' '||chr(10)||'Registration is required at this link: https://tinyurl.com/igdstudent',null);
insert into hudsonu.event values(945086,'New Student BBQ',cast('2016-09-02 17:30' as date),cast('2016-09-02 18:00' as date),'Chapel Steps','Social',NULL,'NC','This is an event to welcome members of the Class of 2020 to both the Newman Community and Newman Board. It is an opportunity to meet the current members of the community and become more informed about religious life on Hudson''s campus. ',null);
insert into hudsonu.event values(9542328,'LASO Annual Carne Asada with Brothers',cast('2023-10-22 13:00' as date),cast('2023-10-22 15:00' as date),'La Casa','Cultural',NULL,'BROS','We welcome the Hudson community to join the Latin American Student Organization and Brothers for an afternoon of fun! Rain or shine, we want everyone to have a taste of Latin America so come join us :)',null);
insert into hudsonu.event values(9593139,'Black Solidarity Dinner',cast('2023-11-10 18:00' as date),cast('2023-11-10 20:00' as date),'ALANA Cultural Center','Cultural',NULL,'BSU','Black Solidarity Day is a day to celebrate solidarity between all Black individuals. On the Hudson campus, BSU uses this as an opportunity to celebrate solidarity between everyone regardless of race, gender, sexuality etc. Black Solidarity Day consists of a Black member of the staff giving a short speech and concludes with Black faculty, staff, and students sharing a meal to commemorate Black Solidarity Day, a memorial day, created in 1969 by Panamanian-born activist, historian, playwright, Carlos E. Russell. This day is annually observed the day before election day in November, the first Monday of the month. The dinner is used as an opportunity to discuss a theme for the day and to provide a safe, welcoming and uniting environment.',null);
insert into hudsonu.event values(9600440,'Night at the Mat',cast('2023-11-11 23:00' as date),cast('2023-11-12 02:00' as date),'The Mat','Social','Concert/Music','SAA','A night of music, food, and giveaways. Bring your friends and dress in neon!',null);
