insert into hudsonu.event values(9880352,'Midnight Philosophy Society Meeting',cast('2024-03-23 22:00' as date),cast('2024-03-24 00:00' as date),'Donovan''s Pub','Social',NULL,'MPS','Midnight Philosophy is a vibrant community of inquisitive and curious students who are excited to explore diverse and relevant philosophical topics! We host welcoming student-to-student conversations about morality, society, religion, metaphysics, and epistemology. Our members are diverse in their beliefs, and we are open to absolutely anyone, with no philosophical experience or major declaration necessary. ',null);
