insert into hudsonu.event values(892902,'Take Two presents Oscars Week: The Danish Girl (2015)',cast('2016-02-19 19:00' as date),cast('2016-02-19 21:00' as date),'Love Auditorium','Social',NULL,'SAA','Showings are 7PM on Friday (2/19) and 10PM on Saturday (2/20) in Love Auditorium!'||chr(10)||'A fictitious love story loosely inspired by the lives of Danish artists Lili Elbe and Gerda Wegener. Lili and Gerda''s marriage and work evolve as they navigate Lili''s groundbreaking journey as a transgender pioneer.',null);
