insert into hudsonu.event values(709533,'Take Two Movies: Pitch Perfect',cast('2015-09-12 22:00' as date),cast('2015-09-12 22:45' as date),'Love Auditorium','Social',NULL,'SAA','Come see a free screening of the 2012 hit, Pitch Perfect! '||chr(10)||'Synopsis: The Barden Bellas are a collegiate, all-girls a cappella singing group thriving on female pop songs and their perfect looks. After a disastrous failing at last year''s finals, they are forced to regroup. Among the new recruits is freshman Beca, an independent, aspiring DJ with no interest in the college life. But after she meets Jesse, from the rival all-male a cappella group, Beca has a new outlook and takes it upon herself to help the Bellas find their new look and sound and get back into the competition.',null);
