insert into hudsonu.event values(698911,'Spy',cast('2015-09-05 22:00' as date),cast('2015-09-05 23:30' as date),'Love Auditorium','Social',NULL,'SAA','Take Two presents a free screening of the 2015 hit comedy, Spy! '||chr(10)||'Susan Cooper is an unassuming, deskbound CIA analyst, and the unsung hero behind the Agency''s most dangerous missions. But when her partner falls off the grid and another top agent is compromised, she volunteers to go deep undercover to infiltrate the world of a deadly arms dealer, and prevent a global crisis.',null);
insert into hudsonu.event values(709530,'Take Two Movies: Pitch Perfect 2',cast('2015-09-12 19:00' as date),cast('2015-09-12 20:00' as date),'Love Auditorium','Social',NULL,'SAA','Come see a free screening of the latest hit, Pitch Perfect 2! '||chr(10)||'Synopsis: The Bellas are back, and they are better than ever. After being humiliated in front of none other than the President of the United States of America, the Bellas are taken out of the Aca-Circuit. In order to clear their name and regain their status, the Bellas take on a seemingly impossible task: winning an International competition no American team has ever won. In order to accomplish this monumental task, they need to strengthen the bonds of friendship and sisterhood, and blow away the competition with their amazing aca-magic! With all new friends and old rivals tagging along for the trip, the Bellas can hopefully accomplish their dreams once again.',null);
