insert into hudsonu.event values(577846,'The Vagina Monolouges',cast('2015-02-14 18:00' as date),cast('2015-02-14 20:30' as date),'Brehmer Theater','Arts',NULL,'SRT','The Vagina Monologues is a show that is performed annually at Hudson. VM was written by playwright and activist Eve Ensler, who crafted the play, sharing a variety of stories of women and their bodies, as well as raise awareness about and to speak back against sexual and domestic violence. The show is performed internationally each year on Valentines day weekend (also know as VDay). Purchase your tickets at the COOP or at the door. All proceeds go to Victims of Violence.',null);
insert into hudsonu.event values(908749,'Breaking the Silence on Sex Trafficking',cast('2016-02-29 12:15' as date),cast('2016-02-29 13:00' as date),'Chapel Basement','Spirituality',NULL,'UC','Sponsored by University Church in collaboration with the Newman Community, Nicole Braddock Bromley speaks on the topic of stopping sex trafficking.'||chr(10)||'Nicole is the founder of OneVOICE and also the founder and Executive Director of OneVOICE4freedom, a non-profit organization stopping child sex trafficking around the world. In 2012 Nicole was the on-camera talent for a child sex trafficking awareness, rescue and restoration film project of Life Outreach International, where she traveled to Cambodia and met with child sex slaves in brothels and heard their stories. She began OneVOICE4freedom after her return from that life-changing work.',null);
insert into hudsonu.event values(1142659,'Brothers Welcomes Dr. Vincent T. Harris',cast('2017-02-02 16:30' as date),cast('2017-02-02 18:30' as date),'Love Auditorium','Thoughtful Learning',NULL,'BROS','The Brothers of Hudson University and other sponsors have invited Dr. Vincent T. Harris to talk to faculty and student leaders about how to integrate intentional strategies for the advancement of our male of color undergraduate students, and about how student leaders must create brave spaces through the intersections of race and gender in consecutive discussions in Love Auditorium on Thursday, February 2nd from 4:30 to 6:30 and Friday, February 3rd from 4:30 to 6:00, and 6:30 to 8:00, respectively. The first day will feature a program directed towards faculty and administration, while the second day will address student leaders as well as members of Brothers and other males of color in separate sessions. Dr. Harris aims to educate attendees about ways Hudson University can demonstrate that it is a destination for the advancement of male of color undergraduate students holistic success. After the first discussion with faculty and administrators, we will hold a small reception for Dr. Harris at the President''s House on the night of the 2nd.'||chr(10)||'Dr. Vincent T. Harris serves as Cal State Fullertons inaugural Director of the Male Success Initiative. He manages the comprehensive retention services of increasing access and persistence of men of color, through academic guidance, student leadership development, social engagement, and pre-graduation support for men of color. He is an experienced higher education administrator-scholar whose professional and research track record restores and explores the lived experiences of undergraduate and graduate students as it relates to the intersection of gender, ethnicity, sexual orientation, faith and culture. Most recently, Dr. Harris completed his post-doc employment at Harvard University as an Administrative Fellow in the Harvard College Women''s Center, through the Harvard University Office of Institutional Diversity and Equity.',null);
